	[Parameter(Mandatory = $false)]
	[string[]]$AgentId,

	[Parameter(Mandatory = $false)]
	[switch]$AgentsOnly,

	[Parameter(Mandatory = $false)]
	[ValidateSet('Prompt', 'Response', 'Both', 'Null')]
