	'sharepointsharingoperation'       = 'SharePointSharingOperation'
	'sharepoint'                       = 'SharePoint'
	'onedrive'                         = 'OneDrive'
	'microsoftteams'                   = 'MicrosoftTeams'
}

$serviceCanonicalMap = @{
