# Script version constant (must appear after param/help to keep param() valid as first executable block)
$ScriptVersion = '1.11.8'

# --- Initialize/Clear persistent script variables to prevent cross-run contamination ---
# Note: Script-scoped variables persist across multiple script invocations in the same PowerShell session
$script:partitionStatus = $null
$script:processedJobIds = $null
$script:shownJobMessages = $null

# --- Microsoft 365 Copilot license detection ---
# No hardcoded SKU GUIDs. Copilot service plans are discovered dynamically at runtime
# from /subscribedSkus by matching servicePlanName against the pattern '*COPILOT*'.
# Per-user eligibility is then computed from the user's assignedPlans where
# capabilityStatus == 'Enabled' and servicePlanId is in the discovered set.
# See Get-UserLicenseData().

# --- Synchronized Timestamp & OutputPath Validation ---

# Generate synchronized timestamp for all output files in this run
$global:ScriptRunTimestamp = Get-Date -Format 'yyyyMMdd_HHmmss'

# --- Logging Helper Functions (defined early for use throughout script) ---
# $script:LogFile was already initialized to a bootstrap temp-path file at the top
# of the script body (right after param()). DO NOT re-null it here; that would
# discard the early-startup log entries already captured. The bootstrap file is
# renamed to the final location once $OutputFile is resolved (see the relocation
# block further down). The in-memory $script:LogBuffer remains a fallback for the
# rare case where bootstrap creation failed (e.g. read-only temp).
if (-not (Get-Variable -Name LogFile -Scope Script -ErrorAction SilentlyContinue)) {
	$script:LogFile = $null
}
$script:LogBuffer = New-Object System.Collections.Generic.List[string]

function Write-Log { 
	param([Parameter(Mandatory = $true)][AllowEmptyString()][string]$Message, [string]$Level = "INFO") 
	$timestamp = Get-Date -Format "yyyy-MM-dd HH:mm:ss"
	$logEntry = "[$timestamp] [$Level] $Message"
	Microsoft.PowerShell.Utility\Write-Host $Message
	try {
		if ($script:LogFile) { Add-Content -Path $script:LogFile -Value $logEntry -Encoding UTF8 -ErrorAction SilentlyContinue }
		else { $script:LogBuffer.Add($logEntry) | Out-Null }
	} catch {}
}

# Log-file-only writer: never echoes to host. Used for diagnostic detail (temp paths,
# argument vectors, stack traces) that should be captured in the run log but not
# clutter the customer-facing console.
function Write-LogFile {
	param([Parameter(Mandatory = $true)][AllowEmptyString()][string]$Message, [string]$Level = "INFO")
	$timestamp = Get-Date -Format "yyyy-MM-dd HH:mm:ss"
	$logEntry = "[$timestamp] [$Level] $Message"
	try {
		if ($script:LogFile) { Add-Content -Path $script:LogFile -Value $logEntry -Encoding UTF8 -ErrorAction SilentlyContinue }
		else { $script:LogBuffer.Add($logEntry) | Out-Null }
	} catch {}
}

function Write-LogHost { 
	param([Parameter(Mandatory = $true)][AllowEmptyString()][string]$Message, [string]$ForegroundColor = "White") 
	Microsoft.PowerShell.Utility\Write-Host $Message -ForegroundColor $ForegroundColor
	try { 
		$timestamp = Get-Date -Format "yyyy-MM-dd HH:mm:ss"
		$logEntry = "[$timestamp] [INFO] $Message"
		if ($script:LogFile) { Add-Content -Path $script:LogFile -Value $logEntry -Encoding UTF8 -ErrorAction SilentlyContinue }
		else { $script:LogBuffer.Add($logEntry) | Out-Null }
	} catch {}
}

# Mirror Write-Host to log file with matching signature
function global:Write-Host {
	[CmdletBinding()]
	param(
		[Parameter(Position=0, ValueFromPipeline=$true, ValueFromRemainingArguments=$true)]
		$Object,
		[object] $Separator,
		[ConsoleColor] $ForegroundColor,
		[ConsoleColor] $BackgroundColor,
		[switch] $NoNewLine
	)
	process {
		Microsoft.PowerShell.Utility\Write-Host @PSBoundParameters
		try {
			# Compose message
			$msgItems = @($Object)
			$msg = ($msgItems | Out-String).TrimEnd()
			if ($msg) {
				$timestamp = Get-Date -Format "yyyy-MM-dd HH:mm:ss"
				$entry = "[$timestamp] [INFO] $msg"
				if ($script:LogFile) { Add-Content -Path $script:LogFile -Value $entry -Encoding UTF8 -ErrorAction SilentlyContinue }
				else { $script:LogBuffer.Add($entry) | Out-Null }
			}
		} catch {}
	}
}

function Get-MaskedUsername {
	<#
	.SYNOPSIS
		Masks a username or email address for secure display in logs and screenshots.
	
	.DESCRIPTION
		Converts "admin@contoso.com" to "a******n@contoso.com" to prevent accidental
		credential exposure in terminal output, screenshots, or log files.
		
		Preserves first and last character of local part, masks middle with 6 asterisks.
		Returns original string if input is null, empty, or doesn't contain "@".
	
	.PARAMETER Username
		The username or email address to mask
	
	.OUTPUTS
		Masked string (e.g., "a******n@contoso.com")
	
	.EXAMPLE
		Get-MaskedUsername -Username "admin@contoso.com"
		Returns: "a******n@contoso.com"
	#>
	
	param(
		[Parameter(Mandatory = $false)]
		[string]$Username
	)
	
	if ([string]::IsNullOrWhiteSpace($Username)) {
		return $Username
	}
	
	# Only mask if it looks like an email address
	if ($Username -notmatch '@') {
		return $Username
	}
	
	$parts = $Username -split '@'
	if ($parts.Count -ne 2) {
		return $Username
	}
	
	$localPart = $parts[0]
	$domain = $parts[1]
	
	# Handle very short usernames
	if ($localPart.Length -le 2) {
		return "$($localPart[0])******@$domain"
	}
	
	$first = $localPart[0]
	$last = $localPart[$localPart.Length - 1]
	$masked = "$first******$last@$domain"
	
	return $masked
}

# ============================================================
# DEIDENTIFICATION (-Deidentify): one-way, salted, deterministic, format-preserving.
# PowerShell deidentifies RAW output files only (the embedded Python processors
# deidentify rollup outputs). The salt, HMAC-SHA256 algorithm, normalization
# (Trim + lower-invariant), lowercase hex, and output formats below are BYTE-FOR-BYTE
# identical to the deid_* helpers in the CopilotInteraction and M365 Python
# processors (PAX deidentify spec) so the same identity hashes to the same token
# across all engines. OFF (default) = no-op: every helper returns its input unchanged.
# Irreversible: no decode map is produced or stored. DO NOT CHANGE THE SALT.
# ============================================================
$script:PaxDeidEnabled  = [bool]$Deidentify
$script:PaxDeidSaltBytes = [System.Text.Encoding]::UTF8.GetBytes('PAX-Deidentify-Salt-v1-DO-NOT-CHANGE-7f3c1e9b2d846050a1c4e8b3')
$script:PaxDeidDomain   = 'deidentified.domain'
$script:PaxDeidCache    = @{}
$script:PaxDeidMarkerSuffix = '@deidentified.domain'  # tail of every deidentified UPN/email token

# -Deidentify is CSV-only: the deprecated Excel workbook path is never scrubbed, so a
# deidentified workbook would silently leak identifiable data. Block the combination.
if ($script:PaxDeidEnabled -and $ExportWorkbook) {
	Write-Host "" -ForegroundColor Red
	Write-Host "ERROR: -Deidentify cannot be combined with -ExportWorkbook (Excel)." -ForegroundColor Red
	Write-Host "Deidentification scrubs CSV output only; the workbook path is not anonymized and would" -ForegroundColor Yellow
	Write-Host "leak identifiable data. Re-run with CSV output (omit -ExportWorkbook) to deidentify." -ForegroundColor Yellow
	exit 1
}

function Get-PaxDeidHex {
	param([string]$Value, [int]$Length)
	$norm = $Value.Trim().ToLowerInvariant()
	$hmac = [System.Security.Cryptography.HMACSHA256]::new($script:PaxDeidSaltBytes)
	try {
		$bytes = $hmac.ComputeHash([System.Text.Encoding]::UTF8.GetBytes($norm))
	} finally {
		$hmac.Dispose()
	}
	$sb = [System.Text.StringBuilder]::new(64)
	foreach ($b in $bytes) { [void]$sb.Append($b.ToString('x2')) }
	return $sb.ToString().Substring(0, $Length)
}

function Get-PaxDeidUpn {
	# UPN / email -> <12hex>@deidentified.domain
	param([string]$Value)
	if (-not $script:PaxDeidEnabled -or [string]::IsNullOrEmpty($Value)) { return $Value }
	$k = "upn`0$Value"
	if ($script:PaxDeidCache.ContainsKey($k)) { return $script:PaxDeidCache[$k] }
	$v = (Get-PaxDeidHex -Value $Value -Length 12) + '@' + $script:PaxDeidDomain
	$script:PaxDeidCache[$k] = $v
	return $v
}

function Get-PaxDeidName {
	# Person / device display name -> <12hex>
	param([string]$Value)
	if (-not $script:PaxDeidEnabled -or [string]::IsNullOrEmpty($Value)) { return $Value }
	$k = "name`0$Value"
	if ($script:PaxDeidCache.ContainsKey($k)) { return $script:PaxDeidCache[$k] }
	$v = Get-PaxDeidHex -Value $Value -Length 12
	$script:PaxDeidCache[$k] = $v
	return $v
}

function Get-PaxDeidGuid {
	# GUID -> deterministic GUID shape xxxxxxxx-xxxx-xxxx-xxxx-xxxxxxxxxxxx
	param([string]$Value)
	if (-not $script:PaxDeidEnabled -or [string]::IsNullOrEmpty($Value)) { return $Value }
	$k = "guid`0$Value"
	if ($script:PaxDeidCache.ContainsKey($k)) { return $script:PaxDeidCache[$k] }
	$h = Get-PaxDeidHex -Value $Value -Length 32
	$v = '{0}-{1}-{2}-{3}-{4}' -f $h.Substring(0,8), $h.Substring(8,4), $h.Substring(12,4), $h.Substring(16,4), $h.Substring(20,12)
	$script:PaxDeidCache[$k] = $v
	return $v
}

function Get-PaxDeidSid {
	# SID -> deterministic S-1-5-21-<d1>-<d2>-<d3>-<d4> shape
	param([string]$Value)
	if (-not $script:PaxDeidEnabled -or [string]::IsNullOrEmpty($Value)) { return $Value }
	$k = "sid`0$Value"
	if ($script:PaxDeidCache.ContainsKey($k)) { return $script:PaxDeidCache[$k] }
	$h = Get-PaxDeidHex -Value $Value -Length 32
	$d1 = [Convert]::ToUInt32($h.Substring(0,8), 16)
	$d2 = [Convert]::ToUInt32($h.Substring(8,8), 16)
	$d3 = [Convert]::ToUInt32($h.Substring(16,8), 16)
	$d4 = [Convert]::ToUInt32($h.Substring(24,8), 16)
	$v = "S-1-5-21-$d1-$d2-$d3-$d4"
	$script:PaxDeidCache[$k] = $v
	return $v
}

function Get-PaxDeidToken {
	# Opaque id (employeeId, immutableId) -> <12hex>
	param([string]$Value)
	if (-not $script:PaxDeidEnabled -or [string]::IsNullOrEmpty($Value)) { return $Value }
	$k = "tok`0$Value"
	if ($script:PaxDeidCache.ContainsKey($k)) { return $script:PaxDeidCache[$k] }
	$v = Get-PaxDeidHex -Value $Value -Length 12
	$script:PaxDeidCache[$k] = $v
	return $v
}

function Get-PaxDeidResource {
	# Resource URL -> site_<12hex> (whole-string hash; preserves distinct-count)
	param([string]$Value)
	if (-not $script:PaxDeidEnabled -or [string]::IsNullOrEmpty($Value)) { return $Value }
	$k = "res`0$Value"
	if ($script:PaxDeidCache.ContainsKey($k)) { return $script:PaxDeidCache[$k] }
	$v = 'site_' + (Get-PaxDeidHex -Value $Value -Length 12)
	$script:PaxDeidCache[$k] = $v
	return $v
}

function Get-PaxDeidFile {
	# File / document name -> file_<12hex>
	param([string]$Value)
	if (-not $script:PaxDeidEnabled -or [string]::IsNullOrEmpty($Value)) { return $Value }
	$k = "file`0$Value"
	if ($script:PaxDeidCache.ContainsKey($k)) { return $script:PaxDeidCache[$k] }
	$v = 'file_' + (Get-PaxDeidHex -Value $Value -Length 12)
	$script:PaxDeidCache[$k] = $v
	return $v
}

function Get-PaxDeidProxy {
	# proxyAddresses entry(ies) -> keep smtp:/SMTP: prefix + deidentified email.
	# Handles ';'-delimited multi-value fields.
	param([string]$Value)
	if (-not $script:PaxDeidEnabled -or [string]::IsNullOrEmpty($Value)) { return $Value }
	$parts = $Value -split ';'
	$out = foreach ($entry in $parts) {
		if ([string]::IsNullOrEmpty($entry)) {
			$entry
		} elseif ($entry.Contains(':')) {
			$idx = $entry.IndexOf(':')
			$entry.Substring(0, $idx) + ':' + (Get-PaxDeidUpn -Value $entry.Substring($idx + 1))
		} else {
			Get-PaxDeidUpn -Value $entry
		}
	}
	return ($out -join ';')
}

function Get-PaxDeidIp {
	# IP address -> deterministic, format-preserving token. IPv4 -> a.b.c.d (4 octets from the
	# first 4 HMAC bytes); IPv6 -> 8 hextets from the 16-byte HMAC. Stays a valid-looking IP so
	# downstream schema/parsers are unaffected. No-op when off or empty.
	param([string]$Value)
	if (-not $script:PaxDeidEnabled -or [string]::IsNullOrEmpty($Value)) { return $Value }
	$k = "ip`0$Value"
	if ($script:PaxDeidCache.ContainsKey($k)) { return $script:PaxDeidCache[$k] }
	$h = Get-PaxDeidHex -Value $Value -Length 32
	if ($Value.Contains(':')) {
		$groups = for ($i = 0; $i -lt 8; $i++) { $h.Substring($i * 4, 4) }
		$v = $groups -join ':'
	} else {
		$octets = for ($i = 0; $i -lt 4; $i++) { [Convert]::ToInt32($h.Substring($i * 2, 2), 16) }
		$v = $octets -join '.'
	}
	$script:PaxDeidCache[$k] = $v
	return $v
}

function Get-PaxDeidByType {
	# Dispatch a single value to the type-appropriate Get-PaxDeid* helper. Used by the JSON
	# scrubber so the same helper set (and tokens) applies to nested AuditData leaves.
	param([string]$Value, [string]$Type)
	switch ($Type) {
		'Upn'      { Get-PaxDeidUpn      -Value $Value }
		'Name'     { Get-PaxDeidName     -Value $Value }
		'Guid'     { Get-PaxDeidGuid     -Value $Value }
		'Sid'      { Get-PaxDeidSid      -Value $Value }
		'Token'    { Get-PaxDeidToken    -Value $Value }
		'Resource' { Get-PaxDeidResource -Value $Value }
		'File'     { Get-PaxDeidFile     -Value $Value }
		'Proxy'    { Get-PaxDeidProxy    -Value $Value }
		'Ip'       { Get-PaxDeidIp       -Value $Value }
		default    { $Value }
	}
}

function Get-PaxDeidJsonMap {
	# PATH-AWARE map of AuditData JSON leaf -> deid type. Path uses '.' for nested objects and
	# '[]' for array elements (e.g. Folders[].FolderItems[].Subject). Path-awareness is required
	# because the same leaf name means different things by location: root 'Id' is the audit
	# RecordId (KEEP) while Item.Id / FolderItems[].Id are item identifiers (scrub). Only the keys
	# below are altered; every other field is preserved verbatim (app/tenant/org identities,
	# operations, types, timestamps, etc. are intentionally absent and therefore kept).
	@{
		# Identity (UPN / SID / GUID)
		'UserId'                                         = 'Upn'
		'MailboxOwnerUPN'                                = 'Upn'
		'LogonUserSid'                                   = 'Sid'
		'MailboxOwnerSid'                                = 'Sid'
		'MailboxGuid'                                    = 'Guid'
		'UserKey'                                        = 'Guid'
		'TokenObjectId'                                  = 'Guid'
		'SessionId'                                      = 'Guid'
		'AppAccessContext.AADSessionId'                  = 'Guid'
		'AppAccessContext.UniqueTokenId'                 = 'Token'
		# IP addresses
		'ClientIP'                                       = 'Ip'
		'ClientIPAddress'                                = 'Ip'
		'ActorIpAddress'                                 = 'Ip'
		# Resources / files (rollup-aligned)
		'SiteUrl'                                        = 'Resource'
		'SourceRelativeUrl'                              = 'Resource'
		'SourceFileName'                                 = 'File'
		'CopilotEventData.ThreadId'                      = 'Token'
		'CopilotEventData.AccessedResources[].SiteUrl'   = 'Resource'
		'CopilotEventData.AccessedResources[].Name'      = 'File'
		# Mail item identifiers + content
		'Folders[].FolderItems[].InternetMessageId'      = 'Token'
		'Folders[].FolderItems[].Id'                     = 'Token'
		'Folders[].FolderItems[].ImmutableId'            = 'Token'
		'Folders[].FolderItems[].Subject'                = 'Token'
		'Folders[].Id'                                   = 'Token'
		'Item.InternetMessageId'                         = 'Token'
		'Item.Id'                                        = 'Token'
		'Item.ImmutableId'                               = 'Token'
		'Item.Subject'                                   = 'Token'
		'Item.Attachments'                               = 'Token'
		'Item.ParentFolder.Id'                           = 'Token'
	}
}

function Invoke-PaxDeidJsonNode {
	# Recursively scrub a System.Text.Json JsonNode in place: any STRING leaf whose path is in
	# $Map is replaced with its deid token; every other leaf/structure is left untouched. Keeps
	# strings as strings (no ConvertFrom-Json date auto-conversion), preserving full fidelity.
	param(
		[System.Text.Json.Nodes.JsonNode]$Node,
		[string]$Path,
		[hashtable]$Map
	)
	if ($null -eq $Node) { return }
	if ($Node -is [System.Text.Json.Nodes.JsonObject]) {
		$keys = @($Node.GetEnumerator() | ForEach-Object { $_.Key })
		foreach ($key in $keys) {
			$child = $Node[$key]
			$childPath = if ($Path) { "$Path.$key" } else { $key }
			if ($child -is [System.Text.Json.Nodes.JsonValue]) {
				if ($child.GetValueKind() -eq [System.Text.Json.JsonValueKind]::String -and $Map.ContainsKey($childPath)) {
					$orig = $child.GetValue[string]()
					$new = Get-PaxDeidByType -Value $orig -Type $Map[$childPath]
					if ($new -ne $orig) { $Node[$key] = [System.Text.Json.Nodes.JsonValue]::Create($new) }
				}
			} else {
				Invoke-PaxDeidJsonNode -Node $child -Path $childPath -Map $Map
			}
		}
	}
	elseif ($Node -is [System.Text.Json.Nodes.JsonArray]) {
		$arrPath = "$Path[]"
		for ($i = 0; $i -lt $Node.Count; $i++) {
			$child = $Node[$i]
			if ($child -is [System.Text.Json.Nodes.JsonValue]) {
				if ($child.GetValueKind() -eq [System.Text.Json.JsonValueKind]::String -and $Map.ContainsKey($arrPath)) {
					$orig = $child.GetValue[string]()
					$new = Get-PaxDeidByType -Value $orig -Type $Map[$arrPath]
					if ($new -ne $orig) { $Node[$i] = [System.Text.Json.Nodes.JsonValue]::Create($new) }
				}
			} else {
				Invoke-PaxDeidJsonNode -Node $child -Path $arrPath -Map $Map
			}
		}
	}
}

function Get-PaxDeidJson {
	# Deidentify a JSON blob (e.g. the AuditData column) IN FULL: parse, recursively scrub only the
	# mapped PII leaves, re-serialize. Returns the value unchanged when off/empty. Returns the
	# redaction marker ONLY when the value cannot be parsed as JSON (safety net so a malformed blob
	# can never leak). Re-serializes with relaxed escaping to stay close to the source formatting.
	param([string]$Value)
	if (-not $script:PaxDeidEnabled -or [string]::IsNullOrEmpty($Value)) { return $Value }
	$node = $null
	try { $node = [System.Text.Json.Nodes.JsonNode]::Parse($Value) } catch { return '[REDACTED-DEIDENTIFY]' }
	if ($null -eq $node) { return $Value }
	if ($null -eq $script:PaxDeidJsonMapCached) { $script:PaxDeidJsonMapCached = Get-PaxDeidJsonMap }
	if ($null -eq $script:PaxDeidJsonOpts) {
		$script:PaxDeidJsonOpts = [System.Text.Json.JsonSerializerOptions]::new()
		$script:PaxDeidJsonOpts.Encoder = [System.Text.Encodings.Web.JavaScriptEncoder]::UnsafeRelaxedJsonEscaping
	}
	Invoke-PaxDeidJsonNode -Node $node -Path '' -Map $script:PaxDeidJsonMapCached
	return $node.ToJsonString($script:PaxDeidJsonOpts)
}

function Invoke-PaxRawDeidentify {
	<#
	.SYNOPSIS
		Post-write pass: deidentify a finished RAW output CSV in place.
	.DESCRIPTION
		Operates on whichever target columns are present in the file's header, so the SAME
		function handles both the EntraUsers CSV (47-col) and the Purview audit CSV (153-col
		exploded). Each present identity/resource column is hashed with the type-appropriate
		Get-PaxDeid* helper; tokens match the Python-deidentified rollup because the salt and
		algorithm are shared. Any raw AuditData / CopilotEventData JSON blob column is
		deidentified IN PLACE via Get-PaxDeidJson — a recursive, path-aware System.Text.Json
		scrub that tokenizes only the PII leaves and leaves every other field (timestamps,
		workload, app/tenant ids, schema urls, flags) byte-for-byte identical, so the blob stays
		full-fidelity Purview data with only PII altered. (A blob that fails to parse is redacted
		to [REDACTED-DEIDENTIFY] as a safety net so PII can never leak.)
		No-op when -Deidentify is off. Rewrites atomically via a temp file + Move-Item, preserving
		column order. PowerShell only ever scrubs RAW files; rollup outputs are owned by Python.
	#>
	param([Parameter(Mandatory = $true)][string]$Path)
	if (-not $script:PaxDeidEnabled) { return }
	if ([string]::IsNullOrWhiteSpace($Path) -or -not (Test-Path -LiteralPath $Path)) { return }

	# Column name -> deid helper kind. Union of audit (153-col) + EntraUsers (47-col) fields.
	# Column names are disjoint across the two schemas, so one map serves both.
	$map = @{
		# Purview audit exploded identity + resource fields
		'UserId'                   = 'Upn'
		'MailboxOwnerUPN'          = 'Upn'
		'MailboxGuid'              = 'Guid'
		'LogonUserSid'             = 'Sid'
		'MailboxOwnerSid'          = 'Sid'
		'DeviceDisplayName'        = 'Name'
		'SiteUrl'                  = 'Resource'
		'SourceRelativeUrl'        = 'Resource'
		'SourceFileName'           = 'File'
		'AccessedResource_SiteUrl' = 'Resource'
		'AccessedResource_Name'    = 'File'
		# Purview audit exploded — additional identity / network / resource fields
		# (flat top-level columns produced by the 153-col explosion; nested JSON PII is
		#  handled separately by Get-PaxDeidJson on the AuditData blob).
		'ClientIP'                 = 'Ip'
		'ClientIPAddress'          = 'Ip'
		'ActorIpAddress'           = 'Ip'
		'UserKey'                  = 'Guid'
		'TokenObjectId'            = 'Guid'
		'SessionId'                = 'Guid'
		'ThreadId'                 = 'Token'
		'ChatId'                   = 'Token'
		'ConversationId'           = 'Token'
		'Site'                     = 'Resource'
		'MeetingURL'               = 'Resource'
		'TeamName'                 = 'Name'
		'ChannelName'              = 'Name'
		'VideoName'                = 'File'
		'FormName'                 = 'File'
		# EntraUsers identity fields
		'userPrincipalName'        = 'Upn'
		'displayName'              = 'Name'
		'mail'                     = 'Upn'
		'givenName'                = 'Name'
		'surname'                  = 'Name'
		'UserName'                 = 'Upn'
		'employeeId'               = 'Token'
		'onPremisesImmutableId'    = 'Token'
		'proxyAddresses_Primary'   = 'Proxy'
		'proxyAddresses_All'       = 'Proxy'
		'id'                       = 'Guid'
		'manager_id'               = 'Guid'
		'manager_userPrincipalName' = 'Upn'
		'manager_displayName'      = 'Name'
		'manager_mail'             = 'Upn'
		'ManagerID'                = 'Guid'
	}
	# JSON blob columns: deidentified in place by recursive path-aware scrub (Get-PaxDeidJson),
	# NOT flat-hashed — their PII lives in nested keys the column map cannot reach.
	$jsonCols = @('AuditData', 'CopilotEventData')

	$rows = @(Import-Csv -LiteralPath $Path)
	if ($rows.Count -eq 0) { return }
	$columns = $rows[0].PSObject.Properties.Name
	$active = @{}
	foreach ($c in $columns) { if ($map.ContainsKey($c)) { $active[$c] = $map[$c] } }
	$activeJson = @($jsonCols | Where-Object { $columns -contains $_ })
	if ($active.Count -eq 0 -and $activeJson.Count -eq 0) { return }

	foreach ($row in $rows) {
		foreach ($col in @($active.Keys)) {
			$val = $row.$col
			if ([string]::IsNullOrEmpty($val)) { continue }
			$row.$col = switch ($active[$col]) {
				'Upn'      { Get-PaxDeidUpn -Value $val }
				'Name'     { Get-PaxDeidName -Value $val }
				'Guid'     { Get-PaxDeidGuid -Value $val }
				'Sid'      { Get-PaxDeidSid -Value $val }
				'Token'    { Get-PaxDeidToken -Value $val }
				'Resource' { Get-PaxDeidResource -Value $val }
				'File'     { Get-PaxDeidFile -Value $val }
				'Proxy'    { Get-PaxDeidProxy -Value $val }
				'Ip'       { Get-PaxDeidIp -Value $val }
			}
		}
		foreach ($jc in $activeJson) {
			if (-not [string]::IsNullOrEmpty($row.$jc)) { $row.$jc = Get-PaxDeidJson -Value $row.$jc }
		}
	}

	# Atomic in-place rewrite (temp + replace), preserving original column order.
	$tmp = "$Path.deid.tmp"
	Open-CsvWriter -Path $tmp -Columns $columns
	Write-CsvRows -Rows $rows -Columns $columns
	Close-CsvWriter
	Move-Item -LiteralPath $tmp -Destination $Path -Force
}

function Test-PaxFileDeidentified {
	<#
	.SYNOPSIS
		Classify a CSV append target as 'deid' | 'raw' | 'unknown' by sampling its identity column.
	.DESCRIPTION
		'deid'   = at least one non-empty identity value carries the deidentify marker
		           (<hex>@deidentified.domain).
		'raw'    = identity values present, none carry the marker.
		'unknown'= file missing/unreadable, no recognised identity column, or no non-empty
		           identity values to judge by (caller skips the guard in that case).
		Streams at most ~200 rows (pipeline short-circuits) so it is cheap on large files.
	#>
	param([Parameter(Mandatory = $true)][string]$Path)
	if ([string]::IsNullOrWhiteSpace($Path) -or -not (Test-Path -LiteralPath $Path)) { return 'unknown' }
	try {
		$sample = @(Import-Csv -LiteralPath $Path | Select-Object -First 200)
	} catch {
		return 'unknown'
	}
	if ($sample.Count -eq 0) { return 'unknown' }
	$cols = $sample[0].PSObject.Properties.Name
	# Identity columns across every deidentified output family (audit raw, CopilotInteraction
	# fact (aibv), M365 rollup, Users dim). The aio fact has no UPN column -> 'unknown' there,
	# but the paired -AppendUserInfo Users dim (PersonId) carries the signal.
	$idCol = @('Audit_UserId', 'UserId', 'PersonId', 'userPrincipalName', 'MailboxOwnerUPN') |
		Where-Object { $cols -contains $_ } | Select-Object -First 1
	if (-not $idCol) { return 'unknown' }
	$sawValue = $false
	foreach ($r in $sample) {
		$v = [string]$r.$idCol
		if ([string]::IsNullOrEmpty($v)) { continue }
		$sawValue = $true
		if ($v.TrimEnd().ToLowerInvariant().EndsWith($script:PaxDeidMarkerSuffix)) { return 'deid' }
	}
	if ($sawValue) { return 'raw' }
	return 'unknown'
}

function Assert-PaxDeidAppendConsistency {
	<#
	.SYNOPSIS
		Hard-stop guard preventing deidentified/raw data from being mixed in an append target.
	.DESCRIPTION
		Data-accuracy gate for -AppendFile / -AppendUserInfo:
		  * BLOCK when the target's deidentify state disagrees with this run's -Deidentify state
		    (mixing hashed + raw identities corrupts user joins and distinct counts).
		  * BLOCK appending into an already-deidentified target in NON-rollup mode (the whole-file
		    post-pass would re-hash existing rows -> double-hashing). Rollup append into a
		    deidentified target is allowed because it MERGES two same-salt outputs.
		Throws on violation; the caller renders the message and exits non-zero.
	#>
	param(
		[Parameter(Mandatory = $true)][AllowEmptyCollection()][object[]]$Targets,
		[Parameter(Mandatory = $true)][bool]$IsRollup
	)
	$runDeid = [bool]$script:PaxDeidEnabled
	foreach ($t in $Targets) {
		$path = [string]$t.Path
		$label = [string]$t.Label
		if ([string]::IsNullOrWhiteSpace($path)) { continue }
		$state = Test-PaxFileDeidentified -Path $path
		if ($state -eq 'unknown') { continue }
		$tgtDeid = ($state -eq 'deid')
		if ($tgtDeid -ne $runDeid) {
			$desc = if ($tgtDeid) { 'is already DEIDENTIFIED but this run is NOT -Deidentify' }
				else { 'is NOT deidentified but this run IS -Deidentify' }
			throw ("-Deidentify/append mismatch: the $label target $desc. Mixing deidentified and raw " +
				"identities in one file corrupts user joins and distinct counts. Use a separate target " +
				"for deidentified output, or re-run with a matching -Deidentify state.`nTarget: $path")
		}
		if ($tgtDeid -and $runDeid -and -not $IsRollup) {
			throw ("-Deidentify cannot append to an already-deidentified file in non-rollup mode: the " +
				"$label target is deidentified and a non-rollup append would re-hash its existing rows " +
				"(double-hashing). Append on a RAW master and deidentify a fresh copy, or use " +
				"-Rollup / -RollupPlusRaw (which merge matching-salt outputs).`nTarget: $path")
		}
	}
}

# --- Helper Function: Detect if PAYG billing is configured in tenant ---
function Test-PAYGBillingEnabled {
	<#
	.SYNOPSIS
		Attempts to detect if Microsoft Purview PAYG billing is configured in the tenant.
	
	.DESCRIPTION
		Checks for indicators that PAYG billing is enabled:
		- Attempts to query audit records for AIAppInteraction type (PAYG-only)
		- If records exist or query succeeds without billing errors, PAYG is likely enabled
		- Returns $null if detection is inconclusive
	
	.OUTPUTS
		$true if PAYG billing appears to be enabled
		$false if PAYG billing appears to be disabled or not configured
		$null if detection is inconclusive (requires actual query attempt)
	#>
	
	# Note: The most reliable way to detect PAYG is to attempt a query for AIAppInteraction
	# and check for specific error responses. However, this requires actual data/timeframe.
	# For now, we return $null to indicate "unknown" and let the post-query detection handle it.
	
	Write-LogHost "PAYG billing detection: Deferred to post-query validation" -ForegroundColor DarkGray
	return $null
}

# --- Excel Export Validation ---

# AppendFile with Excel requires ExportWorkbook
if ($AppendFile -and $ExportWorkbook -eq $false) {
	# AppendFile is fine for CSV (will be handled later), but needs validation for Excel intent
	# This check is only if user explicitly wants Excel append
}

if ($AppendFile -and -not $ExportWorkbook -and -not $PSBoundParameters.ContainsKey('ExportWorkbook')) {
	# User wants AppendFile but didn't specify format - this is OK, will default to CSV append
}

# Rollup post-processor always requires a single combined Purview CSV. When
# -Rollup / -RollupPlusRaw is bound but -CombineOutput is not, force it on
# here so the export-mode banner below reflects the resolved (combined) shape
# instead of the user's default separate-files layout. The broader
# -Rollup / -RollupPlusRaw validation (mutual exclusion, blockers, processor
# mode detection) still runs later in the rollup-handling block; that block's
# own -CombineOutput auto-enable is a no-op once this one has fired.
if (($Rollup -or $RollupPlusRaw) -and -not $CombineOutput) {
	$_rollupSwitchName = if ($Rollup) { '-Rollup' } else { '-RollupPlusRaw' }
	$CombineOutput     = [System.Management.Automation.SwitchParameter]::new($true)
	Write-Host "INFO: $_rollupSwitchName auto-enabled -CombineOutput (rollup post-processor requires a single combined Purview CSV)." -ForegroundColor Cyan
}

# Log export mode
if ($ExportWorkbook) {
	# Determine Excel output mode based on -CombineOutput parameter
	if ($CombineOutput) {
		$excelModeMsg = "Excel export mode: Combined activity tab + separate EntraUsers tab (if requested)"
		if ($IncludeAgent365Info -or $OnlyAgent365Info) { $excelModeMsg += " + Agents365 tab" }
		Write-Host $excelModeMsg -ForegroundColor Cyan
	} else {
		# Default for Excel: separated tabs
		$excelModeMsg = "Excel export mode: Multi-tab workbook (one tab per activity type)"
		if ($IncludeAgent365Info -or $OnlyAgent365Info) { $excelModeMsg += " + Agents365 tab" }
		Write-Host $excelModeMsg -ForegroundColor Cyan
	}
	
	if ($AppendFile) {
		Write-Host "Append mode: Enabled (will validate existing workbook structure)" -ForegroundColor Cyan
	}
	Write-Host ""
} else {
	# CSV export mode
	if ($OnlyUserInfo) {
		# OnlyUserInfo mode: No activity files, just Entra user data
		$onlyUserMsg = "CSV export mode: Entra user directory and licensing data only (no audit logs)"
		if ($IncludeAgent365Info) { $onlyUserMsg += " + separate Agents365 file" }
		Write-Host $onlyUserMsg -ForegroundColor Cyan
	} elseif ($OnlyAgent365Info) {
		# OnlyAgent365Info mode: No activity files, just Agent 365 catalog data
		Write-Host "CSV export mode: Microsoft Agent 365 catalog only (no audit logs, no Entra users)" -ForegroundColor Cyan
	} else {
		# Determine CSV output mode based on -CombineOutput parameter
		if ($RAWInputCSV -and -not $CombineOutput.IsPresent) { $CombineOutput = [System.Management.Automation.SwitchParameter]::new($true) }
		if ($CombineOutput.IsPresent -or $RAWInputCSV) {
			# User specified -CombineOutput switch: combine all activity types
			$csvModeMsg = "Combined activity file"
			if ($IncludeUserInfo) { $csvModeMsg += " + separate EntraUsers file" }
			if ($IncludeAgent365Info) { $csvModeMsg += " + separate Agents365 file" }
			Write-Host "CSV export mode: $csvModeMsg" -ForegroundColor Cyan
		} else {
			# Default for live CSV: separate files per activity type
			$csvModeMsg = "Separate activity files (one per activity type)"
			if ($IncludeUserInfo) { $csvModeMsg += " + EntraUsers file" }
			if ($IncludeAgent365Info) { $csvModeMsg += " + Agents365 file" }
			Write-Host "CSV export mode: $csvModeMsg" -ForegroundColor Cyan
		}
	}
	Write-Host ""
}

# OutputPath shape normalization runs AFTER tier inference below (folder-only
# enforcement applies only to Local tier; SharePoint/Fabric URLs are handled
# by the remote-output plumbing).

# ============================================================================
# DESTINATION VALIDATION AND TIER INFERENCE
# ----------------------------------------------------------------------------
# Storage tier is inferred from each -OutputPath* value's form:
#   Drive-rooted absolute path        -> Local
#   https://*.sharepoint*             -> SharePoint
#   https://*.onelake.dfs.fabric.*    -> Fabric
# UNC paths (\\server\share\...) are rejected on every destination switch.
# All destinations supplied to a single run must resolve to the same storage
# tier (no mixed Local/SP/Fabric in one invocation). Any two destinations
# that resolve to identical fully qualified paths are rejected (FullPath
# collision). $OutputPathLog allows the Fabric Files/ form additionally.
# Legacy $script:RemoteOutputMode / $script:RemoteOutputUrl are populated from
# the inferred Purview destination so downstream code that predates the new
# model continues to operate unchanged.
# ============================================================================
$script:RemoteOutputMode = 'None'   # 'None' | 'SharePoint' | 'Fabric'
$script:RemoteOutputUrl  = $null
$script:RemoteScratchDir = $null

# Per-data-type effective destinations and inferred tiers. Populated below.
$script:DestTier        = @{}   # 'Purview'|'UserInfo'|'Agent365Info'|'Log' -> 'Local'|'SharePoint'|'Fabric'
$script:DestRaw         = @{}   # original user-supplied value (trimmed)
$script:DestIsBound     = @{}   # was the switch actually supplied?

$spUrlPattern     = '^https?://[^/]+\.sharepoint(?:-df|-mil)?\.[a-z]{2,3}(?:/.+)?$'
# Fabric Tables/<schema> segment is constrained to identifier-style strings
# (alpha/underscore start, then alphanumeric/underscore) to match the Schemas-mode
# Lakehouse rules and the downstream Delta-write detection regex (search for
# $fabricDeltaMode). Files/ subpaths remain permissive.
# Item segment is EITHER the name form (<name>.Lakehouse, suffix required) OR the
# GUID form (<itemGUID>, no suffix) - both are first-class OneLake DFS addressing
# modes (learn.microsoft.com/fabric/onelake/onelake-access-api). The workspace
# segment ([^/]+) already accepts a name or GUID.
$fabricItemSeg     = '(?:[^/]+\.Lakehouse|[0-9a-fA-F]{8}-[0-9a-fA-F]{4}-[0-9a-fA-F]{4}-[0-9a-fA-F]{4}-[0-9a-fA-F]{12})'
$fabricRootPattern = "^https://([a-z0-9-]+-)?onelake\.dfs\.fabric\.microsoft\.com/[^/]+/$fabricItemSeg(/Tables(/[A-Za-z_][A-Za-z0-9_]*)?|/Files(/.+)?)?/?`$"
$fabricFilesPattern = "^https://([a-z0-9-]+-)?onelake\.dfs\.fabric\.microsoft\.com/[^/]+/$fabricItemSeg/Files(/.+)?/?`$"

function script:Get-PathTier {
	param([string]$Value, [string]$SwitchName, [switch]$AllowFabricFilesOnly)
	if ([string]::IsNullOrWhiteSpace($Value)) { return $null }
	$v = $Value.Trim()
	if ($v -match '^\\\\') {
		Write-Host ("ERROR: -{0} does not accept UNC paths ('{1}')." -f $SwitchName, $v) -ForegroundColor Red
		Write-Host "       Provide a drive-rooted local path, a SharePoint URL, or a Fabric OneLake URL." -ForegroundColor Yellow
		exit 1
	}
	if ($v -match '^https?://') {
		if ($v -match $spUrlPattern) { return 'SharePoint' }
		if ($AllowFabricFilesOnly) {
			if ($v -match $fabricFilesPattern) { return 'Fabric' }
			Write-Host ("ERROR: -{0} on a Fabric destination must point under Files/ (logs are not tabular)." -f $SwitchName) -ForegroundColor Red
			Write-Host ("       Provided: {0}" -f $v) -ForegroundColor Yellow
			exit 1
		}
		if ($v -match $fabricRootPattern) { return 'Fabric' }
		Write-Host ("ERROR: -{0} URL is not a recognized SharePoint or Fabric Lakehouse destination." -f $SwitchName) -ForegroundColor Red
		Write-Host ("       Provided: {0}" -f $v) -ForegroundColor Yellow
		Write-Host "       Examples:" -ForegroundColor Yellow
		Write-Host "         https://<tenant>.sharepoint.com/sites/<site>/<library>[/<sub>]" -ForegroundColor DarkGray
		Write-Host "         https://onelake.dfs.fabric.microsoft.com/<workspace>/<item>.Lakehouse" -ForegroundColor DarkGray
		Write-Host "         https://onelake.dfs.fabric.microsoft.com/<workspace>/<item>.Lakehouse/Tables" -ForegroundColor DarkGray
		Write-Host "         https://onelake.dfs.fabric.microsoft.com/<workspaceGUID>/<itemGUID>   (GUID form, no .Lakehouse suffix)" -ForegroundColor DarkGray
		exit 1
	}
	# Local: require drive-rooted absolute path.
	if ($v -match '^[A-Za-z]:[\\/]' -or $v -match '^/') {
		return 'Local'
	}
	Write-Host ("ERROR: -{0} must be a drive-rooted absolute path, a SharePoint URL, or a Fabric OneLake URL." -f $SwitchName) -ForegroundColor Red
	Write-Host ("       Provided: {0}" -f $v) -ForegroundColor Yellow
	exit 1
}

$destSwitches = @(
	@{ Key = 'Purview'      ; Name = 'OutputPath'              ; Value = $OutputPath              ; AllowFabricFilesOnly = $false },
	@{ Key = 'UserInfo'     ; Name = 'OutputPathUserInfo'      ; Value = $OutputPathUserInfo      ; AllowFabricFilesOnly = $false },
	@{ Key = 'Agent365Info' ; Name = 'OutputPathAgent365Info'  ; Value = $OutputPathAgent365Info  ; AllowFabricFilesOnly = $false },
	@{ Key = 'Log'          ; Name = 'OutputPathLog'           ; Value = $OutputPathLog           ; AllowFabricFilesOnly = $true  }
)
foreach ($ds in $destSwitches) {
	$bound = $PSBoundParameters.ContainsKey($ds.Name)
	$script:DestIsBound[$ds.Key] = $bound
	if ($bound -and -not [string]::IsNullOrWhiteSpace($ds.Value)) {
		$tier = script:Get-PathTier -Value $ds.Value -SwitchName $ds.Name -AllowFabricFilesOnly:$ds.AllowFabricFilesOnly
		$script:DestTier[$ds.Key] = $tier
		$script:DestRaw[$ds.Key]  = $ds.Value.Trim()
	}
}

# --- Append-side tier inference ---
# Treat the three -Append* switches as alternate suppliers of the stream destination.
# A relative filename (no scheme, no drive letter) is "deferred" — tier is inherited
# from the corresponding -OutputPath* (or the default scratch dir). A URL or drive-
# rooted full path sets the stream tier directly when the -OutputPath* counterpart
# is unbound (the XOR validator below rejects the both-bound case).
$script:AppendIsBound  = @{}
$script:AppendRaw      = @{}
$script:AppendIsRemote = @{}
$appendSwitches = @(
	@{ Key = 'Purview'      ; Name = 'AppendFile'         ; Value = $AppendFile          ; Bound = $PSBoundParameters.ContainsKey('AppendFile')         },
	@{ Key = 'UserInfo'     ; Name = 'AppendUserInfo'     ; Value = $AppendUserInfo      ; Bound = $PSBoundParameters.ContainsKey('AppendUserInfo')     },
	@{ Key = 'Agent365Info' ; Name = 'AppendAgent365Info' ; Value = $AppendAgent365Info  ; Bound = $PSBoundParameters.ContainsKey('AppendAgent365Info') }
)
foreach ($as in $appendSwitches) {
	$script:AppendIsBound[$as.Key] = $as.Bound
	if (-not $as.Bound -or [string]::IsNullOrWhiteSpace($as.Value)) { continue }
	$v = $as.Value.Trim()
	$script:AppendRaw[$as.Key] = $v
	$looksUrl     = $v -match '^https?://'
	$looksRooted  = $v -match '^[A-Za-z]:[\\/]' -or $v -match '^/'
	$looksUnc     = $v -match '^\\\\'
	if ($looksUnc) {
		Write-Host ("ERROR: -{0} does not accept UNC paths ('{1}')." -f $as.Name, $v) -ForegroundColor Red
		Write-Host "       Provide a relative filename, a drive-rooted local path, a SharePoint URL, or a Fabric OneLake URL." -ForegroundColor Yellow
		exit 1
	}
	if ($looksUrl -or $looksRooted) {
		# Full-form: classify via Get-PathTier (which exits on invalid forms).
		$aTier = script:Get-PathTier -Value $v -SwitchName $as.Name
		$script:AppendIsRemote[$as.Key] = ($aTier -ne 'Local')
		# Promote the stream's tier from the Append side when the OutputPath side is unbound.
		if (-not $script:DestTier.ContainsKey($as.Key)) {
			$script:DestTier[$as.Key] = $aTier
			$script:DestRaw[$as.Key]  = $v
		}
		elseif ($script:DestTier[$as.Key] -ne $aTier) {
			# OutputPath* and Append* both bound on different tiers — XOR validator
			# below will fire the canonical "both bound" error, but flag the tier
			# mismatch here too in case XOR is bypassed by a future code path.
			Write-Host ("ERROR: -{0} ({1}) and -{2} ({3}) resolve to different storage tiers." -f $as.Name, $aTier, ($destSwitches | Where-Object Key -EQ $as.Key | Select-Object -First 1 -ExpandProperty Name), $script:DestTier[$as.Key]) -ForegroundColor Red
			exit 1
		}
	} else {
		# Relative filename — tier deferred to the -OutputPath* side (or local default).
		$script:AppendIsRemote[$as.Key] = $false
	}
}

# Tier consistency across all bound destinations (excluding -OutputPathLog when it
# targets Fabric Files/ — the log is allowed under Files/ on a Fabric data run).
$tiersForConsistency = @()
foreach ($k in @('Purview','UserInfo','Agent365Info','Log')) {
	if ($script:DestTier.ContainsKey($k)) { $tiersForConsistency += $script:DestTier[$k] }
}
$tiersForConsistency = $tiersForConsistency | Select-Object -Unique
if ($tiersForConsistency.Count -gt 1) {
	Write-Host ("ERROR: Mixed storage tiers across -OutputPath* switches ({0}). All destinations in one run must resolve to the same tier." -f ($tiersForConsistency -join ', ')) -ForegroundColor Red
	exit 1
}

# FullPath collision: any two bound destinations resolving to identical fully
# qualified paths are rejected. Folder-only inputs that resolve to the same
# folder with different default basenames are not collisions (compared on the
# normalized input as supplied; default basenames are appended downstream).
$normalizedDests = @{}
foreach ($k in @('Purview','UserInfo','Agent365Info','Log')) {
	if (-not $script:DestRaw.ContainsKey($k)) { continue }
	$norm = $script:DestRaw[$k].TrimEnd('/','\').ToLowerInvariant()
	# Only flag collisions when the supplied form is a full file path (contains a basename extension).
	if ($norm -match '\.[a-z0-9]{2,5}$') {
		if ($normalizedDests.ContainsKey($norm)) {
			Write-Host ("ERROR: -{0} and -{1} resolve to the same fully qualified path:" -f $normalizedDests[$norm], $k) -ForegroundColor Red
			Write-Host ("       {0}" -f $script:DestRaw[$k]) -ForegroundColor Yellow
			exit 1
		}
		$normalizedDests[$norm] = $k
	}
}

# Populate legacy back-compat variables from the Purview destination so downstream
# code paths that pre-date the new model keep working without per-call refactors.
# When Purview is out of scope (-OnlyUserInfo / -OnlyAgent365Info), or when Purview
# is in scope but its destination was supplied via -AppendFile (already absorbed
# into $script:DestTier['Purview'] above), the promotion below still fires.
# Additionally, in only-modes the remote tier may come from -OutputPathUserInfo /
# -AppendUserInfo / -OutputPathAgent365Info / -AppendAgent365Info instead — promote
# from whichever stream is in scope so the remote pre-flight + scratch-dir handling
# downstream activates correctly.
if ($script:DestTier.ContainsKey('Purview')) {
	switch ($script:DestTier['Purview']) {
		'SharePoint' {
			$script:RemoteOutputMode = 'SharePoint'
			$script:RemoteOutputUrl  = $script:DestRaw['Purview'].TrimEnd('/')
		}
		'Fabric' {
			$script:RemoteOutputMode = 'Fabric'
			$script:RemoteOutputUrl  = $script:DestRaw['Purview'].TrimEnd('/')
		}
	}
}
# Fallback promotion: when Purview tier is unset (only-modes), promote from
# the first in-scope non-Purview stream that resolved to a remote tier.
if ($script:RemoteOutputMode -eq 'None') {
	foreach ($k in @('UserInfo','Agent365Info')) {
		if (-not $script:DestTier.ContainsKey($k)) { continue }
		$t = $script:DestTier[$k]
		if ($t -eq 'SharePoint' -or $t -eq 'Fabric') {
			$script:RemoteOutputMode = $t
			$script:RemoteOutputUrl  = $script:DestRaw[$k].TrimEnd('/')
			break
		}
	}
}

# Normalize RemoteOutputUrl + populate $script:DestParentUrl with FOLDER URLs.
# When the source switch was -AppendFile / -AppendUserInfo / -AppendAgent365Info,
# or when -OutputPath* was supplied as a file URL, the original DestRaw values are
# FILE URLs (last segment ends in a recognized data-artifact extension). Downstream
# code — Resolve-SharePointTarget / Resolve-FabricTarget (parse the URL as folder +
# leaf), Get-DisplayPath (appends sibling leaves like .log / _PARTIAL.csv), the
# per-data-type parent-URL routing in the upload sweep ($dtParentUrl /
# $logParentOverride), and Get-RemoteFile-* — all assume folder semantics. Leaving
# a file URL in those code paths would produce '.../foo.csv/foo.log' style nesting
# in display, and a 404 NotFound when re-downloading the append target.
#
# $script:DestRaw stays AS-SUPPLIED so the per-data-type destinations banner can
# still print the file-URL form the user typed in.
# $script:DestParentUrl is the FOLDER URL form used by upload/download routing and
# display-leaf composition.
# $script:RemoteOutputUrl is normalized to a folder URL for the same reason.
# .Lakehouse is a folder marker (Lakehouse root); do NOT treat it as a file.
$script:DestParentUrl = @{}
$script:NormalizeFolderUrl = {
	param([string]$u)
	if ([string]::IsNullOrWhiteSpace($u)) { return $u }
	if ($u -match '/[^/]+\.(csv|log|xlsx|json|parquet|txt)$') {
		return ($u -replace '/[^/]+\.[A-Za-z0-9]+$','')
	}
	return $u
}
if ($script:RemoteOutputUrl) {
	$script:RemoteOutputUrl = & $script:NormalizeFolderUrl $script:RemoteOutputUrl
}
foreach ($k in @('Purview','UserInfo','Agent365Info','Log')) {
	if (-not $script:DestRaw.ContainsKey($k)) { continue }
	if (-not $script:DestTier.ContainsKey($k)) { continue }
	if ($script:DestTier[$k] -eq 'Local') { continue }
	$script:DestParentUrl[$k] = & $script:NormalizeFolderUrl $script:DestRaw[$k]
}

# Effective-basename helpers. Single source of truth for the leaf used
# by the EntraUsers and Agent 365 streams everywhere display/banner code mentions
# them. Resolution order:
#   1. If -AppendUserInfo / -AppendAgent365Info is bound, inherit the target's
#      original leaf — the writer reuses that leaf (so the merged output replaces
#      the original remote URL via the upload sweep's Append-leaf match), and
#      the banners need to display the same name the customer typed and the
#      remote destination will end up holding.
#   2. Else if -OutputPath* was supplied in file-form, use that file's leaf.
#   3. Else default to the timestamped basename.
# NOTE: These helpers must run AFTER $script:AppendRaw / $script:DestRaw are
# populated (done by the destSwitches + appendSwitches blocks above).
$script:GetEffectiveEntraBasename = {
	# Returns the basename of the RAW EntraUsers CSV. Under -AppendUserInfo the
	# raw is always written to its natural / pristine name (the caller separately
	# merges raw -> the AppendUserInfo target via Merge-UsersCsv). If the
	# caller-supplied AppendUserInfo leaf happens to collide with the natural raw
	# leaf in the same destination folder, the caller is responsible for adding
	# a '_raw' suffix to the raw filename (Resolve-PristineRawEntraPath).
	#
	# Resolution order for the natural raw basename:
	#   1. If -OutputPathUserInfo is bound with a file leaf, use that leaf.
	#   2. Else default to the timestamped 'EntraUsers_MAClicensing_<ts>.csv'.
	if ($script:DestIsBound -and $script:DestIsBound['UserInfo'] -and $script:DestRaw.ContainsKey('UserInfo')) {
		$leaf = [System.IO.Path]::GetFileName($script:DestRaw['UserInfo'])
		if ($leaf -and $leaf -match '\.[A-Za-z0-9]{2,5}$') { return $leaf }
	}
	return ("EntraUsers_MAClicensing_{0}.csv" -f $global:ScriptRunTimestamp)
}
$script:GetEffectiveAgent365Basename = {
	if ($script:AppendIsBound -and $script:AppendIsBound['Agent365Info'] -and $script:AppendRaw.ContainsKey('Agent365Info')) {
		return [System.IO.Path]::GetFileName($script:AppendRaw['Agent365Info'])
	}
	if ($script:DestIsBound -and $script:DestIsBound['Agent365Info'] -and $script:DestRaw.ContainsKey('Agent365Info')) {
		$leaf = [System.IO.Path]::GetFileName($script:DestRaw['Agent365Info'])
		if ($leaf -and $leaf -match '\.[A-Za-z0-9]{2,5}$') { return $leaf }
	}
	return ("Agent365_{0}.csv" -f $global:ScriptRunTimestamp)
}

# Replay/EOM modes are not supported with remote output.
if ($script:RemoteOutputMode -ne 'None') {
	$remoteBlockers = @()
	if ($UseEOM)      { $remoteBlockers += '-UseEOM' }
	if ($RAWInputCSV) { $remoteBlockers += '-RAWInputCSV' }
	if ($remoteBlockers.Count -gt 0) {
		Write-Host ("ERROR: Remote output destinations are not supported with: {0}" -f ($remoteBlockers -join ', ')) -ForegroundColor Red
		Write-Host "       These modes operate on existing files and have no remote-write story." -ForegroundColor Yellow
		exit 1
	}
}

# ExportWorkbook is restricted to Local and SharePoint tiers.
if ($ExportWorkbook -and $script:DestTier.ContainsKey('Purview') -and $script:DestTier['Purview'] -eq 'Fabric') {
	Write-Host "ERROR: -ExportWorkbook is not supported on Fabric (OneLake) destinations." -ForegroundColor Red
	Write-Host "       Use a Local or SharePoint -OutputPath for workbook output." -ForegroundColor Yellow
	exit 1
}
if ($ExportWorkbook) {
	$workbookCompanionConflict = $false
	if (-not ($OnlyUserInfo -or $OnlyAgent365Info)) {
		if ($script:DestIsBound['UserInfo'])      { $workbookCompanionConflict = $true }
		if ($script:DestIsBound['Agent365Info'])  { $workbookCompanionConflict = $true }
	}
	if ($workbookCompanionConflict) {
		Write-Host "ERROR: -OutputPathUserInfo / -OutputPathAgent365Info cannot be combined with -ExportWorkbook when Purview output is in scope." -ForegroundColor Red
		Write-Host "       The workbook is a single file containing all tabs - companion CSV destinations would be ignored." -ForegroundColor Yellow
		exit 1
	}
}

# Local-tier OutputPath normalization. When the Purview destination is Local (or
# unbound and therefore defaulted to a local folder), ensure it ends with a path
# separator if it is a folder (no extension) and create the directory if needed.
# Full-path-with-basename Local forms are also accepted; downstream auto-basename
# logic detects the file form and uses the supplied basename verbatim.
if (-not $PSBoundParameters.ContainsKey('OutputPath') -or [string]::IsNullOrWhiteSpace($OutputPath)) {
	# When -OutputPath is omitted, infer the run's scratch+log directory from the
	# DOMINANT in-scope stream's bound -Append* / -OutputPath* target. Otherwise
	# $OutputPath would fall back to $PSScriptRoot — polluting the script's own
	# folder with the run log, .pax_incremental shards/seed JSONs, and any rollup
	# temp files even though the customer pinned a real data destination elsewhere
	# via -AppendFile / -AppendUserInfo / -AppendAgent365Info.
	#
	# Dominant stream resolution (mirrors XOR validator's scope rules):
	#   -OnlyUserInfo      -> UserInfo     (AppendUserInfo / OutputPathUserInfo)
	#   -OnlyAgent365Info  -> Agent365Info (AppendAgent365Info / OutputPathAgent365Info)
	#   default            -> Purview      (AppendFile)  [XOR guarantees AppendFile
	#                                       is bound when OutputPath is not, in scope]
	#
	# Source of truth is $script:DestRaw — populated by the destSwitches loop above
	# from -OutputPath* AND by the appendSwitches loop from rooted/URL -Append*
	# values. Relative-filename -Append* forms intentionally do NOT populate DestRaw
	# (they defer to the unspecified -OutputPath*), so they fall through to the
	# legacy $PSScriptRoot default — correct behavior, since the relative form was
	# only ever meaningful with -OutputPath in scope.
	#
	# Remote URLs are excluded from inference: remote-mode runs stage scratch+log
	# locally (the upload sweep handles the move to the remote URL afterward), and
	# the pre-existing $PSScriptRoot scratch behavior is preserved unchanged for
	# those runs. Cross-tier mismatches are already rejected upstream by the
	# tier-consistency validator (L2603-L2613).
	$_pvInferKey = if ($OnlyUserInfo) { 'UserInfo' } elseif ($OnlyAgent365Info) { 'Agent365Info' } else { 'Purview' }
	$_pvInferParent = $null
	if ($script:DestRaw.ContainsKey($_pvInferKey)) {
		$_pvInferRaw = $script:DestRaw[$_pvInferKey]
		if (-not [string]::IsNullOrWhiteSpace($_pvInferRaw) -and ($_pvInferRaw -notmatch '^https?://')) {
			# Folder form -> use as-is; file form -> use parent directory.
			$_pvInferCandidate = if (Test-Path -Path $_pvInferRaw -PathType Container) {
				$_pvInferRaw
			} else {
				Split-Path -Parent $_pvInferRaw
			}
			if ($_pvInferCandidate -and (Test-Path -Path $_pvInferCandidate -PathType Container)) {
				$_pvInferParent = $_pvInferCandidate
			}
		}
	}
	if ($_pvInferParent) {
		$OutputPath = $_pvInferParent
		Write-Host ("INFO: Inferred run scratch+log dir from in-scope -{0}: {1}" -f $(if ($OnlyUserInfo) { 'AppendUserInfo/-OutputPathUserInfo' } elseif ($OnlyAgent365Info) { 'AppendAgent365Info/-OutputPathAgent365Info' } else { 'AppendFile' }), $OutputPath) -ForegroundColor DarkGray
	} elseif ($PSScriptRoot) {
		$OutputPath = $PSScriptRoot
	} else {
		$OutputPath = (Get-Location).Path
	}
	if (-not $OutputPath.EndsWith('\') -and -not $OutputPath.EndsWith('/')) {
		$OutputPath = $OutputPath + '\'
	}
	# Do NOT clobber a Purview tier that was already promoted from a remote
	# -AppendFile URL (SharePoint/Fabric). The Local default only applies when
	# no Append-side promotion has populated DestTier['Purview'] yet — otherwise
	# the per-data-type destinations banner mis-tags Purview as [Local].
	if (-not $script:DestTier.ContainsKey('Purview')) {
		$script:DestTier['Purview'] = 'Local'
		$script:DestRaw['Purview']  = $OutputPath
	}
}
if ($script:DestTier.ContainsKey('Purview') -and $script:DestTier['Purview'] -eq 'Local') {
	$isFileForm = ($OutputPath -match '\.[a-zA-Z0-9]{2,5}$') -and ($OutputPath -notmatch '[\\/]$')
	if (-not $isFileForm) {
		if (-not $OutputPath.EndsWith('\') -and -not $OutputPath.EndsWith('/')) {
			$OutputPath = $OutputPath + '\'
		}
		if (-not (Test-Path -Path $OutputPath -PathType Container)) {
			try {
				New-Item -Path $OutputPath -ItemType Directory -Force | Out-Null
				Write-Host "INFO: Created output directory: $OutputPath" -ForegroundColor Green
			}
			catch {
				Write-Host "ERROR: Failed to create output directory: $OutputPath" -ForegroundColor Red
				Write-Host "Error: $_" -ForegroundColor Red
				exit 1
			}
		}
	} else {
		$parentDir = Split-Path -Parent $OutputPath
		if ($parentDir -and -not (Test-Path -Path $parentDir -PathType Container)) {
			try {
				New-Item -Path $parentDir -ItemType Directory -Force | Out-Null
				Write-Host "INFO: Created output directory: $parentDir" -ForegroundColor Green
			}
			catch {
				Write-Host "ERROR: Failed to create output directory: $parentDir" -ForegroundColor Red
				Write-Host "Error: $_" -ForegroundColor Red
				exit 1
			}
		}
	}
}

# Managed-identity-aware host guard. IDENTITY_ENDPOINT is set by Azure runtimes
# (Functions, App Service, Container Apps, Container Instances, Fabric notebook /
# container runtimes, etc.) to advertise that a managed-identity token endpoint
# is available on the host. It does NOT mean managed identity is the only valid
# auth choice. Two shapes are accepted in MI-aware hosts:
#   1. -Auth ManagedIdentity (uses the assigned identity on the host), or
#   2. -Auth AppRegistration with bound credentials (-ClientId plus one of
#      -ClientSecret / -ClientCertificateThumbprint / -ClientCertificatePath) -
#      legitimate for cross-tenant runs where a service-provider tenant calls
#      into a customer tenant from a host that also happens to expose a local
#      managed identity.
# Only block when neither shape applies (e.g. the operator forgot
# -Auth ManagedIdentity in a runbook, or invoked an interactive auth mode with
# no credentials in a non-interactive host).
if ($env:IDENTITY_ENDPOINT -and $Auth -ne 'ManagedIdentity') {
	$hasAppRegCreds = ($Auth -eq 'AppRegistration') -and `
		$ClientId -and `
		($ClientSecret -or $ClientCertificateThumbprint -or $ClientCertificatePath)
	if (-not $hasAppRegCreds) {
		Write-Host "ERROR: Detected a managed-identity environment (IDENTITY_ENDPOINT is set) but -Auth is '$Auth' without credentials." -ForegroundColor Red
		Write-Host "       Re-run with -Auth ManagedIdentity to use the assigned identity, or supply -ClientId together with -ClientSecret / -ClientCertificateThumbprint / -ClientCertificatePath for -Auth AppRegistration." -ForegroundColor Yellow
		exit 1
	}
	Write-Host "INFO: Managed identity available in host; proceeding with explicit -Auth AppRegistration as requested." -ForegroundColor DarkGray
}

# Resolve-DataTypePaths
# ---------------------
# Central per-data-type effective destination lookup. Each downstream writer that
# emits a customer-visible artifact calls this helper for its data-type key and
# receives:
#   .Tier        - 'Local' | 'SharePoint' | 'Fabric'
#   .Raw         - the as-supplied input (already validated and trimmed)
#   .IsBound     - $true if the caller supplied -OutputPath<DataType> on the CLI
#   .EffectiveDir - parent folder/URL the writer should land its file under
#   .Basename    - default basename to use when the supplied form is folder/URL only
#                  ('' when the supplied form already includes a basename)
# Data-type keys: 'Purview', 'UserInfo', 'Agent365Info', 'Log'.
# When a non-Purview data type was not bound on the CLI, it inherits the Purview
# tier/destination so legacy single-destination behavior is preserved.
function script:Resolve-DataTypePaths {
	param(
		[Parameter(Mandatory)] [ValidateSet('Purview','UserInfo','Agent365Info','Log')] [string]$DataType,
		[string]$DefaultBasename = ''
	)
	$key = $DataType
	$isBound = $false
	$boundViaAppendOnly = $false
	if ($script:DestIsBound -and $script:DestIsBound.ContainsKey($key)) { $isBound = [bool]$script:DestIsBound[$key] }
	# DestIsBound is the narrow "-OutputPath<DataType> was supplied" signal — it does
	# NOT cover the case where only the Append-side counterpart (-AppendUserInfo /
	# -AppendAgent365Info) is bound. When a rooted/URL Append value is supplied for
	# UserInfo or Agent365Info without its OutputPath counterpart, the appendSwitches
	# loop at parse-time (mirrored on resume) promotes $script:DestTier[$key] and
	# $script:DestRaw[$key] from that Append value, but $script:DestIsBound[$key]
	# stays $false. Without the fall-through below, this function would inherit
	# tier/raw from Purview — and under -AppendFile, $script:DestRaw['Purview']
	# is the Purview activity FILE path, so the caller ends up joining the
	# data-type leaf onto a file path and produces a "<PurviewFile>\<DataTypeLeaf>"
	# string that no filesystem accepts. Treat an Append-side promotion as "bound"
	# for path resolution purposes; the narrow DestIsBound semantics used elsewhere
	# (Excel companion conflict check, etc.) remain unchanged.
	if (-not $isBound -and $script:AppendIsBound -and $script:AppendIsBound.ContainsKey($key) -and $script:AppendIsBound[$key] -and $script:DestRaw -and $script:DestRaw.ContainsKey($key)) {
		$isBound = $true
		$boundViaAppendOnly = $true
	}
	if (-not $isBound) {
		# Inherit from Purview tier/raw.
		$tier = if ($script:DestTier.ContainsKey('Purview')) { $script:DestTier['Purview'] } else { 'Local' }
		$raw  = if ($script:DestRaw.ContainsKey('Purview'))  { $script:DestRaw['Purview']  } else { $OutputPath }
	} else {
		$tier = $script:DestTier[$key]
		$raw  = $script:DestRaw[$key]
	}
	# Determine whether $raw is folder/URL form vs. file-form (has a basename extension).
	$isFileForm = $false
	if ($tier -eq 'Local') {
		$isFileForm = ($raw -match '\.[a-zA-Z0-9]{2,5}$') -and ($raw -notmatch '[\\/]$')
	} elseif ($tier -eq 'SharePoint' -or $tier -eq 'Fabric') {
		# Treat trailing-segment-with-extension as file form; otherwise it's a folder/URL.
		$last = ($raw.TrimEnd('/').Split('/') | Select-Object -Last 1)
		$isFileForm = $last -match '\.[a-zA-Z0-9]{2,5}$'
	}
	if ($isFileForm) {
		$effDir = if ($tier -eq 'Local') { Split-Path -Parent $raw } else { ($raw.TrimEnd('/') -replace '/[^/]+$','') }
		# When isBound was promoted ONLY via the Append-side fall-through above,
		# $raw is the merge TARGET (-AppendUserInfo / -AppendAgent365Info), not a
		# customer-specified raw destination basename. The pristine raw output
		# this function's caller will produce must keep its natural name (the
		# caller's $DefaultBasename — e.g., 'EntraUsers_MAClicensing_<currentRunTs>.csv')
		# so that it stays distinct from the merge target on disk; the EffectiveDir
		# is still inherited because the raw needs to land in the same folder as
		# the merge target. Without this carve-out, the caller's collision-check
		# (raw-leaf vs. AppendUserInfo-leaf) would fire spuriously and rename
		# the raw with a '_raw' suffix that the customer never asked for.
		# Agent365's caller already passes the AppendAgent365Info target leaf as
		# its $DefaultBasename (via $script:GetEffectiveAgent365Basename), so
		# returning $DefaultBasename here is semantically identical for Agent365.
		# Callers that explicitly bind -OutputPath<DataType> set DestIsBound and
		# take the normal Split-Path -Leaf $raw branch below — unchanged.
		if ($boundViaAppendOnly) {
			$basename = $DefaultBasename
		} else {
			$basename = if ($tier -eq 'Local') { Split-Path -Leaf $raw } else { ($raw.TrimEnd('/').Split('/') | Select-Object -Last 1) }
		}
		return [pscustomobject]@{
			Tier = $tier; Raw = $raw; IsBound = $isBound
			EffectiveDir = $effDir; Basename = $basename
		}
	}
	return [pscustomobject]@{
		Tier = $tier; Raw = $raw; IsBound = $isBound
		EffectiveDir = $raw; Basename = $DefaultBasename
	}
}

# Redirect OutputPath to a per-run scratch dir under the OS temp folder when remote mode is active.
# Done BEFORE any downstream code derives paths from $OutputPath.
if ($script:RemoteOutputMode -ne 'None') {
	$baseTemp = [System.IO.Path]::GetTempPath()
	$script:RemoteScratchDir = Join-Path $baseTemp ("PAX_" + (Get-Date -Format 'yyyyMMdd_HHmmss'))
	try {
		New-Item -Path $script:RemoteScratchDir -ItemType Directory -Force | Out-Null
	} catch {
		Write-Host ("ERROR: Failed to create scratch directory '{0}': {1}" -f $script:RemoteScratchDir, $_.Exception.Message) -ForegroundColor Red
		exit 1
	}
	$OutputPath = $script:RemoteScratchDir
	$sep = [System.IO.Path]::DirectorySeparatorChar
	if (-not $OutputPath.EndsWith($sep)) { $OutputPath = $OutputPath + $sep }
	Write-Host ("INFO: Remote output mode '{0}' active." -f $script:RemoteOutputMode) -ForegroundColor Cyan
	Write-Host ("INFO: Local scratch dir  : {0}" -f $OutputPath) -ForegroundColor Cyan
	Write-Host  "INFO: Per-data-type destinations shown in the banner below." -ForegroundColor Cyan
}

# Validate -AppendFile / -AppendUserInfo / -AppendAgent365Info combinations.
# Each -Append* parameter targets one logical output stream:
#   -AppendFile          : activity (audit) outputs - CopilotInteraction / M365 / DSPM / etc.
#   -AppendUserInfo      : EntraUsers / MAC licensing snapshot
#   -AppendAgent365Info  : Agent 365 catalog
# Only* and Append* targeting the SAME stream compose naturally: Only* scopes the
# run to that stream's data, Append* picks the write mode (merge vs overwrite).
# Only* with -AppendFile is rejected because Only* skips audit log retrieval
# entirely, leaving -AppendFile with no activity data to merge.
# When only an -Append* is given, the matching -Include* is auto-enabled for ergonomics.

if ($AppendFile -and $OnlyUserInfo) {
	Write-Host "ERROR: -AppendFile cannot be used with -OnlyUserInfo" -ForegroundColor Red
	Write-Host "" -ForegroundColor Yellow
	Write-Host "  -AppendFile targets activity (audit) outputs, but -OnlyUserInfo skips audit" -ForegroundColor Yellow
	Write-Host "  log retrieval entirely, so there is no activity data to merge. To append the" -ForegroundColor Yellow
	Write-Host "  EntraUsers snapshot under -OnlyUserInfo, use -AppendUserInfo (the two compose)." -ForegroundColor Yellow
	exit 1
}

if ($AppendFile -and $OnlyAgent365Info) {
	Write-Host "ERROR: -AppendFile cannot be used with -OnlyAgent365Info" -ForegroundColor Red
	Write-Host "" -ForegroundColor Yellow
	Write-Host "  -AppendFile targets activity (audit) outputs, but -OnlyAgent365Info skips audit" -ForegroundColor Yellow
	Write-Host "  log retrieval entirely, so there is no activity data to merge. To append the" -ForegroundColor Yellow
	Write-Host "  Agent 365 catalog under -OnlyAgent365Info, use -AppendAgent365Info (the two compose)." -ForegroundColor Yellow
	exit 1
}

# Pairing of -AppendFile with -IncludeUserInfo / -IncludeAgent365Info is non-mandatory.
# When -Append* is omitted, the matching dimension file is written non-append for that
# run (the prior target is replaced if it exists). The dedup-on-target join is performed
# only when the matching -Append* switch is also supplied.

# Auto-imply the matching -Include* when only the -Append* is provided.
if ($AppendUserInfo     -and -not $IncludeUserInfo)     { $IncludeUserInfo     = $true }
if ($AppendAgent365Info -and -not $IncludeAgent365Info) { $IncludeAgent365Info = $true }

# ============================================================
# DESTINATION PAIR XOR VALIDATION
# For each output stream, when the stream is in scope, the user must supply
# EXACTLY ONE of (-OutputPath* | -Append*) — never both, never neither.
# When the stream is out of scope, neither member of the pair may be supplied.
# Streams:
#   Purview        : in scope unless -OnlyUserInfo or -OnlyAgent365Info
#   UserInfo       : in scope when -IncludeUserInfo or -OnlyUserInfo
#   Agent365Info   : in scope when -IncludeAgent365Info or -OnlyAgent365Info
# Note: the Purview default-to-$PSScriptRoot fallback fires AFTER this block,
# so we test against $PSBoundParameters here, not the live $OutputPath value.
# Skipped under -Resume: the resume-allowed-list check (later) rejects any
# destination switches on the resume command line, and the checkpoint restore
# rehydrates every per-stream destination from the saved snapshot.
# ============================================================
if (-not $ResumeSpecified) {

$pvOutBound = $PSBoundParameters.ContainsKey('OutputPath')
$pvAppBound = $PSBoundParameters.ContainsKey('AppendFile')
$uiOutBound = $PSBoundParameters.ContainsKey('OutputPathUserInfo')
$uiAppBound = $PSBoundParameters.ContainsKey('AppendUserInfo')
$agOutBound = $PSBoundParameters.ContainsKey('OutputPathAgent365Info')
$agAppBound = $PSBoundParameters.ContainsKey('AppendAgent365Info')

$purviewInScope  = (-not $OnlyUserInfo) -and (-not $OnlyAgent365Info)
$userInfoInScope = $IncludeUserInfo -or $OnlyUserInfo
$agentInScope    = $IncludeAgent365Info -or $OnlyAgent365Info

# --- Purview stream ---
if ($purviewInScope) {
	if ($pvOutBound -and $pvAppBound) {
		Write-Host "ERROR: -OutputPath and -AppendFile cannot both be supplied." -ForegroundColor Red
		Write-Host "  For the Purview activity stream, provide EXACTLY ONE of the pair:" -ForegroundColor Yellow
		Write-Host "    -OutputPath    : write a new file at the supplied folder/full path" -ForegroundColor Yellow
		Write-Host "    -AppendFile    : append to an existing file (filename or full path)" -ForegroundColor Yellow
		exit 1
	}
	if (-not $pvOutBound -and -not $pvAppBound) {
		Write-Host "ERROR: Purview audit output destination not specified." -ForegroundColor Red
		Write-Host "  Supply EXACTLY ONE of: -OutputPath  OR  -AppendFile" -ForegroundColor Yellow
		Write-Host "  Accepted forms (either switch):" -ForegroundColor Yellow
		Write-Host "    Local       : C:\Reports\ (folder) or C:\Reports\Run.csv (full path)" -ForegroundColor DarkGray
		Write-Host "    SharePoint  : https://<tenant>.sharepoint.com/sites/<site>/<library>[/<sub>]" -ForegroundColor DarkGray
		Write-Host "    Fabric      : https://onelake.dfs.fabric.microsoft.com/<ws>/<item>.Lakehouse[/Tables|/Files...]" -ForegroundColor DarkGray
		exit 1
	}
} else {
	# Only-modes: Purview not in scope. -AppendFile makes no sense (no Purview file).
	# -OutputPath is permitted (acts as scratch dir for remote streams) but flagged.
	if ($pvAppBound) {
		$onlyName = if ($OnlyUserInfo) { '-OnlyUserInfo' } else { '-OnlyAgent365Info' }
		Write-Host ("ERROR: -AppendFile is not valid with {0}." -f $onlyName) -ForegroundColor Red
		Write-Host "  -AppendFile targets the Purview activity stream, which is out of scope in only-modes." -ForegroundColor Yellow
		Write-Host "  Use -AppendUserInfo / -AppendAgent365Info to append to the in-scope stream." -ForegroundColor Yellow
		exit 1
	}
}

# --- UserInfo stream ---
if ($userInfoInScope) {
	if ($uiOutBound -and $uiAppBound) {
		Write-Host "ERROR: -OutputPathUserInfo and -AppendUserInfo cannot both be supplied." -ForegroundColor Red
		Write-Host "  Provide EXACTLY ONE for the EntraUsers stream." -ForegroundColor Yellow
		exit 1
	}
	if (-not $uiOutBound -and -not $uiAppBound -and -not $ExportWorkbook) {
		Write-Host "ERROR: -IncludeUserInfo / -OnlyUserInfo requires a destination for the EntraUsers stream." -ForegroundColor Red
		Write-Host "  Supply EXACTLY ONE of: -OutputPathUserInfo  OR  -AppendUserInfo" -ForegroundColor Yellow
		exit 1
	}
} else {
	if ($uiOutBound -or $uiAppBound) {
		$bn = if ($uiOutBound) { '-OutputPathUserInfo' } else { '-AppendUserInfo' }
		Write-Host ("ERROR: {0} requires -IncludeUserInfo or -OnlyUserInfo to be in scope." -f $bn) -ForegroundColor Red
		Write-Host "  Drop the destination switch, or add -IncludeUserInfo / -OnlyUserInfo." -ForegroundColor Yellow
		exit 1
	}
}

# --- Agent 365 stream ---
if ($agentInScope) {
	if ($agOutBound -and $agAppBound) {
		Write-Host "ERROR: -OutputPathAgent365Info and -AppendAgent365Info cannot both be supplied." -ForegroundColor Red
		Write-Host "  Provide EXACTLY ONE for the Agent 365 stream." -ForegroundColor Yellow
		exit 1
	}
	if (-not $agOutBound -and -not $agAppBound -and -not $ExportWorkbook) {
		Write-Host "ERROR: -IncludeAgent365Info / -OnlyAgent365Info requires a destination for the Agent 365 stream." -ForegroundColor Red
		Write-Host "  Supply EXACTLY ONE of: -OutputPathAgent365Info  OR  -AppendAgent365Info" -ForegroundColor Yellow
		exit 1
	}
} else {
	if ($agOutBound -or $agAppBound) {
		$bn = if ($agOutBound) { '-OutputPathAgent365Info' } else { '-AppendAgent365Info' }
		Write-Host ("ERROR: {0} requires -IncludeAgent365Info or -OnlyAgent365Info to be in scope." -f $bn) -ForegroundColor Red
		Write-Host "  Drop the destination switch, or add -IncludeAgent365Info / -OnlyAgent365Info." -ForegroundColor Yellow
		exit 1
	}
}

} # end if (-not $ResumeSpecified) destination-pair XOR validation

# ============================================================
# AGENT 365 SWITCH VALIDATION
# Validates -IncludeAgent365Info / -OnlyAgent365Info parameter
# combinations and prints informational banners where the
# Microsoft Graph Agent Package Management API endpoint
# limitations require user awareness.
# ============================================================

# Mutually exclusive
if ($IncludeAgent365Info -and $OnlyAgent365Info) {
	Write-Host "ERROR: -IncludeAgent365Info and -OnlyAgent365Info are mutually exclusive." -ForegroundColor Red
	Write-Host "  Use -IncludeAgent365Info to add agents data to a normal Purview run." -ForegroundColor Yellow
	Write-Host "  Use -OnlyAgent365Info to skip the audit pull and produce only the agents CSV." -ForegroundColor Yellow
	exit 1
}

# -OnlyAgent365Info conflicts with audit-implying switches
if ($OnlyAgent365Info) {
	$conflictingSwitches = @()
	if ($IncludeM365Usage)            { $conflictingSwitches += '-IncludeM365Usage' }
	if ($IncludeCopilotInteraction)   { $conflictingSwitches += '-IncludeCopilotInteraction' }
	if ($AgentsOnly)                  { $conflictingSwitches += '-AgentsOnly' }
	if ($ExcludeAgents)               { $conflictingSwitches += '-ExcludeAgents' }
	if ($CombineOutput)               { $conflictingSwitches += '-CombineOutput' }
	if ($OnlyUserInfo)                { $conflictingSwitches += '-OnlyUserInfo' }
	if ($AppendFile)                  { $conflictingSwitches += '-AppendFile' }
	if ($conflictingSwitches.Count -gt 0) {
		Write-Host "ERROR: -OnlyAgent365Info cannot be combined with: $($conflictingSwitches -join ', ')" -ForegroundColor Red
		Write-Host "" -ForegroundColor Yellow
		Write-Host "  -OnlyAgent365Info skips the Purview audit pull entirely. Switches that imply" -ForegroundColor Yellow
		Write-Host "  audit retrieval (or another 'Only' mode) are not compatible with it." -ForegroundColor Yellow
		Write-Host "" -ForegroundColor Yellow
		Write-Host "  -IncludeUserInfo is allowed (produces EntraUsers CSV alongside Agent 365 CSV)." -ForegroundColor Green
		exit 1
	}
}

# ==========================================================================
# NONINTERACTIVE-HOST DETECTION HELPER
# ==========================================================================
# Used by:
#   - the Agent365 + -Auth AppRegistration fail-fast gate (below)
#   - Read-Checkpoint's data-loss / selection / re-auth Read-Host prompts
# A host is considered noninteractive when ANY of the following are true:
#   * [Environment]::UserInteractive is $false (Windows service, scheduled task, ACA Job).
#   * Stdin is redirected ([Console]::IsInputRedirected) — true for pipelines, containers
#     that don't allocate a TTY, and most CI runners.
#   * $Host.Name is the remoting endpoint ('ServerRemoteHost').
#   * The PAX_NONINTERACTIVE environment variable is set to a truthy value (escape hatch
#     so operators can force noninteractive behavior on hosts the detection misses).
# Operators can FORCE interactive behavior via PAX_FORCE_INTERACTIVE=1 if they know the
# host genuinely accepts keyboard input despite a redirected stdin (rare; documented).
function script:Test-IsNonInteractive {
	if ($env:PAX_FORCE_INTERACTIVE -in @('1','true','True','TRUE','yes','Yes','YES')) { return $false }
	if ($env:PAX_NONINTERACTIVE   -in @('1','true','True','TRUE','yes','Yes','YES')) { return $true }
	try { if ($Host.Name -eq 'ServerRemoteHost') { return $true } } catch {}
	try { if (-not [Environment]::UserInteractive) { return $true } } catch {}
	try { if ([Console]::IsInputRedirected) { return $true } } catch {}
	return $false
}

# ==========================================================================
# RUNTIME STATE-CONTRACT HELPER
# ==========================================================================
# Validates that critical hashtables (metrics, partitionStatus, checkpoint payload,
# resume state) contain the required keys at the boundaries where they are
# produced or consumed. Intentionally lightweight: it asserts shape only, never
# value semantics, and never mutates the input. On contract violation it throws
# a precise error of the form:
#     "State contract violation: <ContractName> missing required keys: <list>"
# Callers should let the throw propagate; an unguarded violation is a hard bug
# that would otherwise surface as a NullReferenceException later in the run.
function script:Assert-StateContract {
	param(
		[Parameter(Mandatory)] [string]   $ContractName,
		[Parameter(Mandatory)] [AllowNull()] $State,
		[Parameter(Mandatory)] [string[]] $RequiredKeys
	)
	if ($null -eq $State) {
		throw "State contract violation: $ContractName is `$null but required keys are: $($RequiredKeys -join ', ')"
	}
	# Support hashtable, OrderedDictionary, and PSCustomObject inputs uniformly.
	$present = @{}
	if ($State -is [System.Collections.IDictionary]) {
		foreach ($k in $State.Keys) { $present[[string]$k] = $true }
	} elseif ($State.PSObject -and $State.PSObject.Properties) {
		foreach ($p in $State.PSObject.Properties) { $present[$p.Name] = $true }
	} else {
		throw "State contract violation: $ContractName has unsupported type $($State.GetType().FullName); expected IDictionary or PSCustomObject."
	}
	$missing = @()
	foreach ($k in $RequiredKeys) { if (-not $present.ContainsKey($k)) { $missing += $k } }
	if ($missing.Count -gt 0) {
		throw "State contract violation: $ContractName missing required keys: $($missing -join ', ')"
	}
}

# -OnlyAgent365Info is incompatible with replay (-RAWInputCSV), EOM mode, and Resume
# (it skips the audit phase entirely - nothing to checkpoint or resume from).
# -IncludeAgent365Info IS compatible with -Resume: the audit phase resumes from the
# checkpoint and Agent 365 enrichment runs at end of run as it would have originally.
if (($IncludeAgent365Info -or $OnlyAgent365Info)) {
	$incompatModeSwitches = @()
	if ($RAWInputCSV)     { $incompatModeSwitches += '-RAWInputCSV (replay mode)' }
	if ($UseEOM)          { $incompatModeSwitches += '-UseEOM (Exchange Online Management mode)' }
	if ($ResumeSpecified -and $OnlyAgent365Info) { $incompatModeSwitches += '-Resume' }
	if ($incompatModeSwitches.Count -gt 0) {
		$activeAgentSwitch = if ($OnlyAgent365Info) { '-OnlyAgent365Info' } else { '-IncludeAgent365Info' }
		Write-Host "ERROR: $activeAgentSwitch is not supported with: $($incompatModeSwitches -join ', ')" -ForegroundColor Red
		Write-Host "" -ForegroundColor Yellow
		Write-Host "  Agent 365 enrichment requires a fresh live Microsoft Graph context and runs" -ForegroundColor Yellow
		Write-Host "  end-to-end as a single pass. It is not compatible with replay/EOM/Resume modes." -ForegroundColor Yellow
		exit 1
	}
}

# Agent 365 + -Auth ManagedIdentity: rejected.
# Microsoft Graph Agent Package Management API requires the AI Admin or Global Admin
# directory role, which can only be held by a signed-in user. A managed identity has no
# user principal and cannot satisfy this requirement. Reject before any Graph traffic.
if (($IncludeAgent365Info -or $OnlyAgent365Info) -and $Auth -eq 'ManagedIdentity') {
	Write-Host ""
	Write-Host "+----------------------------------------------------------------------+" -ForegroundColor Red
	Write-Host "|  Agent 365 enrichment is not supported with -Auth ManagedIdentity    |" -ForegroundColor Red
	Write-Host "+----------------------------------------------------------------------+" -ForegroundColor Red
	Write-Host "|  The Microsoft Graph Agent Package Management API requires the AI    |" -ForegroundColor Yellow
	Write-Host "|  Admin or Global Admin directory role, which can only be held by a   |" -ForegroundColor Yellow
	Write-Host "|  signed-in user. A managed identity has no user principal and cannot |" -ForegroundColor Yellow
	Write-Host "|  satisfy this requirement, even with admin-consented application     |" -ForegroundColor Yellow
	Write-Host "|  permissions.                                                        |" -ForegroundColor Yellow
	Write-Host "|                                                                      |" -ForegroundColor Yellow
	Write-Host "|  Re-run with one of the supported delegated auth modes:              |" -ForegroundColor Yellow
	Write-Host "|      -Auth WebLogin     (default)                                    |" -ForegroundColor Yellow
	Write-Host "|      -Auth DeviceCode                                                |" -ForegroundColor Yellow
	Write-Host "|      -Auth Credential                                                |" -ForegroundColor Yellow
	Write-Host "|      -Auth Silent                                                    |" -ForegroundColor Yellow
	Write-Host "|      -Auth AppRegistration   (with -IncludeAgent365Info; the script  |" -ForegroundColor Yellow
	Write-Host "|                               will interactively top up a delegated  |" -ForegroundColor Yellow
	Write-Host "|                               context for the Agent 365 phase)       |" -ForegroundColor Yellow
	Write-Host "|                                                                      |" -ForegroundColor Yellow
	Write-Host "|  Or omit -IncludeAgent365Info / -OnlyAgent365Info to skip enrichment.|" -ForegroundColor Yellow
	Write-Host "+----------------------------------------------------------------------+" -ForegroundColor Red
	Write-Host ""
	exit 1
}

# -IncludeAgent365Info / -OnlyAgent365Info + -Auth AppRegistration on a NONINTERACTIVE host: rejected.
# AppReg + Agent365 requires an interactive delegated sign-in (see Invoke-Agent365EarlyInteractiveSignIn).
# In a container/ACA Job/Windows Service/CI runner there is no interactive console — the eager
# delegated prompt would either hang indefinitely waiting on stdin or surface a confusing MSAL
# error mid-run. Fail-fast at parameter validation with a clear, actionable message so the
# operator either drops Agent365 enrichment or switches to a delegated auth mode on a host
# that accepts interactive sign-in.
if (($IncludeAgent365Info -or $OnlyAgent365Info) -and $Auth -eq 'AppRegistration' -and (script:Test-IsNonInteractive)) {
	Write-Host ""
	Write-Host "+----------------------------------------------------------------------+" -ForegroundColor Red
	Write-Host "|  Agent 365 + -Auth AppRegistration is not supported on this host     |" -ForegroundColor Red
	Write-Host "+----------------------------------------------------------------------+" -ForegroundColor Red
	Write-Host "|  Detected a noninteractive host (container, ACA Job, Windows         |" -ForegroundColor Yellow
	Write-Host "|  service, scheduled task, or pipeline with redirected stdin).        |" -ForegroundColor Yellow
	Write-Host "|                                                                      |" -ForegroundColor Yellow
	Write-Host "|  Agent 365 enrichment under -Auth AppRegistration requires an        |" -ForegroundColor Yellow
	Write-Host "|  interactive delegated sign-in BEFORE the audit phase begins (the    |" -ForegroundColor Yellow
	Write-Host "|  Graph Agent Package Management API requires the AI Admin or Global  |" -ForegroundColor Yellow
	Write-Host "|  Admin directory role, which only a user principal can hold). A      |" -ForegroundColor Yellow
	Write-Host "|  noninteractive host cannot satisfy that prompt - the run would      |" -ForegroundColor Yellow
	Write-Host "|  hang indefinitely or fail mid-execution.                            |" -ForegroundColor Yellow
	Write-Host "|                                                                      |" -ForegroundColor Yellow
	Write-Host "|  Choose ONE of the following:                                        |" -ForegroundColor Yellow
	Write-Host "|    1) Drop -IncludeAgent365Info / -OnlyAgent365Info from the run     |" -ForegroundColor Yellow
	Write-Host "|       (audit data is still collected; Agent 365 enrichment skipped). |" -ForegroundColor Yellow
	Write-Host "|    2) Re-run on an interactive workstation with a delegated auth     |" -ForegroundColor Yellow
	Write-Host "|       mode: -Auth WebLogin, -Auth DeviceCode, -Auth Credential,      |" -ForegroundColor Yellow
	Write-Host "|       or -Auth Silent.                                               |" -ForegroundColor Yellow
	Write-Host "|    3) If this host DOES accept keyboard input despite the detector,  |" -ForegroundColor Yellow
	Write-Host "|       set PAX_FORCE_INTERACTIVE=1 and re-run (use with caution).     |" -ForegroundColor Yellow
	Write-Host "+----------------------------------------------------------------------+" -ForegroundColor Red
	Write-Host ""
	exit 1
}

# -OnlyAgent365Info + -Auth AppRegistration: rejected with informational banner
# Microsoft Graph Agent Package Management API does not support app-only application
# permissions; it requires the AI Admin or Global Admin directory role (user-assignable only).
if ($OnlyAgent365Info -and $Auth -eq 'AppRegistration') {
	Write-Host ""
	Write-Host "+----------------------------------------------------------------------+" -ForegroundColor Cyan
	Write-Host "|  -OnlyAgent365Info is incompatible with -Auth AppRegistration        |" -ForegroundColor Cyan
	Write-Host "+----------------------------------------------------------------------+" -ForegroundColor Cyan
	Write-Host "|  The Microsoft Graph endpoint for Agent 365 data (Agent Package      |" -ForegroundColor Cyan
	Write-Host "|  Management API) does not currently support app-only application    |" -ForegroundColor Cyan
	Write-Host "|  permissions. It requires the AI Admin or Global Admin directory    |" -ForegroundColor Cyan
	Write-Host "|  directory role, which can only be held by a signed-in user.        |" -ForegroundColor Cyan
	Write-Host "|                                                                      |" -ForegroundColor Cyan
	Write-Host "|  Re-run with one of the supported interactive auth modes:            |" -ForegroundColor Cyan
	Write-Host "|      -Auth WebLogin     (default)                                    |" -ForegroundColor Cyan
	Write-Host "|      -Auth DeviceCode                                                |" -ForegroundColor Cyan
	Write-Host "|      -Auth Credential                                                |" -ForegroundColor Cyan
	Write-Host "|      -Auth Silent                                                    |" -ForegroundColor Cyan
	Write-Host "|                                                                      |" -ForegroundColor Cyan
	Write-Host "|  Reference:                                                          |" -ForegroundColor Cyan
	Write-Host "|  https://learn.microsoft.com/en-us/microsoft-agent-365/admin/graph-api|" -ForegroundColor Cyan
	Write-Host "+----------------------------------------------------------------------+" -ForegroundColor Cyan
	Write-Host ""
	exit 0
}

# Validate AppendFile has proper filename format
if ($AppendFile) {
	# Check if it's a directory path (ends with slash/backslash or has no extension)
	if ($AppendFile -match '[\\/]$') {
		Write-Host "ERROR: -AppendFile must specify a filename, not a directory path" -ForegroundColor Red
		Write-Host "" -ForegroundColor Yellow
		Write-Host "Valid examples:" -ForegroundColor Green
		Write-Host "  -AppendFile 'MyReport.xlsx'" -ForegroundColor Green
		Write-Host "  -AppendFile 'C:\Data\Audit\Report.csv'" -ForegroundColor Green
		Write-Host "" -ForegroundColor Yellow
		Write-Host "Invalid examples:" -ForegroundColor Red
		Write-Host "  -AppendFile 'C:\Data\'" -ForegroundColor Red
		Write-Host "  -AppendFile 'C:\Data\Audit\'" -ForegroundColor Red
		exit 1
	}
	
	# Extract file extension
	$appendExt = [System.IO.Path]::GetExtension($AppendFile).ToLower()
	
	# Validate extension exists
	if (-not $appendExt) {
		Write-Host "ERROR: -AppendFile must include a file extension (.csv or .xlsx)" -ForegroundColor Red
		Write-Host "" -ForegroundColor Yellow
		Write-Host "Valid examples:" -ForegroundColor Green
		Write-Host "  -AppendFile 'MyReport.xlsx'" -ForegroundColor Green
		Write-Host "  -AppendFile 'AuditData.csv'" -ForegroundColor Green
		exit 1
	}
	
	# Validate extension matches export mode
	if ($ExportWorkbook -and $appendExt -ne '.xlsx') {
		Write-Host "ERROR: -AppendFile must use .xlsx extension when -ExportWorkbook is specified" -ForegroundColor Red
		Write-Host "You specified: $AppendFile" -ForegroundColor Yellow
		Write-Host "" -ForegroundColor Yellow
		Write-Host "Solutions:" -ForegroundColor Green
		Write-Host "  1. Change filename to use .xlsx extension" -ForegroundColor Green
		Write-Host "  2. Remove -ExportWorkbook to append CSV data instead" -ForegroundColor Green
		exit 1
	}
	elseif (-not $ExportWorkbook -and $appendExt -ne '.csv') {
		Write-Host "ERROR: -AppendFile must use .csv extension for CSV mode" -ForegroundColor Red
		Write-Host "You specified: $AppendFile" -ForegroundColor Yellow
		Write-Host "" -ForegroundColor Yellow
		Write-Host "Solutions:" -ForegroundColor Green
		Write-Host "  1. Change filename to use .csv extension" -ForegroundColor Green
		Write-Host "  2. Add -ExportWorkbook to append Excel data instead" -ForegroundColor Green
		exit 1
	}
}

# --- Conflict Detection for -ExcludeCopilotInteraction ---

$script:ConflictResolved = $false
$script:ConflictChoice = $null

# Detect conflicts where user wants to both include AND exclude CopilotInteraction:
# 1. Explicit include via -ActivityTypes parameter
# 2. Explicit include via -IncludeCopilotInteraction switch
$explicitInclude = $ActivityTypes -and ($ActivityTypes -contains 'CopilotInteraction')
$explicitIncludeViaSwitch = $IncludeCopilotInteraction

if ($ExcludeCopilotInteraction -and ($explicitInclude -or $explicitIncludeViaSwitch)) {
	if (-not $Force) {
		Write-Host ""
		Write-Host "============================================================================================================" -ForegroundColor Yellow
		Write-Host "CONFLICT DETECTED" -ForegroundColor Red
		Write-Host "============================================================================================================" -ForegroundColor Yellow
		Write-Host ""
		
		if ($explicitInclude) {
			Write-Host "You provided 'CopilotInteraction' in -ActivityTypes but also specified -ExcludeCopilotInteraction switch." -ForegroundColor Yellow
		}
		elseif ($explicitIncludeViaSwitch) {
			Write-Host "You enabled -IncludeCopilotInteraction but also specified -ExcludeCopilotInteraction." -ForegroundColor Yellow
		}
		
		Write-Host ""
		Write-Host "Microsoft 365 Copilot data (CopilotInteraction) includes:" -ForegroundColor Cyan
		Write-Host "  - M365 Copilot (Word, Excel, PowerPoint, Outlook, Teams meetings, etc.)" -ForegroundColor Cyan
		Write-Host "  - Microsoft 365 Copilot Chat (Office.com)" -ForegroundColor Cyan
		Write-Host "  - Security Copilot" -ForegroundColor Cyan
		Write-Host "  - Copilot Studio interactions" -ForegroundColor Cyan
		Write-Host "  - Billing: FREE (included with E5/Audit Standard)" -ForegroundColor Green
		Write-Host ""
		Write-Host "Do you want to INCLUDE or EXCLUDE Microsoft 365 Copilot activity type?" -ForegroundColor Yellow
		Write-Host "  [I] INCLUDE - Proceed with M365 Copilot data enabled (override -ExcludeCopilotInteraction switch)" -ForegroundColor Green
		Write-Host "  [E] EXCLUDE - Remove CopilotInteraction (honor -ExcludeCopilotInteraction switch)" -ForegroundColor Red
		Write-Host ""

		# Strict noninteractive guard: a container/ACA Job/CI
		# runner cannot answer I/E. Fail-fast with an explicit, scriptable recovery path
		# rather than hanging on stdin.
		if (script:Test-IsNonInteractive) {
			Write-Host "ERROR: Cannot prompt for INCLUDE/EXCLUDE on a noninteractive host." -ForegroundColor Red
			Write-Host "  Re-run with EITHER -IncludeCopilotInteraction (to force include) OR" -ForegroundColor Yellow
			Write-Host "  -ExcludeCopilotInteraction alone (without -IncludeCopilotInteraction) to exclude," -ForegroundColor Yellow
			Write-Host "  OR pass -Force to honour -ExcludeCopilotInteraction without prompting." -ForegroundColor Yellow
			exit 1
		}

		Send-PromptNotification
		$userChoice = Read-Host "Enter your choice (I/E)"
		
		if ($userChoice -eq 'I' -or $userChoice -eq 'i') {
			$ExcludeCopilotInteraction = $false
			$script:ConflictChoice = 'INCLUDE'
			Write-Host ""
			Write-Host "Choice: INCLUDE - Proceeding with CopilotInteraction enabled" -ForegroundColor Green
			Write-Host ""
		}
		elseif ($userChoice -eq 'E' -or $userChoice -eq 'e') {
			$script:ConflictChoice = 'EXCLUDE'
			Write-Host ""
			Write-Host "Choice: EXCLUDE - CopilotInteraction will be removed from ActivityTypes" -ForegroundColor Red
			Write-Host ""
		}
		else {
			Write-Host ""
			Write-Host "ERROR: Invalid choice. Please enter 'I' for INCLUDE or 'E' for EXCLUDE." -ForegroundColor Red
			exit 1
		}
		
		$script:ConflictResolved = $true
	}
	else {
		# Force mode - honor ExcludeCopilotInteraction without prompt
		$script:ConflictChoice = 'EXCLUDE (Force mode)'
		$script:ConflictResolved = $true
	}
}

# ==============================================
# -OnlyAgent365Info preflight (Y/N, default Y)
# ==============================================
# Without -IncludeAgent365Info, audit-derived columns will be blank in the
# Agent 365 CSV (Date created / Created by). Confirm the user wants to proceed.
# -Force auto-continues without prompting.
if ($OnlyAgent365Info) {
	Write-Host ""
	Write-Host "+----------------------------------------------------------------------+" -ForegroundColor Yellow
	Write-Host "|  -OnlyAgent365Info: Audit-log enrichment will be SKIPPED             |" -ForegroundColor Yellow
	Write-Host "+----------------------------------------------------------------------+" -ForegroundColor Yellow
	Write-Host "|  These Agent 365 columns CANNOT be populated without Purview audit  |" -ForegroundColor Yellow
	Write-Host "|  data and will be left blank in this run:                            |" -ForegroundColor Yellow
	Write-Host "|                                                                      |" -ForegroundColor Yellow
	Write-Host "|       - Date created                                                 |" -ForegroundColor Yellow
	Write-Host "|       - Created by                                                   |" -ForegroundColor Yellow
	Write-Host "|                                                                      |" -ForegroundColor Yellow
	Write-Host "|  To populate them, re-run with -IncludeAgent365Info instead.         |" -ForegroundColor Yellow
	Write-Host "+----------------------------------------------------------------------+" -ForegroundColor Yellow
	Write-Host ""
	if ($Force) {
		Write-Host "  -Force specified: continuing without prompt." -ForegroundColor DarkGray
		Write-Host ""
	} else {
		# Strict noninteractive guard: default to Y on
		# noninteractive hosts so scheduled/container runs do not hang on stdin. The
		# default of the prompt is already Y, so this preserves operator intent.
		if (script:Test-IsNonInteractive) {
			Write-Host "  Noninteractive host detected: auto-accepting prompt default (Y) for -OnlyAgent365Info." -ForegroundColor DarkGray
			Write-Host ""
		} else {
			$resp = Read-Host "  Continue with -OnlyAgent365Info anyway? (Y/N) [default Y]"
			if ([string]::IsNullOrWhiteSpace($resp)) { $resp = 'Y' }
			if ($resp -notmatch '^(?i:y|yes)$') {
				Write-Host "  Aborted by user." -ForegroundColor Red
				exit 0
			}
			Write-Host ""
		}
	}
}

# ==============================================
# ImportExcel Module Check (for Excel export)
# ==============================================

if ($ExportWorkbook) {
	Write-Host "Checking ImportExcel module for Excel export..." -ForegroundColor Cyan
	
	$importExcelModule = Get-Module -ListAvailable -Name ImportExcel | Select-Object -First 1
	if (-not $importExcelModule) {
		Write-Host "ImportExcel module not found (required for -ExportWorkbook)." -ForegroundColor Yellow
		Write-Host "Installing ImportExcel module..." -ForegroundColor Yellow
		Write-Host ""
		
		try {
			Install-Module ImportExcel -Scope CurrentUser -Force -AllowClobber -Repository PSGallery -ErrorAction Stop
			Write-Host "ImportExcel module installed successfully!" -ForegroundColor Green
			Write-Host ""
			
			# Re-check for the module
			$importExcelModule = Get-Module -ListAvailable -Name ImportExcel | Select-Object -First 1
			if (-not $importExcelModule) {
				Write-Host "ERROR: Module installation completed but module not found. Try restarting PowerShell." -ForegroundColor Red
				exit 1
			}
		}
		catch {
			Write-Host "ERROR: Failed to install ImportExcel module: $($_.Exception.Message)" -ForegroundColor Red
			Write-Host ""
			Write-Host "Please install manually using:" -ForegroundColor Yellow
			Write-Host "  Install-Module ImportExcel -Scope CurrentUser" -ForegroundColor Yellow
			Write-Host ""
			Write-Host "Falling back to CSV export..." -ForegroundColor Yellow
			$script:ExportWorkbook = $false
			$script:AppendFile = $false
		}
	}
	else {
		Write-Host "ImportExcel module detected: $($importExcelModule.Name) v$($importExcelModule.Version)" -ForegroundColor Green
	}
	
	# Import ImportExcel module
	if ($ExportWorkbook) {
		try {
			Import-Module ImportExcel -ErrorAction Stop
			Write-Host "ImportExcel module imported successfully" -ForegroundColor Green
			Write-Host ""
		}
		catch {
			Write-Host "ERROR: Failed to import ImportExcel module: $($_.Exception.Message)" -ForegroundColor Red
			Write-Host "Falling back to CSV export..." -ForegroundColor Yellow
			$script:ExportWorkbook = $false
			$script:AppendFile = $false
		}
	}
}

# --- Early parameter validation & environment sanity checks ---

# PowerShell version gate.
# The entire script requires PowerShell 7+ (pwsh.exe). The ONLY exception is -UseEOM
# (which uses Exchange Online Management and runs on Windows PowerShell 5.1 / powershell.exe).
# All other modes — including -RAWInputCSV and -Resume — require pwsh.exe because they
# depend on PS 7-only features (ThreadJob parallelism, ForEach-Object -Parallel, JSON
# parsing performance).
if ($PSVersionTable.PSVersion.Major -lt 7 -and -not $UseEOM) {
	Write-Host "" -ForegroundColor Red
	Write-Host "═══════════════════════════════════════════════════════════════════════════════" -ForegroundColor Red
	Write-Host "  ERROR: PowerShell 7+ Required (pwsh.exe)" -ForegroundColor Red
	Write-Host "═══════════════════════════════════════════════════════════════════════════════" -ForegroundColor Red
	Write-Host ""
	Write-Host "  Detected: PowerShell $($PSVersionTable.PSVersion) ($($PSVersionTable.PSEdition))" -ForegroundColor Yellow
	Write-Host "  Required: PowerShell 7.0 or later (pwsh.exe)" -ForegroundColor Yellow
	Write-Host ""
	Write-Host "  PAX requires PowerShell 7+ for Microsoft Graph API mode, parallel query" -ForegroundColor White
	Write-Host "  execution, JSON streaming performance, and post-processing features." -ForegroundColor White
	Write-Host "  Windows PowerShell 5.1 (powershell.exe) is ONLY supported when running with" -ForegroundColor White
	Write-Host "  the -UseEOM switch (Exchange Online Management mode)." -ForegroundColor White
	Write-Host ""
	Write-Host "  SOLUTIONS:" -ForegroundColor Cyan
	Write-Host ""
	Write-Host "    1. Recommended: Install PowerShell 7+ and re-run with pwsh.exe:" -ForegroundColor White
	Write-Host "         https://aka.ms/powershell" -ForegroundColor Gray
	Write-Host "         pwsh.exe -File .\PAX_Purview_Audit_Log_Processor.ps1 [your parameters]" -ForegroundColor Gray
	Write-Host ""
	Write-Host "    2. Or run in EOM mode on Windows PowerShell 5.1 by adding -UseEOM:" -ForegroundColor White
	Write-Host "         .\PAX_Purview_Audit_Log_Processor.ps1 -UseEOM [your other parameters]" -ForegroundColor Gray
	Write-Host ""
	Write-Host "  EOM MODE NOTES:" -ForegroundColor DarkCyan
	Write-Host "    - Uses Search-UnifiedAuditLog cmdlet (serial processing)" -ForegroundColor Gray
	Write-Host "    - Requires Exchange Online Management module" -ForegroundColor Gray
	Write-Host "    - Requires Exchange Admin role or audit log read permissions" -ForegroundColor Gray
	Write-Host "    - Some features (Entra user enrichment, rollup post-processing) not available" -ForegroundColor Gray
	Write-Host ""
	Write-Host "═══════════════════════════════════════════════════════════════════════════════" -ForegroundColor Red
	exit 1
}

if ($ExcludeAgents -and ($AgentId -or $AgentsOnly)) {
	Write-Host "ERROR: -ExcludeAgents cannot be used with -AgentId or -AgentsOnly switches." -ForegroundColor Red
	Write-Host "These switches are mutually exclusive:" -ForegroundColor Yellow
	Write-Host "  -AgentId/-AgentsOnly: Filter to ONLY records with agents" -ForegroundColor Yellow
	Write-Host "  -ExcludeAgents: Filter to ONLY records without agents" -ForegroundColor Yellow
	Write-Host "Please use only one filtering approach and re-run." -ForegroundColor Yellow
	exit 1
}

# ============================================================================
# Rollup post-processor gating
# ============================================================================
# Validates -Rollup / -RollupPlusRaw against incompatible switches and
# determines which embedded Python processor will be invoked at end-of-run.
# Runs early so failures are surfaced BEFORE any Graph API calls or auth.
#
# Sets $script:RollupProcessorMode to one of:
#   'None'                - rollup not requested
#   'CopilotInteraction'  - run Purview_CopilotInteraction_Processor (needs Purview CSV + Entra CSV)
#   'M365Bundle'          - run Purview_M365_Usage_Bundle_Explosion_Processor (needs Purview CSV only)
# ============================================================================
$script:RollupProcessorMode = 'None'
$script:RollupDashboard = 'None'
$script:RollupDashboardProfile = $null

# Resolves -Dashboard <AIO|AIBV|M365> into auto-enabled switches so the existing
# rollup gate + mode decision below operate on a consistent state. Acts only when
# the user explicitly passed -Dashboard; the default 'AIO' is inert so a bare
# -Rollup / -RollupPlusRaw keeps today's behavior exactly.
$dashboardExplicit = $PSBoundParameters.ContainsKey('Dashboard')
$dashboardUC = $Dashboard.ToUpperInvariant()
$dashboardImpliedRollup = $false
if ($dashboardExplicit) {
	# C1: AIO/AIBV (CopilotInteraction) and the M365 usage bundle are different data
	# pulls AND different processors — refuse to guess; make the user pick one.
	if (($dashboardUC -eq 'AIO' -or $dashboardUC -eq 'AIBV') -and $IncludeM365Usage) {
		Write-Host "ERROR: -Dashboard $Dashboard and -IncludeM365Usage are incompatible (different data source AND different processor). Pick one." -ForegroundColor Red
		Write-Host "  -Dashboard AIO|AIBV : CopilotInteraction rollup (AI-in-One / AI Business Value dashboards)." -ForegroundColor Yellow
		Write-Host "  -Dashboard M365     : M365 Usage Analytics rollup (or simply use -IncludeM365Usage)." -ForegroundColor Yellow
		exit 1
	}
	# Rule: -Dashboard M365 implies the M365 usage pull; auto-enable it if absent.
	if ($dashboardUC -eq 'M365' -and -not $IncludeM365Usage) {
		$IncludeM365Usage = [System.Management.Automation.SwitchParameter]::new($true)
		Write-Host "INFO: -Dashboard M365 auto-enabled -IncludeM365Usage (the M365 dashboard consumes the M365 usage bundle)." -ForegroundColor Cyan
	}
	# Rule: -Dashboard implies a rollup run; default to -Rollup when neither rollup
	# switch is present (never -RollupPlusRaw).
	if (-not $Rollup -and -not $RollupPlusRaw) {
		$Rollup = [System.Management.Automation.SwitchParameter]::new($true)
		$dashboardImpliedRollup = $true
		Write-Host "INFO: -Dashboard $Dashboard auto-enabled -Rollup (dashboard output is produced by the rollup post-processor)." -ForegroundColor Cyan
	}
}

if ($Rollup -or $RollupPlusRaw) {
	# Mutually exclusive
	if ($Rollup -and $RollupPlusRaw) {
		Write-Host "ERROR: -Rollup and -RollupPlusRaw are mutually exclusive. Pick one." -ForegroundColor Red
		Write-Host "  -Rollup         : produce ONLY rolled-up CSV(s); raw CSV(s) deleted on success." -ForegroundColor Yellow
		Write-Host "  -RollupPlusRaw  : produce BOTH the raw CSV(s) AND the rolled-up CSV(s)." -ForegroundColor Yellow
		exit 1
	}

	$rollupSwitchName = if ($Rollup) { '-Rollup' } else { '-RollupPlusRaw' }
	$rollupBlockers = @()
	if ($UseEOM)              { $rollupBlockers += '-UseEOM' }
	if ($ExportWorkbook)      { $rollupBlockers += '-ExportWorkbook' }
	if ($OnlyUserInfo)        { $rollupBlockers += '-OnlyUserInfo' }
	if ($OnlyAgent365Info)    { $rollupBlockers += '-OnlyAgent365Info' }
	if ($RAWInputCSV)         { $rollupBlockers += '-RAWInputCSV' }
	if ($ExcludeCopilotInteraction -and -not $IncludeM365Usage) { $rollupBlockers += '-ExcludeCopilotInteraction' }

	if ($rollupBlockers.Count -gt 0) {
		# Name -Dashboard in the message when it is what implied the rollup, so the
		# error references a switch the user actually typed.
		$rollupTrigger = if ($dashboardImpliedRollup) { "-Dashboard $Dashboard (which implies $rollupSwitchName)" } else { $rollupSwitchName }
		Write-Host "ERROR: $rollupTrigger is not supported with the following switch(es): $($rollupBlockers -join ', ')" -ForegroundColor Red
		Write-Host "" -ForegroundColor Yellow
		Write-Host "  $rollupSwitchName runs an embedded Python post-processor at the end of the run." -ForegroundColor Yellow
		Write-Host "  It is only valid for the default CopilotInteraction-only run, an explicit" -ForegroundColor Yellow
		Write-Host "  -ActivityTypes 'CopilotInteraction' run, or an -IncludeM365Usage run." -ForegroundColor Yellow
		Write-Host "" -ForegroundColor Yellow
		Write-Host "  Remove the conflicting switch(es) and re-run." -ForegroundColor Yellow
		exit 1
	}

	# Determine processor mode based on requested activity types.
	# Bind-time logic (mirrors the activity-type finalization that happens later):
	#   - If -IncludeM365Usage is set, mode is M365Bundle.
	#   - Else if user did NOT pass -ActivityTypes (default is CopilotInteraction), mode is CopilotInteraction.
	#   - Else if user passed -ActivityTypes containing exactly the single value 'CopilotInteraction'
	#     (case-insensitive), mode is CopilotInteraction.
	#   - Otherwise: hard-fail (rollup is not defined for arbitrary activity-type combinations).
	if ($IncludeM365Usage) {
		$script:RollupProcessorMode = 'M365Bundle'
		$script:RollupDashboard = 'M365'
		$script:RollupDashboardProfile = $null
	}
	else {
		$userPassedActivityTypes = $PSBoundParameters.ContainsKey('ActivityTypes')
		$normalizedActivity = @()
		if ($userPassedActivityTypes -and $ActivityTypes) {
			$normalizedActivity = @($ActivityTypes | Where-Object { $_ } | ForEach-Object { $_.Trim() })
		}
		$isCopilotOnly = (-not $userPassedActivityTypes) -or
			($normalizedActivity.Count -eq 1 -and $normalizedActivity[0] -ieq 'CopilotInteraction')

		if ($isCopilotOnly) {
			$script:RollupProcessorMode = 'CopilotInteraction'
			# AIO/AIBV only reach here — an explicit -Dashboard M365 auto-enabled
			# -IncludeM365Usage above and took the M365Bundle branch. Default to AIO
			# when -Dashboard was not supplied (preserves today's behavior).
			$script:RollupDashboard = if ($dashboardExplicit) { $dashboardUC } else { 'AIO' }
			$script:RollupDashboardProfile = $script:RollupDashboard.ToLowerInvariant()
		}
		else {
			Write-Host "ERROR: $rollupSwitchName is only valid for CopilotInteraction-only runs or -IncludeM365Usage runs." -ForegroundColor Red
			Write-Host "  Detected -ActivityTypes: $($normalizedActivity -join ', ')" -ForegroundColor Yellow
			Write-Host "  Remove $rollupSwitchName, or restrict -ActivityTypes to 'CopilotInteraction', or use -IncludeM365Usage." -ForegroundColor Yellow
			exit 1
		}
	}

	# CopilotInteraction-mode rollup requires the Entra users CSV for the second processor input.
	# Auto-enable -IncludeUserInfo if not already set (single info message; do not prompt).
	if ($script:RollupProcessorMode -eq 'CopilotInteraction' -and -not $IncludeUserInfo) {
		$IncludeUserInfo = [System.Management.Automation.SwitchParameter]::new($true)
		Write-Host "INFO: $rollupSwitchName (CopilotInteraction mode) auto-enabled -IncludeUserInfo (Entra users CSV is required by the post-processor)." -ForegroundColor Cyan
	}

	# Rollup requires a single combined Purview CSV; auto-enable -CombineOutput when missing.
	if (-not $CombineOutput) {
		$CombineOutput = [System.Management.Automation.SwitchParameter]::new($true)
		Write-Host "INFO: $rollupSwitchName auto-enabled -CombineOutput (rollup post-processor requires a single combined Purview CSV)." -ForegroundColor Cyan
	}
}

# ---------------------------------------------------------------------------
# -FillerLabel: org/manager-hierarchy level-filler for the rolled-up AIO/AIBV
# Users output. The hierarchy itself is always built for AIO/AIBV; this only sets
# what goes in level slots deeper than a user. Rollup-only; never the M365 path.
# Resolved here (after the rollup/dashboard state is finalized above) into the two
# script vars threaded to the embedded CopilotInteraction processor.
# ---------------------------------------------------------------------------
$script:HierarchyFillMode  = 'none'
$script:HierarchyFillLabel = ''
$fillerLabelBound = $PSBoundParameters.ContainsKey('FillerLabel')
$fillerTextBound  = $PSBoundParameters.ContainsKey('FillerLabelText')
if ($fillerTextBound -and -not $fillerLabelBound) {
	Write-Host "ERROR: -FillerLabelText is only valid together with -FillerLabel Fixed." -ForegroundColor Red
	exit 1
}
if ($fillerLabelBound) {
	if (-not ($Rollup -or $RollupPlusRaw)) {
		Write-Host "ERROR: -FillerLabel requires -Rollup or -RollupPlusRaw." -ForegroundColor Red
		Write-Host "  -FillerLabel only affects the rolled-up AI-in-One / AI Business Value Users output." -ForegroundColor Yellow
		exit 1
	}
	if ($script:RollupProcessorMode -eq 'M365Bundle') {
		Write-Host "ERROR: -FillerLabel is not valid with the M365 dashboard (-IncludeM365Usage / -Dashboard M365)." -ForegroundColor Red
		Write-Host "  The org / manager hierarchy is produced only for the AI-in-One and AI Business Value dashboards." -ForegroundColor Yellow
		exit 1
	}
	$fillMode = ([string]$FillerLabel).Trim()
	switch ($fillMode.ToLowerInvariant()) {
		'null'          { $script:HierarchyFillMode = 'none' }
		'self'          { $script:HierarchyFillMode = 'self' }
		'repeatmanager' { $script:HierarchyFillMode = 'manager' }
		'fixed'         { $script:HierarchyFillMode = 'fixed' }
		default {
			Write-Host "ERROR: -FillerLabel value '$fillMode' is not recognized." -ForegroundColor Red
			Write-Host "  Use one of: null, Self, RepeatManager, or Fixed (with -FillerLabelText `"<text>`")." -ForegroundColor Yellow
			exit 1
		}
	}
	if ($script:HierarchyFillMode -eq 'fixed') {
		if (-not $fillerTextBound -or [string]::IsNullOrWhiteSpace($FillerLabelText)) {
			Write-Host "ERROR: -FillerLabel Fixed requires -FillerLabelText `"<text>`" (e.g. -FillerLabel Fixed -FillerLabelText `"Assistive Directs`")." -ForegroundColor Red
			exit 1
		}
		$script:HierarchyFillLabel = [string]$FillerLabelText
	}
	elseif ($fillerTextBound) {
		Write-Host "ERROR: -FillerLabelText is only valid with -FillerLabel Fixed (not with '$fillMode')." -ForegroundColor Red
		exit 1
	}
}

# ============================================================================
# EMBEDDED PYTHON POST-PROCESSORS
# ============================================================================
# Two Python source files are embedded verbatim as single-quoted here-strings
# so the script is fully self-contained — no external .py files are required
# at runtime. When -Rollup or -RollupPlusRaw is used, the relevant body is
# materialized to a temp .py inside .pax_incremental, executed with the
# resolved Python interpreter, and deleted in finally. Single-quoted here-
# strings prevent any PowerShell variable expansion of the Python source.
# ============================================================================
$Script:EMBEDDED_PROCESSOR_COPILOT_VERSION = '4.1.0'
$Script:EMBEDDED_PROCESSOR_M365_VERSION    = '2.6.1'

# >>> BEGIN-EMBEDDED-COPILOT-PROCESSOR
$Script:EMBEDDED_PROCESSOR_COPILOT = @'
#!/usr/bin/env python3
"""
Purview CopilotInteraction Processor v4.1.0
-------------------------------------------
Two-input / two-output preprocessor for the AI Business Value Dashboard
and AI-in-One Rollup PBIPs.

Output profiles (--profile):
    aibv  (default) : AI Business Value Dashboard. 50-column fact superset —
                      3-value Environment {Cowork, Licensed, Unlicensed},
                      all DAX calc-columns pre-computed (Behavior_*, Usage_Mode,
                      Expertise_Role, Efficiency_Breakdown, Human_Baseline_Min,
                      Behavior_Plausible, Workflow_Action, Delegation_Event_Key,
                      Is_Agent_Activity/Web_Grounded_Signal promoted into the
                      grain for sliceability) + Audit_UserId passthrough.
    aio             : AI-in-One Dashboard. 36-column fact — 5-value Environment
                      {Autonomous Agent, Cowork, Agents, Licensed M365 Copilot,
                      Unlicensed Chat}. Reproduces the v3.1.0 AIO output
                      BYTE-IDENTICALLY (validated), so the AIO dashboard is
                      unaffected. ~41% smaller than the aibv fact.

Inputs:
    --purview <raw Purview audit log CSV>     (required)
    --entra   <Entra users CSV w/ licensing>  (required)

Outputs (in --out-dir, default = directory of --purview):
    <purview_stem>_Interactions_<YYYYMMDD_HHMMSS>.csv   (fact table)
    <entra_stem>_Users_<YYYYMMDD_HHMMSS>.csv            (dim table)

    These two files are all the AIBV template needs. Pass --with-aggregates
    (aibv only) to ALSO write 5 pre-aggregated tables for a future calc-table
    offload:
        <purview_stem>_ActiveDaysSummary_<ts>.csv
        <purview_stem>_UserMonthMetrics_<ts>.csv
        <purview_stem>_LicensedUserRankings_<ts>.csv
        <purview_stem>_UnlicensedUserRankings_<ts>.csv
        <purview_stem>_LicensedUserSummary_<ts>.csv

Grain:
    One row per (16-column grain x Message_Id; aibv adds 3 sliceable flag
    keys -> 19). DAX measures use DISTINCTCOUNT(Message_Id) which yields exact
    parity with the semantic-model definitions at every visual / slicer
    combination. Per-resource accumulation is intentionally avoided so counts
    are
    not inflated (~2.25x) by per (prompt x AccessedResource) iteration.

INT-surrogated columns (perf):
    Message_Id, ThreadId, and UserKey (replaces Audit_UserId) are emitted
    as 1-based INTs assigned in input encounter order. Cuts CSV size,
    parse time, AND VertiPaq dictionary build time on the three highest-
    cardinality GUID columns. UserKey is written to BOTH the fact CSV
    and the Users dim CSV (same shared map keyed on normalized UPN), so
    the fact↔Users relationship is INT-to-INT. DISTINCTCOUNT semantics
    are identical between INT and string surrogates of the same set.
    UserMonthKey stays string (cross-processor blast radius).

Calc cols ported from DAX -> precomputed here for ingestion-time speedup:
    Agent_TitleID, Behavior_Source, Value_Outcome, ActivityDate
    (= InteractionDate alias).

Stays in DAX (cross-table dependencies that cannot be precomputed without
shipping Agents 365 / UserMonthMetrics / AgentMetrics into the processor):
    Behavior_Enriched_Full (RELATED Agents 365),
    User_Stage_Maturity / User_Stage (RELATED UserMonthMetrics),
    Usage_Mode, Expertise_Role, Efficiency_Breakdown
    (all depend on Behavior_Enriched_Full),
    Agent Last Used Date (LOOKUPVALUE AgentMetrics).

Requirements:
    Python 3.9+
    pip install orjson   (OPTIONAL - faster JSON parsing; falls back to stdlib json)
"""

from __future__ import annotations

import argparse
import csv
import functools
import hashlib
import hmac
import os
import re
import sys
import time
from datetime import datetime, timedelta, timezone
from pathlib import Path
from typing import Any

try:
    import orjson

    def json_loads(value: str | bytes) -> Any:
        if isinstance(value, str):
            value = value.encode("utf-8")
        return orjson.loads(value)

    _JSON_ENGINE = "orjson"
except ImportError:
    import json as _json

    def json_loads(value: str | bytes) -> Any:
        if isinstance(value, bytes):
            value = value.decode("utf-8")
        return _json.loads(value)

    _JSON_ENGINE = "json (stdlib)"


SCRIPT_VERSION = "4.1.0"

# ---------------------------------------------------------------------------
# Output schemas — TWO PROFILES
#
#   --profile aio   : reproduces the v3.1.0 AIO-faithful output EXACTLY
#                     (36-col fact, 5-value Environment vocabulary). This is
#                     the contract the AI-in-One dashboard already consumes;
#                     it must remain byte-identical to v3.1.0.
#   --profile aibv  : the AIBV-faithful superset (50-col fact, 3-value
#                     Environment, all offloaded calc cols + grain-promoted
#                     sliceable flags) built in this v4.0.0 effort.
#
# Both share one classification CODEBASE; the per-profile vocabulary is
# selected by the `profile` argument threaded through the classifiers.
# ---------------------------------------------------------------------------

# Common grain prefix (identical in both profiles).
_GRAIN_KEYS_COMMON: tuple[str, ...] = (
    "UserKey",
    "InteractionDate",
    "AgentId",
    "AgentName",
    "AppHost",
    "Environment",
    "License Status",
    "Context_Type",
    "Behavior_Category",
    "Behavior_Enriched",
    "AI_Model",
    "Is_Sensitive",
    "Autonomy_Pattern",
    "AppIdentity_AppId",
    "AISystemPlugin_Name",
    "ThreadId",
)

# AIO grain = the common 16 (matches v3.1.0 exactly).
GRAIN_KEYS_AIO: tuple[str, ...] = _GRAIN_KEYS_COMMON

# AIBV grain = common 16 + 3 promoted per-resource flags (sliceability fix).
GRAIN_KEYS_AIBV: tuple[str, ...] = _GRAIN_KEYS_COMMON + (
    # Promoted into the grain (sliceability fix): computed per-resource and
    # bound to AIBV slicers/filters, so they MUST be grain-faithful. Validated
    # at 0.000% row inflation on real data.
    "Is_Agent_Activity",
    "Web_Grounded_Signal",
    "Workflow_Action",
)

# AIO non-grain carried attrs = exactly the v3.1.0 set (ends at ActivityDate).
_NONGRAIN_ATTRS_AIO: tuple[str, ...] = (
    "CreationDate",
    "WeekStart",
    "MonthStart",
    "UserMonthKey",
    "Has license",
    "Resource_Count",
    "SensitivityLabelId",
    "AccessedResource_Type",
    "AccessedResource_Action",
    "AccessedResource_SiteUrl",
    "AccessedResource_SensitivityLabelId",
    "AppIdentity_DisplayName",
    "AISystemPlugin_Id",
    "ModelTransparencyDetails_ModelName",
    "Agent_TitleID",
    "Message_isPrompt",
    # Calc cols ported from DAX (present in AIO since v3.1.0)
    "Behavior_Source",
    "Value_Outcome",
    "ActivityDate",
)

# AIBV non-grain carried attrs = AIO set + AIBV-only offloaded columns.
_NONGRAIN_ATTRS_AIBV: tuple[str, ...] = _NONGRAIN_ATTRS_AIO + (
    # M1: UPN passthrough for AIBV joins + DISTINCTCOUNT.
    "Audit_UserId",
    "Audit_UserId_Normalized",
    # AIBV-faithful row-level flags. (Is_Agent_Activity / Web_Grounded_Signal /
    # Workflow_Action were promoted into GRAIN_KEYS_AIBV.) `Agent Filter`
    # derives from Is_Agent_Activity, so it stays a grain-consistent carried attr.
    "Agent Filter",
    "Agent Publish Status",
    # Downstream classification chain (offloaded; faithful without Agents 365 per F2).
    "Behavior_Enriched_Full",
    "Usage_Mode",
    "Expertise_Role",
    "Efficiency_Breakdown",
    # ROI baseline pre-join (offloads the Human Equivalent Hours SUMX+RELATED).
    "Human_Baseline_Min",
    # Remaining row-level calc cols (offloaded).
    "Behavior_Plausible",
    "Delegation_Event_Key",
)

# Final fact CSV schemas. One row per (grain x Message_Id). Message_Id is
# emitted as a sequential INT surrogate (1-based, assigned in input order).
FACT_HEADER_AIO: list[str] = list(GRAIN_KEYS_AIO) + ["Message_Id"] + list(_NONGRAIN_ATTRS_AIO)
FACT_HEADER_AIBV: list[str] = list(GRAIN_KEYS_AIBV) + ["Message_Id"] + list(_NONGRAIN_ATTRS_AIBV)


def schema_for(profile: str) -> tuple[tuple[str, ...], tuple[str, ...], list[str]]:
    """Return (grain_keys, nongrain_attrs, fact_header) for the profile."""
    if profile == "aio":
        return GRAIN_KEYS_AIO, _NONGRAIN_ATTRS_AIO, FACT_HEADER_AIO
    return GRAIN_KEYS_AIBV, _NONGRAIN_ATTRS_AIBV, FACT_HEADER_AIBV

# Entra column-name aliases used by the existing PBIP M-code. We mirror the
# same renaming so the dim CSV is drop-in compatible with all downstream DAX.
UPN_VARIANTS_NORMALIZED = {"userprincipalname", "upn", "personid"}
DEPARTMENT_VARIANT_NORMALIZED = "department"
JOBTITLE_RAW_NAME = "jobTitle"  # exact-match rename to "JobTitle"
HAS_LICENSE_VARIANTS = (
    "Has license",
    "Has License",
    "hasLicense",
    "HasLicense",
    "Has Copilot License",
    "Has Copilot license",
    "HasCopilotLicense",
    "Has Copilot License Assigned",
    "Has Copilot license assigned",
    "isUser",
)

# ---------------------------------------------------------------------------
# Datetime helpers
# ---------------------------------------------------------------------------

_CREATION_TIME_FORMATS: tuple[str, ...] = (
    "%Y-%m-%dT%H:%M:%S.%fZ",
    "%Y-%m-%dT%H:%M:%SZ",
    "%Y-%m-%dT%H:%M:%S.%f",
    "%Y-%m-%dT%H:%M:%S",
    "%m/%d/%Y %I:%M:%S %p",
    "%m/%d/%Y %H:%M:%S",
)


def safe_get(obj: Any, key: str) -> Any:
    if obj is None:
        return None
    if isinstance(obj, dict):
        return obj.get(key)
    return getattr(obj, key, None)


def get_array(obj: Any, key: str) -> list[Any]:
    value = safe_get(obj, key)
    return value if isinstance(value, list) else []


def to_text(value: Any) -> str:
    if value is None:
        return ""
    if isinstance(value, bool):
        return "TRUE" if value else "FALSE"
    return str(value)


def normalize_user_id(value: Any) -> str:
    return to_text(value).strip().lower()


# ---------------------------------------------------------------------------
# Deidentification (--deidentify): one-way, salted, format-preserving.
# OFF by default; enabled by main() setting the module flag from --deidentify.
# Every PII value becomes a deterministic token so relationships (manager links,
# UserKey/Users joins, distinct-resource counts) are preserved while identities
# are removed. Irreversible (no decode map). The SAME salt + algorithm + formats
# MUST exist verbatim in the PowerShell raw-path deidentifier and the M365
# processor (PAX deidentify spec) so tokens match across engines.
# ---------------------------------------------------------------------------
_DEIDENTIFY: bool = False
_DEID_SALT = b"PAX-Deidentify-Salt-v1-DO-NOT-CHANGE-7f3c1e9b2d846050a1c4e8b3"
_DEID_DOMAIN = "deidentified.domain"
_deid_cache: dict[str, str] = {}


def _deid_hex(value: str, length: int) -> str:
    return hmac.new(
        _DEID_SALT, value.strip().lower().encode("utf-8"), hashlib.sha256
    ).hexdigest()[:length]


def deid_upn(value: str) -> str:
    """UPN / email -> <12hex>@deidentified.domain. No-op when off or value empty."""
    if not _DEIDENTIFY or not value:
        return value
    k = "upn\x00" + value
    v = _deid_cache.get(k)
    if v is None:
        v = _deid_hex(value, 12) + "@" + _DEID_DOMAIN
        _deid_cache[k] = v
    return v


def deid_name(value: str) -> str:
    """Person/device display name -> <12hex>."""
    if not _DEIDENTIFY or not value:
        return value
    k = "name\x00" + value
    v = _deid_cache.get(k)
    if v is None:
        v = _deid_hex(value, 12)
        _deid_cache[k] = v
    return v


def deid_guid(value: str) -> str:
    """GUID -> deterministic GUID shape xxxxxxxx-xxxx-xxxx-xxxx-xxxxxxxxxxxx."""
    if not _DEIDENTIFY or not value:
        return value
    k = "guid\x00" + value
    v = _deid_cache.get(k)
    if v is None:
        h = _deid_hex(value, 32)
        v = f"{h[0:8]}-{h[8:12]}-{h[12:16]}-{h[16:20]}-{h[20:32]}"
        _deid_cache[k] = v
    return v


def deid_sid(value: str) -> str:
    """SID -> deterministic S-1-5-21-<d1>-<d2>-<d3>-<d4> shape."""
    if not _DEIDENTIFY or not value:
        return value
    k = "sid\x00" + value
    v = _deid_cache.get(k)
    if v is None:
        h = _deid_hex(value, 32)
        v = "S-1-5-21-{0}-{1}-{2}-{3}".format(
            int(h[0:8], 16), int(h[8:16], 16), int(h[16:24], 16), int(h[24:32], 16)
        )
        _deid_cache[k] = v
    return v


def deid_token(value: str) -> str:
    """Opaque id (employeeId, immutableId) -> <12hex>."""
    if not _DEIDENTIFY or not value:
        return value
    k = "tok\x00" + value
    v = _deid_cache.get(k)
    if v is None:
        v = _deid_hex(value, 12)
        _deid_cache[k] = v
    return v


def deid_resource(value: str) -> str:
    """Resource URL -> site_<12hex> (whole-string hash; preserves distinct-count)."""
    if not _DEIDENTIFY or not value:
        return value
    k = "res\x00" + value
    v = _deid_cache.get(k)
    if v is None:
        v = "site_" + _deid_hex(value, 12)
        _deid_cache[k] = v
    return v


def deid_file(value: str) -> str:
    """File / document name -> file_<12hex>."""
    if not _DEIDENTIFY or not value:
        return value
    k = "file\x00" + value
    v = _deid_cache.get(k)
    if v is None:
        v = "file_" + _deid_hex(value, 12)
        _deid_cache[k] = v
    return v


def deid_proxy(value: str) -> str:
    """proxyAddresses entry(ies) -> keep smtp:/SMTP: prefix + deidentified email.
    Handles ';'-delimited multi-value fields."""
    if not _DEIDENTIFY or not value:
        return value
    out = []
    for entry in value.split(";"):
        if not entry:
            out.append(entry)
        elif ":" in entry:
            prefix, addr = entry.split(":", 1)
            out.append(prefix + ":" + deid_upn(addr))
        else:
            out.append(deid_upn(entry))
    return ";".join(out)


# Non-human/system identities found in Purview audit logs (Teams Sync, SharePoint app,
# SupervisoryReview bots, ServicePrincipals, NT-style accounts, SIDs, bare GUIDs, etc.).
# These have no matching userPrincipalName in EntraUsers and would render as blank
# User/Department rows in downstream visuals. Filter out before any record is emitted.
_UPN_LOCAL_RE = re.compile(r"^[^\s\\@]+$")
_BARE_GUID_RE = re.compile(r"^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$", re.I)


def _is_human_upn(uid: str) -> bool:
    """True iff uid is a syntactically valid human UPN (local@domain.tld), excluding
    well-known service/bot patterns (SupervisoryReview{...}@..., bare GUIDs)."""
    if not uid:
        return False
    s = uid.strip()
    if _BARE_GUID_RE.match(s):
        return False
    if s.lower().startswith("supervisoryreview{"):
        return False
    if "@" not in s or s.count("@") != 1:
        return False
    local, domain = s.split("@", 1)
    if not _UPN_LOCAL_RE.match(local):
        return False
    if "." not in domain or not domain or domain.startswith(".") or domain.endswith("."):
        return False
    return True


def parse_creation_time(value: Any) -> datetime | None:
    raw = to_text(value).strip()
    if not raw:
        return None
    return _parse_creation_time_cached(raw)


@functools.lru_cache(maxsize=None)
def _parse_creation_time_cached(raw: str) -> datetime | None:
    # Fast path: ISO 8601 (covers ~100% of Purview audit timestamps).
    # datetime.fromisoformat is ~10x faster than strptime and avoids the
    # locale lookup that strptime performs on every call. Python 3.11+
    # accepts a trailing "Z"; for 3.10 and earlier we strip it.
    try:
        if raw.endswith("Z"):
            try:
                return datetime.fromisoformat(raw)
            except ValueError:
                return datetime.fromisoformat(raw[:-1])
        return datetime.fromisoformat(raw)
    except ValueError:
        pass
    # Slow path: legacy non-ISO formats kept for backwards compat with
    # older / hand-edited audit exports.
    for fmt in _CREATION_TIME_FORMATS:
        try:
            return datetime.strptime(raw, fmt)
        except ValueError:
            continue
    return None


def format_creation_date(value: Any) -> str:
    parsed = parse_creation_time(value)
    if parsed is None:
        raw = to_text(value).strip()
        if len(raw) >= 10 and raw[4:5] == "-":
            return raw[:10] + "T00:00:00.000Z"
        return raw
    return parsed.replace(tzinfo=timezone.utc).strftime("%Y-%m-%dT00:00:00.000Z")


def interaction_date(parsed: datetime | None) -> str:
    return parsed.strftime("%Y-%m-%d") if parsed else ""


def week_start(parsed: datetime | None) -> str:
    if parsed is None:
        return ""
    return (parsed - timedelta(days=parsed.weekday())).strftime("%Y-%m-%d")


def month_start(parsed: datetime | None) -> str:
    if parsed is None:
        return ""
    return parsed.replace(day=1).strftime("%Y-%m-%d")


# Cached bundle: given a raw timestamp string, return all 4 derived date
# strings in one shot. Avoids 4x strftime + tzinfo replace per record. The
# distinct raw-timestamp count in a typical dataset is small relative to
# input row count (many records share the same audit timestamp at the
# second granularity), so this collapses ~4N strftime calls to ~K where
# K is the distinct timestamp count.
@functools.lru_cache(maxsize=None)
def _date_strings_for_raw(raw: str) -> tuple[str, str, str, str]:
    """
    Returns (creation_date_iso_z, interaction_date, week_start, month_start)
    for the given raw timestamp string. Empty string is returned for any
    field that cannot be derived (matches non-cached helper semantics).
    """
    if not raw:
        return ("", "", "", "")
    parsed = _parse_creation_time_cached(raw)
    if parsed is None:
        if len(raw) >= 10 and raw[4:5] == "-":
            return (raw[:10] + "T00:00:00.000Z", "", "", "")
        return (raw, "", "", "")
    # Direct f-string formatting is ~10x faster than strftime (which does
    # locale lookup + format-string parsing on every call). Output bytes
    # are byte-identical to the prior strftime("%Y-%m-%d") output for any
    # year in [1000, 9999] (CreationTime range).
    y = parsed.year
    m = parsed.month
    d = parsed.day
    creation = f"{y:04d}-{m:02d}-{d:02d}T00:00:00.000Z"
    interaction = f"{y:04d}-{m:02d}-{d:02d}"
    # Week start (Monday-based, mirroring strftime((parsed-weekday).strftime))
    ws = parsed - timedelta(days=parsed.weekday())
    week = f"{ws.year:04d}-{ws.month:02d}-{ws.day:02d}"
    month = f"{y:04d}-{m:02d}-01"
    return (creation, interaction, week, month)


def slugify(value: str) -> str:
    slug = re.sub(r"[^A-Za-z0-9]+", "-", value.strip())
    return slug.strip("-")


# ---------------------------------------------------------------------------
# Audit JSON shaping
# ---------------------------------------------------------------------------


def app_identity_values(audit_data: dict[str, Any]) -> tuple[str, str]:
    app_identity = safe_get(audit_data, "AppIdentity")
    if isinstance(app_identity, str):
        return "", app_identity
    if isinstance(app_identity, dict):
        return (
            to_text(safe_get(app_identity, "AppId")),
            to_text(safe_get(app_identity, "DisplayName")),
        )
    return "", ""


def derive_agent_name(agent_name: Any, app_identity_display: str, app_identity_app_id: str) -> str:
    # Match the BEFORE PBIP behavior: AgentName comes straight from the audit JSON.
    # Do NOT synthesize from AppIdentity when it's blank — that fabricates distinct
    # agent identities (e.g. "Copilot-Studio-Default-<tenantGuid>-<agentGuid>") that
    # don't exist in the raw data and inflate Active Agents / per-agent rollups.
    return to_text(agent_name).strip()


def derive_agent_title_id(agent_id: Any) -> str:
    agent_id_text = to_text(agent_id).strip()
    if not agent_id_text:
        return ""
    return agent_id_text.rsplit(".", 1)[-1]


def first_dict_item(items: list[Any]) -> dict[str, Any]:
    for item in items:
        if isinstance(item, dict):
            return item
    return {}


def prompt_messages(ced: dict[str, Any]) -> list[dict[str, Any]]:
    prompts: list[dict[str, Any]] = []
    for message in get_array(ced, "Messages"):
        if isinstance(message, dict) and message.get("isPrompt") is True:
            prompts.append(message)
    return prompts


def resource_rows(ced: dict[str, Any]) -> list[dict[str, Any]]:
    resources = [item for item in get_array(ced, "AccessedResources") if isinstance(item, dict)]
    return resources if resources else [{}]


def is_copilot_interaction(audit_data: dict[str, Any], raw_row: dict[str, Any]) -> bool:
    operation = to_text(
        safe_get(audit_data, "Operation")
        or raw_row.get("Operation")
        or raw_row.get("Operations")
    ).strip()
    return operation == "CopilotInteraction"


# ---------------------------------------------------------------------------
# Classification logic (ports of the PBIP DAX calc columns)
# ---------------------------------------------------------------------------

_LICENSE_TRUTHY = {"YES", "TRUE", "Y", "1"}
_ACTIVE_RES_ACTION_TOKENS = ("send", "draft", "create", "post", "invoke", "write", "patch", "execute")


def normalize_has_license(raw: str) -> str:
    """Normalize any truthy/falsy variant to canonical 'TRUE' / 'FALSE'.

    Existing PBIP measures filter with literal `[Has license] = "FALSE"`, so
    we canonicalize here to guarantee those filters match regardless of how
    the upstream Entra/PAX export rendered the value.
    """
    val = (raw or "").strip().upper()
    if val in _LICENSE_TRUTHY:
        return "TRUE"
    if val in {"NO", "FALSE", "N", "0"}:
        return "FALSE"
    return "FALSE"


@functools.lru_cache(maxsize=None)
def compute_license_status(has_license_raw: str) -> str:
    val = (has_license_raw or "").strip().upper()
    return "M365 Copilot Licensed" if val in _LICENSE_TRUTHY else "Unlicensed"


@functools.lru_cache(maxsize=None)
def compute_environment(profile: str, has_license_raw: str, agent_name: str, agent_id: str, app_host: str) -> str:
    license_val = (has_license_raw or "").strip().upper()
    if profile == "aio":
        # v3.1.0 AIO vocabulary (5-value, keyed off app_host + agent presence).
        host = (app_host or "").lower()
        has_agent = bool((agent_name or "").strip()) or bool((agent_id or "").strip())
        if host in {"autonomous", "logic app"}:
            return "Autonomous Agent"
        if "cowork" in host:
            return "Cowork"
        if has_agent:
            return "Agents"
        if license_val in _LICENSE_TRUTHY:
            return "Licensed M365 Copilot"
        return "Unlicensed Chat"
    # AIBV vocabulary (verbatim port of current AIBV calc col `Environment`):
    #   IF(CONTAINSSTRING(LOWER(TRIM(AgentName)),"cowork"),"Cowork",
    #   IF(isLicensed,"Licensed","Unlicensed"))
    if "cowork" in (agent_name or "").strip().lower():
        return "Cowork"
    if license_val in _LICENSE_TRUTHY:
        return "Licensed"
    return "Unlicensed"


@functools.lru_cache(maxsize=None)
def compute_is_sensitive(sens_label: str, resource_sens_label: str) -> str:
    return "TRUE" if (sens_label or "").strip() or (resource_sens_label or "").strip() else "FALSE"


@functools.lru_cache(maxsize=None)
def compute_ai_model(model_name: str) -> str:
    m = (model_name or "").upper()
    if not m or m == "NULL":
        return "Embedded App (no model logged)"
    if "DEEP_LEO" in m:
        return "GPT-4 (Standard)"
    if "REASONING" in m:
        return "Reasoning Model (o1/o3)"
    if "OFFENSIVE" in m:
        return "Safety Filter (blocked)"
    if "GPT-41" in m or "GPT-4.1" in m:
        return "GPT-4.1 (Next Gen)"
    if "O3-MINI" in m or "O3MINI" in m:
        return "o3-mini (Reasoning)"
    if "O3" in m or "O1" in m:
        return "Reasoning Model (o-series)"
    if "GPT-5" in m or "GPT5" in m:
        return "GPT-5 (Next Gen)"
    if "CLAUDE" in m:
        return "Claude (Anthropic)"
    if "GEMINI" in m:
        return "Gemini (Google)"
    if "LLAMA" in m or "META" in m:
        return "LLaMA (Meta)"
    if "PHI" in m:
        return "Phi (Microsoft Small Model)"
    return model_name or ""


def _resource_behavior(
    profile: str, res_type: str, res_action: str, site_url: str, is_active: bool
) -> str:
    if res_action in {"sendemailv2", "draftemail", "senddraftemail", "updatedraftemail"}:
        return "Email Drafting"
    if res_type == "emailmessage":
        return "Email Drafting" if is_active else "Email Summarising"
    if res_action == "mcp_meetingmanagement":
        return "Meeting Scheduling"
    if res_type in {"event", "teamsmeeting"}:
        return "Meeting Prep"
    if res_action in {"postmessagetoconversation", "createchat"}:
        return "Teams Messaging"
    if res_type in {"teamsmessage", "teamschat", "teamschannel"}:
        return "Teams Messaging"
    if profile == "aio":
        # v3.1.0: any flow/connector/http resource -> "Workflow Execution".
        if res_type in {"flow", "connector", "http"}:
            return "Workflow Execution"
    else:
        # AIBV: explicit Flow always; connector/http only with an active verb.
        if res_type == "flow":
            return "Running a Workflow"
        if res_type in {"connector", "http"} and is_active:
            return "Running a Workflow"
    if res_action in {"executedatasetquery", "getitems", "getalltables", "gettableviews"}:
        return "Data Querying"
    if res_type in {"xlsx", "csv", "xlsm", "xlsb", "xls"}:
        return "Excel Assistance" if is_active else "Spreadsheet Review"
    if res_type == "peopleinferenceanswer":
        return "People Lookup"
    if res_type in {"listitem", "aspx"}:
        return "Enterprise Searching"
    if res_type == "websearchquery":
        return "Web Searching"
    if res_type == "pdf":
        return "PDF Analysis"
    if res_type in {"py", "js", "java", "tsx", "jsx", "css", "php", "sh"} and is_active:
        return "Code Writing"
    if res_type in {"py", "sql", "js", "java", "json", "xml", "html", "yaml", "yml", "txt"}:
        return "Code Analysis"
    if res_type in {"png", "jpg", "jpeg", "svg", "gif"} and is_active:
        return "Image Generation"
    if res_type in {"png", "jpg", "jpeg", "gif"}:
        return "Image / Media Analysis"
    if res_type in {"streamvideo", "mp4", "mov", "webm", "mkv"}:
        return "Video Summarising"
    if res_type in {"planid", "taskids"}:
        return "Task Management"
    if res_type == "looppage":
        return "Real-time Collaboration"
    if res_type == "http://schema.skype.com/hyperlink":
        for token in ("github.com", "stackoverflow.com", "npmjs.com", "pypi.org", "docker.com", "kubernetes.io", "leetcode.com"):
            if token in site_url:
                return "Code Analysis"
        for token in ("learning.cloud.microsoft", "coursera.org", "udemy.com"):
            if token in site_url:
                return "Agent: Coaching"
        if "sharepoint.com" in site_url:
            return "Enterprise Searching"
        return "Web Searching"
    if res_type in {"external", "http"}:
        return "Web Searching"
    if res_type in {"docx", "doc", "rtf"}:
        if is_active:
            return "Document Drafting"
        if res_action == "read":
            return "File Retrieval"
        return "Document Summarising"
    if res_type in {"pptx", "ppt", "potx"}:
        if is_active:
            return "Presentation Creation"
        if res_action == "read":
            return "File Retrieval"
        return "Presentation Summarising"
    if "service-now.com" in site_url or "servicenow.com" in site_url:
        return "Agent: IT & Service Desk"
    if "dynamics.com" in site_url:
        return "Agent: Sales & Customer"
    return ""


def _context_behavior(profile: str, app_host: str, ctx_type: str, is_active: bool, has_agent: bool) -> str:
    if ctx_type == "teamsmeeting":
        return "Meeting Prep"
    if ctx_type == "streamvideo":
        return "Video Summarising"
    if ctx_type == "docx":
        return "Document Drafting" if (app_host == "word" and is_active) else "Document Summarising"
    if ctx_type in {"xlsx", "xlsm", "xlsb", "xls", "csv"}:
        return "Spreadsheet Review"
    if ctx_type in {"pptx", "pptm"}:
        return "Presentation Creation" if (app_host == "powerpoint" and is_active) else "Presentation Summarising"
    if ctx_type in {"teamschat", "teamschannel"}:
        return "Teams Messaging"
    if ctx_type == "aspx":
        return "Enterprise Searching"
    if app_host in {"outlook", "outlooksidepane"}:
        return "Email Drafting" if is_active else "Email Summarising"
    if app_host == "excel":
        return "Excel Assistance"
    if app_host == "word":
        return "Document Drafting" if is_active else "Document Summarising"
    if app_host == "powerpoint":
        return "Presentation Creation" if is_active else "Presentation Summarising"
    if app_host == "stream":
        return "Video Summarising"
    if app_host == "sharepoint":
        return "SharePoint Access"
    if app_host == "designer":
        return "Image Generation"
    if app_host == "onenote":
        return "Note Taking"
    if app_host == "forms":
        return "Form / Survey Work"
    if app_host == "planner":
        return "Task Management"
    if app_host in {"loop", "whiteboard", "vivaengage"}:
        return "Real-time Collaboration"
    if app_host == "copilot studio":
        return "Domain-Specific Agent"
    if profile == "aio":
        # v3.1.0: autonomous OR logic app -> "Workflow Execution".
        if app_host in {"autonomous", "logic app"}:
            return "Workflow Execution"
    else:
        # AIBV: autonomous always; logic app only when an agent context is present.
        if app_host == "autonomous":
            return "Running a Workflow"
        if app_host == "logic app" and has_agent:
            return "Running a Workflow"
    if app_host in {"datawarehousing core", "power bi"}:
        return "Data Querying"
    return "General Chat"


@functools.lru_cache(maxsize=None)
def compute_behavior_category(
    profile: str,
    app_host: str,
    ctx_type: str,
    res_type: str,
    res_action: str,
    site_url: str,
    plugin_id: str,
    has_agent: bool,
) -> str:
    app_host_l = (app_host or "").lower()
    ctx_l = (ctx_type or "").lower()
    res_t_l = (res_type or "").lower()
    res_a_l = (res_action or "").lower()
    site_l = (site_url or "").lower()
    plugin_l = (plugin_id or "").lower()
    is_active = any(tok in res_a_l for tok in _ACTIVE_RES_ACTION_TOKENS)

    from_resource = _resource_behavior(profile, res_t_l, res_a_l, site_l, is_active)
    if from_resource:
        return from_resource
    if plugin_l == "enterprisesearch":
        return "Enterprise Searching"
    return _context_behavior(profile, app_host_l, ctx_l, is_active, has_agent)


_GENERIC_QA_BEHAVIORS = {"General Q&A", "M365 Chat Q&A", "Teams Q&A", "Browser Q&A", "General Chat"}
_AGENT_NAME_RULES: tuple[tuple[tuple[str, ...], str], ...] = (
    (("coach", "mentor", "learning", "career"), "Agent: Coaching"),
    (("research", "analyst", "analy"), "Agent: Research & Analysis"),
    (("sales", "commercial", "customer", "crm", "revenue"), "Agent: Sales & Customer"),
    (("hr", "recruit", "talent", "onboard", "people"), "Agent: HR & People"),
    (("policy", "compliance", "legal", "audit", "risk"), "Agent: Compliance & Policy"),
    (("service", "support", "help", "ticket", "incident"), "Agent: IT & Service Desk"),
    (("summar", "draft", "translat", "editor"), "Agent: Content Generation"),
    (("data", "report", "dashboard", "metric"), "Agent: Data & Reporting"),
    (("knowledge", "faq", "wiki", "buddy", "guide"), "Agent: Knowledge Base"),
    (("idea", "brainstorm", "creative", "design"), "Agent: Ideation & Creative"),
)


@functools.lru_cache(maxsize=None)
def compute_behavior_enriched(profile: str, behavior_category: str, agent_name: str, environment: str) -> str:
    # AIO enriches agent/autonomous rows; AIBV enriches agents/cowork rows.
    # (In practice AIBV `Environment` never returns "Agents", so only Cowork enriches.)
    enrich_envs = {"Agents", "Autonomous Agent"} if profile == "aio" else {"Agents", "Cowork"}
    if environment not in enrich_envs:
        return behavior_category
    if behavior_category not in _GENERIC_QA_BEHAVIORS:
        return behavior_category
    name_l = (agent_name or "").lower()
    for tokens, label in _AGENT_NAME_RULES:
        if any(t in name_l for t in tokens):
            return label
    return "Agent: General Purpose"


# Autonomy_Pattern — profile-aware.
#   AIO (v3.1.0): keyed off the 5-value Environment.
#   AIBV: SWITCH(Cowork->3, Is_Agent_Activity->2, Licensed->1, else BLANK).
@functools.lru_cache(maxsize=None)
def compute_autonomy_pattern(profile: str, environment: str, is_agent_activity_str: str) -> str:
    if profile == "aio":
        if environment == "Licensed M365 Copilot":
            return "1 - Copilot"
        if environment == "Agents":
            return "2 - Agent-Assisted"
        if environment == "Autonomous Agent":
            return "3 - Autonomous"
        return ""
    if environment == "Cowork":
        return "3 - Cowork"
    if is_agent_activity_str == "TRUE":
        return "2 - Agent-Assisted"
    if environment == "Licensed":
        return "1 - Copilot"
    return ""


# Behavior_Source — profile-aware (AIO: "Autonomous Agent" branch; AIBV: "Cowork").
@functools.lru_cache(maxsize=None)
def compute_behavior_source(
    profile: str,
    behavior_category: str,
    environment: str,
    agent_name: str,
    plugin_name: str,
    app_host: str,
) -> str:
    agent = (agent_name or "").strip()
    plugin = (plugin_name or "").strip()
    app = (app_host or "").strip()
    if profile == "aio" and environment == "Autonomous Agent":
        source = "Autonomous Agent" + (f": {agent}" if agent else "")
    elif profile != "aio" and environment == "Cowork":
        source = "Cowork" + (f": {agent}" if agent else "")
    elif environment == "Agents" and agent:
        source = f"Agent: {agent}"
    elif plugin:
        source = f"{app} ({plugin})"
    elif app:
        source = app
    else:
        source = "Copilot Chat"
    return f"{behavior_category} → {source}"


