    if _DEIDENTIFY:
        # Exploded (153-col) identity + resource fields. AccessedResource_SiteUrl/Name on
        # Copilot rows are hashed in explode_copilot_record (set there after this returns).
        row["UserId"] = deid_upn(row["UserId"])
