def explode_m365_record(record: dict, audit_data: dict) -> list[dict]:
    """
    Extract a non-Copilot M365 record (Path A).
    Produces exactly 1 row per record with all 153 M code columns.
    No array explosion — M code does not explode non-Copilot arrays.
    """
    return [_build_unified_row(record, audit_data)]


# ═════════════════════════════════════════════════════════════════════════════
# PATH B: COPILOT EXPLOSION
# ═════════════════════════════════════════════════════════════════════════════

def explode_copilot_record(
    record: dict,
    audit_data: dict,
    ced: dict,
    prompt_filter: str | None = None,
) -> list[dict]:
    """
    Explode a Copilot record (Path B).
    Starts from the unified 153-column base row, then overrides CED-specific fields.
    Extracts Messages, Contexts, AccessedResources, AISystemPlugin,
    ModelTransparencyDetails, SensitivityLabels and builds N parallel-indexed rows.
    """
    # Extract array fields from CopilotEventData
    messages = get_array_fast(ced, "Messages")
    contexts = get_array_fast(ced, "Contexts")
    resources = get_array_fast(ced, "AccessedResources")
    plugins_raw = get_array_fast(ced, "AISystemPlugin")
    model_det_raw = get_array_fast(ced, "ModelTransparencyDetails")
    message_ids = get_array_fast(ced, "MessageIds")
    sensitivity_labels = get_array_fast(ced, "SensitivityLabels")

    # Prompt filtering
    if prompt_filter:
        filtered: list = []
        pf_lower = prompt_filter.lower()
        if pf_lower == "null":
            filtered = [m for m in messages if safe_get(m, "isPrompt") is None]
        elif pf_lower == "both":
            filtered = [m for m in messages if safe_get(m, "isPrompt") is not None]
        elif pf_lower == "prompt":
            filtered = [m for m in messages if safe_get(m, "isPrompt") is True]
        elif pf_lower == "response":
            filtered = [m for m in messages if safe_get(m, "isPrompt") is False]
        messages = filtered
        if not messages:
            return []

    # Detect activity type for 2-level explosion
    activity_type = safe_get(audit_data, "Operation") or ""

    # Context items max for CopilotInteraction
    context_items_max: int = 0
    if activity_type == "CopilotInteraction" and contexts:
        for ctx in contexts:
            if ctx:
                items = get_array_fast(ctx, "Items")
                if items and len(items) > context_items_max:
                    context_items_max = len(items)

    # Calculate row count
    if prompt_filter:
        row_count = max(1, len(messages))
    else:
        array_counts = [
            1, len(messages), len(contexts), len(resources),
            len(sensitivity_labels), len(plugins_raw), len(model_det_raw),
        ]
        if context_items_max > 0:
            array_counts.append(context_items_max)
        row_count = max(array_counts)

    row_count = min(row_count, EXPLOSION_PER_RECORD_ROW_CAP)
    if row_count < 1:
        row_count = 1

    # ── Build unified base row with all 153 M code columns ───────────────
    base = _build_unified_row(record, audit_data)

    # ── Override CED-specific scalar fields with deep CED extraction ─────
    # AppHost: prefer CED → audit_data → Workload
    base["AppHost"] = select_first_non_null([
        safe_get(ced, "AppHost"),
        safe_get(audit_data, "AppHost"),
        safe_get(audit_data, "Workload"),
    ]) or ""

    base["ThreadId"] = safe_get(ced, "ThreadId") or ""

    # AgentVersion: prefer audit_data → CED fallbacks
    base["AgentVersion"] = select_first_non_null([
        safe_get(audit_data, "AgentVersion"),
        safe_get(ced, "AgentVersion"),
        safe_get(ced, "Version"),
    ]) or ""

    # ApplicationName: prefer audit_data → CED fallbacks
    base["ApplicationName"] = select_first_non_null([
        safe_get(audit_data, "ApplicationName"),
        safe_get(ced, "HostAppName"),
        safe_get(ced, "ClientAppName"),
    ]) or ""

    # Model fields from CED with fallbacks
    base["ModelId"] = select_first_non_null([
        safe_get(ced, "ModelId"), safe_get(ced, "ModelID"), safe_get(audit_data, "ModelId"),
    ]) or ""
    base["ModelProvider"] = select_first_non_null([
        safe_get(ced, "ModelProvider"), safe_get(ced, "Provider"), safe_get(ced, "ModelVendor"),
    ]) or ""
    base["ModelFamily"] = select_first_non_null([
        safe_get(ced, "ModelFamily"), safe_get(ced, "ModelType"),
    ]) or ""

    # Token usage from CED
    usage_node = select_first_non_null([
        safe_get(ced, "Usage"), safe_get(ced, "TokenUsage"),
        safe_get(ced, "Tokens"), safe_get(audit_data, "Usage"),
    ])
    tokens_total: Any = None
    tokens_input: Any = None
    tokens_output: Any = None
    if usage_node and isinstance(usage_node, dict):
        tokens_total = to_num(select_first_non_null([
            safe_get(usage_node, "Total"), safe_get(usage_node, "TotalTokens"),
            safe_get(usage_node, "TokensTotal"),
        ]))
        tokens_input = to_num(select_first_non_null([
            safe_get(usage_node, "Input"), safe_get(usage_node, "Prompt"),
            safe_get(usage_node, "InputTokens"), safe_get(usage_node, "TokensInput"),
        ]))
        tokens_output = to_num(select_first_non_null([
            safe_get(usage_node, "Output"), safe_get(usage_node, "Completion"),
            safe_get(usage_node, "OutputTokens"), safe_get(usage_node, "TokensOutput"),
        ]))
    if not tokens_total and (tokens_input or tokens_output):
        try:
            tokens_total = (tokens_input or 0) + (tokens_output or 0)
        except Exception:
            pass
    base["TokensTotal"] = tokens_total if tokens_total is not None else ""
    base["TokensInput"] = tokens_input if tokens_input is not None else ""
    base["TokensOutput"] = tokens_output if tokens_output is not None else ""

    # Duration, outcome, conversation from CED
    duration_ms = to_num(select_first_non_null([
        safe_get(ced, "DurationMs"), safe_get(ced, "ElapsedMs"),
        safe_get(ced, "ProcessingTimeMs"), safe_get(ced, "LatencyMs"),
    ]))
    base["DurationMs"] = duration_ms if duration_ms is not None else ""

    outcome_status: Any = select_first_non_null([
        safe_get(ced, "OutcomeStatus"), safe_get(ced, "Outcome"),
        safe_get(ced, "Result"), safe_get(ced, "Status"),
    ])
    if isinstance(outcome_status, bool):
        outcome_status = "Success" if outcome_status else "Failure"
    base["OutcomeStatus"] = outcome_status or ""

    base["ConversationId"] = select_first_non_null([
        safe_get(ced, "ConversationId"), safe_get(ced, "ConversationID"),
        safe_get(ced, "SessionId"),
    ]) or ""

    turn_number = to_num(select_first_non_null([
        safe_get(ced, "TurnNumber"), safe_get(ced, "TurnIndex"),
        safe_get(ced, "MessageIndex"),
    ]))
    base["TurnNumber"] = turn_number if turn_number is not None else ""

    retry_count = to_num(select_first_non_null([
        safe_get(ced, "RetryCount"), safe_get(ced, "Retries"),
    ]))
    base["RetryCount"] = retry_count if retry_count is not None else ""

    base["ClientVersion"] = select_first_non_null([
        safe_get(ced, "ClientVersion"), safe_get(ced, "Version"), safe_get(ced, "Build"),
    ]) or ""
    base["ClientPlatform"] = select_first_non_null([
        safe_get(ced, "ClientPlatform"), safe_get(ced, "Platform"), safe_get(ced, "OS"),
    ]) or ""

    # MessageIds: semicolon-joined (matches M code's Text.Combine)
    base["MessageIds"] = ";".join(str(m) for m in message_ids) if message_ids else ""

    # ── Build rows with indexed array access ─────────────────────────────
    rows: list[dict] = []
    for i in range(row_count):
        row = dict(base)  # shallow copy of all 153 columns

        # Indexed array access — Contexts
        if i < len(contexts) and contexts[i]:
            row["Context_Id"] = safe_get(contexts[i], "Id") or ""
            row["Context_Type"] = safe_get(contexts[i], "Type") or ""
        else:
            row["Context_Id"] = ""
            row["Context_Type"] = ""

        # Messages
        if i < len(messages):
            msg = messages[i]
            if isinstance(msg, dict):
                row["Message_Id"] = safe_get(msg, "Id") or ""
                row["Message_isPrompt"] = bool_tf(safe_get(msg, "isPrompt"))
            else:
                row["Message_Id"] = str(msg) if msg is not None else ""
                row["Message_isPrompt"] = ""
        else:
            row["Message_Id"] = ""
            row["Message_isPrompt"] = ""

        # AccessedResources
        if i < len(resources) and resources[i]:
            res = resources[i]
            row["AccessedResource_Action"] = safe_get(res, "Action") or ""
            row["AccessedResource_PolicyDetails"] = to_json_if_object(safe_get(res, "PolicyDetails"))
            row["AccessedResource_SiteUrl"] = deid_resource(safe_get(res, "SiteUrl") or "")
            row["AccessedResource_Name"] = deid_file(safe_get(res, "Name") or "")
            row["AccessedResource_SensitivityLabel"] = safe_get(res, "SensitivityLabel") or ""
            row["AccessedResource_ResourceType"] = safe_get(res, "ResourceType") or ""
        else:
            row["AccessedResource_Action"] = ""
            row["AccessedResource_PolicyDetails"] = ""
            row["AccessedResource_SiteUrl"] = ""
            row["AccessedResource_Name"] = ""
            row["AccessedResource_SensitivityLabel"] = ""
            row["AccessedResource_ResourceType"] = ""

        # AISystemPlugin
        if i < len(plugins_raw) and plugins_raw[i]:
            row["AISystemPlugin_Id"] = safe_get(plugins_raw[i], "Id") or ""
            row["AISystemPlugin_Name"] = safe_get(plugins_raw[i], "Name") or ""
        else:
            row["AISystemPlugin_Id"] = ""
            row["AISystemPlugin_Name"] = ""

        # ModelTransparencyDetails
        if i < len(model_det_raw) and model_det_raw[i]:
            row["ModelTransparencyDetails_ModelName"] = safe_get(model_det_raw[i], "ModelName") or ""
        else:
            row["ModelTransparencyDetails_ModelName"] = ""

        # SensitivityLabel (from CED SensitivityLabels array)
        if i < len(sensitivity_labels):
            row["SensitivityLabel"] = str(sensitivity_labels[i]) if sensitivity_labels[i] is not None else ""

        # Context_Item — full mode: one item per row across all contexts
        if activity_type == "CopilotInteraction":
            found_item = None
            for ctx in contexts:
                if ctx:
                    items = get_array_fast(ctx, "Items")
                    if items and i < len(items):
                        found_item = items[i]
                        break
            row["Context_Item"] = to_json_if_object(found_item) if found_item else ""
        else:
            row["Context_Item"] = ""

        rows.append(row)

    return rows


# ═════════════════════════════════════════════════════════════════════════════
# ROUTER: Dispatch to Path A or Path B
# ═════════════════════════════════════════════════════════════════════════════

def explode_record(
    record: dict,
    prompt_filter: str | None = None,
) -> list[dict]:
    """
    Parse AuditData and route to appropriate explosion path.
    Returns list of flattened row dicts, or empty list on error.
    """
    audit_data_raw = record.get("AuditData", "")
    if not audit_data_raw or not isinstance(audit_data_raw, str) or not audit_data_raw.strip():
        return []

    try:
        audit_data = json_loads(audit_data_raw)
    except Exception:
        return []

    if not isinstance(audit_data, dict):
        return []

    ced = safe_get(audit_data, "CopilotEventData")
    if ced and isinstance(ced, dict):
        return explode_copilot_record(record, audit_data, ced, prompt_filter=prompt_filter)
    else:
        return explode_m365_record(record, audit_data)


# ═════════════════════════════════════════════════════════════════════════════
# HEADER — Fixed schema, no dynamic discovery needed
# ═════════════════════════════════════════════════════════════════════════════
# Output columns are exactly M365_UNIFIED_HEADER (153 columns in M code order).
# No schema discovery pass is needed because both Path A and Path B produce
# row dicts that contain exactly these keys.


# ═════════════════════════════════════════════════════════════════════════════
# CHUNK PROCESSOR (unit of parallel work)
# ═════════════════════════════════════════════════════════════════════════════

def _process_chunk(args: tuple) -> tuple[list[dict], int, int]:
    """
    Process a chunk of CSV rows → exploded row dicts.
    Returns (exploded_rows, input_count, error_count).
    """
    chunk, prompt_filter = args
    results: list[dict] = []
    errors = 0

    for record in chunk:
        try:
            rows = explode_record(record, prompt_filter=prompt_filter)
            results.extend(rows)
        except Exception:
            errors += 1

    return results, len(chunk), errors


# ═════════════════════════════════════════════════════════════════════════════
# MAIN EXPLOSION ORCHESTRATOR
# ═════════════════════════════════════════════════════════════════════════════

def run_explosion(
    input_csv: str,
    output_csv: str,
    prompt_filter: str | None = None,
    workers: int = 0,
    chunk_size: int = STREAMING_CHUNK_SIZE,
    quiet: bool = False,
) -> dict[str, Any]:
    """
    Main entry point: reads input CSV, explodes all records, writes output CSV.
    Uses multiprocessing for large files, single-process for small ones.

    Returns a stats dict with counts and timing.
    """
    if not os.path.isfile(input_csv):
        print(f"ERROR: Input file not found: {input_csv}", file=sys.stderr)
        sys.exit(1)

    if workers <= 0:
        workers = min(os.cpu_count() or 1, 8)

    t_start = time.perf_counter()
    stats = {
        "input_records": 0,
        "output_rows": 0,
        "errors": 0,
        "chunks_processed": 0,
    }

    if not quiet:
        print(f"Purview M365 Usage Bundle Explosion Processor v{SCRIPT_VERSION}")
        print(f"  JSON engine:    {_JSON_ENGINE}")
        print(f"  Input:          {input_csv}")
        print(f"  Output:         {output_csv}")
        print(f"  Prompt filter:  {prompt_filter or 'None'}")
        print(f"  Workers:        {workers}")
        print(f"  Chunk size:     {chunk_size}")
        print()

    # ── Phase 1: Fixed schema ─────────────────────────────────────────────
    final_header = list(M365_UNIFIED_HEADER)  # 153 columns in M code order
    if not quiet:
        print(f"Phase 1: Using fixed {len(final_header)}-column M code schema")

    # ── Phase 2: Process chunks ──────────────────────────────────────────
    if not quiet:
        print("Phase 2: Processing records...")

    # Accumulate all exploded rows (we need dynamic columns before writing header)
    all_rows: list[dict] = []

    # Read CSV in chunks
    chunks: list[list[dict]] = []
    current_chunk: list[dict] = []

    with open(input_csv, "r", encoding="utf-8-sig", newline="") as f:
        reader = csv.DictReader(f)
        for row in reader:
            current_chunk.append(row)
            if len(current_chunk) >= chunk_size:
                chunks.append(current_chunk)
                current_chunk = []
        if current_chunk:
            chunks.append(current_chunk)

    total_input = sum(len(c) for c in chunks)
    stats["input_records"] = total_input

    if not quiet:
        print(f"  Loaded {total_input:,} input records in {len(chunks)} chunk(s)")

    # Determine whether to use multiprocessing
    use_parallel = workers > 1 and len(chunks) > 1

    if use_parallel:
        chunk_args = [(chunk, prompt_filter) for chunk in chunks]
        with ProcessPoolExecutor(max_workers=workers, initializer=_deid_init_worker, initargs=(_DEIDENTIFY,)) as executor:
            futures = {executor.submit(_process_chunk, arg): idx for idx, arg in enumerate(chunk_args)}
            for future in as_completed(futures):
                try:
                    exploded, _in_count, err_count = future.result()
                    all_rows.extend(exploded)
                    stats["errors"] += err_count
                    stats["chunks_processed"] += 1
                    if not quiet and stats["chunks_processed"] % 5 == 0:
                        print(f"    Chunks completed: {stats['chunks_processed']}/{len(chunks)}")
                except Exception as exc:
                    stats["errors"] += 1
                    if not quiet:
                        print(f"    Chunk failed: {exc}", file=sys.stderr)
    else:
        for chunk in chunks:
            exploded, _in_count, err_count = _process_chunk((chunk, prompt_filter))
            all_rows.extend(exploded)
            stats["errors"] += err_count
            stats["chunks_processed"] += 1
            if not quiet and stats["chunks_processed"] % 5 == 0:
                print(f"    Chunks completed: {stats['chunks_processed']}/{len(chunks)}")

    stats["output_rows"] = len(all_rows)

    # ── Phase 3: Write output CSV with fixed header ──────────────────────
    if not quiet:
        print("Phase 3: Writing output CSV...")

    # Write output using fixed M code-ordered header
    os.makedirs(os.path.dirname(os.path.abspath(output_csv)), exist_ok=True)
    with open(output_csv, "w", encoding="utf-8", newline="") as f:
        writer = csv.DictWriter(f, fieldnames=final_header, extrasaction="ignore", lineterminator="\n")
        writer.writeheader()
        for row in all_rows:
            writer.writerow(row)

    t_elapsed = time.perf_counter() - t_start

    # ── Summary ──────────────────────────────────────────────────────────
    if not quiet:
        print()
        print("=== EXPLOSION SUMMARY ===")
        print(f"  Input records:  {stats['input_records']:,}")
        print(f"  Output rows:    {stats['output_rows']:,}")
        if stats["output_rows"] > stats["input_records"] and stats["input_records"] > 0:
            ratio = round(stats["output_rows"] / stats["input_records"], 2)
            extra = stats["output_rows"] - stats["input_records"]
            print(f"  Expansion:      {ratio}x ({extra:,} additional rows from array explosion)")
        elif stats["output_rows"] == stats["input_records"]:
            print("  Expansion:      1:1 (no arrays exploded)")
        elif stats["input_records"] > 0:
            filtered = stats["input_records"] - stats["output_rows"]
            print(f"  Reduction:      {filtered:,} records filtered out")
        if stats["errors"] > 0:
            print(f"  Errors:         {stats['errors']:,} record(s) failed to process")
        print(f"  Columns:        {len(final_header):,}")
        print(f"  Elapsed:        {t_elapsed:.2f}s")
        if stats["output_rows"] > 0 and t_elapsed > 0:
            print(f"  Throughput:     {stats['output_rows'] / t_elapsed:,.0f} rows/sec")
        print(f"  Output file:    {output_csv}")
        print()

    return stats


# ═════════════════════════════════════════════════════════════════════════════
# ROLLUP ORCHESTRATOR (streaming — no exploded rows in memory)
# ═════════════════════════════════════════════════════════════════════════════

def run_rollup(
    input_csv: str | list[str],
    output_csv: str,
    prompt_filter: str | None = None,
    quiet: bool = False,
    session_stats_csv: str | None = None,
) -> dict[str, Any]:
    """
    Streaming rollup: read one or more CSVs row-by-row → parse AuditData → extract
    9 group keys + CreationTime + agent flag → accumulate into
    dict[GroupKey, RollupAccum] → write 13-column CSV.

    `input_csv` accepts a single path (PAX/PowerShell single-file export) or a
    list of paths (manual 4-pull export from Purview Audit). Output schema is
    identical either way — the same PBIT template ingests both modes.

    When `session_stats_csv` is provided, a parallel pass over CopilotEventData
    accumulates per-(UserId, CreationDate, AppHost) DISTINCTCOUNT(ThreadId) +
    prompt/response counts and writes an 8-column SessionStats CSV. This matches
    the AI in One `Sessions` measure unit (one thread = one session).

    No exploded row dicts are ever stored in memory.
    """
    if isinstance(input_csv, (str, Path)):
        input_paths: list[str] = [str(input_csv)]
    else:
        input_paths = [str(p) for p in input_csv]

    for p in input_paths:
        if not os.path.isfile(p):
            print(f"ERROR: Input file not found: {p}", file=sys.stderr)
            sys.exit(1)

    t_start = time.perf_counter()
    rollup: dict[GroupKey, RollupAccum] = {}
    sessions: dict[SessionKey, SessionAccum] = {} if session_stats_csv else {}
    track_sessions: bool = bool(session_stats_csv)
    stats: dict[str, Any] = {
        "input_records": 0,
        "virtual_exploded_event_count": 0,
        "output_rows": 0,
        "parse_errors": 0,
        "session_rows": 0,
        "session_threads": 0,
        "session_prompts": 0,
    }

    if not quiet:
        print(f"Purview M365 Usage Bundle Explosion Processor v{SCRIPT_VERSION} [ROLLUP MODE]")
        print(f"  JSON engine:    {_JSON_ENGINE}")
        if len(input_paths) == 1:
            print(f"  Input:          {input_paths[0]}")
        else:
            print(f"  Inputs ({len(input_paths)}):")
            for p in input_paths:
                print(f"                  {p}")
        print(f"  Output:         {output_csv}")
        if session_stats_csv:
            print(f"  Session stats:  {session_stats_csv}")
        print(f"  Prompt filter:  {prompt_filter or 'None'}")
        print()
        print("Processing records (streaming rollup)...")

    # ── Streaming read + accumulate (across one OR many input files) ─────
    for input_csv_path in input_paths:
        with open(input_csv_path, "r", encoding="utf-8-sig", newline="") as f:
            reader = csv.DictReader(f)
            for record in reader:
                stats["input_records"] += 1

                # Progress indicator
                if not quiet and stats["input_records"] % 500_000 == 0:
                    print(f"  {stats['input_records']:>12,} records processed, "
                          f"{len(rollup):,} groups...")

                # Parse AuditData JSON
                audit_data_raw = record.get("AuditData", "")
                if not audit_data_raw or not isinstance(audit_data_raw, str) or not audit_data_raw.strip():
                    stats["parse_errors"] += 1
                    continue
                try:
                    audit_data = json_loads(audit_data_raw)
                except Exception:
                    stats["parse_errors"] += 1
                    continue
                if not isinstance(audit_data, dict):
                    stats["parse_errors"] += 1
                    continue

                ced = safe_get(audit_data, "CopilotEventData")
                if ced and not isinstance(ced, dict):
                    ced = None

                # Extract rollup keys (lightweight — no row dict built)
                result = _extract_rollup_keys(record, audit_data, ced, prompt_filter)
                if result is None:
                    continue  # filtered out by prompt_filter or non-human UPN

                (group_key, event_count, items_accessed_count,
                 creation_time, original_uid, is_agent) = result
                stats["virtual_exploded_event_count"] += event_count

                # Accumulate into rollup dict
                if group_key in rollup:
                    acc = rollup[group_key]
                    acc.event_count += event_count
                    acc.items_accessed_count += items_accessed_count
                    if is_agent:
                        acc.is_agent_interaction = True
                    if creation_time:
                        if not acc.min_creation_time or creation_time < acc.min_creation_time:
                            acc.min_creation_time = creation_time
                        if not acc.max_creation_time or creation_time > acc.max_creation_time:
                            acc.max_creation_time = creation_time
                else:
                    rollup[group_key] = RollupAccum(
                        event_count=event_count,
                        items_accessed=items_accessed_count,
                        min_ct=creation_time,
                        max_ct=creation_time,
                        original_uid=original_uid,
                        is_agent=is_agent,
                    )

                # ── SessionStats accumulation (v2.6.0 — AI in One parity) ───
                # Only records with a CopilotEventData payload contribute. Threads
                # without at least one user prompt are excluded (matches AI in One
                # `Message_isPrompt = TRUE` filter).
                if track_sessions and ced:
                    msgs = get_array_fast(ced, "Messages")
                    prompts_here = 0
                    responses_here = 0
                    for m in msgs:
                        ip = safe_get(m, "isPrompt")
                        if ip is True:
                            prompts_here += 1
                        elif ip is False:
                            responses_here += 1
                    thread_id = _norm_key_str(safe_get(ced, "ThreadId"))
                    # group_key layout: (uid_lower, creation_date, op, wl, sfe,
                    # app_host, agent_id, agent_name, context_type)
                    skey: SessionKey = (group_key[0], group_key[1], group_key[5])
                    sacc = sessions.get(skey)
                    if sacc is None:
                        sacc = SessionAccum(original_uid=original_uid)
                        sessions[skey] = sacc
                    sacc.prompt_count += prompts_here
                    sacc.response_count += responses_here
                    if is_agent:
                        sacc.agent_prompt_count += prompts_here  # v2.6.1: exact chat/agent split
                    if thread_id and prompts_here > 0:
                        sacc.thread_ids.add(thread_id)
                        if is_agent:
                            sacc.agent_thread_ids.add(thread_id)
                        stats["session_prompts"] += prompts_here

    # ── Write rollup output CSV ──────────────────────────────────────────
    stats["output_rows"] = len(rollup)

    if not quiet:
        print(f"  {stats['input_records']:>12,} records processed (done)")
        print(f"  Writing {stats['output_rows']:,} rollup rows...")

    os.makedirs(os.path.dirname(os.path.abspath(output_csv)), exist_ok=True)
    with open(output_csv, "w", encoding="utf-8", newline="") as f:
        writer = csv.writer(f, lineterminator="\n")
        writer.writerow(ROLLUP_HEADER)
        for (uid_lower, cdate, op, wl, sfe, ah, agent_id, agent_name, ctx_type), acc in rollup.items():
            writer.writerow([
                deid_upn(acc.original_user_id),  # output original casing, NOT lowered key
                cdate,
                op,
                wl,
                sfe,
                ah,
                acc.event_count,
                acc.items_accessed_count,
                acc.min_creation_time,   # CreationTime = MIN
                acc.max_creation_time,   # MaxCreationTime = MAX
                agent_id,
                agent_name,
                ctx_type,
                "TRUE" if acc.is_agent_interaction else "FALSE",
            ])

    # ── SessionStats CSV (v2.6.0 — AI in One parity) ─────────────────────
    if track_sessions:
        os.makedirs(os.path.dirname(os.path.abspath(session_stats_csv)), exist_ok=True)
        with open(session_stats_csv, "w", encoding="utf-8", newline="") as f:
            writer = csv.writer(f, lineterminator="\n")
            writer.writerow(SESSIONSTATS_HEADER)
            for (uid_lower, cdate, ah), sacc in sessions.items():
                session_count = len(sacc.thread_ids)
                if session_count == 0 and sacc.prompt_count == 0:
                    continue  # no signal — skip
                writer.writerow([
                    deid_upn(sacc.original_user_id),
                    cdate,
                    ah,
                    session_count,
                    sacc.prompt_count,
                    sacc.agent_prompt_count,  # v2.6.1
                    sacc.response_count,
                    len(sacc.agent_thread_ids),
                ])
                stats["session_rows"] += 1
                stats["session_threads"] += session_count

    t_elapsed = time.perf_counter() - t_start

    # ── Summary report ───────────────────────────────────────────────────
    if not quiet:
        pct = 0.0
        if stats["virtual_exploded_event_count"] > 0:
            pct = (1 - stats["output_rows"] / stats["virtual_exploded_event_count"]) * 100
        print()
        print("=== ROLLUP SUMMARY ===")
        print(f"  Input records:              {stats['input_records']:>14,}")
        print(f"  Virtual exploded events:    {stats['virtual_exploded_event_count']:>14,}")
        print(f"  Rollup output rows:         {stats['output_rows']:>14,}")
        print(f"  Row reduction:              {pct:>13.1f}%"
              f"  ({stats['virtual_exploded_event_count']:,} -> {stats['output_rows']:,})")
        if stats["parse_errors"] > 0:
            print(f"  Parse errors:               {stats['parse_errors']:>14,}")
        print(f"  Columns:                    {len(ROLLUP_HEADER):>14}")
        print(f"  Elapsed:                    {t_elapsed:>13.2f}s")
        if stats["input_records"] > 0 and t_elapsed > 0:
            print(f"  Throughput:                 {stats['input_records'] / t_elapsed:>12,.0f} input records/sec")
        print(f"  Output file:                {output_csv}")
        if track_sessions:
            print()
            print("=== SESSIONSTATS SUMMARY (AI in One parity) ===")
            print(f"  SessionStats rows:          {stats['session_rows']:>14,}")
            print(f"  Distinct Copilot sessions:  {stats['session_threads']:>14,}")
            print(f"  User prompts counted:       {stats['session_prompts']:>14,}")
            print(f"  Output file:                {session_stats_csv}")
        print()

    return stats


# ═════════════════════════════════════════════════════════════════════════════
# RECONCILIATION (sample-based validation of rollup correctness)
# ═════════════════════════════════════════════════════════════════════════════

def run_reconcile(
    input_csv: str,
    prompt_filter: str | None = None,
    sample_size: int = RECONCILE_SAMPLE_SIZE,
    quiet: bool = False,
) -> bool:
    """
    Sample-based reconciliation: read a sample of records, run both rollup-key
    extraction and full event-level explosion, compare total and filtered counts.

    Returns True if all checks pass, False otherwise.
    """
    if not os.path.isfile(input_csv):
        print(f"ERROR: Input file not found: {input_csv}", file=sys.stderr)
        return False

    if not quiet:
        print(f"\n=== RECONCILIATION CHECK (sample {sample_size:,} records) ===\n")

    # ── Read sample ──────────────────────────────────────────────────────
    all_records: list[dict] = []
    with open(input_csv, "r", encoding="utf-8-sig", newline="") as f:
        reader = csv.DictReader(f)
        for record in reader:
            all_records.append(record)

    if len(all_records) > sample_size:
        sample = random.sample(all_records, sample_size)
    else:
        sample = all_records
        sample_size = len(sample)

    if not quiet:
        print(f"  Total input records: {len(all_records):,}")
        print(f"  Sample size:         {sample_size:,}")

    # ── Run event-level explosion on sample ──────────────────────────────
    event_rows: list[dict] = []
    event_errors = 0
    for record in sample:
        try:
            rows = explode_record(record, prompt_filter=prompt_filter)
            # Apply same non-human UPN filter as rollup path so totals reconcile
            rows = [r for r in rows if _is_human_upn(r.get("UserId", ""))]
            event_rows.extend(rows)
        except Exception:
            event_errors += 1

    # ── Run rollup-key extraction on same sample ─────────────────────────
    rollup_sample: dict[GroupKey, RollupAccum] = {}
    rollup_errors = 0
    for record in sample:
        audit_data_raw = record.get("AuditData", "")
        if not audit_data_raw or not isinstance(audit_data_raw, str) or not audit_data_raw.strip():
            rollup_errors += 1
            continue
        try:
            audit_data = json_loads(audit_data_raw)
        except Exception:
            rollup_errors += 1
            continue
        if not isinstance(audit_data, dict):
            rollup_errors += 1
            continue

        ced = safe_get(audit_data, "CopilotEventData")
        if ced and not isinstance(ced, dict):
            ced = None

        result = _extract_rollup_keys(record, audit_data, ced, prompt_filter)
        if result is None:
            continue
        (group_key, event_count, items_accessed_count,
         creation_time, original_uid, is_agent) = result

        if group_key in rollup_sample:
            acc = rollup_sample[group_key]
            acc.event_count += event_count
            acc.items_accessed_count += items_accessed_count
            if is_agent:
                acc.is_agent_interaction = True
            if creation_time:
                if not acc.min_creation_time or creation_time < acc.min_creation_time:
                    acc.min_creation_time = creation_time
                if not acc.max_creation_time or creation_time > acc.max_creation_time:
                    acc.max_creation_time = creation_time
        else:
            rollup_sample[group_key] = RollupAccum(
                event_count=event_count,
                items_accessed=items_accessed_count,
                min_ct=creation_time,
                max_ct=creation_time,
                original_uid=original_uid,
                is_agent=is_agent,
            )

    # ── Compare totals ───────────────────────────────────────────────────
    rollup_total = sum(acc.event_count for acc in rollup_sample.values())
    event_total = len(event_rows)
    all_pass = True

    def _check(label: str, rollup_val: Any, event_val: Any) -> bool:
        nonlocal all_pass
        match = rollup_val == event_val
        symbol = "PASS" if match else "FAIL"
        if not quiet:
            print(f"  {label}")
            print(f"    Rollup: {rollup_val}   Event-level: {event_val}   [{symbol}]")
        if not match:
            all_pass = False
        return match

    _check("Total event count (SUM(EventCount) vs COUNTROWS)",
           rollup_total, event_total)

    # ── Filter-specific checks ───────────────────────────────────────────
    # Helper: count event-level rows matching a filter
    def _ev_count(**filters: str | set) -> int:
        count = 0
        for row in event_rows:
            match = True
            for col, val in filters.items():
                row_val = row.get(col, "")
                if isinstance(val, set):
                    if row_val.lower() not in val:
                        match = False
                        break
                else:
                    if row_val != val:
                        match = False
                        break
            if match:
                count += 1
        return count

    # Helper: sum EventCount from rollup for matching groups
    def _ru_count(**filters: str | set) -> int:
        total = 0
        for (uid_l, cdate, op, wl, sfe, ah, agent_id, agent_name, ctx_type), acc in rollup_sample.items():
            match = True
            key_map = {"Operation": op, "Workload": wl,
                       "SourceFileExtension": sfe, "AppHost": ah,
                       "AgentId": agent_id, "AgentName": agent_name,
                       "ContextType": ctx_type}
            for col, val in filters.items():
                key_val = key_map.get(col, "")
                if isinstance(val, set):
                    if key_val.lower() not in val:
                        match = False
                        break
                else:
                    if key_val != val:
                        match = False
                        break
            if match:
                total += acc.event_count
        return total

    # Check 1: Teams MessageSent
    _check("Teams MessageSent (Workload=MicrosoftTeams, Operation=MessageSent)",
           _ru_count(Workload="MicrosoftTeams", Operation="MessageSent"),
           _ev_count(Workload="MicrosoftTeams", Operation="MessageSent"))

    # Check 2: Exchange Send
    _check("Exchange Send (Workload=Exchange, Operation=Send)",
           _ru_count(Workload="Exchange", Operation="Send"),
           _ev_count(Workload="Exchange", Operation="Send"))

    # Check 3: CopilotInteraction + AppHost=Teams
    _check("Copilot Teams (Operation=CopilotInteraction, AppHost=Teams)",
           _ru_count(Operation="CopilotInteraction", AppHost="Teams"),
           _ev_count(Operation="CopilotInteraction", AppHost="Teams"))

    # Check 4: Excel FileAccessed (was FileViewed in pre-v2.3 — renamed via OP_RENAME)
    _check("Excel FileAccessed (Operation=FileAccessed, SourceFileExtension in xlsx/xls/xlsm/csv)",
           _ru_count(Operation="FileAccessed", SourceFileExtension={"xlsx", "xls", "xlsm", "csv"}),
           _ev_count(Operation="FileAccessed", SourceFileExtension={"xlsx", "xls", "xlsm", "csv"}))

    # ── Temporal checks ──────────────────────────────────────────────────
    rollup_min_ct = min((acc.min_creation_time for acc in rollup_sample.values() if acc.min_creation_time), default="")
    rollup_max_ct = max((acc.max_creation_time for acc in rollup_sample.values() if acc.max_creation_time), default="")
    event_times = [r.get("CreationTime", "") for r in event_rows if r.get("CreationTime")]
    event_min_ct = min(event_times) if event_times else ""
    event_max_ct = max(event_times) if event_times else ""

    _check("MIN(CreationTime)", rollup_min_ct, event_min_ct)
    _check("MAX(CreationTime)", rollup_max_ct, event_max_ct)

    if not quiet:
        print()
        reduction_pct = 0.0
        if event_total > 0:
            reduction_pct = (1 - len(rollup_sample) / event_total) * 100
        print(f"  Event-level rows: {event_total:,}  ->  Rollup groups: {len(rollup_sample):,}"
              f"  ({reduction_pct:.1f}% reduction)")
        print(f"  Overall: {'ALL CHECKS PASSED' if all_pass else 'SOME CHECKS FAILED'}")
        print()

    return all_pass


# ═════════════════════════════════════════════════════════════════════════════
# USERSTATS & SESSION COHORT WRITER
# ═════════════════════════════════════════════════════════════════════════════

def write_userstats_files(
    aggregated_csv_path: str | Path,
    userstats_csv_path: str | Path,
    session_csv_path: str | Path,
    quiet: bool,
    session_stats_csv_path: str | Path | None = None,
) -> tuple[int, int]:
    """
    Read the just-written aggregated rollup CSV and produce two additional files:
      *_UserStats.csv     — one row per unique UserId with pre-computed metrics
      *_SessionCohort.csv — one row per (UserId, AppColumn) with session cohort label

    When `session_stats_csv_path` is provided (v2.6.0+), the CECopilotPercentile_*
    columns are computed from per-user PromptCount (human interactions) instead of
    raw audit-event counts. This matches the AI in One semantics and prevents
    service-principal / plugin-chain inflation from skewing the CE Quadrant.

    Returns (user_count, session_cohort_row_count).
    """
    agg_path = Path(aggregated_csv_path)
    if not agg_path.is_file():
        if not quiet:
            print(f"[UserStats] WARNING: Aggregated CSV not found: {agg_path} — skipping.",
                  file=sys.stderr)
        return 0, 0

    userstats_path = Path(userstats_csv_path)
    session_path = Path(session_csv_path)

    t_start = time.perf_counter()

    # ── Per-user accumulators ────────────────────────────────────────────
    uid_original: dict[str, str] = {}          # uid_lower → first-seen casing
    cop_ec: dict[str, int] = defaultdict(int)
    m365_ec: dict[str, int] = defaultdict(int)
    ex_cop_ec: dict[str, int] = defaultdict(int)
    ex_m365_ec: dict[str, int] = defaultdict(int)

    t_days: dict[str, set[str]] = defaultdict(set)
    o_days: dict[str, set[str]] = defaultdict(set)
    w_days: dict[str, set[str]] = defaultdict(set)
    x_days: dict[str, set[str]] = defaultdict(set)
    p_days: dict[str, set[str]] = defaultdict(set)

    t_ec: dict[str, int] = defaultdict(int)
    o_ec: dict[str, int] = defaultdict(int)
    off_ec: dict[str, int] = defaultdict(int)

    # ── v2.5.0: DAX-aligned per-user raw activity counts, computed per window.
    # Three windows (L30, L60, Full) feed both the LP <App> Weighted measures and the
    # CE percentile ranks. Each is a dict keyed by window code → {uid: count}.
    def _wbuckets() -> dict[str, dict[str, int]]:
        return {w: defaultdict(int) for w in RANK_WINDOWS}
    teams_raw = _wbuckets()
    outlook_raw = _wbuckets()
    word_raw = _wbuckets()
    excel_raw = _wbuckets()
    ppt_raw = _wbuckets()
    copilot_chat_raw = _wbuckets()        # Operation = "CopilotInteraction" (LP)
    ce_copilot_raw = _wbuckets()          # broad: Workload="Copilot" OR Op contains "CopilotInteraction" (CE)

    session_ops: dict[tuple[str, str], set[str]] = defaultdict(set)

    # Track every distinct CreationDate seen in the rollup so we can
    # derive the data-window span (max - min + 1 calendar days) and
    # normalize the engagement segmentation to active-days-per-week.
    all_dates: set[str] = set()

    # ── v2.5.0: Pass 1 — determine the trailing-window cutoffs ──────────
    # Scan CreationDate only to find the most-recent date in the rollup. Cutoffs
    # are inclusive lower bounds; a row qualifies for window W iff date_key >= cutoff[W].
    # The "Full" window has no cutoff and always qualifies.
    _d_max_str = ""
    with open(agg_path, "r", encoding="utf-8-sig", newline="") as _f:
        _r = csv.DictReader(_f)
        for _row in _r:
            _dk = (_row.get("CreationDate", "") or "")[:10]
            if _dk and _dk > _d_max_str:
                _d_max_str = _dk
    if _d_max_str:
        try:
            _d_max = date.fromisoformat(_d_max_str)
            cutoff_l30 = (_d_max - timedelta(days=29)).isoformat()
            cutoff_l60 = (_d_max - timedelta(days=59)).isoformat()
        except ValueError:
            # Bad date — fall back to "everything qualifies"
            cutoff_l30 = ""
            cutoff_l60 = ""
    else:
        # No data — sentinel that nothing qualifies for L30/L60 (Full still does)
        cutoff_l30 = "9999-12-31"
        cutoff_l60 = "9999-12-31"
    if not quiet:
        print(f"[UserStats] Window cutoffs: L30 >= {cutoff_l30 or '(all)'}, "
              f"L60 >= {cutoff_l60 or '(all)'}, max date = {_d_max_str or '(none)'}")

    # ── Stream through aggregated CSV ────────────────────────────────────
    row_count = 0
    with open(agg_path, "r", encoding="utf-8-sig", newline="") as f:
        reader = csv.DictReader(f)
        for row in reader:
            row_count += 1

            user_id = row.get("UserId", "")
            uid_lower = user_id.lower()
            if uid_lower not in uid_original:
                uid_original[uid_lower] = user_id

            date_key = row.get("CreationDate", "")[:10]   # YYYY-MM-DD
            op = row.get("Operation", "")
            wl = row.get("Workload", "")
            ext = (row.get("SourceFileExtension", "") or "").lower()
            app_host = (row.get("AppHost", "") or "").lower()

            if date_key:
                all_dates.add(date_key)

            try:
                event_count = int(row.get("EventCount", "1") or "1")
            except (ValueError, TypeError):
                event_count = 1

            copilot = is_copilot(op, wl)
            excel_file = is_excel_file_op(ext, op)

            # Core event counts
            if copilot:
                cop_ec[uid_lower] += event_count
            else:
                m365_ec[uid_lower] += event_count

            # ExCopEC: Copilot interactions in Excel (via AppHost); ExM365EC: Excel file ops by non-Copilot
            if copilot and app_host == "excel":
                ex_cop_ec[uid_lower] += 1        # row count, not EventCount
            if excel_file and not copilot:
                ex_m365_ec[uid_lower] += 1       # row count, not EventCount

            # Active days (distinct CreationDate values)
            if wl == "MicrosoftTeams" and op in TEAMS_OPS:
                t_days[uid_lower].add(date_key)
            if wl == "Exchange" and op in OUTLOOK_OPS:
                o_days[uid_lower].add(date_key)
            if ext in WORD_EXTS and op in FILE_OPS:
                w_days[uid_lower].add(date_key)
            if ext in EXCEL_EXTS and op in FILE_OPS:
                x_days[uid_lower].add(date_key)
            if ext in PPT_EXTS and op in FILE_OPS:
                p_days[uid_lower].add(date_key)

            # Activity event counts
            if wl == "MicrosoftTeams" and op in TEAMS_OPS:
                t_ec[uid_lower] += event_count
            if wl == "Exchange" and op in OUTLOOK_OPS:
                o_ec[uid_lower] += event_count
            if ext in OFFICE_EXTS and op in FILE_OPS:
                off_ec[uid_lower] += event_count

            # ── v2.5.0: DAX-aligned raw counts, accumulated per window.
            # Helper closure: write to Full always; to L60/L30 only if the row's
            # date_key satisfies the trailing-window cutoff.
            def _bump(buckets: dict[str, dict[str, int]], n: int) -> None:
                buckets["Full"][uid_lower] += n
                if date_key >= cutoff_l60:
                    buckets["L60"][uid_lower] += n
                if date_key >= cutoff_l30:
                    buckets["L30"][uid_lower] += n

            if wl == "MicrosoftTeams" and op in DAX_TEAMS_OPS:
                _bump(teams_raw, event_count)
            if wl == "Exchange" and op in DAX_OUTLOOK_OPS:
                _bump(outlook_raw, event_count)
            if op in DAX_FILE_OPS:
                if ext in WORD_EXTS:
                    _bump(word_raw, event_count)
                elif ext in EXCEL_EXTS:
                    _bump(excel_raw, event_count)
                elif ext in PPT_EXTS:
                    _bump(ppt_raw, event_count)
            if op == "CopilotInteraction":
                _bump(copilot_chat_raw, event_count)
            # CE Copilot Percentile filter: Workload="Copilot" OR Operation contains "CopilotInteraction"
            if wl == "Copilot" or "CopilotInteraction" in op:
                _bump(ce_copilot_raw, event_count)

            # Session cohort: distinct active dates per (user, app)
            app = app_column(ext, op, wl)
            if app != "M365 All Apps":
                session_ops[(uid_lower, app)].add(date_key)

    if row_count == 0:
        if not quiet:
            print("[UserStats] Aggregated CSV has 0 rows — skipping.")
        return 0, 0

    # ── Data-window span ────────────────────────────────────────────────
    # Calendar-day span between the earliest and latest CreationDate in the
    # rollup, inclusive. Used to normalize per-app engagement segments to
    # active-days-per-week, so labels mean the same thing whether the pull
    # covers 8 days, 30 days, or 6 months.
    if all_dates:
        try:
            d_min = min(all_dates)
            d_max = max(all_dates)
            window_days = (
                date.fromisoformat(d_max) - date.fromisoformat(d_min)
            ).days + 1
        except ValueError:
            window_days = max(len(all_dates), 1)
    else:
        window_days = 1
    if not quiet:
        print(f"[UserStats] Data window: {window_days} calendar day(s) "
              f"({d_min if all_dates else '?'} -> {d_max if all_dates else '?'})")

    # ── Percentile thresholds ────────────────────────────────────────────
    all_uids = sorted(uid_original.keys())
    total_users = len(all_uids)

    cop_vals = [cop_ec.get(u, 0) for u in all_uids]
    m365_vals = [m365_ec.get(u, 0) for u in all_uids]
    ex_cop_vals = [ex_cop_ec.get(u, 0) for u in all_uids]
    ex_m365_vals = [ex_m365_ec.get(u, 0) for u in all_uids]

    cop_p90 = percentile_inc(cop_vals, 0.90)
    cop_p75 = percentile_inc(cop_vals, 0.75)
    cop_p50 = percentile_inc(cop_vals, 0.50)

    m365_p90 = percentile_inc(m365_vals, 0.90)
    m365_p75 = percentile_inc(m365_vals, 0.75)
    m365_p50 = percentile_inc(m365_vals, 0.50)

    exc_p90 = percentile_inc(ex_cop_vals, 0.90)
    exc_p75 = percentile_inc(ex_cop_vals, 0.75)
    exc_p50 = percentile_inc(ex_cop_vals, 0.50)

    exm_p90 = percentile_inc(ex_m365_vals, 0.90)
    exm_p75 = percentile_inc(ex_m365_vals, 0.75)
    exm_p50 = percentile_inc(ex_m365_vals, 0.50)

    # ── Ranks ────────────────────────────────────────────────────────────
    # Copilot rank: computed only among Copilot users so the range maps to [0, 1]
    # within that group. Non-Copilot users are hardcoded to 0.0 downstream.
    copilot_uids = [u for u in all_uids if cop_ec.get(u, 0) > 0]
    copilot_user_count = len(copilot_uids)
    cop_rank = compute_ranks({u: cop_ec.get(u, 0) for u in copilot_uids})
    m365_rank = compute_ranks({u: m365_ec.get(u, 0) for u in all_uids})

    # ── v2.5.0: CE percentile ranks per window (integer 0–100, match DAX exactly) ──
    # DAX formula: ROUND( COUNTROWS(users with score <= mine) / COUNTROWS(users with score > 0) * 100 , 0)
    # Users with score 0 / no activity → BLANK (we emit empty string).
    def _ce_rank_pct(scores: dict[str, int]) -> dict[str, str]:
        """Return DAX-exact CE percentile rank per user, as a string ('' for BLANK)."""
        positives = sorted(v for v in scores.values() if v > 0)
        total = len(positives)
        out: dict[str, str] = {}
        if total == 0:
            return {u: "" for u in scores}
        for u, v in scores.items():
            if v <= 0:
                out[u] = ""
            else:
                below = bisect.bisect_right(positives, v)
                out[u] = str(round(below / total * 100))
        return out

    # M365 All Apps raw is derived per window (sum of 5 app raws). LP has no M365-AllApps
    # measure, so we only compute the rank — not stored as a column.
    m365_all_apps_raw = {
        w: {
            u: teams_raw[w].get(u, 0) + outlook_raw[w].get(u, 0) + word_raw[w].get(u, 0)
               + excel_raw[w].get(u, 0) + ppt_raw[w].get(u, 0)
            for u in all_uids
        }
        for w in RANK_WINDOWS
    }
    ce_rank_teams   = {w: _ce_rank_pct({u: teams_raw[w].get(u, 0)   for u in all_uids}) for w in RANK_WINDOWS}
    ce_rank_outlook = {w: _ce_rank_pct({u: outlook_raw[w].get(u, 0) for u in all_uids}) for w in RANK_WINDOWS}
    ce_rank_word    = {w: _ce_rank_pct({u: word_raw[w].get(u, 0)    for u in all_uids}) for w in RANK_WINDOWS}
    ce_rank_excel   = {w: _ce_rank_pct({u: excel_raw[w].get(u, 0)   for u in all_uids}) for w in RANK_WINDOWS}
    ce_rank_ppt     = {w: _ce_rank_pct({u: ppt_raw[w].get(u, 0)     for u in all_uids}) for w in RANK_WINDOWS}
    ce_rank_all     = {w: _ce_rank_pct(m365_all_apps_raw[w])                              for w in RANK_WINDOWS}

    # ── v2.6.0: CE Copilot Percentile based on PROMPT COUNT (human interactions) ──
    # Read the SessionStats CSV (if produced by run_rollup) and tally PromptCount per
    # user per window. This is the AI in One semantics: one count per `isPrompt=TRUE`
    # message — resistant to AI-response fanout, plugin chains, retries, and most
    # service-principal noise. Falls back to audit-event tally if SessionStats is
    # missing (older script invocations).
    prompt_raw = _wbuckets()
    if session_stats_csv_path:
        _ss = Path(session_stats_csv_path)
        if _ss.is_file():
            with open(_ss, "r", encoding="utf-8-sig", newline="") as _f:
                _r = csv.DictReader(_f)
                for _row in _r:
                    _uid = (_row.get("UserId") or "").strip().lower()
                    if not _uid:
                        continue
                    _date_key = (_row.get("CreationDate") or "")[:10]
                    try:
                        _pc = int(_row.get("PromptCount") or 0)
                    except ValueError:
                        _pc = 0
                    if _pc <= 0:
                        continue
                    prompt_raw["Full"][_uid] += _pc
                    if cutoff_l60 and _date_key >= cutoff_l60:
                        prompt_raw["L60"][_uid] += _pc
                    if cutoff_l30 and _date_key >= cutoff_l30:
                        prompt_raw["L30"][_uid] += _pc
            if not quiet:
                _tot = sum(prompt_raw["Full"].values())
                print(f"[UserStats] CE Copilot Percentile source: PromptCount "
                      f"({_tot:,} prompts across {len(prompt_raw['Full']):,} users)")
        else:
            if not quiet:
                print(f"[UserStats] WARNING: SessionStats CSV not found: {_ss} — "
                      f"falling back to audit-event count for CE Copilot Percentile.",
                      file=sys.stderr)
            prompt_raw = ce_copilot_raw  # fallback to legacy event-based percentile
    else:
        prompt_raw = ce_copilot_raw  # legacy mode (script invoked without SessionStats)

    ce_copilot_pct  = {w: _ce_rank_pct({u: prompt_raw[w].get(u, 0) for u in all_uids}) for w in RANK_WINDOWS}

    # ── Write *_UserStats.csv ────────────────────────────────────────────
    with open(userstats_path, "w", encoding="utf-8", newline="") as f:
        writer = csv.writer(f, lineterminator="\n")
        writer.writerow(USERSTATS_HEADER)

        for uid in all_uids:
            c_ec = cop_ec.get(uid, 0)
            m_ec = m365_ec.get(uid, 0)
            exc_ec = ex_cop_ec.get(uid, 0)
            exm_ec = ex_m365_ec.get(uid, 0)

            is_cop_user = "Copilot User" if c_ec > 0 else "Non-Copilot User"
            cop_tier = tier_fn(c_ec, cop_p90, cop_p75, cop_p50, zero_is_bottom=True)
            m365_tier = tier_fn(m_ec, m365_p90, m365_p75, m365_p50, zero_is_bottom=False)
            priority = priority_fn(m365_tier, cop_tier)

            ex_m365_tier = tier_fn(exm_ec, exm_p90, exm_p75, exm_p50, zero_is_bottom=False)
            ex_cop_tier = tier_fn(exc_ec, exc_p90, exc_p75, exc_p50, zero_is_bottom=False)
            excel_pri = priority_fn(ex_m365_tier, ex_cop_tier)

            cop_rank_val = 0.0 if c_ec == 0 else cop_rank[uid] / max(copilot_user_count, 1)
            m365_rank_val = m365_rank[uid] / total_users

            td = len(t_days.get(uid, set()))
            od = len(o_days.get(uid, set()))
            wd = len(w_days.get(uid, set()))
            xd = len(x_days.get(uid, set()))
            pd_ = len(p_days.get(uid, set()))

            t_act = t_ec.get(uid, 0)
            o_act = o_ec.get(uid, 0)
            off_act = off_ec.get(uid, 0)

            t_seg = "0. No Usage" if td == 0 else seg_fn(td, window_days)
            o_seg = "0. No Usage" if od == 0 else seg_fn(od, window_days)
            w_seg = "0. No Usage" if wd == 0 else seg_fn(wd, window_days)
            x_seg = "0. No Usage" if xd == 0 else seg_fn(xd, window_days)
            p_seg = "0. No Usage" if pd_ == 0 else seg_fn(pd_, window_days)

            office_days = wd + xd + pd_
            off_seg = "0. No Usage" if office_days == 0 else seg_fn(office_days, window_days)

            overall_days = len(
                t_days.get(uid, set()) | o_days.get(uid, set()) |
                w_days.get(uid, set()) | x_days.get(uid, set()) |
                p_days.get(uid, set())
            )
            overall_seg = "0. No Usage" if overall_days == 0 else seg_fn(overall_days, window_days)

            writer.writerow([
                uid_original[uid],
                c_ec, m_ec, exc_ec, exm_ec,
                is_cop_user, cop_tier, m365_tier,
                priority, excel_pri,
                f"{cop_rank_val:.6f}", f"{m365_rank_val:.6f}",
                td, od, wd, xd, pd_,
                t_act, o_act, off_act,
                t_seg, o_seg, w_seg, x_seg, p_seg,
                off_seg, overall_seg,
                # v2.5.0: precomputed raw + CE rank columns per window (order must
                # match USERSTATS_HEADER: 6 raws × 3 windows, then 7 ranks × 3 windows)
                teams_raw["L30"].get(uid, 0),   teams_raw["L60"].get(uid, 0),   teams_raw["Full"].get(uid, 0),
                outlook_raw["L30"].get(uid, 0), outlook_raw["L60"].get(uid, 0), outlook_raw["Full"].get(uid, 0),
                word_raw["L30"].get(uid, 0),    word_raw["L60"].get(uid, 0),    word_raw["Full"].get(uid, 0),
                excel_raw["L30"].get(uid, 0),   excel_raw["L60"].get(uid, 0),   excel_raw["Full"].get(uid, 0),
                ppt_raw["L30"].get(uid, 0),     ppt_raw["L60"].get(uid, 0),     ppt_raw["Full"].get(uid, 0),
                copilot_chat_raw["L30"].get(uid, 0), copilot_chat_raw["L60"].get(uid, 0), copilot_chat_raw["Full"].get(uid, 0),
                ce_rank_teams["L30"][uid],     ce_rank_teams["L60"][uid],     ce_rank_teams["Full"][uid],
                ce_rank_outlook["L30"][uid],   ce_rank_outlook["L60"][uid],   ce_rank_outlook["Full"][uid],
                ce_rank_word["L30"][uid],      ce_rank_word["L60"][uid],      ce_rank_word["Full"][uid],
                ce_rank_excel["L30"][uid],     ce_rank_excel["L60"][uid],     ce_rank_excel["Full"][uid],
                ce_rank_ppt["L30"][uid],       ce_rank_ppt["L60"][uid],       ce_rank_ppt["Full"][uid],
                ce_rank_all["L30"][uid],       ce_rank_all["L60"][uid],       ce_rank_all["Full"][uid],
                ce_copilot_pct["L30"][uid],    ce_copilot_pct["L60"][uid],    ce_copilot_pct["Full"][uid],
            ])

    # ── Write *_SessionCohort.csv ────────────────────────────────────────
    session_count = 0
    with open(session_path, "w", encoding="utf-8", newline="") as f:
        writer = csv.writer(f, lineterminator="\n")
        writer.writerow(SESSIONCOHORT_HEADER)

        for (uid, app), ops in sorted(session_ops.items()):
            n = len(ops)
            if n == 0:
                continue
            if n <= 5:
                cohort = "1-5 sessions"
            elif n <= 10:
                cohort = "6-10 sessions"
            elif n <= 20:
                cohort = "11-20 sessions"
            elif n <= 40:
                cohort = "21-40 sessions"
            elif n <= 60:
                cohort = "41-60 sessions"
            elif n <= 80:
                cohort = "61-80 sessions"
            else:
                cohort = "81+ sessions"
            writer.writerow([uid_original[uid], app, cohort])
            session_count += 1

    t_elapsed = time.perf_counter() - t_start

    if not quiet:
        print(f"[UserStats]     {total_users:,} users \u2192 {userstats_path.name} "
              f"({len(USERSTATS_HEADER)} columns)")
        print(f"[SessionCohort] {session_count:,} (user, app) pairs \u2192 {session_path.name}")
        print(f"[UserStats]     Elapsed: {t_elapsed:.2f}s")

    return total_users, session_count


# ═════════════════════════════════════════════════════════════════════════════
# CLI ENTRY POINT
# ═════════════════════════════════════════════════════════════════════════════

def main() -> None:
    parser = argparse.ArgumentParser(
        prog="purview_m365_processor",
        description=(
            f"Purview M365 Usage Bundle Processor v{SCRIPT_VERSION}\n"
            "Pre-computes the M365 Usage rollup + UserStats + SessionCohort CSVs\n"
            "consumed by the Power BI template. Accepts either layout:\n"
            "  (A) ONE PAX / PowerShell export ............ use --pax\n"
            "  (B) FOUR manual Purview Audit exports ...... use --teams --outlook --files --copilot\n"
            "Output schema is IDENTICAL for both layouts — same PBIT template ingests either."
        ),
        formatter_class=argparse.RawDescriptionHelpFormatter,
        epilog="""\
EXAMPLES
========

(A) Single PAX export (PAX tool or PowerShell Search-UnifiedAuditLog):

    python %(prog)s --pax Purview_Export.csv

    python %(prog)s --pax Purview_Export.csv --output-dir ./output


(B) Manual 4-pull export from Purview Audit (validated chip strategy):

      Teams   (7d):  MessageSent, MessageRead, ChatCreated, TeamsSessionStarted,
                     MeetingParticipantDetail
      Outlook (30d): MailItemsAccessed, Send, MailboxLogin
      Files   (60d): FileAccessed, FileModified, FileDownloaded, FileUploaded
      Copilot (30d): CopilotInteraction, AIAppInteraction   (filter by record type)

    python %(prog)s ^
        --teams   Teams_Export.csv ^
        --outlook Outlook_Export.csv ^
        --files   Files_Export.csv ^
        --copilot Copilot_Export.csv ^
        --output-dir .\output


OUTPUT (rollup mode, both layouts produce the same three files):

    <stem>_Rollup_<timestamp>.csv         13 cols  -> M365Usage table
    <stem>_UserStats_<timestamp>.csv      40 cols  -> UserStats table
    <stem>_SessionCohort_<timestamp>.csv   3 cols  -> SessionCohort table

  <stem> defaults to the input file's name (single input) or '<firstInputStem>_Combined'
  (multi-input). Rename the file or use --output-dir if you want a tenant-named folder.


ADVANCED
========
  --reconcile         Sample-based correctness check vs full event-level explosion.
  --debug-events      v1-compatible 153-column event-level CSV (single input only).
  --skip-precompute   Skip UserStats and SessionCohort generation.
  --prompt-filter     Copilot message filter: Prompt | Response | Both | Null.
  --input/-i          Power-user / scripted fallback for one or more CSVs.
""",
    )

    # ── Input layout (mutually exclusive, exactly one required) ──────────
    layout = parser.add_argument_group(
        "INPUT LAYOUT  (choose ONE shape that matches how you exported the data)"
    )
    layout.add_argument(
        "--pax",
        metavar="CSV",
        help="(A) Single CSV from PAX or PowerShell Search-UnifiedAuditLog.",
    )
    layout.add_argument(
        "--teams",
        metavar="CSV",
        help="(B) Teams workload pull from Purview Audit.",
    )
    layout.add_argument(
        "--outlook",
        metavar="CSV",
        help="(B) Outlook / Exchange workload pull from Purview Audit.",
    )
    layout.add_argument(
        "--files",
        metavar="CSV",
        help="(B) Files (SharePoint + OneDrive) workload pull from Purview Audit.",
    )
    layout.add_argument(
        "--copilot",
        metavar="CSV",
        help="(B) Copilot record-type pull (CopilotInteraction + AIAppInteraction).",
    )
    layout.add_argument(
        "--input", "-i",
        nargs="+",
        metavar="CSV",
        help="Power-user fallback: one or more CSV paths (any combination).",
    )

    # ── Output naming & location ─────────────────────────────────────────
    output = parser.add_argument_group("OUTPUT")
    output.add_argument(
        "--output-dir", "-o",
        metavar="DIR",
        default=None,
        help="Directory for output files. Default: same folder as the (first) input.",
    )

    # ── Optional behaviour flags ─────────────────────────────────────────
    advanced = parser.add_argument_group("ADVANCED")
    advanced.add_argument(
        "--skip-precompute",
        action="store_true",
        default=False,
        help="Skip *_UserStats.csv and *_SessionCohort.csv (only the Rollup is written).",
    )
    advanced.add_argument(
        "--no-session-stats",
        action="store_true",
        default=False,
        help="Skip *_SessionStats.csv (the AI in One DISTINCTCOUNT(ThreadId) output).",
    )
    advanced.add_argument(
        "--debug-events",
        action="store_true",
        default=False,
        help="Emit v1-compatible 153-column event-level CSV instead of the rollup (single input only).",
    )
    advanced.add_argument(
        "--reconcile",
        action="store_true",
        default=False,
        help="Run sample-based reconciliation against the first input.",
    )
    advanced.add_argument(
        "--prompt-filter",
        choices=["Prompt", "Response", "Both", "Null"],
        default=None,
        help="Filter Copilot messages by isPrompt value.",
    )
    advanced.add_argument(
        "--quiet", "-q",
        action="store_true",
        default=False,
        help="Suppress progress output (only errors are printed).",
    )
    # Hidden legacy alias (kept for older scripts that referenced --no-userstats).
    advanced.add_argument(
        "--no-userstats",
        dest="skip_precompute",
        action="store_true",
        help=argparse.SUPPRESS,
    )
    advanced.add_argument(
        "--deidentify",
        action="store_true",
        default=False,
        help=(
            "One-way hash all identifying values (UserId, mailbox UPN/GUID/SIDs, "
            "device name, resource URLs/file names) for anonymous reporting. "
            "Deterministic and format-preserving; irreversible (no decode map)."
        ),
    )
    advanced.add_argument(
        "--rebuild-sidecars-from-rollup",
        metavar="ROLLUP_CSV",
        default=None,
        help=(
            "Regenerate UserStats and SessionCohort sidecars from an existing rollup CSV "
            "(no Purview input required). Sidecars are written to --output-dir (default: "
            "the rollup's parent directory) using the rollup's base stem."
        ),
    )
    advanced.add_argument(
        "--session-stats-for-rebuild",
        metavar="SESSIONSTATS_CSV",
        default=None,
        help=(
            "Optional companion to --rebuild-sidecars-from-rollup: when supplied, the "
            "CECopilotPercentile_* columns are computed from this SessionStats CSV's "
            "PromptCount (AI in One semantics). If omitted, the sidecar rebuild falls "
            "back to the audit-event count (legacy behaviour)."
        ),
    )
    parser.add_argument(
        "--version",
        action="version",
        version=f"%(prog)s {SCRIPT_VERSION}",
    )

    args = parser.parse_args()

    global _DEIDENTIFY
    _DEIDENTIFY = bool(args.deidentify)

    # ── Standalone sidecar regeneration mode ─────────────────────────────
    # When --rebuild-sidecars-from-rollup is supplied, ignore every other
    # input/dispatch flag and rebuild UserStats + SessionCohort sidecars
    # from the given rollup CSV. Used by the PAX append-merge workflow
    # after the PowerShell side unions the current run's rollup with a
    # customer-supplied target.
    if args.rebuild_sidecars_from_rollup:
        rollup_in = os.path.abspath(args.rebuild_sidecars_from_rollup)
        if not os.path.isfile(rollup_in):
            print(f"ERROR: Rollup CSV not found: {rollup_in}", file=sys.stderr)
            sys.exit(1)
        session_stats_in: str | None = None
        if args.session_stats_for_rebuild:
            session_stats_in = os.path.abspath(args.session_stats_for_rebuild)
            if not os.path.isfile(session_stats_in):
                print(
                    f"ERROR: SessionStats CSV not found: {session_stats_in}",
                    file=sys.stderr,
                )
                sys.exit(1)
        out_dir = (
            Path(os.path.abspath(args.output_dir))
            if args.output_dir
            else Path(rollup_in).parent
        )
        os.makedirs(out_dir, exist_ok=True)
        rollup_stem = Path(rollup_in).stem
        m = re.match(r"^(.*?)(?:_Rollup(?:_\d{8}_\d{6})?)$", rollup_stem)
        base_stem = m.group(1) if m else rollup_stem
        run_ts = datetime.now().strftime("%Y%m%d_%H%M%S")
        userstats_path = str(out_dir / f"{base_stem}_UserStats_{run_ts}.csv")
        session_path = str(out_dir / f"{base_stem}_SessionCohort_{run_ts}.csv")
        write_userstats_files(
            rollup_in, userstats_path, session_path, args.quiet,
            session_stats_csv_path=session_stats_in,
        )
        sys.exit(0)

    # ── Resolve the input layout into a flat list ────────────────────────
    pax_inputs:  list[str] = [args.pax] if args.pax else []
    workload_inputs: list[tuple[str, str]] = []  # [(label, path), ...] preserves order
    for label in ("teams", "outlook", "files", "copilot"):
        path = getattr(args, label)
        if path:
            workload_inputs.append((label, path))
    legacy_inputs: list[str] = list(args.input) if args.input else []

    if pax_inputs and workload_inputs:
        parser.error("--pax cannot be combined with --teams/--outlook/--files/--copilot. "
                     "Pick the shape that matches your export.")
    if (pax_inputs or workload_inputs) and legacy_inputs:
        parser.error("--input/-i cannot be combined with --pax or the workload flags.")

    if pax_inputs:
        input_paths = [os.path.abspath(pax_inputs[0])]
        layout_label = "pax"
    elif workload_inputs:
        input_paths = [os.path.abspath(p) for _, p in workload_inputs]
        layout_label = "manual_4pull"
    elif legacy_inputs:
        input_paths = [os.path.abspath(p) for p in legacy_inputs]
        layout_label = "legacy_input"
    else:
        parser.error(
            "No input given. Use ONE of:\n"
            "    --pax <CSV>                                                    (single PAX export)\n"
            "    --teams <T> --outlook <O> --files <F> --copilot <C>            (manual 4-pull export)\n"
            "    --input/-i <CSV> [<CSV> ...]                                   (power-user fallback)"
        )

    for p in input_paths:
        if not os.path.isfile(p):
            print(f"ERROR: Input file not found: {p}", file=sys.stderr)
            sys.exit(1)

    # ── Determine output directory & filenames ───────────────────────────
    first_stem = Path(input_paths[0]).stem
    stem = first_stem if len(input_paths) == 1 else f"{first_stem}_Combined"

    output_dir = Path(os.path.abspath(args.output_dir)) if args.output_dir else Path(input_paths[0]).parent
    os.makedirs(output_dir, exist_ok=True)

    run_ts = datetime.now().strftime("%Y%m%d_%H%M%S")
    event_level = args.debug_events

    if not event_level:
        rollup_path = str(output_dir / f"{stem}_Rollup_{run_ts}.csv")
        userstats_path = str(output_dir / f"{stem}_UserStats_{run_ts}.csv")
        session_path = str(output_dir / f"{stem}_SessionCohort_{run_ts}.csv")
        session_stats_path: str | None = (
            None if args.no_session_stats
            else str(output_dir / f"{stem}_SessionStats_{run_ts}.csv")
        )
    else:
        if len(input_paths) > 1:
            print("ERROR: --debug-events accepts only one input CSV.", file=sys.stderr)
            sys.exit(1)
        rollup_path = str(output_dir / f"{stem}_Exploded_{run_ts}.csv")
        session_stats_path = None

    # ── Dispatch ─────────────────────────────────────────────────────────
    if not event_level:
        stats = run_rollup(
            input_csv=input_paths if len(input_paths) > 1 else input_paths[0],
            output_csv=rollup_path,
            prompt_filter=args.prompt_filter,
            quiet=args.quiet,
            session_stats_csv=session_stats_path,
        )
        exit_code = 1 if stats["parse_errors"] > stats["input_records"] * 0.1 else 0

        if not args.skip_precompute:
            write_userstats_files(
                rollup_path, userstats_path, session_path, args.quiet,
                session_stats_csv_path=session_stats_path,
            )
    else:
        stats = run_explosion(
            input_csv=input_paths[0],
            output_csv=rollup_path,
            prompt_filter=args.prompt_filter,
            quiet=args.quiet,
        )
        exit_code = 1 if stats["errors"] > 0 else 0

    if args.reconcile:
        reconcile_passed = run_reconcile(
            input_csv=input_paths[0],
            prompt_filter=args.prompt_filter,
            quiet=args.quiet,
        )
        if not reconcile_passed:
            exit_code = 1

    sys.exit(exit_code)


if __name__ == "__main__":
    main()
'@
# <<< END-EMBEDDED-M365-PROCESSOR

# ============================================================================
# ROLLUP POST-PROCESSOR HELPER FUNCTIONS
# ============================================================================
# Resolve-PythonExe         -> locates a Python 3.10+ interpreter (auto-installs via winget,
#                              falls back to the python.org installer if winget unavailable).
# Install-OrjsonIfMissing   -> installs the optional 'orjson' package; warn-and-continue
#                              on failure (both processors auto-fallback to stdlib json).
# Invoke-EmbeddedProcessor  -> materializes the embedded .py to .pax_incremental,
#                              runs it with the provided argument list, captures stderr,
#                              and deletes the temp file in finally.
# All three functions log via Write-LogHost / Write-Log (defined earlier in the script).
# These functions are only invoked when -Rollup or -RollupPlusRaw is used.
# Minimum required Python version is 3.10 (the embedded processors use PEP 604 unions).
# ============================================================================

$Script:ROLLUP_PYTHON_MIN_MAJOR = 3
$Script:ROLLUP_PYTHON_MIN_MINOR = 10

function Resolve-PythonExe {
	[CmdletBinding()]
	param([switch]$AllowAutoInstall)

	# Returns: hashtable @{ Path=<full path or 'py'>; Args=<launcher args, e.g. '-3.13'>; Version='3.13.1' }
	# Throws on hard failure (no usable interpreter even after install attempts).

	$candidates = @(
		@{ Cmd = 'python';  LauncherArgs = @() }
		@{ Cmd = 'py';      LauncherArgs = @('-3.13') }
		@{ Cmd = 'py';      LauncherArgs = @('-3.12') }
		@{ Cmd = 'py';      LauncherArgs = @('-3.11') }
		@{ Cmd = 'py';      LauncherArgs = @('-3.10') }
		@{ Cmd = 'python3'; LauncherArgs = @() }
	)

	foreach ($c in $candidates) {
		try {
			$cmdInfo = Get-Command -Name $c.Cmd -ErrorAction SilentlyContinue
			if (-not $cmdInfo) { continue }
			$probeArgs = @($c.LauncherArgs) + @('-c', 'import sys; print("{}.{}.{}".format(sys.version_info.major, sys.version_info.minor, sys.version_info.micro))')
			$verOutput = & $c.Cmd @probeArgs 2>$null
			if ($LASTEXITCODE -ne 0 -or -not $verOutput) { continue }
			$verText = ($verOutput | Select-Object -First 1).Trim()
			if ($verText -notmatch '^(\d+)\.(\d+)\.(\d+)') { continue }
			$maj = [int]$Matches[1]
			$min = [int]$Matches[2]
			if ($maj -lt $Script:ROLLUP_PYTHON_MIN_MAJOR) { continue }
			if ($maj -eq $Script:ROLLUP_PYTHON_MIN_MAJOR -and $min -lt $Script:ROLLUP_PYTHON_MIN_MINOR) { continue }
			return @{ Path = $c.Cmd; Args = $c.LauncherArgs; Version = $verText }
		}
		catch { continue }
	}

	if (-not $AllowAutoInstall) {
		throw "No Python $($Script:ROLLUP_PYTHON_MIN_MAJOR).$($Script:ROLLUP_PYTHON_MIN_MINOR)+ interpreter found on PATH."
	}

	# Auto-install path: try winget first, then python.org installer.
	Write-LogHost "Rollup: no Python $($Script:ROLLUP_PYTHON_MIN_MAJOR).$($Script:ROLLUP_PYTHON_MIN_MINOR)+ found. Attempting auto-install..." -ForegroundColor Yellow

	$winget = Get-Command -Name 'winget' -ErrorAction SilentlyContinue
	$installed = $false
	if ($winget) {
		Write-LogHost "Rollup: installing Python 3.13 via winget (Python.Python.3.13)..." -ForegroundColor Cyan
		try {
			$wingetArgs = @('install', '--id', 'Python.Python.3.13', '-e', '--accept-source-agreements', '--accept-package-agreements', '--scope', 'user', '--silent')
			& winget @wingetArgs | Out-Host
			if ($LASTEXITCODE -eq 0) { $installed = $true }
		}
		catch {
			Write-LogHost "Rollup: winget install failed: $($_.Exception.Message)" -ForegroundColor Yellow
		}
	}
	else {
		Write-LogHost "Rollup: winget is not available on this host; falling back to python.org installer." -ForegroundColor Yellow
	}

	if (-not $installed) {
		# python.org per-user silent install
		try {
			$tmpDir = Join-Path ([IO.Path]::GetTempPath()) ("PAX_PythonInstaller_" + [guid]::NewGuid().ToString('N'))
			New-Item -ItemType Directory -Path $tmpDir -Force | Out-Null
			$installerUrl = 'https://www.python.org/ftp/python/3.13.1/python-3.13.1-amd64.exe'
			$installerPath = Join-Path $tmpDir 'python-3.13.1-amd64.exe'
			Write-LogHost "Rollup: downloading $installerUrl ..." -ForegroundColor Cyan
			Invoke-WebRequest -Uri $installerUrl -OutFile $installerPath -UseBasicParsing
			Write-LogHost "Rollup: running silent per-user install (PrependPath=1)..." -ForegroundColor Cyan
			$proc = Start-Process -FilePath $installerPath -ArgumentList @('/quiet', 'InstallAllUsers=0', 'PrependPath=1', 'Include_launcher=1', 'Include_pip=1') -Wait -PassThru
			if ($proc.ExitCode -eq 0) { $installed = $true }
			else { Write-LogHost "Rollup: python.org installer exited with code $($proc.ExitCode)." -ForegroundColor Yellow }
		}
		catch {
			Write-LogHost "Rollup: python.org install failed: $($_.Exception.Message)" -ForegroundColor Yellow
		}
	}

	if (-not $installed) {
		throw "Rollup: failed to auto-install Python $($Script:ROLLUP_PYTHON_MIN_MAJOR).$($Script:ROLLUP_PYTHON_MIN_MINOR)+. Install Python manually from https://www.python.org/downloads/ and re-run."
	}

	# Refresh PATH from process + machine + user scopes so new install is visible without restart.
	$paths = @(
		[Environment]::GetEnvironmentVariable('Path', 'Machine'),
		[Environment]::GetEnvironmentVariable('Path', 'User'),
		$env:Path
	) | Where-Object { $_ }
	$env:Path = ($paths -join ';')

	# Recurse once with auto-install disabled to prevent loops.
	return Resolve-PythonExe -AllowAutoInstall:$false
}

function Install-OrjsonIfMissing {
	[CmdletBinding()]
	param(
		[Parameter(Mandatory)] [string]   $PythonExe,
		[Parameter(Mandatory)] [AllowEmptyCollection()] [string[]] $LauncherArgs
	)

	# Best-effort install. Both embedded processors fall back to stdlib json on import failure,
	# so we warn-and-continue on any error here rather than throwing.
	$showArgs = @($LauncherArgs) + @('-m', 'pip', 'show', 'orjson')
	& $PythonExe @showArgs 2>$null | Out-Null
	if ($LASTEXITCODE -eq 0) { return $true }

	Write-LogHost "Rollup: 'orjson' not installed; installing for faster JSON parsing (~5-10x). Falls back to stdlib json on failure." -ForegroundColor Cyan
	$installArgs = @($LauncherArgs) + @('-m', 'pip', 'install', '--quiet', '--disable-pip-version-check', '--user', 'orjson')
	try {
		& $PythonExe @installArgs 2>&1 | ForEach-Object { Write-Log $_ }
		if ($LASTEXITCODE -eq 0) { return $true }
		Write-LogHost "Rollup: 'orjson' install returned exit code $LASTEXITCODE. Continuing with stdlib json." -ForegroundColor Yellow
		return $false
	}
	catch {
		Write-LogHost "Rollup: 'orjson' install threw: $($_.Exception.Message). Continuing with stdlib json." -ForegroundColor Yellow
		return $false
	}
}

function Install-DeltalakeIfMissing {
	<#
	.SYNOPSIS
		Ensures the Python 'deltalake' package is installed for Fabric Lakehouse Delta-table writes.

	.DESCRIPTION
		Invoked only when the run will write to a Fabric Lakehouse target (Tables/ namespace).
		Performs a quiet per-user install on first use. On failure, returns $false with a clear
		actionable message — the caller must abort the Delta write path rather than continue.

		Unlike Install-OrjsonIfMissing, the deltalake package is NOT optional: the Fabric Tables
		write path cannot fall back to a pure-Python implementation. Callers must check the
		return value and abort the run cleanly if the install fails.
	#>
	[CmdletBinding()]
	param(
		[Parameter(Mandatory)] [string]   $PythonExe,
		[Parameter(Mandatory)] [AllowEmptyCollection()] [string[]] $LauncherArgs
	)

	$showArgs = @($LauncherArgs) + @('-m', 'pip', 'show', 'deltalake')
	& $PythonExe @showArgs 2>$null | Out-Null
	if ($LASTEXITCODE -eq 0) { return $true }

	Write-LogHost "Fabric: 'deltalake' Python package not installed; installing (required for Lakehouse Tables/ writes)." -ForegroundColor Cyan
	$installArgs = @($LauncherArgs) + @('-m', 'pip', 'install', '--quiet', '--disable-pip-version-check', '--user', 'deltalake>=0.15')
	try {
		& $PythonExe @installArgs 2>&1 | ForEach-Object { Write-Log $_ }
		if ($LASTEXITCODE -eq 0) {
			Write-LogHost "Fabric: 'deltalake' installed successfully." -ForegroundColor Green
			return $true
		}
		Write-LogHost "Fabric: 'deltalake' install returned exit code $LASTEXITCODE. Install manually with 'pip install deltalake' and re-run." -ForegroundColor Red
		return $false
	}
	catch {
		Write-LogHost "Fabric: 'deltalake' install threw: $($_.Exception.Message). Install manually with 'pip install deltalake' and re-run." -ForegroundColor Red
		return $false
	}
}

function ConvertTo-UsersSeedMap {
	<#
	.SYNOPSIS
		Extract {PersonId_Normalized -> UserKey (INT)} from a target Users CSV and write it
		as a compact JSON file the embedded CopilotInteraction processor consumes via
		`--seed-userkey-map`.

	.DESCRIPTION
		Pre-flight helper for -AppendUserInfo. Read the existing target Users CSV produced by a
		prior run, build a dict of PersonId_Normalized -> UserKey, and write JSON. Skips rows
		with empty PersonId_Normalized or non-integer UserKey. First occurrence of any
		PersonId_Normalized wins (target is the source of truth).

	.OUTPUTS
		Int count of entries written.
	#>
	[CmdletBinding()]
	param(
		[Parameter(Mandatory)] [string] $TargetUsersCsv,
		[Parameter(Mandatory)] [string] $OutJsonPath
	)
	if (-not (Test-Path -LiteralPath $TargetUsersCsv -PathType Leaf)) {
		throw "ConvertTo-UsersSeedMap: target Users CSV not found: '$TargetUsersCsv'"
	}
	$rows = @(Import-Csv -LiteralPath $TargetUsersCsv -Encoding UTF8)
	$map = [ordered]@{}
	foreach ($r in $rows) {
		$personId = $r.PersonId_Normalized
		$uk       = $r.UserKey
		if ([string]::IsNullOrWhiteSpace($personId)) { continue }
		if ([string]::IsNullOrWhiteSpace($uk))       { continue }
		$ukInt = 0
		if (-not [int]::TryParse([string]$uk, [ref]$ukInt)) { continue }
		if (-not $map.Contains($personId)) { $map[$personId] = $ukInt }
	}
	$json = if ($map.Count -gt 0) { ($map | ConvertTo-Json -Compress -Depth 2) } else { '{}' }
	$utf8NoBom = [System.Text.UTF8Encoding]::new($false)
	$outDir = Split-Path -Parent $OutJsonPath
	if ($outDir -and -not (Test-Path -LiteralPath $outDir -PathType Container)) {
		New-Item -ItemType Directory -Path $outDir -Force | Out-Null
	}
	[System.IO.File]::WriteAllText($OutJsonPath, $json, $utf8NoBom)
	return $map.Count
}

function ConvertTo-FactSeedMaps {
	<#
	.SYNOPSIS
		Extract {Message_Id_Raw -> Message_Id (INT)} and {ThreadId_Raw -> ThreadKey (INT)}
		from a target CopilotInteraction Fact CSV and write each as a compact JSON file
		the embedded processor consumes via `--seed-mid-map` / `--seed-thread-map`.

	.DESCRIPTION
		Pre-flight helper for -AppendFile (CopilotInteraction rollup mode). Reads the
		existing target Fact CSV produced by a prior run, builds two dicts keyed by the
		raw GUID columns, and writes both JSON files. First occurrence wins. Rows with
		blank raw GUID or non-integer surrogate are skipped.

	.OUTPUTS
		PSCustomObject with .MidCount and .ThreadCount integer fields.
	#>
	[CmdletBinding()]
	param(
		[Parameter(Mandatory)] [string] $TargetFactCsv,
		[Parameter(Mandatory)] [string] $OutMidJsonPath,
		[Parameter(Mandatory)] [string] $OutThreadJsonPath
	)
	if (-not (Test-Path -LiteralPath $TargetFactCsv -PathType Leaf)) {
		throw "ConvertTo-FactSeedMaps: target Fact CSV not found: '$TargetFactCsv'"
	}
	$rows = @(Import-Csv -LiteralPath $TargetFactCsv -Encoding UTF8)
	$midMap    = [ordered]@{}
	$threadMap = [ordered]@{}
	foreach ($r in $rows) {
		$midRaw    = $r.Message_Id_Raw
		$threadRaw = $r.ThreadId_Raw
		$midInt    = 0
		$threadInt = 0
		if (-not [string]::IsNullOrWhiteSpace($midRaw)) {
			if ([int]::TryParse([string]$r.Message_Id, [ref]$midInt)) {
				if (-not $midMap.Contains($midRaw)) { $midMap[$midRaw] = $midInt }
			}
		}
		if (-not [string]::IsNullOrWhiteSpace($threadRaw)) {
			$threadVal = if ($r.PSObject.Properties.Match('ThreadKey').Count) { $r.ThreadKey } else { $r.ThreadId }
			if ([int]::TryParse([string]$threadVal, [ref]$threadInt)) {
				if (-not $threadMap.Contains($threadRaw)) { $threadMap[$threadRaw] = $threadInt }
			}
		}
	}
	$utf8NoBom = [System.Text.UTF8Encoding]::new($false)
	foreach ($pair in @(@($OutMidJsonPath, $midMap), @($OutThreadJsonPath, $threadMap))) {
		$path = $pair[0]
		$dict = $pair[1]
		$outDir = Split-Path -Parent $path
		if ($outDir -and -not (Test-Path -LiteralPath $outDir -PathType Container)) {
			New-Item -ItemType Directory -Path $outDir -Force | Out-Null
		}
		$json = if ($dict.Count -gt 0) { ($dict | ConvertTo-Json -Compress -Depth 2) } else { '{}' }
		[System.IO.File]::WriteAllText($path, $json, $utf8NoBom)
	}
	return [PSCustomObject]@{
		MidCount    = $midMap.Count
		ThreadCount = $threadMap.Count
	}
}

function ConvertTo-RecordIdExclusion {
	<#
	.SYNOPSIS
		Extract the RecordId column from a target exploded/event-level CSV and write a
		newline-delimited file the embedded M365Bundle processor consumes via
		`--exclude-record-ids` for cross-run dedup.

	.DESCRIPTION
		Pre-flight helper for -AppendFile (M365Bundle event-level mode / -RollupPlusRaw
		raw-CSV append). Streams the target CSV without loading the full row set, finds
		the RecordId column index from the header, and writes one RecordId per line.
		Blank / duplicate RecordIds are skipped.

	.OUTPUTS
		Int count of unique RecordIds written.
	#>
	[CmdletBinding()]
	param(
		[Parameter(Mandatory)] [string] $TargetCsv,
		[Parameter(Mandatory)] [string] $OutListPath
	)
	if (-not (Test-Path -LiteralPath $TargetCsv -PathType Leaf)) {
		throw "ConvertTo-RecordIdExclusion: target CSV not found: '$TargetCsv'"
	}
	$utf8NoBom = [System.Text.UTF8Encoding]::new($false)
	$outDir = Split-Path -Parent $OutListPath
	if ($outDir -and -not (Test-Path -LiteralPath $outDir -PathType Container)) {
		New-Item -ItemType Directory -Path $outDir -Force | Out-Null
	}
	$reader = $null
	$writer = $null
	$seen   = [System.Collections.Generic.HashSet[string]]::new()
	try {
		$reader = [System.IO.StreamReader]::new($TargetCsv, [System.Text.Encoding]::UTF8)
		$headerLine = $reader.ReadLine()
		if (-not $headerLine) { return 0 }
		# Tolerate UTF-8 BOM on header
		if ($headerLine.Length -gt 0 -and [int][char]$headerLine[0] -eq 0xFEFF) {
			$headerLine = $headerLine.Substring(1)
		}
		$cols = $headerLine.Split(',')
		$ridIdx = -1
		for ($i = 0; $i -lt $cols.Length; $i++) {
			$name = $cols[$i].Trim().Trim('"')
			if ($name -eq 'RecordId') { $ridIdx = $i; break }
		}
		if ($ridIdx -lt 0) {
			throw "ConvertTo-RecordIdExclusion: 'RecordId' column not found in '$TargetCsv'."
		}
		$writer = [System.IO.StreamWriter]::new($OutListPath, $false, $utf8NoBom)
		while (-not $reader.EndOfStream) {
			$line = $reader.ReadLine()
			if ([string]::IsNullOrEmpty($line)) { continue }
			# Lightweight CSV split that respects double-quoted fields containing commas.
			$fields = [System.Collections.Generic.List[string]]::new()
			$buf = [System.Text.StringBuilder]::new()
			$inQ = $false
			for ($j = 0; $j -lt $line.Length; $j++) {
				$ch = $line[$j]
				if ($ch -eq '"') { $inQ = -not $inQ; continue }
				if ($ch -eq ',' -and -not $inQ) {
					[void]$fields.Add($buf.ToString()); [void]$buf.Clear(); continue
				}
				[void]$buf.Append($ch)
			}
			[void]$fields.Add($buf.ToString())
			if ($ridIdx -ge $fields.Count) { continue }
			$rid = $fields[$ridIdx].Trim()
			if ([string]::IsNullOrEmpty($rid)) { continue }
			if ($seen.Add($rid)) {
				$writer.WriteLine($rid)
			}
		}
	}
	finally {
		if ($writer) { $writer.Dispose() }
		if ($reader) { $reader.Dispose() }
	}
	return $seen.Count
}

function script:Import-CsvDeduped {
	<#
	.SYNOPSIS
		Import-Csv wrapper that tolerates duplicate / BOM-prefixed / whitespace-padded
		header columns. Required when reading Users CSVs that may have round-tripped
		through the embedded Python processor and acquired duplicate header tokens
		(e.g. both 'userPrincipalName' and 'PersonId' present pre-rename).

	.DESCRIPTION
		PowerShell's Import-Csv calls Add-Member internally for each header cell, which
		throws 'The member "X" is already present' when two header cells normalize to
		the same name. This helper rewrites the header line with later duplicates
		suffixed (_dup2, _dup3, …) before parsing, so the file always loads. The first
		occurrence keeps its original name; callers that care can drop the *_dup* extras.

		Also strips a leading BOM from the header line and trims whitespace from each
		header cell. The data rows are passed through unchanged.

	.OUTPUTS
		Array of [pscustomobject]. Empty array if file is missing or contains only a
		header (or only whitespace).
	#>
	[CmdletBinding()]
	param([Parameter(Mandatory)][string]$LiteralPath)
	if (-not (Test-Path -LiteralPath $LiteralPath -PathType Leaf)) { return @() }
	$lines = @(Get-Content -LiteralPath $LiteralPath -Encoding UTF8)
	if ($lines.Count -eq 0) { return @() }
	$hdrLine = $lines[0] -replace '^\uFEFF',''
	# Parse header honoring quoted commas using TextFieldParser.
	try { Add-Type -AssemblyName Microsoft.VisualBasic -ErrorAction Stop } catch { }
	$sr = [System.IO.StringReader]::new($hdrLine)
	$tfp = New-Object Microsoft.VisualBasic.FileIO.TextFieldParser($sr)
	$tfp.SetDelimiters(',')
	$tfp.HasFieldsEnclosedInQuotes = $true
	$hdrCells = @()
	try { $hdrCells = @($tfp.ReadFields()) } catch { $hdrCells = @($hdrLine -split ',') }
	finally { $tfp.Dispose(); $sr.Dispose() }
	$seen = [System.Collections.Generic.Dictionary[string,int]]::new([System.StringComparer]::OrdinalIgnoreCase)
	$newHdr = New-Object System.Collections.Generic.List[string]
	foreach ($c in $hdrCells) {
		$n = ($c -as [string])
		if ($null -eq $n) { $n = '' }
		$n = $n.Trim()
		if ([string]::IsNullOrEmpty($n)) { $n = '_blank' }
		if ($seen.ContainsKey($n)) {
			$seen[$n] = $seen[$n] + 1
			$newHdr.Add(('{0}_dup{1}' -f $n, $seen[$n]))
		} else {
			$seen[$n] = 1
			$newHdr.Add($n)
		}
	}
	$newHdrLine = ($newHdr | ForEach-Object { '"' + ($_ -replace '"','""') + '"' }) -join ','
	if ($lines.Count -eq 1) { return @() }
	$rest = $lines | Select-Object -Skip 1
	$rewritten = @($newHdrLine) + @($rest)
	return @($rewritten | ConvertFrom-Csv)
}

function Merge-UsersCsv {
	<#
	.SYNOPSIS
		Union-merge a target Users CSV with the current run's freshly-emitted Users CSV.

	.DESCRIPTION
		Post-Python helper for -AppendUserInfo. Reads both files and writes a single union
		CSV. By default the union is written in place of the current-run CSV (legacy
		behavior). Pass -OutputPath to direct the union to a third path so the current-run
		CSV remains pristine (the pristine-raw separation pattern used by -AppendUserInfo).
		Semantics:
		  - Retained users (in BOTH): keep target's UserKey + Date_Added; In_Latest_Append=TRUE.
		  - New users (only in current run): mint Date_Added=today; In_Latest_Append=TRUE.
		  - Departed users (only in target): carry target row forward; In_Latest_Append=FALSE.
		  - Latest_Append_Date stamped today on every row.
		  - TotalEmployees recomputed across the union and rewritten on every row.

		Atomic rewrite: writes to '<output>.merging' then renames over the output path.

	.OUTPUTS
		Hashtable with stats (Retained / New / Departed / Union).
	#>
	[CmdletBinding()]
	param(
		[Parameter(Mandatory)] [string] $TargetUsersCsv,
		[Parameter(Mandatory)] [string] $CurrentUsersCsv,
		[Parameter()]          [string] $OutputPath,
		[Parameter()]          [string] $RunDate = (Get-Date -Format 'yyyy-MM-dd')
	)
	if (-not (Test-Path -LiteralPath $CurrentUsersCsv -PathType Leaf)) {
		throw "Merge-UsersCsv: current Users CSV not found: '$CurrentUsersCsv'"
	}
	if ([string]::IsNullOrWhiteSpace($OutputPath)) { $OutputPath = $CurrentUsersCsv }
	# Use script:Import-CsvDeduped instead of Import-Csv: a round-tripped Users CSV
	# can contain duplicate header columns (e.g. both pre-rename 'userPrincipalName'
	# and post-rename 'PersonId') which crashes Import-Csv with "member already
	# present". The helper rewrites the header to dedupe (suffixing later dupes
	# with _dup2/_dup3) before parsing.
	$targetRows = @()
	if (Test-Path -LiteralPath $TargetUsersCsv -PathType Leaf) {
		$targetRows = @(script:Import-CsvDeduped -LiteralPath $TargetUsersCsv)
	}
	# Schema-narrowing warning. The only header we strictly require on the target
	# is the dedup key (PersonId_Normalized) — without it the union cannot
	# correctly classify Retained vs New vs Departed. Display / enrichment
	# columns (userPrincipalName, mail, id, displayName, UserKey) are intentionally
	# renamed or surrogate-replaced by the rollup processor (e.g. userPrincipalName
	# → PersonId on the rolled-up Users CSV), so checking for them here would
	# produce false-positive warnings on every rollup-shape seed. Header union
	# handles legitimately absent display columns gracefully (target rows get
	# blanks for current-only fields; current rows get blanks for target-only
	# fields).
	#
	# Derive PersonId_Normalized on-the-fly when absent or empty: the raw
	# 47-column EntraUsers CSV emitted by the M365 bundle path does NOT carry
	# this column (it is added only by the CopilotInteraction Python rollup at
	# L4651). Without derivation, both target and current dedup indexes stay
	# empty on M365-bundle append runs and the seed content is silently dropped
	# from the union. Fallback chain: PersonId_Normalized -> userPrincipalName
	# -> PersonId, each lower+trim (matches the Python normalization exactly).
	$_normPid = {
		param($row)
		$v = $row.PSObject.Properties['PersonId_Normalized']
		if ($v -and -not [string]::IsNullOrWhiteSpace([string]$v.Value)) { return ([string]$v.Value).Trim().ToLowerInvariant() }
		$v = $row.PSObject.Properties['userPrincipalName']
		if ($v -and -not [string]::IsNullOrWhiteSpace([string]$v.Value)) { return ([string]$v.Value).Trim().ToLowerInvariant() }
		$v = $row.PSObject.Properties['PersonId']
		if ($v -and -not [string]::IsNullOrWhiteSpace([string]$v.Value)) { return ([string]$v.Value).Trim().ToLowerInvariant() }
		return ''
	}
	$currentRows = @(script:Import-CsvDeduped -LiteralPath $CurrentUsersCsv)

	$targetByPid       = @{}
	$targetDerivedCnt  = 0
	foreach ($r in $targetRows) {
		$personId = & $_normPid $r
		if ([string]::IsNullOrWhiteSpace($personId)) { continue }
		$existing = $r.PSObject.Properties['PersonId_Normalized']
		if (-not $existing -or [string]::IsNullOrWhiteSpace([string]$existing.Value)) {
			$r | Add-Member -NotePropertyName 'PersonId_Normalized' -NotePropertyValue $personId -Force
			$targetDerivedCnt++
		}
		if (-not $targetByPid.ContainsKey($personId)) { $targetByPid[$personId] = $r }
	}
	$currentByPid      = @{}
	$currentDerivedCnt = 0
	foreach ($r in $currentRows) {
		$personId = & $_normPid $r
		if ([string]::IsNullOrWhiteSpace($personId)) { continue }
		$existing = $r.PSObject.Properties['PersonId_Normalized']
		if (-not $existing -or [string]::IsNullOrWhiteSpace([string]$existing.Value)) {
			$r | Add-Member -NotePropertyName 'PersonId_Normalized' -NotePropertyValue $personId -Force
			$currentDerivedCnt++
		}
		if (-not $currentByPid.ContainsKey($personId)) { $currentByPid[$personId] = $r }
	}
	# Surface the derivation result so the run log is auditable. The warning
	# only fires now when derivation truly failed for every target row (no
	# usable dedup field anywhere on the seed) — in that case the union really
	# does fall back to current-run-only and the operator needs to know.
	if ($targetRows.Count -gt 0 -and $targetByPid.Count -eq 0) {
		Write-LogHost (
			("WARNING: Merge-UsersCsv: target Users CSV has no derivable dedup key (PersonId_Normalized / userPrincipalName / PersonId are all empty on every row). " +
			 "Cannot classify Retained / New / Departed; the union will contain only the current-run rows. " +
			 "Target: {0}") -f $TargetUsersCsv
		) -ForegroundColor Yellow
	}
	elseif ($targetDerivedCnt -gt 0 -or $currentDerivedCnt -gt 0) {
		Write-LogHost (
			"Merge-UsersCsv: derived PersonId_Normalized on the fly (target rows: {0}, current rows: {1}) — column was absent on the seed/raw shape (expected for M365-bundle EntraUsers CSVs)." -f $targetDerivedCnt, $currentDerivedCnt
		) -ForegroundColor Cyan
	}

	# Header union: preserve current-run order, then append target-only columns, then provenance.
	$hdrSet   = [System.Collections.Generic.HashSet[string]]::new([System.StringComparer]::OrdinalIgnoreCase)
	$hdrOrder = New-Object System.Collections.Generic.List[string]
	if ($currentRows.Count -gt 0) {
		foreach ($p in $currentRows[0].PSObject.Properties) {
			if ($hdrSet.Add($p.Name)) { $hdrOrder.Add($p.Name) }
		}
	}
	if ($targetRows.Count -gt 0) {
		foreach ($p in $targetRows[0].PSObject.Properties) {
			if ($hdrSet.Add($p.Name)) { $hdrOrder.Add($p.Name) }
		}
	}
	foreach ($c in @('Date_Added','Latest_Append_Date','In_Latest_Append')) {
		if ($hdrSet.Add($c)) { $hdrOrder.Add($c) }
	}

	$merged = New-Object System.Collections.Generic.List[psobject]

	# 1. Current-run rows (retained + new).
	foreach ($r in $currentRows) {
		$personId = $r.PersonId_Normalized
		$obj = [ordered]@{}
		foreach ($c in $hdrOrder) { $obj[$c] = '' }
		foreach ($p in $r.PSObject.Properties) { $obj[$p.Name] = $p.Value }

		if ($personId -and $targetByPid.ContainsKey($personId)) {
			$tr = $targetByPid[$personId]
			# Target's UserKey wins (continuity across runs).
			if ($tr.UserKey -and -not [string]::IsNullOrWhiteSpace([string]$tr.UserKey)) {
				$obj['UserKey'] = $tr.UserKey
			}
			$tda = $tr.PSObject.Properties['Date_Added']
			if ($tda -and -not [string]::IsNullOrWhiteSpace([string]$tda.Value)) {
				$obj['Date_Added'] = $tda.Value
			} else {
				# Target lacked Date_Added — first-seen today.
				$obj['Date_Added'] = $RunDate
			}
		} else {
			$obj['Date_Added'] = $RunDate
		}
		$obj['Latest_Append_Date'] = $RunDate
		$obj['In_Latest_Append']   = 'TRUE'
		$merged.Add([pscustomobject]$obj)
	}

	# 2. Departed users (in target, not in current).
	$departedCount = 0
	foreach ($personId in $targetByPid.Keys) {
		if ($currentByPid.ContainsKey($personId)) { continue }
		$tr = $targetByPid[$personId]
		$obj = [ordered]@{}
		foreach ($c in $hdrOrder) { $obj[$c] = '' }
		foreach ($p in $tr.PSObject.Properties) { $obj[$p.Name] = $p.Value }
		$tda = $tr.PSObject.Properties['Date_Added']
		if (-not $tda -or [string]::IsNullOrWhiteSpace([string]$tda.Value)) {
			$obj['Date_Added'] = $RunDate
		}
		$obj['Latest_Append_Date'] = $RunDate
		$obj['In_Latest_Append']   = 'FALSE'
		$merged.Add([pscustomobject]$obj)
		$departedCount++
	}

	# 3. Recompute TotalEmployees over the union.
	$unionCount = $merged.Count
	if ($hdrSet.Contains('TotalEmployees')) {
		foreach ($r in $merged) { $r.TotalEmployees = "$unionCount" }
	}

	# 4. Atomic rewrite.
	$tmpPath = "$OutputPath.merging"
	$hdrArray = [string[]]$hdrOrder.ToArray()
	$merged | Select-Object -Property $hdrArray | Export-Csv -LiteralPath $tmpPath -NoTypeInformation -Encoding UTF8
	Move-Item -LiteralPath $tmpPath -Destination $OutputPath -Force

	$retainedCount = 0
	$newCount      = 0
	foreach ($personId in $currentByPid.Keys) {
		if ($targetByPid.ContainsKey($personId)) { $retainedCount++ } else { $newCount++ }
	}

	return @{
		Retained = $retainedCount
		New      = $newCount
		Departed = $departedCount
		Union    = $unionCount
	}
}

function Merge-FactCsv {
	<#
	.SYNOPSIS
		Union-merge a target Interactions/Fact CSV with the current run's freshly-emitted Fact CSV.

	.DESCRIPTION
		Post-Python helper for -AppendFile. Mirrors Merge-UsersCsv semantics but for the
		fact CSV. Keyed on -KeyColumn (default 'Message_Id_Raw' for the rollup Fact CSV;
		pass 'RecordId' for the raw audit CSV used by non-rollup -AppendFile). By default
		the union is written in place of the current-run CSV (rollup semantics). Pass
		-OutputPath to direct the union to a third path so the current-run CSV remains
		pristine (the pristine-raw separation pattern used by non-rollup -AppendFile).

		When -KeyColumn is 'Message_Id_Raw' the target's Message_Id INT is carried
		forward on retained rows (continuity across runs). For any other key column the
		current-run row's values are taken verbatim (target serves only as the source
		of departed rows).

		Atomic rewrite: writes to '<output>.merging' then renames over the output path.

	.OUTPUTS
		Hashtable with stats (Retained / New / Departed / Union).
	#>
	[CmdletBinding()]
	param(
		[Parameter(Mandatory)] [string] $TargetFactCsv,
		[Parameter(Mandatory)] [string] $CurrentFactCsv,
		[Parameter()]          [string] $OutputPath,
		[Parameter()]          [string] $KeyColumn = 'Message_Id_Raw',
		[Parameter()]          [string] $RunDate = (Get-Date -Format 'yyyy-MM-dd')
	)
	if (-not (Test-Path -LiteralPath $CurrentFactCsv -PathType Leaf)) {
		throw "Merge-FactCsv: current Fact CSV not found: '$CurrentFactCsv'"
	}
	if ([string]::IsNullOrWhiteSpace($OutputPath)) { $OutputPath = $CurrentFactCsv }
	# Use script:Import-CsvDeduped for header-dupe safety (parallel to Merge-UsersCsv).
	$targetRows = @()
	if (Test-Path -LiteralPath $TargetFactCsv -PathType Leaf) {
		$targetRows = @(script:Import-CsvDeduped -LiteralPath $TargetFactCsv)
	}
	# Schema-narrowing warning. The only header we strictly require on the target
	# is the dedup key (-KeyColumn) — without it the union cannot correctly
	# classify Retained vs New vs Departed. Display / enrichment columns
	# (PersonId_Normalized, ThreadId, Message_Id, etc.) are intentionally renamed
	# or surrogate-replaced by the rollup processor on the rolled-up Fact CSV, so
	# checking for them here would produce false-positive warnings on every
	# rollup-shape seed. Header union handles legitimately absent display columns
	# gracefully (target rows get blanks for current-only fields; current rows
	# get blanks for target-only fields).
	if ($targetRows.Count -gt 0) {
		$targetHeaders = @($targetRows[0].PSObject.Properties.Name)
		if ($KeyColumn -notin $targetHeaders) {
			Microsoft.PowerShell.Utility\Write-Host (
				("WARNING: Merge-FactCsv: target Fact CSV is missing dedup key column '{0}'. " +
				 "Cannot classify Retained / New / Departed rows reliably; treating ALL current-run rows as New. " +
				 "Target: {1}") -f $KeyColumn, $TargetFactCsv
			) -ForegroundColor Yellow
		}
	}
	$currentRows = @(script:Import-CsvDeduped -LiteralPath $CurrentFactCsv)

	$targetByKey  = @{}
	foreach ($r in $targetRows) {
		$kProp = $r.PSObject.Properties[$KeyColumn]
		$k = if ($kProp) { $kProp.Value } else { $null }
		if (-not [string]::IsNullOrWhiteSpace([string]$k) -and -not $targetByKey.ContainsKey([string]$k)) {
			$targetByKey[[string]$k] = $r
		}
	}
	$currentByKey = @{}
	foreach ($r in $currentRows) {
		$kProp = $r.PSObject.Properties[$KeyColumn]
		$k = if ($kProp) { $kProp.Value } else { $null }
		if (-not [string]::IsNullOrWhiteSpace([string]$k) -and -not $currentByKey.ContainsKey([string]$k)) {
			$currentByKey[[string]$k] = $r
		}
	}

	# Header union: preserve current-run order, then append target-only columns, then provenance.
	$hdrSet   = [System.Collections.Generic.HashSet[string]]::new([System.StringComparer]::OrdinalIgnoreCase)
	$hdrOrder = New-Object System.Collections.Generic.List[string]
	if ($currentRows.Count -gt 0) {
		foreach ($p in $currentRows[0].PSObject.Properties) {
			if ($hdrSet.Add($p.Name)) { $hdrOrder.Add($p.Name) }
		}
	}
	if ($targetRows.Count -gt 0) {
		foreach ($p in $targetRows[0].PSObject.Properties) {
			if ($hdrSet.Add($p.Name)) { $hdrOrder.Add($p.Name) }
		}
	}
	foreach ($c in @('Date_Added','Latest_Append_Date','In_Latest_Append')) {
		if ($hdrSet.Add($c)) { $hdrOrder.Add($c) }
	}

	$merged = New-Object System.Collections.Generic.List[psobject]

	# 1. Current-run rows (retained + new).
	foreach ($r in $currentRows) {
		$kProp = $r.PSObject.Properties[$KeyColumn]
		$k = if ($kProp) { [string]$kProp.Value } else { '' }
		$obj = [ordered]@{}
		foreach ($c in $hdrOrder) { $obj[$c] = '' }
		foreach ($p in $r.PSObject.Properties) { $obj[$p.Name] = $p.Value }

		if ($k -and $targetByKey.ContainsKey($k)) {
			$tr = $targetByKey[$k]
			# When dedup-keyed on Message_Id_Raw, target's Message_Id INT wins
			# (continuity across runs; embedded Python seed-mid-map normally aligns
			# this, but enforce here so a seed-prep failure still produces a
			# continuous union). For other key columns (e.g. RecordId on the raw
			# audit CSV) there is no surrogate-INT continuity contract.
			if ($KeyColumn -eq 'Message_Id_Raw') {
				$trMid = $tr.PSObject.Properties['Message_Id']
				if ($trMid -and -not [string]::IsNullOrWhiteSpace([string]$trMid.Value)) {
					$obj['Message_Id'] = $trMid.Value
				}
			}
			$tda = $tr.PSObject.Properties['Date_Added']
			if ($tda -and -not [string]::IsNullOrWhiteSpace([string]$tda.Value)) {
				$obj['Date_Added'] = $tda.Value
			} else {
				$obj['Date_Added'] = $RunDate
			}
		} else {
			$obj['Date_Added'] = $RunDate
		}
		$obj['Latest_Append_Date'] = $RunDate
		$obj['In_Latest_Append']   = 'TRUE'
		$merged.Add([pscustomobject]$obj)
	}

	# 2. Departed rows (in target, not in current).
	$departedCount = 0
	foreach ($k in $targetByKey.Keys) {
		if ($currentByKey.ContainsKey($k)) { continue }
		$tr = $targetByKey[$k]
		$obj = [ordered]@{}
		foreach ($c in $hdrOrder) { $obj[$c] = '' }
		foreach ($p in $tr.PSObject.Properties) { $obj[$p.Name] = $p.Value }
		$tda = $tr.PSObject.Properties['Date_Added']
		if (-not $tda -or [string]::IsNullOrWhiteSpace([string]$tda.Value)) {
			$obj['Date_Added'] = $RunDate
		}
		$obj['Latest_Append_Date'] = $RunDate
		$obj['In_Latest_Append']   = 'FALSE'
		$merged.Add([pscustomobject]$obj)
		$departedCount++
	}

	# 3. Atomic rewrite.
	$unionCount = $merged.Count
	$tmpPath = "$OutputPath.merging"
	$hdrArray = [string[]]$hdrOrder.ToArray()
	$merged | Select-Object -Property $hdrArray | Export-Csv -LiteralPath $tmpPath -NoTypeInformation -Encoding UTF8
	Move-Item -LiteralPath $tmpPath -Destination $OutputPath -Force

	$retainedCount = 0
	$newCount      = 0
	foreach ($k in $currentByKey.Keys) {
		if ($targetByKey.ContainsKey($k)) { $retainedCount++ } else { $newCount++ }
	}

	return @{
		Retained = $retainedCount
		New      = $newCount
		Departed = $departedCount
		Union    = $unionCount
	}
}

function Merge-M365RollupCsv {
	<#
	.SYNOPSIS
		Union-merge a target M365Bundle rollup CSV with the current run's freshly-emitted rollup.

	.DESCRIPTION
		Post-Python helper for -AppendFile in M365Bundle mode. Performs a 9-tuple-keyed
		union-merge with additive counter semantics:

		  Composite key      : (lower(UserId), CreationDate, Operation, Workload,
		                        lower(SourceFileExtension), AppHost, AgentId,
		                        AgentName, ContextType)
		  EventCount         : target + current
		  ItemsAccessedCount : target + current
		  CreationTime       : min(target, current)  (lexicographic on ISO-8601)
		  MaxCreationTime    : max(target, current)
		  IsAgentInteraction : OR  (any TRUE -> TRUE)
		  UserId             : target's casing wins on retained groups (first-seen)

		Schema tolerance: target may be a legacy 9- or 10-column rollup. Missing
		columns are padded with empty strings; IsAgentInteraction defaults to FALSE.

		Atomic rewrite: writes to '<output>.merging' and renames over -OutputPath.
		-OutputPath defaults to -TargetRollupCsv (in-place append semantics).

	.OUTPUTS
		PSCustomObject with stats (Retained / New / Updated / Union).
	#>
	[CmdletBinding()]
	param(
		[Parameter(Mandatory)] [string] $TargetRollupCsv,
		[Parameter(Mandatory)] [string] $CurrentRollupCsv,
		[Parameter()]          [string] $OutputPath
	)

	if (-not (Test-Path -LiteralPath $CurrentRollupCsv -PathType Leaf)) {
		throw "Merge-M365RollupCsv: current rollup CSV not found: '$CurrentRollupCsv'"
	}
	if ([string]::IsNullOrWhiteSpace($OutputPath)) { $OutputPath = $TargetRollupCsv }

	# Canonical 14-column rollup header (order is contractual for downstream sidecar regen).
	$rollupHeader = @(
		'UserId','CreationDate','Operation','Workload','SourceFileExtension',
		'AppHost','EventCount','ItemsAccessedCount','CreationTime','MaxCreationTime',
		'AgentId','AgentName','ContextType','IsAgentInteraction'
	)

	# Project an incoming row onto the 14 canonical columns. Missing columns
	# become '' (except IsAgentInteraction which defaults to 'FALSE' so legacy
	# 9/10-col targets contribute correctly to the OR aggregate).
	$projectRow = {
		param($row)
		$obj = [ordered]@{}
		foreach ($c in $rollupHeader) {
			$p = $row.PSObject.Properties[$c]
			$obj[$c] = if ($p) { [string]$p.Value } else { '' }
		}
		if ([string]::IsNullOrWhiteSpace([string]$obj['IsAgentInteraction'])) {
			$obj['IsAgentInteraction'] = 'FALSE'
		}
		return $obj
	}

	# Composite 9-tuple key (case-folded UserId + SourceFileExtension).
	$makeKey = {
		param($obj)
		$userLc = ([string]$obj['UserId']).ToLowerInvariant()
		$extLc  = ([string]$obj['SourceFileExtension']).ToLowerInvariant()
		'{0}|{1}|{2}|{3}|{4}|{5}|{6}|{7}|{8}' -f `
			$userLc, $obj['CreationDate'], $obj['Operation'], $obj['Workload'], `
			$extLc, $obj['AppHost'], $obj['AgentId'], $obj['AgentName'], $obj['ContextType']
	}

	# Accumulate one (already-projected) row into an existing bucket entry.
	$accumulateInto = {
		param($acc, $obj)
		$accEC = 0; [void][int]::TryParse([string]$acc['EventCount'],         [ref]$accEC)
		$rEC   = 0; [void][int]::TryParse([string]$obj['EventCount'],         [ref]$rEC)
		$accIA = 0; [void][int]::TryParse([string]$acc['ItemsAccessedCount'], [ref]$accIA)
		$rIA   = 0; [void][int]::TryParse([string]$obj['ItemsAccessedCount'], [ref]$rIA)
		$acc['EventCount']         = ($accEC + $rEC).ToString()
		$acc['ItemsAccessedCount'] = ($accIA + $rIA).ToString()
		$rCT  = [string]$obj['CreationTime']
		$rMCT = [string]$obj['MaxCreationTime']
		if (-not [string]::IsNullOrWhiteSpace($rCT)) {
			$accCT = [string]$acc['CreationTime']
			if ([string]::IsNullOrWhiteSpace($accCT) -or ($rCT -lt $accCT)) { $acc['CreationTime'] = $rCT }
		}
		if (-not [string]::IsNullOrWhiteSpace($rMCT)) {
			$accMCT = [string]$acc['MaxCreationTime']
			if ([string]::IsNullOrWhiteSpace($accMCT) -or ($rMCT -gt $accMCT)) { $acc['MaxCreationTime'] = $rMCT }
		}
		if (([string]$obj['IsAgentInteraction']).Equals('TRUE', [System.StringComparison]::OrdinalIgnoreCase)) {
			$acc['IsAgentInteraction'] = 'TRUE'
		}
	}

	# Load inputs.
	$targetRows = @()
	if (Test-Path -LiteralPath $TargetRollupCsv -PathType Leaf) {
		$targetRows = @(script:Import-CsvDeduped -LiteralPath $TargetRollupCsv)
	}
	$currentRows = @(script:Import-CsvDeduped -LiteralPath $CurrentRollupCsv)

	# Schema-narrowing warning for legacy 9/10-col targets.
	if ($targetRows.Count -gt 0) {
		$targetHeaders = @($targetRows[0].PSObject.Properties.Name)
		$missing = @($rollupHeader | Where-Object { $_ -notin $targetHeaders })
		if ($missing.Count -gt 0) {
			Microsoft.PowerShell.Utility\Write-Host (
				("WARNING: Merge-M365RollupCsv: target rollup is missing {0} of the {1} canonical columns " +
				 "({2}). Padding with empty values; IsAgentInteraction defaults to FALSE. " +
				 "Target: {3}") -f $missing.Count, $rollupHeader.Count, ($missing -join ','), $TargetRollupCsv
			) -ForegroundColor Yellow
		}
	}

	# Bucket: composite key -> accumulator ordered hashtable.
	# Seed target rows first so the target's UserId casing wins on retained groups.
	$bucket = [ordered]@{}
	foreach ($r in $targetRows) {
		$obj = & $projectRow $r
		$k   = & $makeKey $obj
		if ($bucket.Contains($k)) {
			& $accumulateInto $bucket[$k] $obj
		} else {
			$bucket[$k] = $obj
		}
	}

	# Snapshot keys present after target-seed (to classify Retained vs New for current rows).
	$targetKeys = [System.Collections.Generic.HashSet[string]]::new([System.StringComparer]::Ordinal)
	foreach ($k in $bucket.Keys) { [void]$targetKeys.Add($k) }

	# Merge in current-run rows.
	$newCount      = 0
	$retainedCount = 0
	$updatedCount  = 0
	foreach ($r in $currentRows) {
		$obj = & $projectRow $r
		$k   = & $makeKey $obj
		if ($bucket.Contains($k)) {
			& $accumulateInto $bucket[$k] $obj
			$updatedCount++
			if ($targetKeys.Contains($k)) { $retainedCount++ }
		} else {
			$bucket[$k] = $obj
			$newCount++
		}
	}

	# Atomic rewrite: write to <out>.merging, rename over $OutputPath.
	$unionCount = $bucket.Count
	$tmpPath = "$OutputPath.merging"
	[pscustomobject[]]$mergedRows = $bucket.Values | ForEach-Object { [pscustomobject]$_ }
	$mergedRows | Select-Object -Property $rollupHeader | Export-Csv -LiteralPath $tmpPath -NoTypeInformation -Encoding UTF8
	Move-Item -LiteralPath $tmpPath -Destination $OutputPath -Force

	return [pscustomobject]@{
		Retained = $retainedCount
		New      = $newCount
		Updated  = $updatedCount
		Union    = $unionCount
	}
}

function Merge-M365SessionStatsCsv {
	<#
	.SYNOPSIS
		Union-merge a target M365Bundle SessionStats CSV with the current run's freshly-emitted SessionStats.

	.DESCRIPTION
		Post-Python helper for -AppendFile in M365Bundle mode. Performs a 3-tuple-keyed
		union-merge with additive counter semantics on the SessionStats sidecar (v2.6.0+):

		  Composite key      : (lower(UserId), CreationDate, AppHost)
		  SessionCount       : target + current
		  PromptCount        : target + current
		  AgentPromptCount   : target + current
		  ResponseCount      : target + current
		  AgentSessionCount  : target + current
		  UserId             : target's casing wins on retained groups (first-seen)

		Schema tolerance: target may be missing one or more counter columns (e.g. a
		pre-2.6.0 placeholder). Missing counters are treated as 0 during accumulation
		and emitted as the union value.

		Atomic rewrite: writes to '<output>.merging' and renames over -OutputPath.
		-OutputPath defaults to -TargetSessionStatsCsv (in-place append semantics).

	.OUTPUTS
		PSCustomObject with stats (Retained / New / Updated / Union).
	#>
	[CmdletBinding()]
	param(
		[Parameter(Mandatory)] [string] $TargetSessionStatsCsv,
		[Parameter(Mandatory)] [string] $CurrentSessionStatsCsv,
		[Parameter()]          [string] $OutputPath
	)

	if (-not (Test-Path -LiteralPath $CurrentSessionStatsCsv -PathType Leaf)) {
		throw "Merge-M365SessionStatsCsv: current SessionStats CSV not found: '$CurrentSessionStatsCsv'"
	}
	if ([string]::IsNullOrWhiteSpace($OutputPath)) { $OutputPath = $TargetSessionStatsCsv }

	# Canonical 8-column SessionStats header (matches SESSIONSTATS_HEADER in the embedded processor).
	$ssHeader = @(
		'UserId','CreationDate','AppHost',
		'SessionCount','PromptCount','AgentPromptCount','ResponseCount','AgentSessionCount'
	)

	# Project an incoming row onto the 8 canonical columns. Missing columns become ''.
	$projectRow = {
		param($row)
		$obj = [ordered]@{}
		foreach ($c in $ssHeader) {
			$p = $row.PSObject.Properties[$c]
			$obj[$c] = if ($p) { [string]$p.Value } else { '' }
		}
		return $obj
	}

	# Composite 3-tuple key (case-folded UserId).
	$makeKey = {
		param($obj)
		$userLc = ([string]$obj['UserId']).ToLowerInvariant()
		'{0}|{1}|{2}' -f $userLc, $obj['CreationDate'], $obj['AppHost']
	}

	# Accumulate one (already-projected) row into an existing bucket entry.
	$accumulateInto = {
		param($acc, $obj)
		foreach ($col in @('SessionCount','PromptCount','AgentPromptCount','ResponseCount','AgentSessionCount')) {
			$accV = 0; [void][int]::TryParse([string]$acc[$col], [ref]$accV)
			$rV   = 0; [void][int]::TryParse([string]$obj[$col], [ref]$rV)
			$acc[$col] = ($accV + $rV).ToString()
		}
	}

	# Load inputs.
	$targetRows = @()
	if (Test-Path -LiteralPath $TargetSessionStatsCsv -PathType Leaf) {
		$targetRows = @(script:Import-CsvDeduped -LiteralPath $TargetSessionStatsCsv)
	}
	$currentRows = @(script:Import-CsvDeduped -LiteralPath $CurrentSessionStatsCsv)

	# Schema-narrowing warning for legacy targets missing canonical columns.
	if ($targetRows.Count -gt 0) {
		$targetHeaders = @($targetRows[0].PSObject.Properties.Name)
		$missing = @($ssHeader | Where-Object { $_ -notin $targetHeaders })
		if ($missing.Count -gt 0) {
			Microsoft.PowerShell.Utility\Write-Host (
				("WARNING: Merge-M365SessionStatsCsv: target SessionStats is missing {0} of the {1} canonical columns " +
				 "({2}). Padding with empty values; missing counters treated as 0. Target: {3}") `
				-f $missing.Count, $ssHeader.Count, ($missing -join ','), $TargetSessionStatsCsv
			) -ForegroundColor Yellow
		}
	}

	# Bucket: composite key -> accumulator ordered hashtable.
	# Seed target rows first so the target's UserId casing wins on retained groups.
	$bucket = [ordered]@{}
	foreach ($r in $targetRows) {
		$obj = & $projectRow $r
		$k   = & $makeKey $obj
		if ($bucket.Contains($k)) {
			& $accumulateInto $bucket[$k] $obj
		} else {
			$bucket[$k] = $obj
		}
	}

	# Snapshot keys present after target-seed (to classify Retained vs New for current rows).
	$targetKeys = [System.Collections.Generic.HashSet[string]]::new([System.StringComparer]::Ordinal)
	foreach ($k in $bucket.Keys) { [void]$targetKeys.Add($k) }

	# Merge in current-run rows.
	$newCount      = 0
	$retainedCount = 0
	$updatedCount  = 0
	foreach ($r in $currentRows) {
		$obj = & $projectRow $r
		$k   = & $makeKey $obj
		if ($bucket.Contains($k)) {
			& $accumulateInto $bucket[$k] $obj
			$updatedCount++
			if ($targetKeys.Contains($k)) { $retainedCount++ }
		} else {
			$bucket[$k] = $obj
			$newCount++
		}
	}

	# Atomic rewrite: write to <out>.merging, rename over $OutputPath.
	$unionCount = $bucket.Count
	$tmpPath = "$OutputPath.merging"
	[pscustomobject[]]$mergedRows = $bucket.Values | ForEach-Object { [pscustomobject]$_ }
	$mergedRows | Select-Object -Property $ssHeader | Export-Csv -LiteralPath $tmpPath -NoTypeInformation -Encoding UTF8
	Move-Item -LiteralPath $tmpPath -Destination $OutputPath -Force

	return [pscustomobject]@{
		Retained = $retainedCount
		New      = $newCount
		Updated  = $updatedCount
		Union    = $unionCount
	}
}

function Convert-CsvToDelta {
	<#
	.SYNOPSIS
		Convert a local CSV file to a Delta Lake table at a OneLake DFS URI (or local path).

	.DESCRIPTION
		Invokes Python with the 'deltalake' package to read the CSV with pyarrow and write
		it as a Delta table at the destination. Used by the rollup post-processor to land
		Fabric Lakehouse Tables/ outputs after the embedded Python processor has written
		the canonical CSV.

		Supports two destination forms:
		  • Local path (file:// or absolute path) — used for unit testing and for the
		    pre-publish stage when -OutputPath resolves to a Fabric OneLake URL.
		  • OneLake DFS URL (https://<workspace>-onelake.dfs.fabric.microsoft.com/.../Tables/<name>)
		    — used directly for Fabric Lakehouse Tables/ destinations. The caller supplies
		    a bearer token (OneLake storage audience).

		Schema evolution: write_deltalake is called with schema_mode='merge' so additive
		column changes do not require a full overwrite. The mode itself is the caller's
		choice (overwrite for first run, append for subsequent appends).

	.PARAMETER InputCsv
		Local path to the source CSV. Must exist and be UTF-8 encoded.

	.PARAMETER TargetUri
		Destination Delta table URI. Either a local absolute path or a OneLake DFS https URL.

	.PARAMETER Mode
		Delta write mode: 'overwrite' or 'append'. Defaults to 'overwrite'.

	.PARAMETER BearerToken
		Optional OneLake storage-audience access token. Required when TargetUri is a
		Fabric DFS URL. Ignored for local destinations.

	.PARAMETER PythonExe
		Resolved Python interpreter path (from Resolve-PythonExe).

	.PARAMETER LauncherArgs
		Launcher arguments (e.g. py -3 prefix) for the resolved interpreter.

	.OUTPUTS
		$true on success, $false on failure (errors are logged via Write-LogHost).
	#>
	[CmdletBinding()]
	param(
		[Parameter(Mandatory)] [string]   $InputCsv,
		[Parameter(Mandatory)] [string]   $TargetUri,
		[Parameter()] [ValidateSet('overwrite','append')] [string] $Mode = 'overwrite',
		[Parameter()] [string]            $BearerToken = '',
		[Parameter(Mandatory)] [string]   $PythonExe,
		[Parameter(Mandatory)] [AllowEmptyCollection()] [string[]] $LauncherArgs
	)
	if (-not (Test-Path -LiteralPath $InputCsv -PathType Leaf)) {
		Write-LogHost "Convert-CsvToDelta: input CSV not found: '$InputCsv'" -ForegroundColor Red
		return $false
	}
	# Inline Python: pyarrow reads CSV, deltalake writes table. Storage options only
	# when TargetUri is a remote OneLake URL. Column names are sanitized to satisfy
	# Delta's forbidden-character set (' ,;{}()\n\t='); the source CSV on disk is
	# left unchanged so PBIP semantic models that read the CSV directly continue
	# to bind by the original column names.
	$inlinePy = @"
import os, sys, json, re
in_csv  = os.environ['PAX_DELTA_IN']
out_uri = os.environ['PAX_DELTA_OUT']
mode    = os.environ['PAX_DELTA_MODE']
token   = os.environ.get('PAX_DELTA_TOKEN', '')
try:
    import pyarrow.csv as pacsv
    from deltalake import write_deltalake
except Exception as e:
    print(f'Convert-CsvToDelta: import failed: {e}', file=sys.stderr)
    sys.exit(2)
# Delta forbids these characters in column names; the Fabric SQL endpoint also
# rejects spaces in column names. Replace each with an underscore. Collisions
# after sanitization (e.g., two source columns differing only in a forbidden
# character) are disambiguated by appending _2, _3, ... . The disambiguated
# name is also recorded so a later raw column whose sanitized form literally
# matches an earlier disambiguated name cannot silently map to the same Delta
# column.
_DELTA_FORBIDDEN = re.compile(r'[ ,;\{\}\(\)\n\t=]')
def _sanitize_col_names(cols):
    seen = {}
    out = []
    for c in cols:
        s = _DELTA_FORBIDDEN.sub('_', c)
        if s in seen:
            seen[s] += 1
            candidate = f'{s}_{seen[s]}'
            while candidate in seen:
                seen[s] += 1
                candidate = f'{s}_{seen[s]}'
            s = candidate
            seen[s] = 1
        else:
            seen[s] = 1
        out.append(s)
    return out
try:
    # All-string read avoids per-column inference mismatches between runs; the
    # Lakehouse semantic model casts at query time.
    table = pacsv.read_csv(
        in_csv,
        convert_options=pacsv.ConvertOptions(strings_can_be_null=False),
    )
    cols = table.column_names
    safe_cols = _sanitize_col_names(cols)
    import pyarrow as pa
    table = pa.Table.from_arrays([table.column(c).cast(pa.string()) for c in cols], names=safe_cols)
    storage_options = None
    if out_uri.startswith('https://') or out_uri.startswith('abfss://'):
        if not token:
            print('Convert-CsvToDelta: remote target requires a bearer token', file=sys.stderr)
            sys.exit(3)
        storage_options = {'bearer_token': token, 'use_fabric_endpoint': 'true'}
    write_deltalake(
        out_uri,
        table,
        mode=mode,
        schema_mode='merge',
        storage_options=storage_options,
    )
    print(f'Convert-CsvToDelta: wrote {table.num_rows} rows to {out_uri} (mode={mode})')
except Exception as e:
    print(f'Convert-CsvToDelta: write failed: {e}', file=sys.stderr)
    sys.exit(4)
"@
	$env:PAX_DELTA_IN   = $InputCsv
	$env:PAX_DELTA_OUT  = $TargetUri
	$env:PAX_DELTA_MODE = $Mode
	$env:PAX_DELTA_TOKEN = $BearerToken
	try {
		$fullArgs = @($LauncherArgs) + @('-c', $inlinePy)
		& $PythonExe @fullArgs 2>&1 | ForEach-Object { Write-Log $_ }
		$exit = $LASTEXITCODE
	}
	finally {
		Remove-Item Env:\PAX_DELTA_IN -ErrorAction SilentlyContinue
		Remove-Item Env:\PAX_DELTA_OUT -ErrorAction SilentlyContinue
		Remove-Item Env:\PAX_DELTA_MODE -ErrorAction SilentlyContinue
		Remove-Item Env:\PAX_DELTA_TOKEN -ErrorAction SilentlyContinue
	}
	if ($exit -eq 0) { return $true }
	Write-LogHost "Convert-CsvToDelta: Python exited $exit (input='$InputCsv', target='$TargetUri', mode=$Mode)." -ForegroundColor Red
	return $false
}

function Test-DeltaTableSchemaCompat {
	<#
	.SYNOPSIS
		Pre-flight check: confirm an existing Delta table at TargetUri has a column set
		compatible with the CSV the caller is about to convert.

	.DESCRIPTION
		Reads the Delta table's schema (column names only — types are all strings in our
		write path) and compares against the CSV header. Compatible = every existing-table
		column is present in the new CSV (schema_mode='merge' will additively expand it).
		Incompatible = at least one existing column is absent from the new CSV (would
		require a destructive overwrite-with-different-schema).

		Returns a hashtable: { Compatible=<bool>, ExistingCols=[], NewCols=[], Missing=[] }.
		When the Delta table does not yet exist, returns Compatible=$true with empty arrays.

	.PARAMETER TargetUri
		Delta table URI (local path or OneLake DFS URL).

	.PARAMETER NewCsv
		Local CSV whose header is the proposed new schema.

	.PARAMETER BearerToken
		Optional OneLake storage-audience token for remote URIs.

	.PARAMETER PythonExe
		Resolved Python interpreter.

	.PARAMETER LauncherArgs
		Launcher prefix args.
	#>
	[CmdletBinding()]
	param(
		[Parameter(Mandatory)] [string]   $TargetUri,
		[Parameter(Mandatory)] [string]   $NewCsv,
		[Parameter()] [string]            $BearerToken = '',
		[Parameter(Mandatory)] [string]   $PythonExe,
		[Parameter(Mandatory)] [AllowEmptyCollection()] [string[]] $LauncherArgs
	)
	if (-not (Test-Path -LiteralPath $NewCsv -PathType Leaf)) {
		return @{ Compatible = $false; ExistingCols = @(); NewCols = @(); Missing = @(); Error = "New CSV not found: '$NewCsv'" }
	}
	$inlinePy = @"
import os, sys, json, csv, re
target  = os.environ['PAX_DELTA_OUT']
new_csv = os.environ['PAX_DELTA_IN']
token   = os.environ.get('PAX_DELTA_TOKEN', '')
try:
    from deltalake import DeltaTable
except Exception as e:
    print(json.dumps({'error': f'import: {e}'}))
    sys.exit(0)
# Must match the sanitization applied by Convert-CsvToDelta — otherwise the
# compat probe would compare sanitized stored names against unsanitized CSV
# headers and always report drift.
_DELTA_FORBIDDEN = re.compile(r'[ ,;\{\}\(\)\n\t=]')
def _sanitize_col_names(cols):
    seen = {}
    out = []
    for c in cols:
        s = _DELTA_FORBIDDEN.sub('_', c)
        if s in seen:
            seen[s] += 1
            candidate = f'{s}_{seen[s]}'
            while candidate in seen:
                seen[s] += 1
                candidate = f'{s}_{seen[s]}'
            s = candidate
            seen[s] = 1
        else:
            seen[s] = 1
        out.append(s)
    return out
try:
    with open(new_csv, 'r', encoding='utf-8-sig', newline='') as f:
        rdr = csv.reader(f)
        new_cols = _sanitize_col_names(next(rdr, []))
except Exception as e:
    print(json.dumps({'error': f'csv-header: {e}'}))
    sys.exit(0)
storage_options = None
if target.startswith('https://') or target.startswith('abfss://'):
    if token:
        storage_options = {'bearer_token': token, 'use_fabric_endpoint': 'true'}
try:
    dt = DeltaTable(target, storage_options=storage_options)
    existing = [f.name for f in dt.schema().fields]
except Exception:
    print(json.dumps({'existing': [], 'new': new_cols, 'exists': False}))
    sys.exit(0)
print(json.dumps({'existing': existing, 'new': new_cols, 'exists': True}))
"@
	$env:PAX_DELTA_OUT   = $TargetUri
	$env:PAX_DELTA_IN    = $NewCsv
	$env:PAX_DELTA_TOKEN = $BearerToken
	$outJson = ''
	try {
		$fullArgs = @($LauncherArgs) + @('-c', $inlinePy)
		$outJson = (& $PythonExe @fullArgs 2>&1 | Out-String).Trim()
	}
	finally {
		Remove-Item Env:\PAX_DELTA_OUT -ErrorAction SilentlyContinue
		Remove-Item Env:\PAX_DELTA_IN -ErrorAction SilentlyContinue
		Remove-Item Env:\PAX_DELTA_TOKEN -ErrorAction SilentlyContinue
	}
	try {
		$parsed = $outJson | ConvertFrom-Json -ErrorAction Stop
	} catch {
		return @{ Compatible = $false; ExistingCols = @(); NewCols = @(); Missing = @(); Error = "Could not parse schema probe output: $outJson" }
	}
	if ($parsed.PSObject.Properties['error']) {
		return @{ Compatible = $false; ExistingCols = @(); NewCols = @(); Missing = @(); Error = [string]$parsed.error }
	}
	$existing = @($parsed.existing)
	$newCols  = @($parsed.new)
	if (-not $parsed.exists) {
		return @{ Compatible = $true; ExistingCols = $existing; NewCols = $newCols; Missing = @() }
	}
	$newSet = [System.Collections.Generic.HashSet[string]]::new([string[]]$newCols, [System.StringComparer]::OrdinalIgnoreCase)
	$missing = @($existing | Where-Object { -not $newSet.Contains($_) })
	$compatible = ($missing.Count -eq 0)
	return @{ Compatible = $compatible; ExistingCols = $existing; NewCols = $newCols; Missing = $missing }
}

function Write-DeltaAppend {
	<#
	.SYNOPSIS
		Append a local CSV to a Delta table (Fabric Lakehouse Tables/ or local), creating
		the table if it does not yet exist. Hard-errors on destructive schema drift.

	.DESCRIPTION
		Thin wrapper around Test-DeltaTableSchemaCompat + Convert-CsvToDelta:
		  1. Probe the target Delta schema. If unreachable due to nonexistent table,
		     fall through to Convert-CsvToDelta with mode='append' (deltalake creates
		     the table on first write). The returned object's IsInit flag is set so
		     callers can label the banner '[append-init]'.
		  2. If the table exists, refuse the write when any existing column is absent
		     from the new CSV header (column removal / type narrowing). Additive new
		     columns are absorbed via schema_mode='merge'.
		  3. On compatible schema, invoke Convert-CsvToDelta -Mode append.

	.OUTPUTS
		Hashtable: { Success=<bool>, IsInit=<bool>, AddedCols=[], Missing=[], Error=<string?> }.
	#>
	[CmdletBinding()]
	param(
		[Parameter(Mandatory)] [string]   $InputCsv,
		[Parameter(Mandatory)] [string]   $TargetUri,
		[Parameter()] [string]            $BearerToken = '',
		[Parameter(Mandatory)] [string]   $PythonExe,
		[Parameter(Mandatory)] [AllowEmptyCollection()] [string[]] $LauncherArgs
	)
	if (-not (Test-Path -LiteralPath $InputCsv -PathType Leaf)) {
		return @{ Success = $false; IsInit = $false; AddedCols = @(); Missing = @(); Error = "Input CSV not found: '$InputCsv'" }
	}
	$probe = Test-DeltaTableSchemaCompat -TargetUri $TargetUri -NewCsv $InputCsv -BearerToken $BearerToken -PythonExe $PythonExe -LauncherArgs $LauncherArgs
	$isInit = (-not ($probe.ExistingCols -and @($probe.ExistingCols).Count -gt 0))
	if (-not $probe.Compatible -and -not $isInit) {
		$missingList = ($probe.Missing -join ', ')
		$msg = "Write-DeltaAppend: destructive schema drift rejected. Existing column(s) not present in source CSV: $missingList"
		Write-LogHost $msg -ForegroundColor Red
		return @{ Success = $false; IsInit = $false; AddedCols = @(); Missing = @($probe.Missing); Error = $msg }
	}
	$existingSet = if ($probe.ExistingCols) { [System.Collections.Generic.HashSet[string]]::new([string[]]@($probe.ExistingCols), [System.StringComparer]::OrdinalIgnoreCase) } else { [System.Collections.Generic.HashSet[string]]::new([System.StringComparer]::OrdinalIgnoreCase) }
	$addedCols = @(@($probe.NewCols) | Where-Object { -not $existingSet.Contains($_) })
	$ok = Convert-CsvToDelta -InputCsv $InputCsv -TargetUri $TargetUri -Mode 'append' -BearerToken $BearerToken -PythonExe $PythonExe -LauncherArgs $LauncherArgs
	if (-not $ok) {
		return @{ Success = $false; IsInit = $isInit; AddedCols = $addedCols; Missing = @(); Error = 'Convert-CsvToDelta returned failure.' }
	}
	$tag = if ($isInit) { '[append-init]' } else { '[append]' }
	$colNote = if ($addedCols.Count -gt 0) { (" (added columns: {0})" -f ($addedCols -join ', ')) } else { '' }
	Write-LogHost "Write-DeltaAppend: $tag '$TargetUri'$colNote" -ForegroundColor Green
	return @{ Success = $true; IsInit = $isInit; AddedCols = $addedCols; Missing = @() }
}

# ============================================================================
# REMOTE OUTPUT HELPERS — SharePoint (Graph drives API) and Fabric (OneLake DFS)
# ----------------------------------------------------------------------------
# All helpers are no-ops when $script:RemoteOutputMode -eq 'None'. They are
# invoked from a single dispatch point: Invoke-OutputUpload.
#
# SharePoint path:
#   - Reuses the existing Connect-MgGraph token (Graph audience).
#   - Resolves the SP URL to siteId/driveId/folder via Graph site lookup.
#   - Files <= 250 MB: PUT /drives/{driveId}/root:/path:/content (Graph simple-upload max)
#   - Larger files: createUploadSession + 5 MB chunked PUT (must be 320 KB-aligned).
#
# Fabric/OneLake path:
#   - Uses a SEPARATE token with audience https://storage.azure.com/ (Az.Accounts).
#   - DFS Create -> Append (chunked) -> Flush. Path = /<workspace>/<item>.Lakehouse/Files/<rel>
# ============================================================================

function Get-DisplayPath {
	<#
	.SYNOPSIS
		Returns the user-visible path to display for an output artifact, accounting for
		a SharePoint or OneLake -OutputPath* value. Local-output runs see the local path unchanged;
		remote-output runs see the destination URL the file is uploaded to.

	.DESCRIPTION
		Every "Output File: ...", "Output Directory: ...", "Log file: ..." line in the
		console / log banner should be filtered through this helper. The local scratch
		path is irrelevant to a customer who passed a SharePoint or OneLake -OutputPath*;
		showing it implies the artifact lives there, which it does not (it is uploaded
		then, on success, the local copy is reaped).

		File mode (default): appends the local file's leaf name to the remote root URL.
		-Directory mode: returns the remote root URL with no leaf appended.

		When $script:RemoteOutputMode -eq 'None' (or remote URL not yet set), the input
		path is returned verbatim — making this safe to call unconditionally at every
		display site.

	.PARAMETER LocalPath
		The local scratch path of the artifact. Required. Can be empty/null.

	.PARAMETER Directory
		If set, treats LocalPath as a directory and returns the remote root URL alone
		(no leaf appended). Use for "Output Directory: <path>" lines.
	#>
	[CmdletBinding()]
	param(
		[Parameter(Mandatory)] [AllowNull()] [AllowEmptyString()] [string] $LocalPath,
		[switch] $Directory
	)
	if ($script:RemoteOutputMode -eq 'None' -or [string]::IsNullOrWhiteSpace($LocalPath) -or [string]::IsNullOrWhiteSpace($script:RemoteOutputUrl)) {
		return $LocalPath
	}
	$base = $script:RemoteOutputUrl.TrimEnd('/')
	if ($Directory) { return $base }
	$leaf = [System.IO.Path]::GetFileName($LocalPath.TrimEnd('\','/'))
	if ([string]::IsNullOrWhiteSpace($leaf)) { return $base }
	# Guard against URL doubling: $RemoteOutputUrl can be either a folder URL
	# (the normal -OutputPath case) or already a full file URL (when promoted
	# from -AppendFile or when -OutputPath was given as a file URL). The
	# upstream normalizer in the param-validation block strips the file leaf
	# from RemoteOutputUrl when it can recognize the extension, but this
	# helper is called from many sites and must remain robust if a caller
	# leaves $base as a file URL.
	#
	# Two doubling cases to defend against:
	#   1) Same name  ('.../foo.csv' + 'foo.csv'  -> '.../foo.csv'        )
	#   2) Sibling    ('.../foo.csv' + 'foo.log'  -> '.../foo.log'        )
	# When $baseLeaf carries a data-artifact extension, strip it before
	# appending $leaf so siblings land in the correct parent folder.
	# .Lakehouse is a folder marker; do NOT strip.
	$baseLeaf = ($base -split '/') | Select-Object -Last 1
	if ($baseLeaf -ieq $leaf) { return $base }
	if ($baseLeaf -match '\.(csv|log|xlsx|json|parquet|txt)$') {
		$base = ($base -replace '/[^/]+$','')
	}
	return ($base + '/' + $leaf)
}

function Resolve-SharePointTarget {
	[CmdletBinding()]
	param([Parameter(Mandatory)] [string] $Url)

	# Accepts any of:
	#   https://<host>/sites/<site>/<library>[/<sub>]
	#   https://<host>/teams/<team>/<library>[/<sub>]
	#   https://<host>/personal/<user>/<library>[/<sub>]
	#   https://<host>/<library>[/<sub>]                  (root site collection)
	# where <host> can be any sharepoint.* tenant variant (sharepoint.com,
	# sharepoint-df.com, sharepoint.us, sharepoint.de, sharepoint.cn,
	# sharepoint-mil.us, ...).
	#
	# The first one or two URL segments identify the site collection; the remainder
	# is library + (optional) folder path. Graph's site-lookup endpoint is the
	# authoritative resolver -- we just hand it the server-relative site path.
	$u = [Uri]$Url
	$hostName = $u.Host
	$segments = ($u.AbsolutePath.TrimStart('/') -split '/') | Where-Object { $_ -ne '' }
	if (-not $segments -or $segments.Count -lt 1) {
		throw "SharePoint URL has no path; expected https://<host>/<sites|teams|personal>/<name>/<library>[/<sub>] : '$Url'"
	}

	# Determine where the site collection ends and the library begins.
	$prefixed = @('sites','teams','personal') -contains $segments[0].ToLower()
	if ($prefixed) {
		if ($segments.Count -lt 3) {
			throw "SharePoint URL is missing a library/folder after the site name: '$Url'"
		}
		$sitePathSegs   = $segments[0..1]   # e.g. sites/Analytics  or  teams/MyTeam
		$libAndFolder   = $segments[2..($segments.Count-1)]
		$siteName       = $segments[1]
	} else {
		# Root site collection: no /sites/ or /teams/ prefix; first segment is the library.
		$sitePathSegs   = @()
		$libAndFolder   = $segments
		$siteName       = '(root)'
	}
	$libraryName     = $libAndFolder[0]
	$folderInLibrary = if ($libAndFolder.Count -gt 1) { ($libAndFolder[1..($libAndFolder.Count-1)]) -join '/' } else { '' }

	# Resolve site via Graph. Site path is server-relative; if root, omit the colon-path.
	if ($sitePathSegs.Count -gt 0) {
		$sitePath      = ($sitePathSegs -join '/')
		$siteLookupUri = "https://graph.microsoft.com/v1.0/sites/${hostName}:/${sitePath}"
	} else {
		$siteLookupUri = "https://graph.microsoft.com/v1.0/sites/${hostName}"
	}
	try {
		$site = Invoke-MgGraphRequest -Method GET -Uri $siteLookupUri -ErrorAction Stop
	} catch {
		# Classify the failure so customers see actionable guidance instead of raw Graph plumbing.
		# We inspect the HTTP status, current Graph context state, and granted scopes to decide
		# the most likely cause. The structured message is consumed by Test-RemoteDestination's
		# error block (which formats the banner with permissions-table back-reference).
		$status = 0
		try { $status = [int]$_.Exception.Response.StatusCode.value__ } catch {}
		if ($status -eq 0) { try { if ($_.Exception.Response.StatusCode -is [System.Net.HttpStatusCode]) { $status = [int]$_.Exception.Response.StatusCode } } catch {} }

		$mgCtx = $null
		try { $mgCtx = Get-MgContext -ErrorAction SilentlyContinue } catch {}
		$hasToken = [bool]$mgCtx
		$grantedScopes = @()
		if ($mgCtx -and $mgCtx.Scopes) { $grantedScopes = @($mgCtx.Scopes) }
		$isAppOnly = $false
		if ($mgCtx) { $isAppOnly = ([string]::IsNullOrWhiteSpace($mgCtx.Account)) -or ($mgCtx.AuthType -eq 'AppOnly') }

		# Surface the raw response body for context (truncated; appended to the classified message).
		$rawDetail = $_.Exception.Message
		try {
			if ($_.ErrorDetails -and $_.ErrorDetails.Message) { $rawDetail = $_.ErrorDetails.Message }
			elseif ($_.Exception.Response) {
				$resp = $_.Exception.Response
				$reader = New-Object System.IO.StreamReader($resp.GetResponseStream())
				$body = $reader.ReadToEnd(); $reader.Close()
				if ($body) { $rawDetail = "HTTP $status $body" }
			}
		} catch {}
		if ($rawDetail.Length -gt 600) { $rawDetail = $rawDetail.Substring(0, 600) + '...(truncated)' }

		# Build the classified diagnosis. Lines are joined with newline so Test-RemoteDestination
		# can split and indent them under its banner.
		$diagLines = New-Object System.Collections.Generic.List[string]
		$diagLines.Add("SharePoint site lookup failed (host '$hostName', site path '$($sitePathSegs -join '/')').")

		if (-not $hasToken) {
			$diagLines.Add('Cause: Microsoft Graph is not connected (no MgContext present).')
			$diagLines.Add('Action: This is unexpected at this point in the script — please report it as a bug.')
		}
		elseif ($status -eq 401) {
			if (-not $isAppOnly -and ($grantedScopes -notcontains 'Sites.ReadWrite.All')) {
				$diagLines.Add('Cause: The Graph access token is missing the Sites.ReadWrite.All scope.')
				$diagLines.Add('Action: Re-run after granting/consenting Sites.ReadWrite.All. See the')
				$diagLines.Add('        "Permissions Required for THIS run" table earlier in this output')
				$diagLines.Add('        for the full list of required scopes for SharePoint output.')
			} else {
				$diagLines.Add('Cause: Graph rejected the token (401). For app-only auth this usually means')
				$diagLines.Add('       application permissions (Sites.ReadWrite.All / Files.ReadWrite.All)')
				$diagLines.Add('       have not been ADMIN-CONSENTED on the app registration / managed identity.')
				$diagLines.Add('Action: Have a Global Administrator grant admin consent to the application')
				$diagLines.Add('        permissions listed in the "Permissions Required for THIS run" table above.')
			}
		}
		elseif ($status -eq 403) {
			$signedIn = if ($mgCtx -and $mgCtx.Account) { $mgCtx.Account } else { '(app identity)' }
			$diagLines.Add("Cause: The signed-in identity ('$signedIn') is authenticated but does not have")
			$diagLines.Add('       access to the target SharePoint site (HTTP 403 Forbidden).')
			$diagLines.Add('Action: In SharePoint, add this identity to the target site as at least Member,')
			$diagLines.Add('        OR re-run with an identity that already has access to the site.')
		}
		elseif ($status -eq 404) {
			$diagLines.Add("Cause: The site was not found on host '$hostName' (HTTP 404).")
			$diagLines.Add('Action: Verify the URL was copied via SharePoint Details -> Path -> Copy.')
			$diagLines.Add('        Check spelling of the /sites/<name> or /teams/<name> segment.')
		}
		elseif ($status -ge 500) {
			$diagLines.Add("Cause: Microsoft Graph returned a server error (HTTP $status). This is usually transient.")
			$diagLines.Add('Action: Wait a minute and retry. If it persists, check https://status.cloud.microsoft.')
		}
		else {
			# Includes name-resolution failures (no HTTP status) — typically dogfood/PPE hostnames.
			if ($hostName -match 'sharepoint-(df|ppe)\.com$') {
				$diagLines.Add("Cause: Host '$hostName' is a Microsoft-internal dogfood/PPE SharePoint endpoint")
				$diagLines.Add('       and is not reachable from the public Microsoft Graph service. This script')
				$diagLines.Add('       does not currently support dogfood/PPE SharePoint targets.')
				$diagLines.Add('Action: Use a production SharePoint URL (*.sharepoint.com) instead.')
			} else {
				$diagLines.Add("Cause: Graph site lookup failed (HTTP status: $status).")
				$diagLines.Add('Action: Verify the URL is correct and reachable, and that the signed-in identity')
				$diagLines.Add('        has the required Graph scopes and SharePoint site access.')
			}
		}
		$diagLines.Add('')
		$diagLines.Add("Graph response: $rawDetail")

		throw ($diagLines -join "`n")
	}
	$siteId = $site.id
	if (-not $siteId) { throw "Unable to resolve SharePoint site '$Url' (Graph returned no id)." }

	# Resolve drive (document library) by name
	$drivesUri = "https://graph.microsoft.com/v1.0/sites/${siteId}/drives"
	$drives = Invoke-MgGraphRequest -Method GET -Uri $drivesUri -ErrorAction Stop
	$drive = $drives.value | Where-Object { $_.name -eq $libraryName -or $_.webUrl -match "/$libraryName(/|$)" } | Select-Object -First 1
	if (-not $drive) {
		# Fallback: default drive
		$drive = Invoke-MgGraphRequest -Method GET -Uri "https://graph.microsoft.com/v1.0/sites/${siteId}/drive" -ErrorAction Stop
		# If the URL named a non-default library, treat the entire path-after-site as folder under default drive
		$folderInLibrary = ($libAndFolder -join '/')
	}

	return [pscustomobject]@{
		HostName     = $hostName
		SiteName     = $siteName
		SiteId       = $siteId
		DriveId      = $drive.id
		LibraryName  = $libraryName
		FolderPath   = $folderInLibrary.TrimEnd('/')
		WebUrl       = $drive.webUrl
	}
}

function Resolve-FabricTarget {
	[CmdletBinding()]
	param([Parameter(Mandatory)] [string] $Url)

	# Accepted URL shapes (all return enough metadata for callers to route correctly):
	#   1. https://onelake.dfs.fabric.microsoft.com/<workspace>/<item>.Lakehouse
	#      (root mode - recommended; operational artifacts auto-routed under Files/,
	#      Delta tables under Tables/)
	#   2. https://onelake.dfs.fabric.microsoft.com/<workspace>/<item>.Lakehouse/Files[/<rel>]
	#      (explicit Files; FilesPath = <rel>)
	#   3. https://onelake.dfs.fabric.microsoft.com/<workspace>/<item>.Lakehouse/Tables[/<schema>]
	#      (explicit Tables for table-typed destinations; TablesPath = <schema>)
	# All three shapes are accepted here; the call-site helpers
	# (Send-FileToOneLake / Get-RemoteFile-OneLake) route operational artifacts
	# under /Files/ regardless of TablesPath, so an -OutputPath that points at
	# the lakehouse root or at an explicit /Tables/<schema> still lands
	# log / checkpoint / mirror artifacts in the correct /Files/ subtree.
	$u = [Uri]$Url
	$accountUrl = "{0}://{1}" -f $u.Scheme, $u.Host
	$segments = ($u.AbsolutePath.TrimStart('/') -split '/' | Where-Object { $_ -ne '' })
	# Force into an array shape so .Count is reliable even for 1- or 0-element results.
	$segments = @($segments)
	if ($segments.Count -lt 2) {
		throw "Fabric URL must include workspace and item: '$Url'"
	}
	$workspace = $segments[0]
	$itemFull  = $segments[1]   # e.g. MyLakehouse.Lakehouse  OR  an item GUID
	$itemGuidPattern = '^[0-9a-fA-F]{8}-[0-9a-fA-F]{4}-[0-9a-fA-F]{4}-[0-9a-fA-F]{4}-[0-9a-fA-F]{12}$'
	if ($itemFull -match '\.(Lakehouse|Warehouse)$') {
		$itemType  = $Matches[1]
		$itemName  = $itemFull.Substring(0, $itemFull.Length - ($itemType.Length + 1))
	}
	elseif ($itemFull -match $itemGuidPattern) {
		# GUID-addressed item: OneLake references the item by its GUID with no type
		# suffix (https://onelake.dfs.fabric.microsoft.com/<wsGuid>/<itemGuid>/...).
		# The DFS path is type-agnostic; PAX only emits Lakehouse-shaped output, so
		# record the type as Lakehouse for display/diagnostics. ItemFull stays the
		# GUID verbatim so every downstream path ("$FilesystemBase/$ItemFull/...")
		# builds the correct GUID-form DFS URL.
		$itemType  = 'Lakehouse'
		$itemName  = $itemFull
	}
	else {
		throw "Fabric item must end with .Lakehouse/.Warehouse, or be an item GUID: '$itemFull'"
	}

	$filesPath  = ''
	$tablesPath = ''
	$rootMode   = $false
	if ($segments.Count -eq 2) {
		$rootMode = $true
	}
	elseif ($segments[2] -eq 'Files') {
		$filesPath = if ($segments.Count -gt 3) { ($segments | Select-Object -Skip 3) -join '/' } else { '' }
	}
	elseif ($segments[2] -eq 'Tables') {
		$tablesPath = if ($segments.Count -gt 3) { ($segments | Select-Object -Skip 3) -join '/' } else { '' }
	}
	else {
		throw "Fabric URL third segment must be 'Files', 'Tables', or absent (lakehouse root): '$Url'"
	}

	return [pscustomobject]@{
		AccountUrl     = $accountUrl
		Workspace      = $workspace
		ItemName       = $itemName
		ItemType       = $itemType
		ItemFull       = $itemFull
		FilesPath      = $filesPath.TrimEnd('/')
		TablesPath     = $tablesPath.TrimEnd('/')
		RootMode       = $rootMode
		FilesystemBase = "$accountUrl/$workspace"
	}
}

# ==============================================
# AZURE (FABRIC/ONELAKE) TOKEN INFRASTRUCTURE
# ==============================================
# Mirrors the Graph token refresh design ($script:SharedAuthState +
# Refresh-GraphTokenIfNeeded + Invoke-TokenRefresh) but for the OneLake DFS
# audience (https://storage.azure.com/), which is acquired through Az.Accounts.
#
# Layers:
#   Get-FabricStorageTokenRaw   - private; runs Connect-AzAccount/Get-AzAccessToken;
#                                 normalizes ExpiresOn to UTC DateTime; tags AuthMethod.
#   Invoke-AzTokenAcquire       - private; calls Raw + stale-token rejection +
#                                 updates $script:AzAuthState + emits log line.
#   Refresh-FabricTokenIfNeeded - public; proactive (5-min buffer + 50-min age cap),
#                                 cooldown (auth-mode aware), -Force for 401 reactive.
#   Get-FabricStorageToken      - public; backward-compatible string-returning wrapper
#                                 (always returns a refresh-checked token).
#   Invoke-FabricWebRequest     - public; wraps Invoke-WebRequest for OneLake calls.
#                                 Pre-flight refresh + transparent 401 retry once.
# Reactive triggers: 401 detected by Invoke-FabricWebRequest -> -Force refresh + retry.
# Proactive triggers: BufferMinutes (5) or token age >50 min, whichever comes first.
# Cooldown: 45s for app-only/MI (silent client_credentials/IMDS); 5min for interactive
#           (avoids re-prompt spam on long upload phases).
function Get-FabricStorageTokenRaw {
	[CmdletBinding()]
	param()
	$resource = 'https://storage.azure.com/'
	if (-not (Get-Module -Name Az.Accounts -ListAvailable -ErrorAction SilentlyContinue)) {
		throw "Az.Accounts module not installed. Install with: Install-Module Az.Accounts -Scope CurrentUser"
	}
	Import-Module Az.Accounts -ErrorAction Stop | Out-Null

	$authMethodTag = 'Interactive'
	$ctx = Get-AzContext -ErrorAction SilentlyContinue
	if (-not $ctx) {
		if ($Auth -eq 'ManagedIdentity') {
			$authMethodTag = 'ManagedIdentity'
			if ($env:AZURE_CLIENT_ID) {
				Connect-AzAccount -Identity -AccountId $env:AZURE_CLIENT_ID -ErrorAction Stop | Out-Null
			} else {
				Connect-AzAccount -Identity -ErrorAction Stop | Out-Null
			}
		}
		elseif ($Auth -eq 'AppRegistration' -and $script:TenantId -and $script:ClientId -and $script:ClientSecret) {
			$authMethodTag = 'AppRegistration'
			$secureSecret = ConvertTo-SecureString -String $script:ClientSecret -AsPlainText -Force
			$cred = New-Object System.Management.Automation.PSCredential($script:ClientId, $secureSecret)
			Connect-AzAccount -ServicePrincipal -Tenant $script:TenantId -Credential $cred -ErrorAction Stop | Out-Null
		}
		else {
			Connect-AzAccount -ErrorAction Stop | Out-Null
		}
	} else {
		# Reuse existing context; classify by account type so cooldown/log lines stay accurate.
		if ($ctx.Account -and $ctx.Account.Type -eq 'ManagedService') { $authMethodTag = 'ManagedIdentity' }
		elseif ($ctx.Account -and $ctx.Account.Type -eq 'ServicePrincipal') { $authMethodTag = 'AppRegistration' }
	}

	$tokenObj = Get-AzAccessToken -ResourceUrl $resource -ErrorAction Stop
	# Token shape: newer Az returns SecureString; older returns plain string.
	$tokenStr = if ($tokenObj.Token -is [System.Security.SecureString]) {
		[System.Net.NetworkCredential]::new('', $tokenObj.Token).Password
	} else {
		[string]$tokenObj.Token
	}
	# ExpiresOn shape: newer Az returns DateTimeOffset; older returns DateTime; defensive parse for string.
	$expiresUtc = if ($tokenObj.ExpiresOn -is [System.DateTimeOffset]) {
		$tokenObj.ExpiresOn.UtcDateTime
	} elseif ($tokenObj.ExpiresOn -is [datetime]) {
		if ($tokenObj.ExpiresOn.Kind -eq [System.DateTimeKind]::Utc) { $tokenObj.ExpiresOn } else { $tokenObj.ExpiresOn.ToUniversalTime() }
	} else {
		([datetime]$tokenObj.ExpiresOn).ToUniversalTime()
	}

	return [pscustomobject]@{
		Token      = $tokenStr
		ExpiresOn  = $expiresUtc
		AuthMethod = $authMethodTag
	}
}

function Invoke-AzTokenAcquire {
	[CmdletBinding()]
	param([string] $Reason = 'initial')
	try {
		$tokenObj = Get-FabricStorageTokenRaw
		# Stale-token rejection: refuse a token that is already at/near expiry. Protects
		# against MSAL cache returning a stale entry after process suspension or system sleep.
		$nowUtc = (Get-Date).ToUniversalTime()
		$minutesValid = ($tokenObj.ExpiresOn - $nowUtc).TotalMinutes
		if ($minutesValid -le 2) {
			throw ("Acquired OneLake storage token is already expired or near-expiry (expires in {0:N1} min)." -f $minutesValid)
		}

		$script:AzAuthState.Token              = $tokenObj.Token
		$script:AzAuthState.ExpiresOn          = $tokenObj.ExpiresOn
		$script:AzAuthState.AcquiredAt         = Get-Date
		$script:AzAuthState.LastRefresh        = Get-Date
		$script:AzAuthState.RefreshCount++
		$script:AzAuthState.AuthMethod         = $tokenObj.AuthMethod
		# Mirror to legacy $script:FabricToken so any cached references stay in sync.
		$script:FabricToken                    = $tokenObj.Token

		$verb = if ($script:AzAuthState.RefreshCount -eq 1) { 'acquired' } else { 'refreshed' }
		Write-LogHost ("  [AZ-TOKEN] OneLake storage token {0} ({1}); auth: {2}; expires {3} UTC; refresh #{4}" -f $verb, $Reason, $tokenObj.AuthMethod, $tokenObj.ExpiresOn.ToString('yyyy-MM-dd HH:mm:ss'), $script:AzAuthState.RefreshCount) -ForegroundColor Gray
		return $true
	}
	catch {
		Write-LogHost ("  [AZ-TOKEN] [!] Failed to acquire OneLake storage token ({0}): {1}" -f $Reason, $_.Exception.Message) -ForegroundColor Red
		return $false
	}
}

function Refresh-FabricTokenIfNeeded {
	<#
	.SYNOPSIS
		Proactively refreshes the Fabric/OneLake storage token if nearing expiry.
	.PARAMETER BufferMinutes
		Refresh if token expires within this many minutes. Default: 5.
	.PARAMETER Force
		Bypass cooldown and force re-acquisition (used by 401 reactive retry).
	.OUTPUTS
		$true  - token is valid (either still-valid or freshly refreshed)
		$false - acquisition/refresh failed; caller must surface the error
	#>
	[CmdletBinding()]
	param(
		[int]    $BufferMinutes = 5,
		[switch] $Force
	)
	$now = (Get-Date).ToUniversalTime()

	# First-time acquisition: no state yet.
	if (-not $script:AzAuthState.Token -or -not $script:AzAuthState.ExpiresOn) {
		return (Invoke-AzTokenAcquire -Reason 'initial')
	}

	$minutesRemaining = ($script:AzAuthState.ExpiresOn - $now).TotalMinutes
	$tokenAge = if ($script:AzAuthState.AcquiredAt) {
		((Get-Date) - $script:AzAuthState.AcquiredAt).TotalMinutes
	} else { 999 }

	# Trigger conditions:
	#   - Forced (typically 401 reactive)
	#   - Within BufferMinutes of expiry (proactive)
	#   - Token age > 50 min (belt-and-suspenders for any auth mode where ExpiresOn might be optimistic)
	$needRefresh = $Force.IsPresent -or ($minutesRemaining -le $BufferMinutes) -or ($tokenAge -gt 50)
	if (-not $needRefresh) { return $true }

	# Cooldown: app-only / MI refresh silently via client_credentials or IMDS (cheap),
	# so 45s is enough. Interactive may prompt the user, so 5 min keeps that bearable.
	$isAppOnly = ($script:AzAuthState.AuthMethod -in @('ManagedIdentity', 'AppRegistration'))
	$cooldownMinutes = if ($isAppOnly) { 0.75 } else { 5.0 }
	if (-not $Force -and $script:AzAuthState.LastRefreshAttempt) {
		$sinceLast = ((Get-Date) - $script:AzAuthState.LastRefreshAttempt).TotalMinutes
		if ($sinceLast -lt $cooldownMinutes) {
			# Still in cooldown; report current token as valid only if it actually is.
			return ($minutesRemaining -gt 0)
		}
	}
	$script:AzAuthState.LastRefreshAttempt = Get-Date

	$reason = if ($Force.IsPresent) {
		'forced (401 retry or explicit)'
	} elseif ($minutesRemaining -le $BufferMinutes) {
		("near-expiry ({0:N1} min remaining)" -f $minutesRemaining)
	} else {
		("age cap ({0:N1} min)" -f $tokenAge)
	}
	return (Invoke-AzTokenAcquire -Reason $reason)
}

function Get-FabricStorageToken {
	<#
	.SYNOPSIS
		Returns a valid OneLake storage-audience bearer token (string) for OneLake DFS calls.
	.DESCRIPTION
		Backward-compatible wrapper around the Az token state machine. Always invokes
		Refresh-FabricTokenIfNeeded first so callers receive a token guaranteed to have at
		least BufferMinutes of validity (or a fresh one). Throws if acquisition fails.
	#>
	[CmdletBinding()] param()
	$ok = Refresh-FabricTokenIfNeeded
	if (-not $ok -or -not $script:AzAuthState.Token) {
		throw "Failed to acquire Fabric/OneLake storage token (see prior [AZ-TOKEN] messages)."
	}
	return $script:AzAuthState.Token
}

function Invoke-FabricWebRequest {
	<#
	.SYNOPSIS
		Invoke-WebRequest wrapper for OneLake DFS calls with proactive token refresh
		and transparent 401 reactive retry.
	.DESCRIPTION
		Before each call: ensures token is fresh via Refresh-FabricTokenIfNeeded.
		During the call: if a 401 Unauthorized is returned, forces a refresh and
		retries the request once with the new token. Any other status (429, 5xx,
		403, 404, etc.) is re-thrown unchanged so the caller's existing retry/error
		handling (e.g., chunk-upload 429/5xx backoff loops) continues to work.
	.PARAMETER Headers
		Caller-supplied headers. The Authorization header is ALWAYS overwritten with
		the current $script:AzAuthState.Token. x-ms-version defaults to '2021-06-08'
		if the caller does not supply it.
	#>
	[CmdletBinding()]
	param(
		[Parameter(Mandatory)] [string]   $Uri,
		[Parameter(Mandatory)] [string]   $Method,
		[hashtable] $Headers,
		$Body,
		[string]    $ContentType,
		[string]    $OutFile
	)
	# Pre-flight refresh.
	$null = Refresh-FabricTokenIfNeeded
	if (-not $script:AzAuthState.Token) {
		throw "Invoke-FabricWebRequest: no OneLake storage token available."
	}

	# Build effective headers; always set Authorization from current state.
	$h = @{}
	if ($Headers) {
		foreach ($k in $Headers.Keys) {
			if ($k -ne 'Authorization') { $h[$k] = $Headers[$k] }
		}
	}
	$h['Authorization'] = "Bearer $($script:AzAuthState.Token)"
	if (-not $h.ContainsKey('x-ms-version')) { $h['x-ms-version'] = '2021-06-08' }

	$invokeParams = @{
		Uri             = $Uri
		Method          = $Method
		Headers         = $h
		UseBasicParsing = $true
		ErrorAction     = 'Stop'
	}
	if ($PSBoundParameters.ContainsKey('Body')) { $invokeParams.Body = $Body }
	if ($ContentType)                           { $invokeParams.ContentType = $ContentType }
	if ($OutFile)                               { $invokeParams.OutFile = $OutFile }

	try {
		return Invoke-WebRequest @invokeParams
	}
	catch {
		$status = try { $_.Exception.Response.StatusCode.value__ } catch { 0 }
		if ($status -eq 401) {
			Write-LogHost "  [AZ-TOKEN] OneLake returned 401 Unauthorized - forcing token refresh and retrying once..." -ForegroundColor Yellow
			$refreshed = Refresh-FabricTokenIfNeeded -Force
			if (-not $refreshed) {
				throw ("OneLake 401 Unauthorized and token refresh failed: {0}" -f $_.Exception.Message)
			}
			$h['Authorization'] = "Bearer $($script:AzAuthState.Token)"
			$invokeParams.Headers = $h
			return Invoke-WebRequest @invokeParams
		}
		throw
	}
}

function Test-RemoteDestination {
	[CmdletBinding()] param()
	if ($script:RemoteOutputMode -eq 'None') { return }
	if ($script:RemoteOutputMode -eq 'SharePoint') {
		$resolved = Resolve-SharePointTarget -Url $script:RemoteOutputUrl
		$script:SPResolved = $resolved
		# Ensure folder exists (create if missing)
		if ($resolved.FolderPath) {
			$folderUri = "https://graph.microsoft.com/v1.0/drives/$($resolved.DriveId)/root:/$($resolved.FolderPath)"
			try {
				Invoke-MgGraphRequest -Method GET -Uri $folderUri -ErrorAction Stop | Out-Null
			} catch {
				# Create folder hierarchy
				$parts = $resolved.FolderPath -split '/'
				$accumulated = ''
				foreach ($p in $parts) {
					$parentUri = if ($accumulated) { "https://graph.microsoft.com/v1.0/drives/$($resolved.DriveId)/root:/${accumulated}:/children" } else { "https://graph.microsoft.com/v1.0/drives/$($resolved.DriveId)/root/children" }
					# FolderPath segments come from [Uri].AbsolutePath, which percent-encodes spaces
					# and other reserved characters (e.g. 'PAX Exports' -> 'PAX%20Exports'). The
					# parent addressing above (root:/...:/children) is colon-path syntax that Graph
					# DECODES, but the 'name' field below is a literal display name that Graph does
					# NOT decode — so passing the raw segment created a folder literally named
					# 'PAX%20Exports' alongside the decoded 'PAX Exports' that the upload path
					# (Send-FileToSharePoint, also colon-path) resolves to. Decode the segment for
					# the display name so both mechanisms agree and only one folder is created.
					$folderDisplayName = [System.Uri]::UnescapeDataString($p)
					$body = @{ name = $folderDisplayName; folder = @{}; '@microsoft.graph.conflictBehavior' = 'replace' } | ConvertTo-Json
					try { Invoke-MgGraphRequest -Method POST -Uri $parentUri -Body $body -ContentType 'application/json' -ErrorAction Stop | Out-Null } catch {}
					$accumulated = if ($accumulated) { "$accumulated/$p" } else { $p }
				}
			}
		}
	}
	elseif ($script:RemoteOutputMode -eq 'Fabric') {
		$resolved = Resolve-FabricTarget -Url $script:RemoteOutputUrl
		$script:FabricResolved = $resolved
		# Initial token acquisition (populates $script:AzAuthState). Classify Az/auth
		# failures here so customers see Cause/Action lines instead of raw exceptions.
		try {
			$null = Get-FabricStorageToken
		} catch {
			$tokenErr = $_.Exception.Message
			$tokenDiag = New-Object System.Collections.Generic.List[string]
			$tokenDiag.Add("OneLake storage token acquisition failed for workspace '$($resolved.Workspace)'.")
			if ($tokenErr -match 'Az\.Accounts module not installed') {
				$tokenDiag.Add('Cause: The Az.Accounts PowerShell module is not installed.')
				$tokenDiag.Add('Action: Install-Module Az.Accounts -Scope CurrentUser')
			} elseif ($tokenErr -match 'AADSTS' -or $tokenErr -match 'consent' -or $tokenErr -match 'admin') {
				$tokenDiag.Add('Cause: Azure AD rejected the sign-in for the storage.azure.com audience.')
				$tokenDiag.Add('Action: Verify the identity has Azure AD sign-in to your tenant, and that')
				$tokenDiag.Add('        any conditional access / MFA requirements are satisfied.')
			} elseif ($tokenErr -match 'IDENTITY|managed identity|MSI|IMDS') {
				$tokenDiag.Add('Cause: Managed identity token acquisition failed (no IMDS endpoint reachable,')
				$tokenDiag.Add('       or AZURE_CLIENT_ID points to an identity not assigned to this host).')
				$tokenDiag.Add('Action: Re-run from a host with an assigned managed identity, or use')
				$tokenDiag.Add('        -Auth Interactive / -Auth AppRegistration instead.')
			} else {
				$tokenDiag.Add('Cause: Az.Accounts could not acquire a token for https://storage.azure.com/.')
				$tokenDiag.Add('Action: Verify your authentication mode (-Auth) and that you can sign in via')
				$tokenDiag.Add('        Connect-AzAccount manually.')
			}
			$tokenDiag.Add('')
			$tokenDiag.Add("Az response: $tokenErr")
			throw ($tokenDiag -join "`n")
		}
		# HEAD the filesystem (workspace) to verify access. Invoke-FabricWebRequest sets
		# Authorization + x-ms-version automatically and handles 401 reactive refresh.
		$probeUri = "$($resolved.FilesystemBase)?resource=filesystem"
		try {
			$null = Invoke-FabricWebRequest -Uri $probeUri -Method HEAD
		} catch {
			# Classify OneLake DFS responses. Unlike Graph, OneLake rarely returns a JSON
			# body on auth failures — the HTTP status is the primary signal.
			$status = 0
			try { $status = [int]$_.Exception.Response.StatusCode.value__ } catch {}
			if ($status -eq 0) { try { if ($_.Exception.Response.StatusCode -is [System.Net.HttpStatusCode]) { $status = [int]$_.Exception.Response.StatusCode } } catch {} }
			$rawDetail = $_.Exception.Message
			if ($rawDetail.Length -gt 600) { $rawDetail = $rawDetail.Substring(0, 600) + '...(truncated)' }

			$diagLines = New-Object System.Collections.Generic.List[string]
			$diagLines.Add("OneLake filesystem probe failed (workspace '$($resolved.Workspace)', item '$($resolved.ItemFull)').")

			if ($status -eq 401) {
				$diagLines.Add('Cause: OneLake rejected the storage token (401). The token audience is correct')
				$diagLines.Add('       but the identity is not recognized by this Fabric workspace.')
				$diagLines.Add('Action: Verify the identity is signed in to the same tenant that owns the Fabric')
				$diagLines.Add('        workspace, and that the storage.azure.com token is not expired/blocked.')
			}
			elseif ($status -eq 403) {
				$diagLines.Add('Cause: The identity is authenticated but lacks permissions on the Fabric workspace')
				$diagLines.Add('       (HTTP 403 Forbidden from OneLake DFS).')
				$diagLines.Add('Action: In the Fabric portal -> Workspace settings -> Manage access, grant the')
				$diagLines.Add('        identity at least Contributor. See the "Permissions Required for THIS run"')
				$diagLines.Add('        table earlier in this output for the exact Azure RBAC roles required.')
			}
			elseif ($status -eq 404) {
				$diagLines.Add("Cause: Workspace or item not found (HTTP 404). One of these is wrong:")
				$diagLines.Add("         workspace = '$($resolved.Workspace)'")
				$diagLines.Add("         item      = '$($resolved.ItemFull)' (must exist as a Lakehouse/Warehouse)")
				$diagLines.Add('Action: Verify the URL by opening the lakehouse in the Fabric portal and using')
				$diagLines.Add('        the OneLake "Copy ABFS path" option, then converting to https:// form.')
			}
			elseif ($status -ge 500) {
				$diagLines.Add("Cause: OneLake returned a server error (HTTP $status). This is usually transient.")
				$diagLines.Add('Action: Wait a minute and retry. If it persists, check Fabric service health.')
			}
			else {
				$diagLines.Add("Cause: OneLake DFS probe failed (HTTP status: $status).")
				$diagLines.Add('Action: Verify the Fabric workspace URL is correct and that the identity has')
				$diagLines.Add('        the Azure RBAC roles listed in the "Permissions Required for THIS run" table.')
			}
			$diagLines.Add('')
			$diagLines.Add("OneLake response: $rawDetail")

			throw ($diagLines -join "`n")
		}
	}
}

function Get-GraphErrorDetail {
	# Best-effort extraction of the Microsoft Graph error body from a caught error.
	# PowerShell attaches the raw HTTP response body to $_.ErrorDetails.Message for both
	# Invoke-MgGraphRequest and Invoke-WebRequest; fall back to the response stream, then
	# to the plain exception message. Returns a short single-line string for logging.
	[CmdletBinding()]
	param([Parameter(Mandatory)] $ErrorRecord)
	$raw = $null
	if ($ErrorRecord.ErrorDetails -and $ErrorRecord.ErrorDetails.Message) {
		$raw = $ErrorRecord.ErrorDetails.Message
	}
	elseif ($ErrorRecord.Exception -and $ErrorRecord.Exception.Response) {
		try {
			$stream = $ErrorRecord.Exception.Response.GetResponseStream()
			if ($stream) {
				$reader = New-Object System.IO.StreamReader($stream)
				$raw = $reader.ReadToEnd()
				$reader.Dispose()
			}
		} catch { }
	}
	if (-not $raw) { return $ErrorRecord.Exception.Message }
	# Try to pull error.code / error.message out of the JSON body.
	try {
		$j = $raw | ConvertFrom-Json -ErrorAction Stop
		if ($j.error) {
			$code = $j.error.code
			$msg  = $j.error.message
			return ("{0}: {1}" -f $code, $msg).Trim(': ')
		}
	} catch { }
	# Non-JSON body - return a trimmed single line.
	return ($raw -replace '\s+', ' ').Trim()
}

function Send-FileToSharePoint {
	[CmdletBinding()]
	param(
		[Parameter(Mandatory)] [string] $LocalPath,
		[string] $RemoteFileName,
		# Optional per-data-type SharePoint parent URL. When supplied, the destination
		# is resolved against $ParentOverride instead of the script-wide Purview
		# RemoteOutputUrl. Used by per-data-type append surfaces (UserInfo / Agent365 /
		# Log) when their -OutputPath* points at a different SharePoint folder than
		# the primary Purview output.
		[string] $ParentOverride
	)
	if (-not (Test-Path -LiteralPath $LocalPath)) { throw "Send-FileToSharePoint: source not found: $LocalPath" }
	if ($ParentOverride) {
		$resolved = Resolve-SharePointTarget -Url $ParentOverride
	}
	else {
		if (-not $script:SPResolved) { $script:SPResolved = Resolve-SharePointTarget -Url $script:RemoteOutputUrl }
		$resolved = $script:SPResolved
	}
	$fileName = if ($RemoteFileName) { $RemoteFileName } else { Split-Path -Leaf $LocalPath }
	# Per-segment URI escaping for the filename. The auto-defaulted basenames used by
	# this script are safe ASCII (timestamps + underscores), but routing custom basenames
	# through the same encoding pipeline avoids any per-call-site special casing.
	$fileNameEnc = [System.Uri]::EscapeDataString($fileName)
	$relPath  = if ($resolved.FolderPath) { "$($resolved.FolderPath)/$fileNameEnc" } else { $fileNameEnc }
	$fileInfo = Get-Item -LiteralPath $LocalPath
	$sizeMb = $fileInfo.Length / 1MB

	# Graph simple upload (PUT .../content) supports up to 250 MB; use it for everything
	# up to that ceiling so as many files as possible avoid the resumable-upload-session
	# API (which some locked-down libraries / egress proxies reject even when a simple PUT
	# is allowed). Files above 250 MB still use createUploadSession + chunked PUT.
	$simpleUploadMax = 250MB
	if ($fileInfo.Length -le $simpleUploadMax) {
		$putUri = "https://graph.microsoft.com/v1.0/drives/$($resolved.DriveId)/root:/${relPath}:/content"
		$bytes  = [System.IO.File]::ReadAllBytes($LocalPath)
		try {
			Invoke-MgGraphRequest -Method PUT -Uri $putUri -Body $bytes -ContentType 'application/octet-stream' -ErrorAction Stop | Out-Null
		}
		catch {
			$detail = Get-GraphErrorDetail -ErrorRecord $_
			throw "SharePoint simple upload (PUT) failed for '$relPath': $detail"
		}
	}
	else {
		# Create upload session
		$sessUri = "https://graph.microsoft.com/v1.0/drives/$($resolved.DriveId)/root:/${relPath}:/createUploadSession"
		$sessBody = @{ item = @{ '@microsoft.graph.conflictBehavior' = 'replace'; name = $fileName } } | ConvertTo-Json -Depth 4
		try {
			$session = Invoke-MgGraphRequest -Method POST -Uri $sessUri -Body $sessBody -ContentType 'application/json' -ErrorAction Stop
		}
		catch {
			$detail = Get-GraphErrorDetail -ErrorRecord $_
			throw "createUploadSession failed for '$relPath': $detail"
		}
		$uploadUrl = $session.uploadUrl
		if (-not $uploadUrl) { throw "SharePoint createUploadSession returned no uploadUrl for '$relPath'." }

		$chunkSize = 5MB   # multiple of 320 KB
		$fs = [System.IO.File]::OpenRead($LocalPath)
		try {
			$buffer = New-Object byte[] $chunkSize
			$offset = 0L
			while ($offset -lt $fileInfo.Length) {
				$toRead = [int][Math]::Min([int64]$chunkSize, $fileInfo.Length - $offset)
				# FileStream.Read may return fewer bytes than requested; loop until the
				# fragment is fully populated (or EOF) so every Content-Range fragment
				# carries exactly the byte count its header declares.
				$read = 0
				while ($read -lt $toRead) {
					$n = $fs.Read($buffer, $read, $toRead - $read)
					if ($n -le 0) { break }
					$read += $n
				}
				if ($read -le 0) { break }
				$end = $offset + $read - 1
				$range = "bytes $offset-$end/$($fileInfo.Length)"
				# Send a true byte[] body. PowerShell range-indexing ($buffer[0..N])
				# returns an Object[] of boxed bytes, which Invoke-WebRequest stringifies
				# instead of sending as raw bytes — producing a body whose length does not
				# match the declared Content-Range and a 400 (Bad Request) from Graph on
				# the final partial fragment. Copy into a right-sized byte[] instead.
				if ($read -eq $chunkSize) {
					$slice = $buffer
				}
				else {
					$slice = New-Object byte[] $read
					[System.Array]::Copy($buffer, 0, $slice, 0, $read)
				}
				$attempt = 0
				while ($true) {
					try {
						$null = Invoke-WebRequest -Uri $uploadUrl -Method PUT -Body $slice -Headers @{ 'Content-Range' = $range } -ContentType 'application/octet-stream' -UseBasicParsing -ErrorAction Stop
						break
					}
					catch {
						$status = try { $_.Exception.Response.StatusCode.value__ } catch { 0 }
						$retryAfter = try { [int]$_.Exception.Response.Headers['Retry-After'] } catch { 0 }
						$attempt++
						if (($status -eq 429 -or $status -ge 500) -and $attempt -lt 5) {
							$wait = if ($retryAfter -gt 0) { $retryAfter } else { [Math]::Min(60, [Math]::Pow(2, $attempt)) }
							Start-Sleep -Seconds $wait
							continue
						}
						throw
					}
				}
				$offset += $read
			}
		}
		finally { $fs.Dispose() }
	}
	Write-LogHost ("  -> SharePoint upload OK: {0} ({1:N2} MB)" -f $relPath, $sizeMb) -ForegroundColor DarkGray
}

function Send-FileToOneLake {
	[CmdletBinding()]
	param(
		[Parameter(Mandatory)] [string] $LocalPath,
		[string] $RemoteFileName,
		# Optional per-data-type Fabric/OneLake parent URL. See Send-FileToSharePoint
		# for the rationale. When omitted, falls back to the script-wide Purview URL.
		[string] $ParentOverride
	)
	if (-not (Test-Path -LiteralPath $LocalPath)) { throw "Send-FileToOneLake: source not found: $LocalPath" }
	if ($ParentOverride) {
		$resolved = Resolve-FabricTarget -Url $ParentOverride
	}
	else {
		if (-not $script:FabricResolved) { $script:FabricResolved = Resolve-FabricTarget -Url $script:RemoteOutputUrl }
		$resolved = $script:FabricResolved
	}
	$fileName = if ($RemoteFileName) { $RemoteFileName } else { Split-Path -Leaf $LocalPath }
	# Per-SEGMENT URI escaping. $RemoteFileName may contain '/' separators
	# (e.g. ".pax_resume/<ts>/<file>" from Sync-FabricResumeMirror); escaping the
	# whole string as one data segment would percent-encode the slashes ('%2F'),
	# malforming the DFS path so PUT (Create File) and PATCH (Append) target
	# different resolved files, surfacing as "400 (position not equal to length)".
	# Split-then-escape-per-segment preserves the hierarchical path.
	$fileNameEnc = ($fileName -split '/' | ForEach-Object { [System.Uri]::EscapeDataString($_) }) -join '/'
	$relInItem = if ($resolved.FilesPath) { "$($resolved.FilesPath)/$fileNameEnc" } else { $fileNameEnc }
	$dfsPath   = "$($resolved.FilesystemBase)/$($resolved.ItemFull)/Files/$relInItem"
	$fileInfo  = Get-Item -LiteralPath $LocalPath
	$sizeMb    = $fileInfo.Length / 1MB

	# Authorization + x-ms-version are set per-request by Invoke-FabricWebRequest using the
	# current $script:AzAuthState. Do not cache headers locally - the token may rotate.

	# Step 0: Pre-create any parent directories. OneLake Lakehouse Files/ uses a
	# hierarchical namespace; PUT ?resource=file does not auto-create intermediate
	# directories. Without this, mirroring artifacts to e.g. ".pax_resume/<ts>/"
	# can land the leaf file in an inconsistent state that surfaces downstream as
	# a 400 (position not equal to length) on the first append. Idempotent: a 409
	# response means the directory already exists and is treated as success.
	$parentRel = $null
	if ($relInItem -match '/') { $parentRel = $relInItem.Substring(0, $relInItem.LastIndexOf('/')) }
	if ($parentRel) {
		$dirUri = "$($resolved.FilesystemBase)/$($resolved.ItemFull)/Files/$parentRel`?resource=directory"
		try {
			$null = Invoke-FabricWebRequest -Uri $dirUri -Method PUT
		}
		catch {
			$dirStatus = try { $_.Exception.Response.StatusCode.value__ } catch { 0 }
			if ($dirStatus -ne 409) { throw }
		}
	}

	# Step 1: Create (PUT ?resource=file) - overwrites any existing file.
	$createUri = "$dfsPath`?resource=file"
	$null = Invoke-FabricWebRequest -Uri $createUri -Method PUT

	# Step 2: Append in chunks (PATCH ?action=append&position=N).
	# Inner retry loop handles 429/5xx with exponential backoff. 401 is handled transparently
	# inside Invoke-FabricWebRequest (force-refresh + retry once); any 401 that escapes here
	# means refresh itself failed, which is fatal for this upload and propagates up.
	$chunkSize = 4MB
	$fs = [System.IO.File]::OpenRead($LocalPath)
	try {
		$buffer = New-Object byte[] $chunkSize
		$position = 0L
		while ($position -lt $fileInfo.Length) {
			$toRead = [Math]::Min([int64]$chunkSize, $fileInfo.Length - $position)
			$read   = $fs.Read($buffer, 0, [int]$toRead)
			if ($read -le 0) { break }
			$slice = if ($read -eq $chunkSize) { $buffer } else { $buffer[0..($read-1)] }
			$appendUri = "$dfsPath`?action=append&position=$position"
			$attempt = 0
			while ($true) {
				try {
					$null = Invoke-FabricWebRequest -Uri $appendUri -Method PATCH -Body $slice -ContentType 'application/octet-stream'
					break
				}
				catch {
					$status = try { $_.Exception.Response.StatusCode.value__ } catch { 0 }
					$retryAfter = try { [int]$_.Exception.Response.Headers['Retry-After'] } catch { 0 }
					$attempt++
					if (($status -eq 429 -or $status -ge 500) -and $attempt -lt 5) {
						$wait = if ($retryAfter -gt 0) { $retryAfter } else { [Math]::Min(60, [Math]::Pow(2, $attempt)) }
						Start-Sleep -Seconds $wait
						continue
					}
					throw
				}
			}
			$position += $read
		}
	}
	finally { $fs.Dispose() }

	# Step 3: Flush (PATCH ?action=flush&position=<size>)
	$flushUri = "$dfsPath`?action=flush&position=$($fileInfo.Length)"
	$null = Invoke-FabricWebRequest -Uri $flushUri -Method PATCH

	Write-LogHost ("  -> OneLake upload OK: {0} ({1:N2} MB)" -f $relInItem, $sizeMb) -ForegroundColor DarkGray
}

function Get-RemoteFile-SharePoint {
	[CmdletBinding()]
	param(
		[Parameter(Mandatory)] [string] $RelativeName,
		[Parameter(Mandatory)] [string] $DestinationPath,
		# Optional per-data-type SharePoint parent URL (see Send-FileToSharePoint).
		[string] $ParentOverride
	)
	if ($ParentOverride) {
		$resolved = Resolve-SharePointTarget -Url $ParentOverride
	}
	else {
		if (-not $script:SPResolved) { $script:SPResolved = Resolve-SharePointTarget -Url $script:RemoteOutputUrl }
		$resolved = $script:SPResolved
	}
	$relName   = [System.Uri]::EscapeDataString($RelativeName)
	$relPath  = if ($resolved.FolderPath) { "$($resolved.FolderPath)/$relName" } else { $relName }
	$dlUri    = "https://graph.microsoft.com/v1.0/drives/$($resolved.DriveId)/root:/${relPath}:/content"
	Invoke-MgGraphRequest -Method GET -Uri $dlUri -OutputFilePath $DestinationPath -ErrorAction Stop | Out-Null
}

function Get-RemoteFile-OneLake {
	[CmdletBinding()]
	param(
		[Parameter(Mandatory)] [string] $RelativeName,
		[Parameter(Mandatory)] [string] $DestinationPath,
		# Optional per-data-type Fabric/OneLake parent URL (see Send-FileToSharePoint).
		[string] $ParentOverride
	)
	if ($ParentOverride) {
		$resolved = Resolve-FabricTarget -Url $ParentOverride
	}
	else {
		if (-not $script:FabricResolved) { $script:FabricResolved = Resolve-FabricTarget -Url $script:RemoteOutputUrl }
		$resolved = $script:FabricResolved
	}
	# Per-SEGMENT URI escaping. $RelativeName may contain '/' separators (e.g.
	# ".pax_resume/<ts>/<file>" from Restore-FabricResumeMirror); escaping the
	# whole string as one data segment would percent-encode the slashes to '%2F'
	# and resolve to a different (or non-existent) DFS path than the uploader
	# wrote to. Mirrors the Send-FileToOneLake fix.
	$relName   = ($RelativeName -split '/' | ForEach-Object { [System.Uri]::EscapeDataString($_) }) -join '/'
	$relInItem = if ($resolved.FilesPath) { "$($resolved.FilesPath)/$relName" } else { $relName }
	$dfsPath   = "$($resolved.FilesystemBase)/$($resolved.ItemFull)/Files/$relInItem"
	# Invoke-FabricWebRequest handles Authorization, x-ms-version, proactive refresh, 401 retry.
	$null = Invoke-FabricWebRequest -Uri $dfsPath -Method GET -OutFile $DestinationPath
}

function Get-DataTypeForOutputFile {
	# Map a customer-visible artifact basename to its data-type key. Used by the
	# upload sweep to route each file to its per-data-type destination (-OutputPath*).
	# Returns one of: 'Purview' | 'UserInfo' | 'Agent365Info' | 'Log'.
	# Unknown / unmatched names fall back to 'Purview' (primary audit destination).
	[CmdletBinding()]
	param([Parameter(Mandatory)] [string] $FileName)
	$n = [System.IO.Path]::GetFileName($FileName)
	if ($n -like 'EntraUsers_*' -or $n -like '*_Users.csv' -or $n -like '*_Users_*.csv') { return 'UserInfo' }
	if ($n -like 'Agent365_*' -or $n -like 'Agent365.csv')                                { return 'Agent365Info' }
	if ($n -like '*.log' -or $n -like '*.partial.log')                                    { return 'Log' }
	return 'Purview'
}

function Invoke-OutputUpload {
	[CmdletBinding()]
	param(
		[Parameter(Mandatory)] [string] $LocalPath,
		# Optional per-data-type parent URL. When supplied, the upload targets this
		# URL instead of the script-wide Purview destination. Used to honor
		# -OutputPathUserInfo / -OutputPathAgent365Info / -OutputPathLog routing.
		[string] $ParentOverride
	)
	if ($script:RemoteOutputMode -eq 'None') { return }
	if (-not (Test-Path -LiteralPath $LocalPath)) {
		Write-Verbose "Invoke-OutputUpload: skipping (file not found): $LocalPath"
		return
	}
	# NOTE: No catch wrapper here — every caller either (a) has its own try/catch with a
	# context-specific WARNING (upload sweep / metrics / log file) or (b) wants silent
	# best-effort behavior with Write-Verbose only (checkpoint mirror). An inner WARNING
	# would always be either redundant or unwanted. Let exceptions propagate untouched.
	switch ($script:RemoteOutputMode) {
		'SharePoint' { Send-FileToSharePoint -LocalPath $LocalPath -ParentOverride $ParentOverride }
		'Fabric'     { Send-FileToOneLake    -LocalPath $LocalPath -ParentOverride $ParentOverride }
	}
}

function Invoke-EmbeddedProcessor {
	[CmdletBinding()]
	param(
		[Parameter(Mandatory)] [ValidateSet('CopilotInteraction', 'M365Bundle')]
		[string] $ProcessorMode,

		[Parameter(Mandatory)] [string]   $PythonExe,
		[Parameter(Mandatory)] [AllowEmptyCollection()] [string[]] $LauncherArgs,
		[Parameter(Mandatory)] [string[]] $ProcessorArgs,
		[Parameter(Mandatory)] [string]   $IncrementalDir
	)

	# Materialize the appropriate embedded source as a temp .py inside .pax_incremental,
	# named with the global run timestamp so it is auto-reaped by the end-of-run cleanup
	# AND the finally-block safety-net even if we crash. Returns the processor's exit code.

	if (-not (Test-Path -LiteralPath $IncrementalDir -PathType Container)) {
		New-Item -ItemType Directory -Path $IncrementalDir -Force | Out-Null
	}

	switch ($ProcessorMode) {
		'CopilotInteraction' {
			$label  = 'CopilotInteractionProcessor'
			$source = $Script:EMBEDDED_PROCESSOR_COPILOT
			$ver    = $Script:EMBEDDED_PROCESSOR_COPILOT_VERSION
		}
		'M365Bundle' {
			$label  = 'M365BundleProcessor'
			$source = $Script:EMBEDDED_PROCESSOR_M365
			$ver    = $Script:EMBEDDED_PROCESSOR_M365_VERSION
		}
	}

	$tempPyName = "PAX_${label}_$($global:ScriptRunTimestamp).py"
	$tempPyPath = Join-Path $IncrementalDir $tempPyName

	$utf8NoBom = [Text.UTF8Encoding]::new($false)
	[IO.File]::WriteAllText($tempPyPath, $source, $utf8NoBom)

	Write-LogHost "Rollup: invoking embedded $label v$ver ($PythonExe)" -ForegroundColor Cyan
	Write-LogFile "Rollup: temp script -> $tempPyPath"
	Write-LogFile "Rollup: args        -> $($ProcessorArgs -join ' ')"

	$exitCode = 1
	# Force UTF-8 across the Python subprocess boundary so Unicode glyphs the
	# processor emits to stdout / stderr (right-arrow, section separators,
	# bullets) are not mojibaked when captured through PowerShell on hosts
	# whose console output encoding defaults to a legacy OEM code page.
	# Both sides matter:
	#   * [Console]::OutputEncoding controls how PowerShell decodes the bytes
	#     it reads back from the subprocess.
	#   * $env:PYTHONIOENCODING tells the Python interpreter what to encode
	#     its stdout / stderr text streams as.
	# Outer values are captured here and restored in the finally block so the
	# host's session-wide encoding is not perturbed.
	$prevConsoleOutEnc = [Console]::OutputEncoding
	$prevPyIoEnc       = $env:PYTHONIOENCODING
	try {
		[Console]::OutputEncoding = [System.Text.UTF8Encoding]::new($false)
		$env:PYTHONIOENCODING     = 'utf-8'
		$fullArgs = @($LauncherArgs) + @($tempPyPath) + @($ProcessorArgs)
		# In remote-output mode, suppress the Python processors' echoed input/output PATH
		# lines (e.g. "Purview input:", "Output file:"). Those values are LOCAL scratch
		# paths; surfacing them to the customer when a remote -OutputPath* is
		# in effect is misleading. The remote-aware path summary is emitted by the
		# PowerShell wrapper after the processor returns. All other Python output
		# (header, counts, timing, errors) is preserved verbatim.
		$pathLineRegex = if ($script:RemoteOutputMode -ne 'None') {
			'^\s*(Purview input:|Entra input:|Purview output:|Entra output:|Input:|Output:|Output file:)\s'
		} else { $null }
		& $PythonExe @fullArgs 2>&1 | ForEach-Object {
			$line = [string]$_
			if ($pathLineRegex -and $line -match $pathLineRegex) { return }
			# Stream stdout+stderr through Write-Log (which mirrors to host AND log file).
			Write-Log $line
		}
		$exitCode = $LASTEXITCODE
	}
	catch {
		Write-LogHost "Rollup: $label threw an exception: $($_.Exception.Message)" -ForegroundColor Red
		$exitCode = 1
	}
	finally {
		# Restore the outer console output encoding and PYTHONIOENCODING regardless
		# of outcome so subsequent host writes (and any later subprocess) see the
		# same environment they would have without this call.
		try { [Console]::OutputEncoding = $prevConsoleOutEnc } catch { }
		if ($null -eq $prevPyIoEnc) {
			Remove-Item Env:PYTHONIOENCODING -ErrorAction SilentlyContinue
		} else {
			$env:PYTHONIOENCODING = $prevPyIoEnc
		}
		try {
			if (Test-Path -LiteralPath $tempPyPath) { Remove-Item -LiteralPath $tempPyPath -Force -ErrorAction SilentlyContinue }
		}
		catch { }
	}

	return $exitCode
}

# Validate MaxConcurrency range (Microsoft Purview enforces 10 concurrent search job limit per user account)
# ============================================================================
# APPENDFILE COLUMN VALIDATION FUNCTIONS
# ============================================================================
# Early validation to prevent wasting time on Graph API queries when explosion
# parameters don't match between existing file and new data parameters.
# Note: For explosion modes, actual column schemas are dynamic and vary by data,
# so we validate explosion parameter compatibility rather than exact columns.
# ============================================================================

function Get-LikelyExplosionParams {
	param([string[]]$Columns)
	
	# Check for deep explosion indicators (CopilotEventData.* columns)
	$hasDeepColumns = $Columns | Where-Object { $_ -match '^CopilotEventData\.' }
	if ($hasDeepColumns) {
		return @{ Mode = "ExplodeDeep"; DisplayName = "-ExplodeDeep" }
	}
	
	# Check for array explosion indicators (exploded field names like Message_, Context_, AgentId, etc.)
	$hasArrayColumns = $Columns | Where-Object { $_ -match '^(Message_|Context_|Interaction_|AgentId|AgentName|AgentVersion|AccessedResource_|AISystemPlugin_)' }
	if ($hasArrayColumns) {
		return @{ Mode = "ExplodeArrays"; DisplayName = "-ExplodeArrays" }
	}
	
	# Check for standard mode indicators (AuditData JSON column present)
	$hasAuditData = $Columns -contains 'AuditData'
	if ($hasAuditData) {
		return @{ Mode = "Standard"; DisplayName = "Standard (no explosion)" }
	}
	
	# Unable to determine
	return @{ Mode = "Unknown"; DisplayName = "Unknown mode" }
}

function Get-AppendFileRecordIds {
	<#
	.SYNOPSIS
		Stream the RecordId column from an existing AppendFile (CSV or XLSX) into a HashSet.

	.DESCRIPTION
		Cross-run dedup helper for -AppendFile. Reads only the RecordId column from the
		existing target file and returns a HashSet[string] of identifiers. Used to seed
		Merge-IncrementalSaves-Streaming's -ExcludeRecordIds parameter so this run skips
		records already present in the target.

		CSV path: streams via StreamReader + manual header parse — never loads the entire
		file into memory (the target may be hundreds of MB).
		Excel path: uses Import-Excel (RecordId column only). The Excel branch is bounded
		by ImportExcel's own behavior; very large workbooks should use CSV.

	.PARAMETER Path
		Path to the AppendFile. Missing file returns an empty set (first-run semantic).

	.OUTPUTS
		HashSet[string] of RecordIds (empty when the file or column is absent).
	#>
	[CmdletBinding()]
	param(
		[Parameter(Mandatory)] [string] $Path
	)
	$set = New-Object System.Collections.Generic.HashSet[string]
	if (-not (Test-Path -LiteralPath $Path -PathType Leaf)) { return ,$set }

	$ext = [System.IO.Path]::GetExtension($Path).ToLowerInvariant()
	if ($ext -eq '.xlsx') {
		try {
			if (-not (Get-Module -Name ImportExcel -ListAvailable)) { return ,$set }
			Import-Module ImportExcel -ErrorAction Stop
			$rows = Import-Excel -Path $Path -ErrorAction Stop
			foreach ($r in $rows) {
				$rid = $r.RecordId
				if ($rid -and -not [string]::IsNullOrWhiteSpace([string]$rid)) {
					[void]$set.Add([string]$rid)
				}
			}
		} catch {
			Write-LogHost "Get-AppendFileRecordIds: failed to read '$Path': $($_.Exception.Message). Cross-run dedup disabled for this file." -ForegroundColor Yellow
		}
		return ,$set
	}

	# CSV path — manual streaming for memory safety on large files.
	try {
		$reader = [System.IO.StreamReader]::new($Path, [System.Text.Encoding]::UTF8)
		try {
			$header = $reader.ReadLine()
			if (-not $header) { return ,$set }
			$cols = $header.Split(',') | ForEach-Object { $_.Trim('"') }
			$ridIdx = -1
			for ($i = 0; $i -lt $cols.Count; $i++) {
				if ($cols[$i] -ieq 'RecordId') { $ridIdx = $i; break }
			}
			if ($ridIdx -lt 0) { return ,$set }
			$line = $null
			while ($null -ne ($line = $reader.ReadLine())) {
				if ([string]::IsNullOrWhiteSpace($line)) { continue }
				# Simple field split; AppendFiles use Export-Csv quoting so RecordId (a GUID)
				# never contains commas or quotes. Fall back to ConvertFrom-Csv for the rare
				# row that has embedded commas before the RecordId column.
				$fields = $line.Split(',')
				if ($fields.Count -gt $ridIdx) {
					$raw = $fields[$ridIdx].Trim('"').Trim()
					if ($raw) { [void]$set.Add($raw) }
				}
			}
		} finally {
			$reader.Dispose()
		}
	} catch {
		Write-LogHost "Get-AppendFileRecordIds: failed to read '$Path': $($_.Exception.Message). Cross-run dedup disabled for this file." -ForegroundColor Yellow
	}
	return ,$set
}

function Test-AppendFileCompatibility {
	param(
		[string]$FilePath,
		[bool]$IsExcel,
		[bool]$ExplodeArrays,
		[bool]$ExplodeDeep,
		[string]$TargetSheet = $null
	)
	
	$result = @{
		Compatible = $true
		ExistingMode = $null
		CurrentMode = $null
		ExistingColumns = @()
		ExistingCount = 0
		ErrorMessage = $null
	}
	
	try {
		# Determine current explosion mode
		if ($ExplodeDeep) {
			$result.CurrentMode = @{ Mode = "ExplodeDeep"; DisplayName = "-ExplodeDeep" }
		}
		elseif ($ExplodeArrays) {
			$result.CurrentMode = @{ Mode = "ExplodeArrays"; DisplayName = "-ExplodeArrays" }
		}
		else {
			$result.CurrentMode = @{ Mode = "Standard"; DisplayName = "Standard (no explosion)" }
		}
		
		# Read existing file columns
		if ($IsExcel) {
			# Validate Excel file and read columns
			if (-not (Get-Module -Name ImportExcel -ListAvailable)) {
				$result.ErrorMessage = "ImportExcel module not available for validation"
				$result.Compatible = $false
				return $result
			}
			
			Import-Module ImportExcel -ErrorAction Stop
			
			# Get sheet info
			$sheets = Get-ExcelSheetInfo -Path $FilePath -ErrorAction Stop
			
			if ($TargetSheet) {
				# Validate specific sheet
				$sheet = $sheets | Where-Object { $_.Name -eq $TargetSheet }
				if (-not $sheet) {
					$result.ErrorMessage = "Target sheet '$TargetSheet' not found in workbook"
					$result.Compatible = $false
					return $result
				}
			}
			else {
				# Use first sheet
				$sheet = $sheets | Select-Object -First 1
			}
			
			# Read header row from Excel
			$headerData = Import-Excel -Path $FilePath -WorksheetName $sheet.Name -StartRow 1 -EndRow 1 -NoHeader -ErrorAction Stop
			$existingCols = $headerData[0].PSObject.Properties.Value | Where-Object { $_ }
		}
		else {
			# CSV: Read first line (header)
			$firstLine = Get-Content -Path $FilePath -First 1 -Encoding UTF8 -ErrorAction Stop
			$existingCols = ($firstLine -split ',') | ForEach-Object { $_.Trim('"') }
		}
		
		$result.ExistingColumns = $existingCols
		$result.ExistingCount = $existingCols.Count
		
		# Detect explosion mode of existing file
		$result.ExistingMode = Get-LikelyExplosionParams -Columns $existingCols
		
		# Check if explosion modes match
		if ($result.ExistingMode.Mode -ne $result.CurrentMode.Mode) {
			$result.Compatible = $false
			$result.ErrorMessage = "Explosion parameter mismatch: existing file is '$($result.ExistingMode.DisplayName)' but current command uses '$($result.CurrentMode.DisplayName)'"
		}
		else {
			# Modes match - compatible
			# Note: We don't validate exact columns because explosion schemas are dynamic
			# and vary based on actual data content. As long as explosion params match,
			# the append will work correctly.
			$result.Compatible = $true
		}
	}
	catch {
		$result.ErrorMessage = $_.Exception.Message
		$result.Compatible = $false
	}
	
	return $result
}

# ============================================================================
# END APPENDFILE VALIDATION FUNCTIONS
# ============================================================================

if ($MaxConcurrency -lt 1 -or $MaxConcurrency -gt 10) {
	Write-Host "ERROR: -MaxConcurrency must be between 1 and 10." -ForegroundColor Red
	Write-Host "Microsoft Purview enforces a maximum of 10 concurrent search jobs per user account." -ForegroundColor Yellow
	Write-Host "Current value: $MaxConcurrency" -ForegroundColor Yellow
	Write-Host "Please specify a value between 1 and 10 and re-run." -ForegroundColor Yellow
	exit 1
}

# Establish date defaults / validation depending on mode.
if ($RAWInputCSV) {
	$parsedStart = $null; $parsedEnd = $null
	if ($PSBoundParameters.ContainsKey('StartDate')) {
		try { $parsedStart = [datetime]::ParseExact($StartDate, 'yyyy-MM-dd', [System.Globalization.CultureInfo]::InvariantCulture) } catch { Write-Host "ERROR: StartDate must be yyyy-MM-dd if provided." -ForegroundColor Red; exit 1 }
	}
	if ($PSBoundParameters.ContainsKey('EndDate')) {
		try { $parsedEnd = [datetime]::ParseExact($EndDate, 'yyyy-MM-dd', [System.Globalization.CultureInfo]::InvariantCulture) } catch { Write-Host "ERROR: EndDate must be yyyy-MM-dd if provided." -ForegroundColor Red; exit 1 }
	}
	if ($parsedStart -and $parsedEnd -and $parsedEnd -lt $parsedStart) { Write-Host "ERROR: EndDate ($EndDate) is earlier than StartDate ($StartDate)." -ForegroundColor Red; exit 1 }
	if (-not $PSBoundParameters.ContainsKey('StartDate')) { $StartDate = '*' }
	if (-not $PSBoundParameters.ContainsKey('EndDate')) { $EndDate = '*' }
}
else {
	if (-not $PSBoundParameters.ContainsKey('StartDate') -and -not $PSBoundParameters.ContainsKey('EndDate')) {
		$yesterdayUtc = (Get-Date).ToUniversalTime().Date.AddDays(-1)
		$StartDate = $yesterdayUtc.ToString('yyyy-MM-dd')
		$EndDate = $yesterdayUtc.AddDays(1).ToString('yyyy-MM-dd')
	}
	elseif (-not $PSBoundParameters.ContainsKey('StartDate')) {
		$StartDate = '*'
		try {
			$parsedEnd = [datetime]::ParseExact($EndDate, 'yyyy-MM-dd', [System.Globalization.CultureInfo]::InvariantCulture)
		} catch { Write-Host "ERROR: EndDate must be yyyy-MM-dd format." -ForegroundColor Red; exit 1 }
	}
	elseif (-not $PSBoundParameters.ContainsKey('EndDate')) {
		$EndDate = '*'
		try {
			$parsedStart = [datetime]::ParseExact($StartDate, 'yyyy-MM-dd', [System.Globalization.CultureInfo]::InvariantCulture)
		} catch { Write-Host "ERROR: StartDate must be yyyy-MM-dd format." -ForegroundColor Red; exit 1 }
	}
	else {
		try {
			$parsedStart = [datetime]::ParseExact($StartDate, 'yyyy-MM-dd', [System.Globalization.CultureInfo]::InvariantCulture)
			$parsedEnd = [datetime]::ParseExact($EndDate, 'yyyy-MM-dd', [System.Globalization.CultureInfo]::InvariantCulture)
		}
		catch { Write-Host "ERROR: StartDate/EndDate must be in yyyy-MM-dd format." -ForegroundColor Red; exit 1 }
		if ($parsedEnd -lt $parsedStart) { Write-Host "ERROR: EndDate ($EndDate) is earlier than StartDate ($StartDate)." -ForegroundColor Red; exit 1 }
	}
}

# Client-side date-range trim boundaries — Purview's partition-based indexing can
# return records outside the requested date range (observed up to ~10 h past EndDate).
# These UTC boundaries are used after dedup to trim any out-of-range records.
# SpecifyKind(Utc) is critical: ParseExact returns Kind=Unspecified, and .ToUniversalTime()
# on Unspecified assumes LOCAL time, shifting the boundary by the machine's UTC offset.
$script:TrimStartDateUTC = if ($StartDate -ne '*') { [datetime]::SpecifyKind([datetime]::ParseExact($StartDate, 'yyyy-MM-dd', [System.Globalization.CultureInfo]::InvariantCulture), [System.DateTimeKind]::Utc) } else { $null }
$script:TrimEndDateUTC   = if ($EndDate   -ne '*') { [datetime]::SpecifyKind([datetime]::ParseExact($EndDate,   'yyyy-MM-dd', [System.Globalization.CultureInfo]::InvariantCulture), [System.DateTimeKind]::Utc) } else { $null }
$script:DateTrimCount    = 0

if ($BlockHours -le 0) { Write-Host "ERROR: BlockHours must be positive." -ForegroundColor Red; exit 1 }

try { if ($PSVersionTable.PSEdition -eq 'Core' -and ($global:InformationPreference -in @('SilentlyContinue', 'Ignore'))) { $global:InformationPreference = 'Continue' } } catch {}

if ($RAWInputCSV) {
	$rawConflictParams = @('BlockHours', 'ResultSize', 'PacingMs', 'Auth', 'ParallelMode', 'MaxParallelGroups', 'MaxConcurrency', 'EnableParallel', 'GroupNames')
	$specifiedConflicts = @()
	foreach ($cp in $rawConflictParams) { if ($PSBoundParameters.ContainsKey($cp)) { $specifiedConflicts += $cp } }
	if ($specifiedConflicts.Count -gt 0) {
		Write-Host "ERROR: -RAWInputCSV cannot be combined with live query parameter(s): $($specifiedConflicts -join ', ')" -ForegroundColor Red
		Write-Host "Remove those conflicting parameters and re-run. Allowed with RAWInputCSV: StartDate, EndDate, ActivityTypes, AgentId, AgentsOnly, UserIds, OutputFile, AppendFile, explosion switches." -ForegroundColor Yellow
		Write-Host "Note: -GroupNames requires authentication and cannot be used in replay mode. Use -UserIds with explicit email addresses instead." -ForegroundColor Yellow
		exit 1
	}
}

# Validate -UseEOM compatibility with parallel processing
if ($UseEOM) {
	$parallelConflicts = @()
	
	# Check for explicit parallel mode settings
	if ($PSBoundParameters.ContainsKey('EnableParallel') -and $EnableParallel) {
		$parallelConflicts += '-EnableParallel'
	}
	
	if ($PSBoundParameters.ContainsKey('ParallelMode') -and $ParallelMode -ne 'Off') {
		$parallelConflicts += "-ParallelMode $ParallelMode"
	}
	
	if ($parallelConflicts.Count -gt 0) {
		Write-Host ""
		Write-Host "════════════════════════════════════════════════════════════════════" -ForegroundColor Red
		Write-Host "  ERROR: -UseEOM Incompatible with Parallel Processing" -ForegroundColor Red
		Write-Host "════════════════════════════════════════════════════════════════════" -ForegroundColor Red
		Write-Host ""
		Write-Host "Exchange Online Management mode (-UseEOM) only supports SERIAL processing." -ForegroundColor Yellow
		Write-Host "The Search-UnifiedAuditLog cmdlet cannot be used in parallel ThreadJobs due to" -ForegroundColor Gray
		Write-Host "implicit remoting architecture limitations in the EOM PowerShell module." -ForegroundColor Gray
		Write-Host ""
		Write-Host "CONFLICTING PARAMETERS DETECTED:" -ForegroundColor Yellow
		foreach ($conflict in $parallelConflicts) {
			Write-Host "  • $conflict" -ForegroundColor Red
		}
		Write-Host ""
		Write-Host "RESOLUTION OPTIONS:" -ForegroundColor Cyan
		Write-Host "  1. Remove -UseEOM switch to enable Graph API mode (supports parallel processing)" -ForegroundColor White
		Write-Host "  2. Remove parallel parameters and use serial-only processing with -UseEOM" -ForegroundColor White
		Write-Host "  3. Set -ParallelMode Off explicitly: -UseEOM -ParallelMode Off" -ForegroundColor White
		Write-Host ""
		Write-Host "NOTE: Graph API mode (default, no -UseEOM) supports parallel processing in PowerShell 7+." -ForegroundColor Gray
		Write-Host ""
		Write-Host "════════════════════════════════════════════════════════════════════" -ForegroundColor Red
		
		# Log to file if log initialized
		if ($script:logFile -and (Test-Path $script:logFile)) {
			$timestamp = Get-Date -Format 'yyyy-MM-dd HH:mm:ss'
			Add-Content -Path $script:logFile -Value "[$timestamp] ERROR: -UseEOM incompatible with parallel processing parameters: $($parallelConflicts -join ', ')"
			Add-Content -Path $script:logFile -Value "[$timestamp] Script terminated. Resolution: Remove -UseEOM or disable parallel mode."
		}
		
		exit 1
	}
	
	# Force ParallelMode Off in EOM mode even if Auto is set
	if ($ParallelMode -ne 'Off') {
		Write-Host ""
		Write-Host "NOTE: -UseEOM mode requires serial processing. Forcing -ParallelMode Off." -ForegroundColor Yellow
		Write-Host ""
		$ParallelMode = 'Off'
	}
}

$script:learnedActivityBlockSize = @{}
$script:globalLearnedBlockSize = $BlockHours
$script:subdivisionSequence = @(0.5, 0.25, 0.133333, 0.066667, 0.033333, 0.016667, 0.010417, 0.005556, 0.002778, 0.001389)  # 12h, 6h, 3.2h, 1.6h, 48m, 24m, 15m, 8m, 4m, 2m
$script:Hit10KLimit = $false
$script:Hit1MLimit = $false  # Graph API 1,000,000 record limit per query
$script:LimitTimeWindow = ""
$script:SubdividedPartitions = @{}  # Track partitions that needed subdivision (key=original range, value=count)
$script:Connected = $false

# ============================================================================
# GRAPH API SECURITY AUDIT ENDPOINT VERSION CONFIGURATION
# ============================================================================
# Manually configure these variables if Microsoft updates the API version
# PAX will try CURRENT version first, then fallback to PREVIOUS version
# ============================================================================
$script:GraphAuditApiVersion_Current  = 'v1.0'  # Try this version first
$script:GraphAuditApiVersion_Previous = 'beta'  # Fallback to this version if current unavailable
$script:GraphAuditApiVersion = $null            # Runtime-detected version (do not edit)
# ============================================================================

# Suppress PowerShell's web request progress bar (prevents "Reading web response stream" noise)
$ProgressPreference = 'SilentlyContinue'

# Telemetry tracking for Graph API parallel queries (per-slice lifecycle data)
$script:telemetryData = @()

# ============================================================================
# SHAPE CONTRACTS
# ----------------------------------------------------------------------------
# These two helpers freeze the canonical shapes of $script:metrics and of each
# entry in $script:partitionStatus. They are intentionally cheap, fail-fast,
# and called only at well-known initialization points. They do NOT police every
# mutation; their purpose is to catch a future change that introduces an
# incompatible re-init (e.g. drops a required key) at script-start time rather
# than at consumer-time hours later.
#
# If you add a new REQUIRED field to either structure, add it here so the
# contract drift is caught early.
# ============================================================================
$script:MetricsRequiredFields = @(
	'StartTime', 'QueryMs', 'ExplosionMs', 'ExportMs',
	'PagesFetched', 'TotalRecordsFetched', 'TotalStructuredRows',
	'ExplosionEvents', 'ExplosionRowsFromEvents', 'ExplosionMaxPerRecord', 'ExplosionTruncated',
	'Activities',
	'FilteringSkippedRecords', 'FilteringMissingAuditData',
	'FilteringPromptFiltered', 'FilteringParseFailures'
)
$script:PartitionStatusRequiredFields = @(
	'Partition', 'AttemptNumber', 'QueryId', 'QueryName',
	'Status', 'LastError', 'RecordCount'
)

function Assert-MetricsShape {
	<#
	.SYNOPSIS
		Fail-fast contract check for $script:metrics.
	.DESCRIPTION
		Verifies the script-scope metrics hashtable exists and contains every
		required field. Throws a single descriptive error on first mismatch so
		the failure surfaces at startup rather than via a NullReferenceException
		deep in the summary writer.
	#>
	param([hashtable]$Metrics = $script:metrics)
	if (-not $Metrics) {
		throw "Assert-MetricsShape: \$script:metrics is null. A required initialization step was skipped."
	}
	foreach ($k in $script:MetricsRequiredFields) {
		if (-not $Metrics.ContainsKey($k)) {
			throw "Assert-MetricsShape: \$script:metrics is missing required field '$k'. This indicates a structural mismatch."
		}
	}
}

function Assert-PartitionStatusEntry {
	<#
	.SYNOPSIS
		Fail-fast contract check for a single $script:partitionStatus entry.
	.DESCRIPTION
		Verifies the supplied entry contains every field required by the
		downstream STATUS display, retry logic, and summary writer. Optional
		fields (ParentPartition, SubdivisionReason) are intentionally not
		asserted.
	#>
	param(
		[Parameter(Mandatory = $true)] $Entry,
		[string]$Context = '<unspecified>'
	)
	if ($null -eq $Entry) {
		throw "Assert-PartitionStatusEntry [$Context]: entry is null."
	}
	foreach ($k in $script:PartitionStatusRequiredFields) {
		if (-not $Entry.ContainsKey($k)) {
			throw "Assert-PartitionStatusEntry [$Context]: missing required field '$k'. This indicates a structural mismatch."
		}
	}
}

