Write-LogHost "    ensuring its use complies with all applicable laws, regulations," -ForegroundColor Yellow
Write-LogHost "    contractual obligations, and internal policies - including but not" -ForegroundColor Yellow
Write-LogHost "    limited to GDPR, HIPAA, CCPA, employee monitoring laws, works-council" -ForegroundColor Yellow
Write-LogHost "    agreements, and data-residency requirements." -ForegroundColor Yellow
Write-LogHost "  * Microsoft has no visibility into, control over, or responsibility" -ForegroundColor Yellow
Write-LogHost "    for the data customers extract using this tool or how that data is" -ForegroundColor Yellow
Write-LogHost "    subsequently used, shared, or stored. Microsoft disclaims any and all" -ForegroundColor Yellow
Write-LogHost "    liability arising from or related to customer use of this script and" -ForegroundColor Yellow
Write-LogHost "    its output." -ForegroundColor Yellow
Write-LogHost "  * Treat all output files as HIGHLY CONFIDENTIAL. Restrict access to" -ForegroundColor Yellow
Write-LogHost "    authorized personnel with a documented business need. Encrypt at rest" -ForegroundColor Yellow
Write-LogHost "    and in transit. Apply tenant DLP / sensitivity labels as appropriate." -ForegroundColor Yellow
Write-LogHost "=========================================================================" -ForegroundColor Yellow
Write-LogHost ""

if ($RAWInputCSV) {
	# Set replay mode flag for graceful exit handling (skip Graph disconnect messaging)
	$env:PAX_REPLAY_MODE = "1"
	Write-LogHost "`nReplay mode: Skipping module loading`n" -ForegroundColor Cyan
}
elseif (-not $UseEOM) {
	# DEFAULT MODE: Microsoft Graph Security API
	# Requires Microsoft.Graph.Authentication and Microsoft.Graph.Security modules
	Write-LogHost ""
	Write-LogHost "Loading Microsoft Graph modules..." -ForegroundColor Cyan

	try {
		# ============================================
		# AUTO-UPDATE CHECK: Ensure latest SDK version
		# ============================================
		# The Graph Security auditLog API has known issues with older SDK versions.
		# Always check for and install the latest version to ensure compatibility.
		
		Write-LogHost "  Checking for Microsoft Graph SDK updates..." -ForegroundColor Gray
		
		# Get currently installed version
		$installedAuth = Get-Module -ListAvailable -Name Microsoft.Graph.Authentication | Sort-Object Version -Descending | Select-Object -First 1
		$installedAuthVersion = if ($installedAuth) { $installedAuth.Version } else { [Version]"0.0.0" }
		
		# Check PSGallery for latest version (with 15-second timeout to avoid hangs)
		$latestAuthVersion = $null
		try {
			$updateCheckJob = Start-Job -ScriptBlock { Find-Module -Name Microsoft.Graph.Authentication -Repository PSGallery -ErrorAction Stop }
			$jobCompleted = Wait-Job -Job $updateCheckJob -Timeout 15
			if ($jobCompleted) {
				$galleryAuth = Receive-Job -Job $updateCheckJob -ErrorAction Stop
				$latestAuthVersion = [Version]$galleryAuth.Version
			}
			else {
				Write-LogHost "  PSGallery check timed out (15s) - skipping update check" -ForegroundColor Yellow
			}
			Remove-Job -Job $updateCheckJob -Force -ErrorAction SilentlyContinue
		}
		catch {
			Write-LogHost "  Warning: Could not check PSGallery for updates: $($_.Exception.Message)" -ForegroundColor Yellow
			Write-LogHost "  Continuing with installed version..." -ForegroundColor Yellow
		}
		
		# Update if newer version available
		$updatePerformed = $false
		if ($latestAuthVersion -and ($latestAuthVersion -gt $installedAuthVersion)) {
			Write-LogHost "  Update available: v$installedAuthVersion → v$latestAuthVersion" -ForegroundColor Yellow
			Write-LogHost "  Installing Microsoft.Graph.Authentication v$latestAuthVersion..." -ForegroundColor Yellow
			
			try {
				# Install latest Authentication module
				Install-Module -Name Microsoft.Graph.Authentication -Scope CurrentUser -Force -AllowClobber -ErrorAction Stop
				Write-LogHost "  Microsoft.Graph.Authentication updated to v$latestAuthVersion" -ForegroundColor Green
				
				# Install matching Security module
				Write-LogHost "  Installing Microsoft.Graph.Security v$latestAuthVersion..." -ForegroundColor Yellow
				Install-Module -Name Microsoft.Graph.Security -RequiredVersion $latestAuthVersion -Scope CurrentUser -Force -AllowClobber -ErrorAction Stop
				Write-LogHost "  Microsoft.Graph.Security updated to v$latestAuthVersion" -ForegroundColor Green
				
				$updatePerformed = $true
				
				# Refresh module info after update
				$installedAuth = Get-Module -ListAvailable -Name Microsoft.Graph.Authentication | Sort-Object Version -Descending | Select-Object -First 1
				$installedAuthVersion = $installedAuth.Version
			}
			catch {
				Write-LogHost "  Warning: Update failed: $($_.Exception.Message)" -ForegroundColor Yellow
				Write-LogHost "  Continuing with existing version v$installedAuthVersion..." -ForegroundColor Yellow
			}
		}
		elseif ($latestAuthVersion) {
			Write-LogHost "  Microsoft Graph SDK is up to date (v$installedAuthVersion)" -ForegroundColor Green
		}
		else {
			Write-LogHost "  Using installed version v$installedAuthVersion" -ForegroundColor Gray
		}
		
		# ============================================
		# LOAD MODULES
		# ============================================
		
		$authModule = Get-Module -Name Microsoft.Graph.Authentication | Select-Object -First 1
		if (-not $authModule) {
			$authModule = Get-Module -ListAvailable -Name Microsoft.Graph.Authentication | Sort-Object Version -Descending | Select-Object -First 1
		}
		if (-not $authModule) {
			Write-LogHost "  Installing Microsoft.Graph.Authentication module (CurrentUser scope)..." -ForegroundColor Yellow
			Install-Module -Name Microsoft.Graph.Authentication -Scope CurrentUser -Force -AllowClobber -ErrorAction Stop
			$authModule = Get-Module -ListAvailable -Name Microsoft.Graph.Authentication | Sort-Object Version -Descending | Select-Object -First 1
		}
		$authVersion = $authModule.Version
		Write-LogHost "  Importing Microsoft.Graph.Authentication v$authVersion..." -ForegroundColor Gray
		Import-Module Microsoft.Graph.Authentication -RequiredVersion $authVersion -Force -ErrorAction Stop
		Write-LogHost "  Microsoft.Graph.Authentication v$authVersion loaded" -ForegroundColor Green

		# Load Microsoft.Graph.Security matching auth version (exact if possible, otherwise same major/minor)
		$securityModule = Get-Module -Name Microsoft.Graph.Security | Where-Object { $_.Version -eq $authVersion } | Select-Object -First 1
		if (-not $securityModule) {
			$securityModule = Get-Module -ListAvailable -Name Microsoft.Graph.Security |
				Where-Object { $_.Version.Major -eq $authVersion.Major -and $_.Version.Minor -eq $authVersion.Minor } |
				Sort-Object Version -Descending |
				Select-Object -First 1
		}
		if (-not $securityModule) {
			Write-LogHost "  Installing Microsoft.Graph.Security v$authVersion (CurrentUser scope)..." -ForegroundColor Yellow
			Install-Module -Name Microsoft.Graph.Security -RequiredVersion $authVersion -Scope CurrentUser -Force -AllowClobber -ErrorAction Stop
			$securityModule = Get-Module -ListAvailable -Name Microsoft.Graph.Security | Where-Object { $_.Version -eq $authVersion } | Select-Object -First 1
		}
		$secVersion = $securityModule.Version
		Write-LogHost "  Importing Microsoft.Graph.Security v$secVersion..." -ForegroundColor Gray
		Import-Module Microsoft.Graph.Security -RequiredVersion $secVersion -Force -ErrorAction Stop
		Write-LogHost "  Microsoft.Graph.Security v$secVersion loaded" -ForegroundColor Green
	}
	catch {
		Write-LogHost "  ERROR: Failed to load Microsoft Graph module: $($_.Exception.Message)" -ForegroundColor Red
		Write-LogHost "`nTroubleshooting:" -ForegroundColor Yellow
		Write-LogHost "  1. Ensure PowerShell Gallery access is available" -ForegroundColor White
		Write-LogHost "  2. Try manual installation: Install-Module -Name Microsoft.Graph -Force" -ForegroundColor White
		Write-LogHost "  3. Use -UseEOM switch to fall back to Exchange Online Management mode" -ForegroundColor White
		throw
	}

	Write-LogHost "Microsoft Graph modules loaded successfully`n" -ForegroundColor Green
}
else {
	# EOM MODE: Exchange Online Management
	# Graph modules not required in EOM mode
	Write-LogHost "`nEOM Mode: Skipping Microsoft Graph module loading`n" -ForegroundColor Cyan
}

# ==============================================
# DUAL-MODE AUTHENTICATION FUNCTION
# ==============================================
# Unified authentication supporting both EOM and Graph API modes

function Connect-PurviewAudit {
	<#
	.SYNOPSIS
		Unified authentication for Purview audit log access via EOM or Graph API.
	
	.DESCRIPTION
		Authenticates to Microsoft 365 using either Exchange Online Management (EOM)
		or Microsoft Graph Security API based on the -UseEOM switch.
		
		EOM Mode (-UseEOM):
		  - Uses Connect-ExchangeOnline cmdlet
		  - Requires Exchange Online RBAC roles
		  - Serial processing only
		
		Graph API Mode (Default):
		  - Uses Connect-MgGraph with AuditLogsQuery.Read.All scope
		  - Requires Azure AD roles + Graph API permissions
		  - Supports parallel processing
	
	.PARAMETER AuthMethod
		Authentication method: WebLogin, DeviceCode, Credential, Silent, AppRegistration
	
	.PARAMETER UseEOMMode
		If true, use EOM mode. If false, use Graph API mode.
	#>
	
	param(
		[Parameter(Mandatory = $true)]
		[ValidateSet('WebLogin', 'DeviceCode', 'Credential', 'Silent', 'AppRegistration', 'ManagedIdentity')]
		[string]$AuthMethod,
		
		[Parameter(Mandatory = $false)]
		[bool]$UseEOMMode = $false
	)
	
	if ($UseEOMMode) {
		# ========================================
		# EOM MODE: Exchange Online Management
		# ========================================
		
		if ($script:Connected) {
			Write-LogHost "Already connected to Exchange Online." -ForegroundColor Gray
			return
		}
		
		Write-LogHost "Connecting to Microsoft 365 Security & Compliance Center (EOM)..." -ForegroundColor Cyan
		
		# Ensure ExchangeOnlineManagement module is available
		try {
			$existingEOM = Get-Module -ListAvailable -Name ExchangeOnlineManagement | Sort-Object Version -Descending | Select-Object -First 1
			if (-not $existingEOM) {
				Write-LogHost "Installing ExchangeOnlineManagement module (CurrentUser scope)..." -ForegroundColor Yellow
				Install-Module -Name ExchangeOnlineManagement -Scope CurrentUser -Force -AllowClobber -ErrorAction Stop
			}
			Import-Module ExchangeOnlineManagement -Force -ErrorAction Stop
			
			$eomVersion = (Get-Module ExchangeOnlineManagement).Version
			Write-LogHost "  ExchangeOnlineManagement v$eomVersion loaded" -ForegroundColor Green
		}
		catch {
			Write-LogHost "ERROR: Module load/install failure: $($_.Exception.Message)" -ForegroundColor Red
			throw
		}
		
		# Authenticate based on method
		try {
			switch ($AuthMethod.ToLower()) {
				'appregistration' {
					Write-LogHost "AppRegistration authentication is not supported with -UseEOM. Remove -UseEOM to use Graph mode." -ForegroundColor Yellow
					throw "AppRegistration authentication is only available in Graph API mode"
				}
				'weblogin' {
					$exoCmd = Get-Command Connect-ExchangeOnline -ErrorAction Stop
					$hasUseWeb = $exoCmd.Parameters.ContainsKey('UseWebLogin')
					
					if ($hasUseWeb) {
						Write-LogHost "Using Connect-ExchangeOnline -UseWebLogin..." -ForegroundColor Gray
						Connect-ExchangeOnline -ShowBanner:$false -UseWebLogin -ErrorAction Stop | Out-Null
					}
					else {
						Write-LogHost "UseWebLogin parameter not available; using standard interactive auth..." -ForegroundColor Yellow
						Connect-ExchangeOnline -ShowBanner:$false -ErrorAction Stop | Out-Null
					}
				}
				
				'devicecode' {
					Write-LogHost "Using device code flow..." -ForegroundColor Gray
					Connect-ExchangeOnline -ShowBanner:$false -Device -ErrorAction Stop | Out-Null
				}
				
				'credential' {
					Write-LogHost "Using credential-based authentication..." -ForegroundColor Gray
					$cred = Get-Credential -Message 'Enter admin credentials for Exchange Online'
					Connect-ExchangeOnline -ShowBanner:$false -Credential $cred -ErrorAction Stop | Out-Null
				}
				
				'silent' {
					Write-LogHost "Attempting silent authentication..." -ForegroundColor Gray
					$silentOk = $true
					try {
						Connect-ExchangeOnline -ShowBanner:$false -ErrorAction Stop | Out-Null
					}
					catch {
						$silentOk = $false
					}
					
					if (-not $silentOk) {
						Write-LogHost "Silent auth failed, falling back to WebLogin..." -ForegroundColor Yellow
						try {
							Connect-ExchangeOnline -ShowBanner:$false -UseWebLogin -ErrorAction Stop | Out-Null
						}
						catch {
							Write-LogHost "ERROR: Silent + fallback auth failed: $($_.Exception.Message)" -ForegroundColor Red
							throw
						}
					}
				}
				'managedidentity' {
					Write-LogHost "ERROR: -Auth ManagedIdentity is not supported with -UseEOM." -ForegroundColor Red
					Write-LogHost "       Exchange Online Management does not accept managed-identity auth." -ForegroundColor Yellow
					Write-LogHost "       Use -Auth ManagedIdentity without -UseEOM (Graph API path)." -ForegroundColor Yellow
					throw "ManagedIdentity auth is not supported with -UseEOM"
				}
			}
			
			$script:Connected = $true
			Write-LogHost "Successfully connected to Exchange Online" -ForegroundColor Green
			
			# Verify connection
			try {
				$connInfo = Get-ConnectionInformation -ErrorAction SilentlyContinue | Where-Object { $_.TokenStatus -ne 'Expired' } | Select-Object -First 1
				if ($connInfo) {
					Write-LogHost "  Tenant ID: $($connInfo.TenantId)" -ForegroundColor Gray
					Write-LogHost "  User: $($connInfo.UserPrincipalName)" -ForegroundColor Gray
				}
			}
			catch {
				# Connection info not critical, continue
			}
		}
		catch {
			Write-LogHost "ERROR: EOM authentication failed: $($_.Exception.Message)" -ForegroundColor Red
			Write-LogHost "`nTroubleshooting:" -ForegroundColor Yellow
			Write-LogHost "  1. Verify you have required Exchange Online roles" -ForegroundColor White
			Write-LogHost "  2. Check Multi-Factor Authentication requirements" -ForegroundColor White
			Write-LogHost "  3. Try a different auth method (-Auth parameter)" -ForegroundColor White
			throw
		}
	}
	else {
		# ========================================
		# GRAPH API MODE: Microsoft Graph Security
		# ========================================
		
		# Clear any stale Graph session from a previous script run or Ctrl+C in this terminal.
		# This forces a fresh Connect-MgGraph with a new token, preventing issues where MSAL
		# silently returns a cached expired token or a token from a different user account.
		Write-LogHost "Clearing any previous Graph session..." -ForegroundColor Gray
		try { Disconnect-MgGraph -ErrorAction SilentlyContinue | Out-Null } catch { }
		
		Write-LogHost "Connecting to Microsoft Graph Security API..." -ForegroundColor Cyan
		
		# Define required scopes for Purview audit log access via the Microsoft Graph
		# Security API. The exact scope set is built dynamically based on which features
		# the caller has activated, so users only consent to what they actually use.
		#
		# Conditional (added only when the relevant switch is set):
		#   Audit query (skipped under -OnlyUserInfo since no audit calls are made):
		#       AuditLogsQuery.Read.All - umbrella scope for /security/auditLog/queries
		#                                 (covers CopilotInteraction and other workload-
		#                                 agnostic record types)
		#   -IncludeM365Usage:
		#       AuditLogsQuery-Exchange.Read.All
		#       AuditLogsQuery-OneDrive.Read.All
		#       AuditLogsQuery-SharePoint.Read.All
		#   -IncludeUserInfo / -OnlyUserInfo (Graph API mode only):
		#       User.Read.All           (read /users for Entra directory + license map)
		#       Organization.Read.All   (read /subscribedSkus for license SKU lookup)
		#   -GroupNames (Graph API mode only):
		#       GroupMember.Read.All    (least-privilege scope per Microsoft Graph docs
		#                                for GET /groups and GET /groups/{id}/members;
		#                                used by Expand-PurviewGroupMembership)
		$RequiredScopes = [System.Collections.Generic.List[string]]::new()
		if (-not $OnlyUserInfo -and -not $OnlyAgent365Info) {
			[void]$RequiredScopes.Add('AuditLogsQuery.Read.All')
		}
		if ($IncludeM365Usage) {
			[void]$RequiredScopes.Add('AuditLogsQuery-Exchange.Read.All')
			[void]$RequiredScopes.Add('AuditLogsQuery-OneDrive.Read.All')
			[void]$RequiredScopes.Add('AuditLogsQuery-SharePoint.Read.All')
		}
		if ($IncludeUserInfo -or $OnlyUserInfo) {
			if ($RequiredScopes -notcontains 'User.Read.All')         { [void]$RequiredScopes.Add('User.Read.All') }
			if ($RequiredScopes -notcontains 'Organization.Read.All') { [void]$RequiredScopes.Add('Organization.Read.All') }
		}
		if ($GroupNames -and $GroupNames.Count -gt 0) {
			if ($RequiredScopes -notcontains 'GroupMember.Read.All') { [void]$RequiredScopes.Add('GroupMember.Read.All') }
		}
		# Microsoft Agent 365 enrichment scopes (interactive/delegated auth modes only).
		# AppRegistration path takes a separate interactive context for the agent phase
		# (see banner 7a near Connect-PurviewAudit), so these are not added there.
		# ManagedIdentity is rejected up-front by parameter validation (no user principal
		# can hold the AI Admin / Global Admin role the endpoint requires), but exclude
		# it here as defense-in-depth so the scope is never added even if validation
		# changes.
		if (($IncludeAgent365Info -or $OnlyAgent365Info) -and $AuthMethod -notin @('AppRegistration','ManagedIdentity')) {
			if ($RequiredScopes -notcontains 'CopilotPackages.Read.All') { [void]$RequiredScopes.Add('CopilotPackages.Read.All') }
			if ($RequiredScopes -notcontains 'Application.Read.All')    { [void]$RequiredScopes.Add('Application.Read.All') }
		}
		# SharePoint remote-output destination needs delegated/app drive write scopes.
		# Fabric/OneLake uses a separate storage-audience token (Az.Accounts), not a Graph scope.
		if ($script:RemoteOutputMode -eq 'SharePoint') {
			if ($RequiredScopes -notcontains 'Sites.ReadWrite.All') { [void]$RequiredScopes.Add('Sites.ReadWrite.All') }
			if ($RequiredScopes -notcontains 'Files.ReadWrite.All') { [void]$RequiredScopes.Add('Files.ReadWrite.All') }
		}
		$RequiredScopes = $RequiredScopes.ToArray()

		try {
			switch ($AuthMethod.ToLower()) {
				'weblogin' {
					Write-LogHost "Using interactive browser authentication..." -ForegroundColor Gray
					Connect-MgGraph -Scopes $RequiredScopes -NoWelcome -ErrorAction Stop
				}
				
				'devicecode' {
					Write-LogHost "Using device code flow..." -ForegroundColor Gray
					Write-LogHost "A browser window will open. Follow the instructions to authenticate." -ForegroundColor Yellow
					Connect-MgGraph -Scopes $RequiredScopes -UseDeviceCode -NoWelcome -ErrorAction Stop
				}
				
				'credential' {
					Write-LogHost "Using client secret credential..." -ForegroundColor Gray
					
					# Check for required environment variables
					$tenantId = $env:GRAPH_TENANT_ID
					$clientId = $env:GRAPH_CLIENT_ID
					$clientSecret = $env:GRAPH_CLIENT_SECRET
					
					if (-not $tenantId -or -not $clientId -or -not $clientSecret) {
						Write-LogHost "ERROR: Credential authentication requires environment variables:" -ForegroundColor Red
						Write-LogHost "  GRAPH_TENANT_ID     : Your Azure AD Tenant ID" -ForegroundColor Yellow
						Write-LogHost "  GRAPH_CLIENT_ID     : Your App Registration Client ID" -ForegroundColor Yellow
						Write-LogHost "  GRAPH_CLIENT_SECRET : Your App Registration Client Secret" -ForegroundColor Yellow
						Write-LogHost ""
						Write-LogHost "Set these variables before running the script:" -ForegroundColor Yellow
						Write-LogHost "  `$env:GRAPH_TENANT_ID = 'your-tenant-id'" -ForegroundColor White
						Write-LogHost "  `$env:GRAPH_CLIENT_ID = 'your-client-id'" -ForegroundColor White
						Write-LogHost "  `$env:GRAPH_CLIENT_SECRET = 'your-client-secret'" -ForegroundColor White
						throw "Missing required environment variables for credential authentication"
					}
					
					$secureSecret = ConvertTo-SecureString -String $clientSecret -AsPlainText -Force
					$credential = New-Object System.Management.Automation.PSCredential($clientId, $secureSecret)
					
					# Clear plain-text secret from memory
					Clear-Variable -Name clientSecret -Force -ErrorAction SilentlyContinue
					
					Connect-MgGraph -TenantId $tenantId -ClientSecretCredential $credential -NoWelcome -ErrorAction Stop
				}
				
				'silent' {
					Write-LogHost "Using managed identity or existing token..." -ForegroundColor Gray
					Connect-MgGraph -Identity -NoWelcome -ErrorAction Stop
				}
				'managedidentity' {
					Write-LogHost "Using managed identity (system-assigned or user-assigned)..." -ForegroundColor Gray
					if ($env:AZURE_CLIENT_ID) {
						Write-LogHost ("  -> User-assigned MI client id: {0}" -f $env:AZURE_CLIENT_ID) -ForegroundColor DarkGray
						Connect-MgGraph -Identity -ClientId $env:AZURE_CLIENT_ID -NoWelcome -ErrorAction Stop
					} else {
						Connect-MgGraph -Identity -NoWelcome -ErrorAction Stop
					}
				}
				'appregistration' {
					Write-LogHost "Using app registration authentication..." -ForegroundColor Gray

					$appTenantId = $script:TenantId
					if ([string]::IsNullOrWhiteSpace($appTenantId)) { $appTenantId = $env:GRAPH_TENANT_ID }
					if ([string]::IsNullOrWhiteSpace($appTenantId)) {
						Write-LogHost "ERROR: -TenantId or GRAPH_TENANT_ID is required for AppRegistration auth." -ForegroundColor Red
						throw "Missing TenantId for AppRegistration authentication"
					}

					$appClientId = $script:ClientId
					if ([string]::IsNullOrWhiteSpace($appClientId)) { $appClientId = $env:GRAPH_CLIENT_ID }
					if ([string]::IsNullOrWhiteSpace($appClientId)) {
						Write-LogHost "ERROR: -ClientId or GRAPH_CLIENT_ID is required for AppRegistration auth." -ForegroundColor Red
						throw "Missing ClientId for AppRegistration authentication"
					}

					# Store auth config for potential re-authentication during long-running operations
					$script:AuthConfig.Method = 'AppRegistration'
					$script:AuthConfig.TenantId = $appTenantId
					$script:AuthConfig.ClientId = $appClientId
					$script:AuthConfig.CertStoreLocation = $script:ClientCertificateStoreLocation

					$secretValue = $script:ClientSecret
					if ([string]::IsNullOrWhiteSpace($secretValue)) { $secretValue = $env:GRAPH_CLIENT_SECRET }

					$certThumbprint = $script:ClientCertificateThumbprint
					if ([string]::IsNullOrWhiteSpace($certThumbprint)) { $certThumbprint = $env:GRAPH_CLIENT_CERT_THUMBPRINT }

					$certPath = $script:ClientCertificatePath
					if ([string]::IsNullOrWhiteSpace($certPath)) { $certPath = $env:GRAPH_CLIENT_CERT_PATH }

					$certPasswordSecure = $script:ClientCertificatePassword
					if (-not $certPasswordSecure -and $env:GRAPH_CLIENT_CERT_PASSWORD) {
						$certPasswordSecure = ConvertTo-SecureString $env:GRAPH_CLIENT_CERT_PASSWORD -AsPlainText -Force
					}

					$certPasswordPlain = $null
					if ($certPasswordSecure) {
						$certPasswordPlain = [System.Net.NetworkCredential]::new('', $certPasswordSecure).Password
					}

					if (-not [string]::IsNullOrWhiteSpace($secretValue)) {
						Write-LogHost "  -> Authenticating with client secret" -ForegroundColor Gray
						$secureSecret = ConvertTo-SecureString -String $secretValue -AsPlainText -Force
						$credential = New-Object System.Management.Automation.PSCredential($appClientId, $secureSecret)
						# Store secret securely for re-authentication (keep a copy before clearing)
						$script:AuthConfig.ClientSecret = $secureSecret.Copy()
						$script:AuthConfig.CanReauthenticate = $true
						Clear-Variable -Name secretValue -Force -ErrorAction SilentlyContinue
						Connect-MgGraph -TenantId $appTenantId -ClientSecretCredential $credential -NoWelcome -ErrorAction Stop
						Clear-Variable -Name secureSecret -Force -ErrorAction SilentlyContinue
						Clear-Variable -Name credential -Force -ErrorAction SilentlyContinue
					}
					elseif (-not [string]::IsNullOrWhiteSpace($certThumbprint)) {
						# Normalize: strip spaces and any non-hex paste artifacts (the Windows cert
						# dialog can prepend a hidden left-to-right mark), then upper-case.
						$certThumbprint = ($certThumbprint -replace '[^0-9A-Fa-f]', '').ToUpperInvariant()
						Write-LogHost "  -> Authenticating with certificate thumbprint $certThumbprint" -ForegroundColor Gray
						# Search the requested store first, then the OTHER store. App-registration
						# certs on servers are commonly in LocalMachine\My even when the run defaults
						# to CurrentUser; this finds the cert in either location.
						$requestedLoc = $script:ClientCertificateStoreLocation
						$otherLoc     = if ($requestedLoc -eq 'LocalMachine') { 'CurrentUser' } else { 'LocalMachine' }
						$certificate  = $null
						$resolvedLoc  = $null
						foreach ($loc in @($requestedLoc, $otherLoc)) {
							$storeLocation = [System.Security.Cryptography.X509Certificates.StoreLocation]::$loc
							$store = New-Object System.Security.Cryptography.X509Certificates.X509Store("My", $storeLocation)
							try {
								$store.Open([System.Security.Cryptography.X509Certificates.OpenFlags]::ReadOnly)
								$match = @($store.Certificates | Where-Object { $_.Thumbprint -eq $certThumbprint })
								if ($match.Count -gt 0) {
									# Prefer a copy that carries the private key.
									$withKey = @($match | Where-Object { $_.HasPrivateKey } | Select-Object -First 1)
									$certificate = if ($withKey.Count -gt 0) { $withKey[0] } else { $match[0] }
									$resolvedLoc = $loc
									break
								}
							}
							catch {
								# This store could not be opened/read (e.g. access denied to
								# LocalMachine\My); skip it and try the other store.
							}
							finally {
								$store.Close()
							}
						}
						if (-not $certificate) {
							Write-LogHost "ERROR: Certificate with thumbprint '$certThumbprint' not found in CurrentUser\My or LocalMachine\My." -ForegroundColor Red
							throw "Certificate not found"
						}
						if (-not $certificate.HasPrivateKey) {
							Write-LogHost "ERROR: Certificate '$certThumbprint' was found in $resolvedLoc\My but has no accessible private key (only the public .cer appears to be installed, or the running account cannot read the key)." -ForegroundColor Red
							throw "Certificate has no usable private key"
						}
						if ($resolvedLoc -ne $requestedLoc) {
							Write-LogHost "  -> Certificate located in $resolvedLoc\My (requested store was $requestedLoc\My)." -ForegroundColor Gray
						}
						# Pin the resolved cert object for the whole run + token refreshes. Passing
						# -Certificate (not -CertificateThumbprint) makes the lookup deterministic and
						# independent of which stores the SDK searches; pinning prevents the
						# SafeCertContext handle from being GC-invalidated on later token requests
						# (same rationale as the -ClientCertificatePath branch).
						$script:AuthConfig.CertThumbprint   = $certThumbprint
						$script:AuthConfig.CertStoreLocation = $resolvedLoc
						$script:AuthConfig.CertObject        = $certificate
						$script:AuthConfig.CanReauthenticate = $true
						Connect-MgGraph -TenantId $appTenantId -ClientId $appClientId -Certificate $certificate -NoWelcome -ErrorAction Stop
					}
					elseif (-not [string]::IsNullOrWhiteSpace($certPath)) {
						Write-LogHost "  -> Authenticating with certificate file $certPath" -ForegroundColor Gray
						# CRITICAL: EphemeralKeySet keeps the private key in process memory only (no temp
						# .pfx-key file in %APPDATA%\Microsoft\Crypto\) and ties the SafeCertContext lifetime
						# to the X509Certificate2 object itself. Without this flag, default DefaultKeySet/UserKeySet
						# storage causes Azure.Identity's ClientCertificateCredential to throw
						# 'm_safeCertContext is an invalid handle' on every token request after the first.
						# Exportable is required so the SDK can re-export the key for token signing.
						$flags = [System.Security.Cryptography.X509Certificates.X509KeyStorageFlags]::EphemeralKeySet `
							-bor [System.Security.Cryptography.X509Certificates.X509KeyStorageFlags]::Exportable
						$cert = $null
						try {
							if ($certPasswordPlain) {
								$cert = New-Object System.Security.Cryptography.X509Certificates.X509Certificate2($certPath, $certPasswordPlain, $flags)
							}
							else {
								# 3-arg ctor with empty password is required so the explicit flags apply.
								$cert = New-Object System.Security.Cryptography.X509Certificates.X509Certificate2($certPath, [string]'', $flags)
							}
							# Store cert path and password for re-authentication
							$script:AuthConfig.CertPath = $certPath
							if ($certPasswordSecure) { $script:AuthConfig.CertPassword = $certPasswordSecure.Copy() }
							# CRITICAL: Pin the cert object on $script: scope so it lives for the entire run.
							# Azure.Identity's ClientCertificateCredential keeps a managed reference but does
							# NOT clone the SafeCertContext - if the cert is GC'd or Disposed, every later
							# token request fails with 'invalid handle'. The cert MUST NOT be disposed in
							# the finally block; it is released at script exit when $script:AuthConfig is torn down.
							$script:AuthConfig.CertObject = $cert
							$script:AuthConfig.CanReauthenticate = $true
							Connect-MgGraph -TenantId $appTenantId -ClientId $appClientId -Certificate $cert -NoWelcome -ErrorAction Stop
						}
						finally {
							# Intentionally NOT disposing $cert here - it must outlive Connect-MgGraph for the
							# duration of the script run. EphemeralKeySet ensures no on-disk artifacts to clean up;
							# the cert is fully released at script exit when $script:AuthConfig is torn down.
							if ($certPasswordPlain) {
								Clear-Variable -Name certPasswordPlain -Force -ErrorAction SilentlyContinue
							}
						}
					}
					else {
						Write-LogHost "ERROR: Provide either -ClientSecret, -ClientCertificateThumbprint, or -ClientCertificatePath for AppRegistration auth." -ForegroundColor Red
						throw "No credential material supplied for AppRegistration"
					}

					if ($certPasswordSecure) {
						Clear-Variable -Name certPasswordSecure -Force -ErrorAction SilentlyContinue
					}
				}
			}
			
			# Build a context-aware connection-success message
			$connectMsg = if ($AuthMethod.ToLower() -eq 'appregistration') {
				if ($IncludeAgent365Info -or $OnlyAgent365Info) {
					"Successfully connected to Microsoft Graph (Phase 1 of 2: app-only audit context). The Phase 2 (Agent 365) interactive sign-in will be requested NEXT, up-front, before audit work begins."
				} else {
					"Successfully connected to Microsoft Graph (app-only context)."
				}
			} else {
				"Successfully connected to Microsoft Graph (delegated user context)."
			}
			Write-LogHost $connectMsg -ForegroundColor Green
			
			# Record token issue time for proactive refresh tracking
			$script:AuthConfig.TokenIssueTime = Get-Date
			
			# Initialize shared auth state for thread jobs (enables proactive token refresh)
			$tokenInfo = Get-GraphAccessTokenWithExpiry
			if ($tokenInfo) {
				$script:SharedAuthState.Token = $tokenInfo.Token
				$script:SharedAuthState.ExpiresOn = $tokenInfo.ExpiresOn
				$script:SharedAuthState.LastRefresh = Get-Date
				$script:SharedAuthState.AuthMethod = $AuthMethod.ToLower()
				Write-LogHost "  Token expires: $($tokenInfo.ExpiresOn.ToString('yyyy-MM-dd HH:mm:ss')) UTC (source: $($tokenInfo.Source))" -ForegroundColor Gray
			}
			
			# Get and display current context
			$context = Get-MgContext
			# Detect dual-context run: AppRegistration audit phase + delegated Agent 365 phase.
			# In that case, defer the per-line Tenant/Account/Scopes display until AFTER Phase 2
			# sign-in completes, so the log shows BOTH phases honestly side-by-side. Capture the
			# Phase 1 context now into script-scope vars so the combined emitter can use them.
			$script:DeferAuthContextDisplay = ($AuthMethod -eq 'AppRegistration') -and ($IncludeAgent365Info -or $OnlyAgent365Info)
			if ($script:DeferAuthContextDisplay) {
				$script:Phase1Context = [pscustomobject]@{
					TenantId        = $context.TenantId
					Account         = $context.Account
					GrantedRequired = @($RequiredScopes | Where-Object { $context.Scopes -contains $_ })
					RequiredScopes  = @($RequiredScopes)
				}
				Write-LogHost "  Phase 1 (audit) connected." -ForegroundColor Gray
			} else {
				Write-LogHost "  Tenant ID: $($context.TenantId)" -ForegroundColor Gray
				$maskedAccount = Get-MaskedUsername -Username $context.Account
				if ([string]::IsNullOrWhiteSpace($maskedAccount)) {
					# App-only contexts have no signed-in user; surface the auth mode instead of a blank value.
					$maskedAccount = if ($AuthMethod -eq 'AppRegistration') { '(app-only / AppRegistration - no interactive user)' }
									 elseif ($AuthMethod -eq 'ManagedIdentity') {
										if ($env:AZURE_CLIENT_ID) { "(app-only / ManagedIdentity - clientId $env:AZURE_CLIENT_ID)" }
										else                      { '(app-only / ManagedIdentity - system-assigned)' }
									 }
									 else { '(no signed-in user)' }
				}
				Write-LogHost "  Account:   $maskedAccount" -ForegroundColor Gray
				# Filter displayed scopes to those required by this script (avoids confusion when the
				# user/app holds additional consented scopes unrelated to PAX). Granted required scopes
				# are shown; any required scopes missing from the token are surfaced separately below.
				$grantedRequired = @($RequiredScopes | Where-Object { $context.Scopes -contains $_ })
				Write-LogHost "  Scopes:    $($grantedRequired -join ', ')" -ForegroundColor Gray
			}
			
			# Trigger Graph API version detection early (before queries start)
			$null = Get-GraphAuditApiUri -Path 'queries'
			
			# Validate required scopes are present
			# NOTE: For app-only (AppRegistration) contexts, the access token carries permissions
			# in the 'roles' claim (application permissions), not the 'scp' claim. The Graph SDK
			# only populates $context.Scopes from 'scp', so $context.Scopes is empty/partial for
			# app-only auth even when admin-consented application permissions are fully granted.
			# A scope-membership check would falsely flag every required permission as missing.
			# App permissions are validated server-side at API call time, so we skip the warning.
			$isAppOnlyContext = $false
			if ($context) {
				$isAppOnlyContext = ([string]::IsNullOrWhiteSpace($context.Account)) -or ($context.AuthType -eq 'AppOnly')
			}
			$missingScopes = @()
			if (-not $isAppOnlyContext) {
				foreach ($scope in $RequiredScopes) {
					if ($context.Scopes -notcontains $scope) {
						$missingScopes += $scope
					}
				}
			}
			
			if ($missingScopes.Count -gt 0) {
				Write-LogHost ""
				Write-LogHost "WARNING: Missing required scope(s):" -ForegroundColor Yellow
				foreach ($scope in $missingScopes) {
					Write-LogHost "  • $scope" -ForegroundColor Yellow
				}
				Write-LogHost ""
				Write-LogHost "Script may fail when accessing audit logs." -ForegroundColor Yellow
				Write-LogHost "Consider re-authenticating with full permissions." -ForegroundColor Yellow
				Write-LogHost ""
			}
			
			$script:Connected = $true
		}
		catch {
			Write-LogHost "ERROR: Graph API authentication failed: $($_.Exception.Message)" -ForegroundColor Red
			Write-LogHost ""
			Write-LogHost "Troubleshooting:" -ForegroundColor Yellow
			Write-LogHost "  1. Ensure you have AuditLogsQuery.Read.All permission" -ForegroundColor White
			Write-LogHost "  2. Verify Azure AD role (Compliance/Security Administrator)" -ForegroundColor White
			Write-LogHost "  3. Check network connectivity to Microsoft Graph API" -ForegroundColor White
			Write-LogHost "  4. Try a different authentication method (-Auth parameter)" -ForegroundColor White
			Write-LogHost "  5. Use -UseEOM switch to fall back to EOM mode" -ForegroundColor White
			Write-LogHost ""
			throw
		}
	}
}

# ==============================================
# ACCESS TOKEN EXTRACTION HELPER
# ==============================================
function Get-GraphAccessToken {
	<#
	.SYNOPSIS
		Extracts the current access token from an active Microsoft Graph session.
	
	.DESCRIPTION
		Microsoft Graph PowerShell SDK 2.x does NOT expose AccessToken via Get-MgContext
		for security reasons. This function reliably extracts the token by making a
		lightweight request and extracting the Authorization header.
		
		Primary method: HTTP request header extraction (reliable in SDK 2.x)
		Fallback method: Get-MgContext.AccessToken (for older SDK versions)
	
	.OUTPUTS
		[string] The access token, or $null if extraction fails
	#>
	[CmdletBinding()]
	param()
	
	# Primary method: Extract token from HTTP response headers (reliable in SDK 2.x)
	try {
		$response = Invoke-MgGraphRequest -Method GET -Uri 'https://graph.microsoft.com/v1.0/$metadata' -OutputType HttpResponseMessage -ErrorAction Stop
		$token = $response.RequestMessage.Headers.Authorization.Parameter
		if ($token) {
			return $token
		}
	}
	catch {
		# HTTP method failed, try fallback
	}
	
	# Fallback method: Get-MgContext.AccessToken (works in older SDK versions)
	try {
		$context = Get-MgContext -ErrorAction SilentlyContinue
		if ($context -and $context.AccessToken) {
			return $context.AccessToken
		}
	}
	catch {
		# Fallback also failed
	}
	
	return $null
}

# ==============================================
# ACCESS TOKEN WITH EXPIRY EXTRACTION (for shared auth state)
# ==============================================
function Get-GraphAccessTokenWithExpiry {
	<#
	.SYNOPSIS
		Extracts access token AND expiry time from the active Microsoft Graph session.
	
	.DESCRIPTION
		Decodes the JWT access token to extract the actual 'exp' (expiry) claim.
		This is more reliable than Azure.Identity reflection and doesn't cause
		extra authentication popups.
		
		JWT tokens have three base64-encoded parts: header.payload.signature
		The payload contains the 'exp' claim as a Unix timestamp.
		
		Falls back to 50-minute estimated expiry if JWT decode fails.
	
	.OUTPUTS
		[hashtable] with Token (string) and ExpiresOn (DateTime) properties
		Returns $null if no token can be extracted
	#>
	[CmdletBinding()]
	param()
	
	$result = @{
		Token = $null
		ExpiresOn = $null
		Source = 'unknown'
	}
	
	# First, get the token using existing reliable method
	$result.Token = Get-GraphAccessToken
	if (-not $result.Token) {
		return $null
	}
	
	# Try to decode JWT to get actual expiry from 'exp' claim
	# JWT format: base64url(header).base64url(payload).signature
	try {
		$tokenParts = $result.Token.Split('.')
		if ($tokenParts.Count -ge 2) {
			# Decode the payload (second part)
			$payloadBase64 = $tokenParts[1]
			
			# Add padding if needed (base64url uses no padding)
			$paddingNeeded = 4 - ($payloadBase64.Length % 4)
			if ($paddingNeeded -lt 4) {
				$payloadBase64 += ('=' * $paddingNeeded)
			}
			
			# Convert base64url to standard base64 (replace - with +, _ with /)
			$payloadBase64 = $payloadBase64.Replace('-', '+').Replace('_', '/')
			
			# Decode and parse JSON
			$payloadBytes = [Convert]::FromBase64String($payloadBase64)
			$payloadJson = [System.Text.Encoding]::UTF8.GetString($payloadBytes)
			$payload = $payloadJson | ConvertFrom-Json
			
			if ($payload.exp) {
				# 'exp' is Unix timestamp (seconds since 1970-01-01 UTC)
				$unixEpoch = [DateTime]::new(1970, 1, 1, 0, 0, 0, [DateTimeKind]::Utc)
				$result.ExpiresOn = $unixEpoch.AddSeconds($payload.exp)
				$result.Source = 'JWT'
				
				# Calculate time remaining for logging
				$timeRemaining = $result.ExpiresOn - (Get-Date).ToUniversalTime()
				if ($timeRemaining.TotalMinutes -gt 0) {
					Write-Verbose "Token expires in $([int]$timeRemaining.TotalMinutes) minutes (from JWT 'exp' claim)"
				}
				
				return $result
			}
		}
	}
	catch {
		# JWT decode failed, use fallback
		Write-Verbose "JWT decode failed: $($_.Exception.Message)"
	}
	
	# Fallback: estimate 50-minute expiry from now (observed token lifetime ~45-60 minutes)
	# With 5-minute buffer, proactive refresh triggers at ~45 min mark
	$result.ExpiresOn = (Get-Date).ToUniversalTime().AddMinutes(50)
	$result.Source = 'estimated'
	
	return $result
}

# ==============================================
# TOKEN REFRESH FUNCTION FOR LONG-RUNNING OPERATIONS
# ==============================================
function Invoke-TokenRefresh {
	<#
	.SYNOPSIS
		Forces re-authentication for AppRegistration auth mode to get fresh access token.
	
	.DESCRIPTION
		When using App Registration authentication (client secret or certificate),
		this function reconnects to Microsoft Graph to obtain a fresh access token.
		This is critical for long-running operations that exceed the default OAuth
		token lifetime (~60-90 minutes).
		
		For interactive auth modes, this function returns $false as re-authentication
		would require user interaction.
	
	.PARAMETER Force
		Force re-authentication even if token doesn't appear expired.
	
	.OUTPUTS
		[PSCustomObject] with Success ($true/$false) and NewToken properties
	#>
	[CmdletBinding()]
	param(
		[switch]$Force
	)
	
	$result = [PSCustomObject]@{
		Success = $false
		NewToken = $null
		Message = ""
		AuthMethod = $script:AuthConfig.Method
	}
	
	# Check if we can re-authenticate
	if (-not $script:AuthConfig.CanReauthenticate) {
		$result.Message = "Auth method '$($script:AuthConfig.Method)' does not support automatic re-authentication"
		return $result
	}
	
	# Validate we have stored config
	if ($script:AuthConfig.Method -ne 'AppRegistration') {
		$result.Message = "Only AppRegistration auth mode supports automatic token refresh"
		return $result
	}
	
	if ([string]::IsNullOrWhiteSpace($script:AuthConfig.TenantId) -or 
		[string]::IsNullOrWhiteSpace($script:AuthConfig.ClientId)) {
		$result.Message = "Missing TenantId or ClientId in stored auth config"
		return $result
	}
	
	Write-LogHost "  [TOKEN-REFRESH] Attempting re-authentication using AppRegistration..." -ForegroundColor Cyan
	
	try {
		# Disconnect first to ensure clean state
		try {
			Disconnect-MgGraph -ErrorAction SilentlyContinue | Out-Null
		} catch { }
		
		# Re-authenticate based on stored credential type
		$reconnected = $false
		
		# Try client secret first
		if ($script:AuthConfig.ClientSecret) {
			Write-LogHost "  [TOKEN-REFRESH] Reconnecting with client secret..." -ForegroundColor Gray
			$credential = New-Object System.Management.Automation.PSCredential(
				$script:AuthConfig.ClientId, 
				$script:AuthConfig.ClientSecret
			)
			Connect-MgGraph -TenantId $script:AuthConfig.TenantId `
				-ClientSecretCredential $credential `
				-NoWelcome -ErrorAction Stop
			$reconnected = $true
		}
		# Try certificate thumbprint
		elseif ($script:AuthConfig.CertThumbprint) {
			Write-LogHost "  [TOKEN-REFRESH] Reconnecting with certificate thumbprint..." -ForegroundColor Gray
			if ($script:AuthConfig.CertObject) {
				# Reuse the cert object resolved + pinned at initial login (carries the
				# CurrentUser/LocalMachine resolution; avoids re-searching the stores).
				Connect-MgGraph -TenantId $script:AuthConfig.TenantId `
					-ClientId $script:AuthConfig.ClientId `
					-Certificate $script:AuthConfig.CertObject `
					-NoWelcome -ErrorAction Stop
			}
			else {
				Connect-MgGraph -TenantId $script:AuthConfig.TenantId `
					-ClientId $script:AuthConfig.ClientId `
					-CertificateThumbprint $script:AuthConfig.CertThumbprint `
					-NoWelcome -ErrorAction Stop
			}
			$reconnected = $true
		}
		# Try certificate file
		elseif ($script:AuthConfig.CertPath) {
			Write-LogHost "  [TOKEN-REFRESH] Reconnecting with certificate file..." -ForegroundColor Gray
			# Prefer the cert object pinned at initial login - it already has the correct
			# EphemeralKeySet+Exportable storage flags applied, and reusing it avoids any
			# chance of leaking a second key file or invalidating the credential's handle.
			$cert = $script:AuthConfig.CertObject
			if (-not $cert) {
				$flags = [System.Security.Cryptography.X509Certificates.X509KeyStorageFlags]::EphemeralKeySet `
					-bor [System.Security.Cryptography.X509Certificates.X509KeyStorageFlags]::Exportable
				if ($script:AuthConfig.CertPassword) {
					$plainPassword = [Runtime.InteropServices.Marshal]::PtrToStringAuto(
						[Runtime.InteropServices.Marshal]::SecureStringToBSTR($script:AuthConfig.CertPassword)
					)
					try {
						$cert = New-Object System.Security.Cryptography.X509Certificates.X509Certificate2(
							$script:AuthConfig.CertPath, $plainPassword, $flags
						)
					}
					finally {
						Clear-Variable -Name plainPassword -Force -ErrorAction SilentlyContinue
					}
				}
				else {
					$cert = New-Object System.Security.Cryptography.X509Certificates.X509Certificate2(
						$script:AuthConfig.CertPath, [string]'', $flags
					)
				}
				# Re-pin so subsequent refreshes can reuse this same instance.
				$script:AuthConfig.CertObject = $cert
			}
			Connect-MgGraph -TenantId $script:AuthConfig.TenantId `
				-ClientId $script:AuthConfig.ClientId `
				-Certificate $cert `
				-NoWelcome -ErrorAction Stop
			# Intentionally NOT disposing $cert - must outlive Connect-MgGraph for the rest
			# of the run. Cleanup happens at script exit when $script:AuthConfig is released.
			$reconnected = $true
		}
		
		if ($reconnected) {
			# Use reliable token extraction helper (HTTP method primary)
			$result.NewToken = Get-GraphAccessToken
			if ($result.NewToken) {
				$result.Success = $true
				$result.Message = "Successfully refreshed token"
				
				# Update token timing and reset auth failure flags
				$script:AuthConfig.TokenIssueTime = Get-Date
				$script:TokenAcquiredTime = Get-Date
				$script:AuthFailureDetected = $false
				$script:Auth401MessageShown = $false  # Reset for next auth failure cycle
				
				Write-LogHost "  [TOKEN-REFRESH] Successfully obtained fresh access token" -ForegroundColor Green
				Write-LogHost "  [TOKEN-REFRESH] Token acquired at $(Get-Date -Format 'HH:mm:ss') - proactive refresh at 30-minute age" -ForegroundColor DarkGray
			}
			else {
				$result.Message = "Reconnected but could not extract access token"
				Write-LogHost "  [TOKEN-REFRESH] ✗ $($result.Message)" -ForegroundColor Red
			}
		}
		else {
			$result.Message = "No valid credential found in stored auth config"
		}
	}
	catch {
		$result.Message = "Re-authentication failed: $($_.Exception.Message)"
		Write-LogHost "  [TOKEN-REFRESH] ✗ $($result.Message)" -ForegroundColor Red
	}
	
	return $result
}

# ==============================================
# PROACTIVE TOKEN REFRESH FOR LONG-RUNNING OPERATIONS
# ==============================================
function Refresh-GraphTokenIfNeeded {
	<#
	.SYNOPSIS
		Proactively refreshes the Graph access token if it's nearing expiry.
	
	.DESCRIPTION
		Checks SharedAuthState.ExpiresOn and refreshes token if less than 10 minutes
		remain before expiry. Uses Azure.Identity for interactive auth modes, or
		Invoke-TokenRefresh for AppRegistration mode.
		
		This function is called from the main thread's job monitoring loop to ensure
		thread jobs always have a valid token in SharedAuthState.
		
		IMPORTANT: Includes cooldown logic to prevent spam - only attempts refresh
		once per 5 minutes. If silent refresh fails, sets AuthFailureDetected to
		trigger interactive re-auth prompt.
	
	.PARAMETER BufferMinutes
		Refresh if token expires within this many minutes. Default: 5.
	
	.OUTPUTS
		$true - Token was refreshed successfully (silent or interactive)
		$false - No refresh needed (token still valid) or within cooldown period
		'Quit' - User chose to quit at the re-auth prompt
		
		CRITICAL: Callers MUST check for 'Quit' return and handle gracefully!
	#>
	[CmdletBinding()]
	param(
		[int]$BufferMinutes = 5
	)
	
	# Check if we have shared auth state
	if (-not $script:SharedAuthState.ExpiresOn) {
		return $false
	}
	
	$now = (Get-Date).ToUniversalTime()
	$expiresOn = $script:SharedAuthState.ExpiresOn
	$minutesRemaining = ($expiresOn - $now).TotalMinutes
	
	# PROACTIVE REFRESH FOR APPREG: Refresh at 30-minute token age (not just near expiry)
	# AppRegistration can refresh silently, so we do this proactively to avoid 401s
	$needsProactiveRefresh = $false
	if ($script:AuthConfig.Method -eq 'AppRegistration' -and $script:AuthConfig.CanReauthenticate) {
		if ($script:AuthConfig.TokenIssueTime) {
			$tokenAge = (Get-Date) - $script:AuthConfig.TokenIssueTime
			if ($tokenAge.TotalMinutes -gt 30) {
				$needsProactiveRefresh = $true
				Write-LogHost "  [TOKEN] Token age: $([Math]::Round($tokenAge.TotalMinutes, 1)) minutes - proactive refresh triggered" -ForegroundColor Yellow
			}
		}
	}
	
	if ($minutesRemaining -gt $BufferMinutes -and -not $needsProactiveRefresh) {
		return $false  # Token still valid, no refresh needed
	}
	
	# COOLDOWN CHECK: Auth-mode-aware cooldown between refresh attempts
	# AppReg: 45 seconds (silent client_credentials grant - cheap and fast)
	# Interactive: 5 minutes (avoids spamming browser/prompt windows)
	$cooldownMinutes = if ($script:AuthConfig.Method -eq 'AppRegistration') { 0.75 } else { 5 }
	if ($script:LastProactiveRefreshAttempt) {
		$timeSinceLastAttempt = ((Get-Date) - $script:LastProactiveRefreshAttempt).TotalMinutes
		if ($timeSinceLastAttempt -lt $cooldownMinutes) {
			return $false
		}
	}
	$script:LastProactiveRefreshAttempt = Get-Date
	
	# Log appropriate message based on trigger reason
	if (-not $needsProactiveRefresh) {
		Write-LogHost "  [TOKEN] Token expires in $([Math]::Round($minutesRemaining, 1)) minutes - attempting proactive refresh..." -ForegroundColor Yellow
	}
	
	# Try to refresh using Azure.Identity (uses cached MSAL tokens, may prompt if needed)
	$tokenInfo = Get-GraphAccessTokenWithExpiry
	if ($tokenInfo -and $tokenInfo.Token -ne $script:SharedAuthState.Token) {
		# Validate the new token is actually valid (ExpiresOn must be > 2 min in the future)
		# Protects against stale MSAL cache returning already-expired tokens (e.g., after process suspension)
		$tokenExpiresOn = $tokenInfo.ExpiresOn
		$nowUtc = (Get-Date).ToUniversalTime()
		$minutesUntilExpiry = ($tokenExpiresOn - $nowUtc).TotalMinutes
		if ($minutesUntilExpiry -le 2) {
			Write-LogHost "  [TOKEN] WARNING: Refreshed token is already expired or near-expiry (expires in $([Math]::Round($minutesUntilExpiry, 1)) min) - forcing full re-authentication" -ForegroundColor Red
			# Fall through to Invoke-TokenRefresh -Force below
		} else {
			# Got a genuinely valid new token
			$script:SharedAuthState.Token = $tokenInfo.Token
			$script:SharedAuthState.ExpiresOn = $tokenInfo.ExpiresOn
			$script:SharedAuthState.LastRefresh = Get-Date
			$script:SharedAuthState.RefreshCount++
			
			Write-LogHost "  [TOKEN] Token refreshed silently (expires: $($tokenInfo.ExpiresOn.ToString('HH:mm:ss')) UTC, refresh #$($script:SharedAuthState.RefreshCount))" -ForegroundColor Green
			Write-LogHost "  [TOKEN]   Note: In-flight queries may still require re-auth before this expiration" -ForegroundColor DarkGray
			return $true
		}
	}
	
	# Azure.Identity didn't give us a new token (or it was stale), try AppRegistration refresh if available
	if ($script:AuthConfig.CanReauthenticate) {
		$refreshResult = Invoke-TokenRefresh -Force
		if ($refreshResult.Success) {
			$script:SharedAuthState.Token = $refreshResult.NewToken
			$script:SharedAuthState.ExpiresOn = (Get-Date).ToUniversalTime().AddMinutes(50)
			$script:SharedAuthState.LastRefresh = Get-Date
			$script:SharedAuthState.RefreshCount++
			$script:AuthConfig.TokenIssueTime = Get-Date  # Reset age timer for proactive refresh
			
			Write-LogHost "  [TOKEN] Token refreshed via AppRegistration (refresh #$($script:SharedAuthState.RefreshCount))" -ForegroundColor Green
			return $true
		}
	}
	
	# SILENT REFRESH FAILED
	# For AppRegistration + Force: FATAL exit (true headless operation)
	# For AppRegistration without Force: Fall back to interactive prompt
	# For interactive modes: Prompt user for re-authentication
	Write-LogHost "  [TOKEN] [!] Silent token refresh failed - interactive re-authentication required" -ForegroundColor Red
	
	# AppRegistration mode with -Force: Silent refresh failure is fatal (no interactive fallback for headless runs)
	if ($script:AuthConfig.Method -eq 'AppRegistration' -and $Force) {
		Write-LogHost "  [TOKEN] FATAL: AppRegistration token refresh failed. Cannot continue headless (-Force mode)." -ForegroundColor Red
		Write-LogHost "  [TOKEN] Check: client secret expiration, certificate validity, or API permissions." -ForegroundColor Yellow
		return 'Quit'
	}
	
	# Interactive modes OR AppRegistration without -Force: prompt user for re-authentication
	$refreshResult = Invoke-TokenRefreshPrompt
	if ($refreshResult -eq 'Quit') {
		# User chose to quit - return special value for callers to handle
		return 'Quit'
	}
	
	# User pressed R and successfully re-authenticated
	# Invoke-TokenRefreshPrompt already updated SharedAuthState and reset AuthFailureDetected
	return $true
}

# ==============================================
# CHECKPOINT/RESUME FUNCTIONS FOR LONG-RUNNING OPERATIONS
# ==============================================

function Initialize-CheckpointForNewRun {
	<#
	.SYNOPSIS
		Creates new checkpoint structure for a fresh run (not resume mode).
	.DESCRIPTION
		Initializes checkpoint data structure with all processing parameters,
		creates _PARTIAL output filename, and saves initial checkpoint file to disk.
		On resume, all parameters are restored from checkpoint to ensure consistency.
	#>
	param(
		[Parameter(Mandatory)]
		[string]$OutputPath,
		
		[Parameter(Mandatory)]
		[string]$BaseOutputFileName,
		
		[Parameter(Mandatory)]
		[string]$RunTimestamp,
		
		[Parameter(Mandatory)]
		[datetime]$StartDate,
		
		[Parameter(Mandatory)]
		[datetime]$EndDate,
		
		[Parameter()]
		[hashtable]$AllParameters
	)
	
	# Create _PARTIAL filename
	$fileNameWithoutExt = [System.IO.Path]::GetFileNameWithoutExtension($BaseOutputFileName)
	$fileExt = [System.IO.Path]::GetExtension($BaseOutputFileName)
	$partialFileName = "${fileNameWithoutExt}_PARTIAL${fileExt}"
	$script:PartialOutputPath = Join-Path $OutputPath $partialFileName
	
	# Create checkpoint file path (hidden file with dot prefix)
	$script:CheckpointPath = Join-Path $OutputPath ".pax_checkpoint_${RunTimestamp}.json"

	# Acquire exclusive lock on this checkpoint so a second replica running against
	# the same OutputPath cannot silently corrupt our state. Fails loudly if another
	# live PAX process is already using this checkpoint.
	script:Acquire-CheckpointLock -CheckpointPath $script:CheckpointPath
	
	# Initialize checkpoint data structure with comprehensive parameter snapshot
	$script:CheckpointData = @{
		version = 2  # Bumped version for expanded parameter storage
		# Structured schema/compatibility metadata. Read-Checkpoint
		# uses these for forward/backward compatibility checks (Test-CheckpointCompatibility).
		# `checkpointSchemaVersion` is a SemVer-style identifier for the file format. The
		# legacy integer `version` field is preserved for older readers.
		checkpointSchemaVersion    = '2.1.0'
		compatibilityMinimumVersion = '1.11.0'
		createdByVersion           = $ScriptVersion
		createdUtc                 = (Get-Date).ToUniversalTime().ToString('o')
		checkpointType             = 'PurviewAudit'
		runTimestamp = $RunTimestamp
		created = (Get-Date).ToUniversalTime().ToString('o')
		lastUpdated = (Get-Date).ToUniversalTime().ToString('o')
		parameters = @{
			# Date range
			startDate = $StartDate.ToUniversalTime().ToString('o')
			endDate = $EndDate.ToUniversalTime().ToString('o')
			
			# Activity/Record filtering
			activityTypes = if ($AllParameters.ActivityTypes) { @($AllParameters.ActivityTypes) } else { @() }
			recordTypes = if ($AllParameters.RecordTypes) { @($AllParameters.RecordTypes) } else { @() }
			serviceTypes = if ($AllParameters.ServiceTypes) { @($AllParameters.ServiceTypes) } else { @() }
			userIds = if ($AllParameters.UserIds) { @($AllParameters.UserIds) } else { @() }
			groupNames = if ($AllParameters.GroupNames) { @($AllParameters.GroupNames) } else { @() }
			
			# Agent filtering
			agentId = if ($AllParameters.AgentId) { @($AllParameters.AgentId) } else { @() }
			agentsOnly = [bool]$AllParameters.AgentsOnly
			excludeAgents = [bool]$AllParameters.ExcludeAgents
			
			# Prompt filtering
			promptFilter = if ($AllParameters.PromptFilter) { $AllParameters.PromptFilter } else { $null }
			
			# Schema/Explosion settings
			explodeArrays = [bool]$AllParameters.ExplodeArrays
			explodeDeep = [bool]$AllParameters.ExplodeDeep
			explosionThreads = if ($AllParameters.ExplosionThreads) { $AllParameters.ExplosionThreads } else { 0 }
			flatDepth = if ($AllParameters.FlatDepth) { $AllParameters.FlatDepth } else { 120 }
			streamingSchemaSample = if ($AllParameters.StreamingSchemaSample) { $AllParameters.StreamingSchemaSample } else { 5000 }
			streamingChunkSize = if ($AllParameters.StreamingChunkSize) { $AllParameters.StreamingChunkSize } else { 5000 }
			
			# M365/User info bundles
			includeM365Usage = [bool]$AllParameters.IncludeM365Usage
			includeUserInfo = [bool]$AllParameters.IncludeUserInfo
			includeCopilotInteraction = [bool]$AllParameters.IncludeCopilotInteraction
			excludeCopilotInteraction = [bool]$AllParameters.ExcludeCopilotInteraction
			includeAgent365Info = [bool]$AllParameters.IncludeAgent365Info
			onlyAgent365Info = [bool]$AllParameters.OnlyAgent365Info
			
			# Partitioning
			blockHours = if ($AllParameters.BlockHours) { $AllParameters.BlockHours } else { 0.5 }
			partitionHours = if ($AllParameters.PartitionHours) { $AllParameters.PartitionHours } else { 0 }
			maxPartitions = if ($AllParameters.MaxPartitions) { $AllParameters.MaxPartitions } else { 160 }
			
			# Output settings
			# Persist the USER-SUPPLIED -OutputPath (SharePoint URL / Fabric OneLake URL /
			# local path), NOT the script-rewritten local scratch dir. At checkpoint-save
			# time $OutputPath has already been redirected to $script:RemoteScratchDir for
			# remote modes (the parse-time redirect block earlier in the script), so saving
			# $OutputPath here would lose the destination URL and a -Resume run would
			# re-resolve the tier as 'Local' — no upload sweep would ever fire.
			#
			# $script:DestRaw['Purview'] is the canonical source of truth. It is populated
			# at parse-time from the ORIGINAL CLI-bound value (the SharePoint / Fabric URL
			# or local path) BEFORE the scratch redirect runs, and is REPOPULATED on each
			# resume from the restored value BEFORE the resume-side scratch redirect
			# rewrites $OutputPath — so it carries the user-supplied destination across
			# both fresh runs and resumes. Falls back to $OutputPath only for runs where
			# -OutputPath was never bound and $script:DestRaw['Purview'] is unset
			# (default PSScriptRoot). Tier-agnostic: identical behavior for Local,
			# SharePoint, and Fabric (OneLake) modes.
			outputPath = if ($script:DestRaw -and $script:DestRaw['Purview']) { [string]$script:DestRaw['Purview'] } else { $OutputPath }
			exportWorkbook = [bool]$AllParameters.ExportWorkbook
			combineOutput = [bool]$AllParameters.CombineOutput
			# Deidentify: persisted so a resumed run keeps the original run's anonymization.
			# -Deidentify cannot be passed on the resume command line (resume allow-list rejects
			# it), so the checkpoint is the sole source of truth for it on resume.
			deidentify = [bool]$AllParameters.Deidentify

			# FillerLabel: persisted (resolved hierarchy-filler mode + literal) so a resumed
			# AIO/AIBV rollup keeps the original run's level-filler choice. -FillerLabel /
			# -FillerLabelText cannot be passed on resume (allow-list), so the checkpoint is the
			# sole source of truth for them on resume.
			fillerLabelMode = [string]$AllParameters.FillerLabel
			fillerLabelText = [string]$AllParameters.FillerLabelText

			# Append-mode targets. Persisted so a resumed run continues to merge
			# against the same target file/dim, even if the resume command line omits the
			# -Append* parameter. Empty string means "not set on this run".
			appendFile = if ($AllParameters.AppendFile) { [string]$AllParameters.AppendFile } else { '' }
			appendUserInfo = if ($AllParameters.AppendUserInfo) { [string]$AllParameters.AppendUserInfo } else { '' }
			appendAgent365Info = if ($AllParameters.AppendAgent365Info) { [string]$AllParameters.AppendAgent365Info } else { '' }

			# Per-data-type destinations (captured so resume re-targets correctly).
			# Storage tier is inferred from each value's form at resume time; no separate
			# tier field is persisted.
			outputPathUserInfo = if ($AllParameters.OutputPathUserInfo) { [string]$AllParameters.OutputPathUserInfo } else { '' }
			outputPathAgent365Info = if ($AllParameters.OutputPathAgent365Info) { [string]$AllParameters.OutputPathAgent365Info } else { '' }
			outputPathLog = if ($AllParameters.OutputPathLog) { [string]$AllParameters.OutputPathLog } else { '' }
			outputDestinationType = if ($script:RemoteOutputMode) { [string]$script:RemoteOutputMode } else { 'None' }

			# Rollup post-processor mode (None|Rollup|RollupPlusRaw) and the resolved
			# embedded-processor mode (None|CopilotInteraction|M365Bundle). Persisted so resume
			# runs can restore the original rollup intent when the user does not pass a switch
			# on the resume command line. If a rollup switch IS passed on resume, the resume
			# value wins (last-write-wins) and these fields are overwritten on the next save.
			rollupMode = if ([bool]$AllParameters.Rollup) { 'Rollup' } elseif ([bool]$AllParameters.RollupPlusRaw) { 'RollupPlusRaw' } else { 'None' }
			processorMode = if ($script:RollupProcessorMode) { $script:RollupProcessorMode } else { 'None' }
			# Resolved rollup dashboard (None|AIO|AIBV|M365). Persisted so a resumed
			# CopilotInteraction run restores the correct --profile (AIO vs AIBV cannot
			# be re-derived from -IncludeM365Usage alone). Last-write-wins on resume.
			rollupDashboard = if ($script:RollupDashboard) { $script:RollupDashboard } else { 'None' }
			
			# Auth (method only - no secrets)
			auth = if ($AllParameters.Auth) { $AllParameters.Auth } else { 'WebLogin' }
			tenantId = if ($AllParameters.TenantId) { $AllParameters.TenantId } else { $null }
			clientId = if ($AllParameters.ClientId) { $AllParameters.ClientId } else { $null }
			# Note: ClientSecret is NOT stored for security
			
			# Other settings
			resultSize = if ($AllParameters.ResultSize) { $AllParameters.ResultSize } else { 10000 }
			maxConcurrency = if ($AllParameters.MaxConcurrency) { $AllParameters.MaxConcurrency } else { 10 }
			maxMemoryMB = if ($AllParameters.MaxMemoryMB) { $AllParameters.MaxMemoryMB } else { 0 }
			useEOM = [bool]$AllParameters.UseEOM
			autoCompleteness = [bool]$AllParameters.AutoCompleteness
			includeTelemetry = [bool]$AllParameters.IncludeTelemetry
		}
		outputFiles = @{
			partialCsv = $partialFileName
			finalCsv = $BaseOutputFileName
		}
		partitions = @{
			total = 0
			blockHours = if ($AllParameters.BlockHours) { $AllParameters.BlockHours } else { 0.5 }
			completed = @()
			queryCreated = @()
		}
		statistics = @{
			totalRecordsSaved = 0
			partitionsComplete = 0
			partitionsQueryCreated = 0
			partitionsRemaining = 0
		}
		explosion = @{
			status = 'NotStarted'  # NotStarted, InProgress, Completed
			recordsProcessed = 0
			rowsGenerated = 0
			lastUpdateTime = $null
		}
	}
	
	# Save initial checkpoint
	Save-CheckpointToDisk
	
	return $script:PartialOutputPath
}

function Sync-FabricResumeMirror {
	<#
	.SYNOPSIS
		Mirrors local resume artifacts to OneLake Files/.pax_resume/<RunTimestamp>/.
	.DESCRIPTION
		Uploads the checkpoint JSON, every changed .pax_incremental/*.jsonl shard,
		and the *_PARTIAL.csv companion to a durable OneLake folder so a Fabric
		container restart can rehydrate the run via Restore-FabricResumeMirror.

		No-op unless the Purview destination tier is Fabric. Failures throw so the
		calling try/catch (in Save-CheckpointToDisk) can abort the run and keep the
		local + mirror artifact set consistent.

		Per-file change tracking lives in $script:FabricResumeMirrorState keyed by
		full local path with "{size}:{ticks}" stamps to avoid re-uploading
		unchanged shards on every checkpoint write.
	#>
	[CmdletBinding()]
	param()
	if (-not $script:DestTier -or $script:DestTier['Purview'] -ne 'Fabric') { return }
	if (-not $script:CheckpointPath -or -not (Test-Path -LiteralPath $script:CheckpointPath)) { return }
	if (-not $global:ScriptRunTimestamp) { return }

	if (-not $script:FabricResumeMirrorState) { $script:FabricResumeMirrorState = @{} }
	$mirrorBase = ".pax_resume/$global:ScriptRunTimestamp"

	# Checkpoint JSON — always upload (small, mutates every call).
	$cpName = Split-Path -Leaf $script:CheckpointPath
	Send-FileToOneLake -LocalPath $script:CheckpointPath -RemoteFileName "$mirrorBase/$cpName"

	# .pax_incremental shards — upload only those whose size or mtime changed since last sync.
	$cpDir = Split-Path -Parent $script:CheckpointPath
	$incDir = Join-Path $cpDir ".pax_incremental"
	if (Test-Path -LiteralPath $incDir -PathType Container) {
		foreach ($f in (Get-ChildItem -LiteralPath $incDir -Filter '*.jsonl' -File -ErrorAction SilentlyContinue)) {
			$key = $f.FullName
			$stamp = "{0}:{1}" -f $f.Length, $f.LastWriteTimeUtc.Ticks
			if ($script:FabricResumeMirrorState[$key] -eq $stamp) { continue }
			Send-FileToOneLake -LocalPath $f.FullName -RemoteFileName "$mirrorBase/.pax_incremental/$($f.Name)"
			$script:FabricResumeMirrorState[$key] = $stamp
		}
	}

	# *_PARTIAL.csv — upload if present and changed.
	if ($script:PartialOutputPath -and (Test-Path -LiteralPath $script:PartialOutputPath)) {
		$pf = Get-Item -LiteralPath $script:PartialOutputPath
		$pkey = $pf.FullName
		$pstamp = "{0}:{1}" -f $pf.Length, $pf.LastWriteTimeUtc.Ticks
		if ($script:FabricResumeMirrorState[$pkey] -ne $pstamp) {
			Send-FileToOneLake -LocalPath $pf.FullName -RemoteFileName "$mirrorBase/$($pf.Name)"
			$script:FabricResumeMirrorState[$pkey] = $pstamp
		}
	}
}

function Restore-FabricResumeMirror {
	<#
	.SYNOPSIS
		Hydrates local resume artifacts from OneLake Files/.pax_resume/<RunTimestamp>/.
	.DESCRIPTION
		Used on startup of a Fabric run when a resume is requested and the local
		working copy is missing or partial (typical after a container restart).
		Lists the mirror folder via the ADLS Gen2 List Paths API and downloads
		every file into the supplied LocalDir, preserving the .pax_incremental
		subfolder layout. Returns the number of files downloaded.

		Throws on partial-download failure so callers can abort rather than
		resume from a torn artifact set.
	#>
	[CmdletBinding()]
	param(
		[Parameter(Mandatory)] [string] $RunTimestamp,
		[Parameter(Mandatory)] [string] $LocalDir
	)
	if (-not $script:DestTier -or $script:DestTier['Purview'] -ne 'Fabric') { return 0 }
	if (-not $script:FabricResolved) { $script:FabricResolved = Resolve-FabricTarget -Url $script:RemoteOutputUrl }
	$resolved = $script:FabricResolved

	$relInItem = if ($resolved.FilesPath) { "$($resolved.FilesPath)/.pax_resume/$RunTimestamp" } else { ".pax_resume/$RunTimestamp" }
	$dirParam  = [System.Uri]::EscapeDataString("Files/$relInItem")
	$listUri   = "$($resolved.FilesystemBase)?resource=filesystem&recursive=true&directory=$($resolved.ItemFull)/$dirParam"

	$resp = $null
	try {
		$resp = Invoke-FabricWebRequest -Uri $listUri -Method GET
	} catch {
		$status = try { $_.Exception.Response.StatusCode.value__ } catch { 0 }
		if ($status -eq 404) { return 0 }
		throw
	}
	if (-not $resp -or -not $resp.Content) { return 0 }
	$parsed = try { $resp.Content | ConvertFrom-Json -ErrorAction Stop } catch { $null }
	if (-not $parsed -or -not $parsed.paths) { return 0 }

	if (-not (Test-Path -LiteralPath $LocalDir -PathType Container)) {
		New-Item -Path $LocalDir -ItemType Directory -Force | Out-Null
	}

	$downloaded = 0
	$prefix = "$($resolved.ItemFull)/Files/$relInItem/"
	foreach ($entry in $parsed.paths) {
		$isDir = $entry.isDirectory
		if ($isDir -eq 'true' -or $isDir -eq $true) { continue }
		$name = "$($entry.name)"
		$rest = if ($name.StartsWith($prefix)) { $name.Substring($prefix.Length) } else { Split-Path -Leaf $name }
		if (-not $rest) { continue }
		$dest = Join-Path $LocalDir $rest
		$destDir = Split-Path -Parent $dest
		if ($destDir -and -not (Test-Path -LiteralPath $destDir -PathType Container)) {
			New-Item -Path $destDir -ItemType Directory -Force | Out-Null
		}
		Get-RemoteFile-OneLake -RelativeName ".pax_resume/$RunTimestamp/$rest" -DestinationPath $dest
		$downloaded++
	}
	return $downloaded
}

function Remove-FabricResumeMirror {
	<#
	.SYNOPSIS
		Deletes the OneLake Files/.pax_resume/<RunTimestamp>/ mirror after a successful run.
	.DESCRIPTION
		Best-effort cleanup. Failures are logged at Verbose only — they do not
		abort the run because the customer-visible outputs are already durable
		and a leftover mirror folder is purely cosmetic.
	#>
	[CmdletBinding()]
	param([Parameter(Mandatory)] [string] $RunTimestamp)
	if (-not $script:DestTier -or $script:DestTier['Purview'] -ne 'Fabric') { return }
	if (-not $script:FabricResolved) { return }
	$resolved = $script:FabricResolved
	$relInItem = if ($resolved.FilesPath) { "$($resolved.FilesPath)/.pax_resume/$RunTimestamp" } else { ".pax_resume/$RunTimestamp" }
	$dfsPath = "$($resolved.FilesystemBase)/$($resolved.ItemFull)/Files/$relInItem`?recursive=true"
	try {
		$null = Invoke-FabricWebRequest -Uri $dfsPath -Method DELETE
		if ($script:FabricResumeMirrorState) { $script:FabricResumeMirrorState.Clear() }
	} catch {
		Write-Verbose ("Resume mirror cleanup failed: {0}" -f $_.Exception.Message)
	}
}

function Restore-AllFabricResumeMirrors {
	<#
	.SYNOPSIS
		Discovers all in-progress run mirrors under OneLake Files/.pax_resume/ and
		downloads their artifacts to a local directory for auto-discover resume.
	.DESCRIPTION
		Lists Files/.pax_resume/ recursively, then for each <RunTimestamp>/ folder
		downloads every file (checkpoint JSON, *_PARTIAL.csv, .pax_incremental/*.jsonl)
		into LocalDir, flattening the <RunTimestamp>/ prefix because every artifact
		filename already embeds the run timestamp. Returns the number of files
		downloaded. No-op on Local/SharePoint tiers.
	#>
	[CmdletBinding()]
	param([Parameter(Mandatory)] [string] $LocalDir)
	if (-not $script:DestTier -or $script:DestTier['Purview'] -ne 'Fabric') { return 0 }
	if (-not $script:FabricResolved) { $script:FabricResolved = Resolve-FabricTarget -Url $script:RemoteOutputUrl }
	$resolved = $script:FabricResolved

	$relInItem = if ($resolved.FilesPath) { "$($resolved.FilesPath)/.pax_resume" } else { ".pax_resume" }
	$dirParam  = [System.Uri]::EscapeDataString("Files/$relInItem")
	$listUri   = "$($resolved.FilesystemBase)?resource=filesystem&recursive=true&directory=$($resolved.ItemFull)/$dirParam"

	$resp = $null
	try {
		$resp = Invoke-FabricWebRequest -Uri $listUri -Method GET
	} catch {
		$status = try { $_.Exception.Response.StatusCode.value__ } catch { 0 }
		if ($status -eq 404) { return 0 }
		throw
	}
	if (-not $resp -or -not $resp.Content) { return 0 }
	$parsed = try { $resp.Content | ConvertFrom-Json -ErrorAction Stop } catch { $null }
	if (-not $parsed -or -not $parsed.paths) { return 0 }

	if (-not (Test-Path -LiteralPath $LocalDir -PathType Container)) {
		New-Item -Path $LocalDir -ItemType Directory -Force | Out-Null
	}

	$prefix = "$($resolved.ItemFull)/Files/$relInItem/"
	$count = 0
	foreach ($e in $parsed.paths) {
		$isDir = $e.isDirectory
		if ($isDir -eq 'true' -or $isDir -eq $true) { continue }
		$n = "$($e.name)"
		if (-not $n.StartsWith($prefix)) { continue }
		$rest = $n.Substring($prefix.Length)
		if (-not $rest) { continue }
		# rest = "<RunTimestamp>/<file>" or "<RunTimestamp>/.pax_incremental/<file>".
		# Flatten the <RunTimestamp>/ prefix; filenames already embed it.
		$slash = $rest.IndexOf('/')
		if ($slash -lt 0) { continue }
		$localRel = $rest.Substring($slash + 1)
		$dest = Join-Path $LocalDir $localRel
		$destDir = Split-Path -Parent $dest
		if ($destDir -and -not (Test-Path -LiteralPath $destDir -PathType Container)) {
			New-Item -Path $destDir -ItemType Directory -Force | Out-Null
		}
		Get-RemoteFile-OneLake -RelativeName ".pax_resume/$rest" -DestinationPath $dest
		$count++
	}
	return $count
}

function Save-CsvAtomic {
	<#
	.SYNOPSIS
		Atomic CSV write helper using temp+rename, mirroring Save-CheckpointToDisk.
	.DESCRIPTION
		Replaces direct `Export-Csv -Path $target` calls at output sites that previously
		risked a half-written file on Ctrl+C / power loss / container OOM-kill.
		Writes to "$Path.tmp" first, then Move-Item -Force overwrites the target in a
		single filesystem operation. On any failure the temp file is removed and the
		original $Path (if any) is left untouched.

		For remote tiers (SharePoint / Fabric) the caller still passes a LOCAL scratch
		path; remote upload happens later via the existing upload pipeline. So this
		helper only needs to handle the local atomic-rename case.

		Encoding/quote handling mirrors what the existing call sites used (UTF-8,
		NoTypeInformation) so output bytes are unchanged for successful writes.
	.PARAMETER InputObject
		Rows to export. Accepts arrays, lists, or single objects via pipeline.
	.PARAMETER Path
		Final destination path. Will be replaced atomically when the write succeeds.
	.PARAMETER NoTypeInformation
		Forwarded to Export-Csv. Default $true (matches all current call sites).
	.PARAMETER Encoding
		Forwarded to Export-Csv. Default 'UTF8' (matches all current call sites).
	#>
	[CmdletBinding()]
	param(
		[Parameter(Mandatory, ValueFromPipeline)]
		[AllowNull()]
		$InputObject,

		[Parameter(Mandatory)]
		[string]$Path,

		[switch]$NoTypeInformation = $true,
		[string]$Encoding = 'UTF8'
	)
	begin {
		$rows = New-Object System.Collections.Generic.List[object]
	}
	process {
		if ($null -ne $InputObject) {
			# Accept arrays piped as a single object, single objects, or per-pipeline-element streams.
			if ($InputObject -is [System.Collections.IEnumerable] -and -not ($InputObject -is [string])) {
				foreach ($r in $InputObject) { if ($null -ne $r) { [void]$rows.Add($r) } }
			} else {
				[void]$rows.Add($InputObject)
			}
		}
	}
	end {
		$tmp = "$Path.tmp"
		try {
			# Ensure destination directory exists (caller may have skipped this).
			$destDir = Split-Path -Path $Path -Parent
			if ($destDir -and -not (Test-Path -LiteralPath $destDir -PathType Container)) {
				New-Item -Path $destDir -ItemType Directory -Force | Out-Null
			}

			if ($rows.Count -eq 0) {
				# Header-only fallback: write an empty file (best-effort header derived from $InputObject's first row would be ambiguous here).
				# Match the behavior of `Export-Csv -InputObject @()`: produce an empty file with no header.
				Set-Content -LiteralPath $tmp -Value '' -Encoding $Encoding -NoNewline
			} else {
				$rows | Export-Csv -Path $tmp -NoTypeInformation:$NoTypeInformation -Encoding $Encoding -Force -ErrorAction Stop
			}

			# Atomic replace. On Windows, Move-Item -Force will overwrite an existing file.
			Move-Item -LiteralPath $tmp -Destination $Path -Force -ErrorAction Stop
		}
		catch {
			# Best-effort cleanup of temp; rethrow so callers see the failure.
			try { if (Test-Path -LiteralPath $tmp) { Remove-Item -LiteralPath $tmp -Force -ErrorAction SilentlyContinue } } catch {}
			throw
		}
	}
}

# ==========================================================================
# CHECKPOINT LOCKING (G-9)
# ==========================================================================
# Defends against two replicas of the same PAX run racing on the same checkpoint
# file. The race surface is real only when an operator deliberately sets ACA Job
# parallelism > 1 (or runs two PAX invocations against the same OutputPath in
# the same wall-clock second). The default ACA Job replicaCompletionCount=1
# path is safe; this is defense-in-depth for the misconfigured case.
#
# Lock file: "<CheckpointPath>.lock"
# Contents:  JSON { pid, host, started, runTimestamp }
# Stale detection:
#   - If the lock file's pid is dead on this machine -> treat as stale, take over.
#   - If pid is alive on this machine -> reject (loud error, exit non-zero).
#   - If the lock file is on a different host (different "host" field) AND was
#     last touched more than $script:CheckpointLockStaleTtl ago -> treat as
#     stale, take over (cannot verify a foreign PID).
# The exclusive FileStream we open on the lock file is held for the lifetime of
# the run, so a concurrent acquire on the same Windows host will fail at the
# filesystem level even if the JSON-based check races.
$script:CheckpointLockStream    = $null
$script:CheckpointLockPath      = $null
$script:CheckpointLockStaleTtl  = [TimeSpan]::FromMinutes(10)

function script:Acquire-CheckpointLock {
	param(
		[Parameter(Mandatory)][string]$CheckpointPath
	)
	$lockPath = "$CheckpointPath.lock"

	# Inspect any existing lock for stale-takeover eligibility BEFORE attempting open.
	if (Test-Path -LiteralPath $lockPath -PathType Leaf) {
		$existing = $null
		try { $existing = Get-Content -LiteralPath $lockPath -Raw -ErrorAction Stop | ConvertFrom-Json -ErrorAction Stop } catch {}
		$stale = $false
		$reason = ''
		if (-not $existing) {
			$stale = $true; $reason = 'unreadable lock file (corrupt or empty)'
		}
		elseif ($existing.host -eq [System.Net.Dns]::GetHostName()) {
			# Same-host: definitive PID check.
			$alive = $false
			try { $alive = [bool](Get-Process -Id ([int]$existing.pid) -ErrorAction Stop) } catch { $alive = $false }
			if (-not $alive) { $stale = $true; $reason = "owning PID $($existing.pid) is no longer running on this host" }
		}
		else {
			# Foreign host: fall back to age-based TTL.
			try {
				$age = (Get-Date) - ([datetime]$existing.started)
				if ($age -gt $script:CheckpointLockStaleTtl) {
					$stale = $true
					$reason = "foreign-host lock from $($existing.host) is older than $($script:CheckpointLockStaleTtl.TotalMinutes) min (age $([int]$age.TotalMinutes) min)"
				}
			} catch { $stale = $true; $reason = 'foreign-host lock has unparseable timestamp' }
		}

		if ($stale) {
			Write-LogHost "  Checkpoint lock at $lockPath is stale ($reason); taking over." -ForegroundColor Yellow
			try { Remove-Item -LiteralPath $lockPath -Force -ErrorAction Stop } catch {
				throw "G-9: Could not remove stale checkpoint lock at $lockPath`: $($_.Exception.Message)"
			}
		}
		else {
			$ownerDesc = if ($existing) { "pid=$($existing.pid) host=$($existing.host) started=$($existing.started)" } else { '(unknown owner)' }
			throw "G-9: Another PAX run is using this checkpoint ($ownerDesc). Refusing to start. If you know the other run is dead, delete the lock file manually: $lockPath"
		}
	}

	# Open the lock file exclusively (CreateNew + FileShare.None). Hold the stream for the lifetime of the run.
	try {
		$stream = [System.IO.File]::Open($lockPath, [System.IO.FileMode]::CreateNew, [System.IO.FileAccess]::Write, [System.IO.FileShare]::None)
	}
	catch {
		throw "G-9: Failed to acquire checkpoint lock at $lockPath`: $($_.Exception.Message). Another process may have raced in."
	}

	# Stamp the lock with our identity so other replicas can do stale detection later.
	$payload = @{
		pid          = $PID
		host         = [System.Net.Dns]::GetHostName()
		started      = (Get-Date).ToUniversalTime().ToString('o')
		runTimestamp = $global:ScriptRunTimestamp
	} | ConvertTo-Json -Compress
	$bytes = [System.Text.Encoding]::UTF8.GetBytes($payload)
	$stream.Write($bytes, 0, $bytes.Length)
	$stream.Flush()

	$script:CheckpointLockStream = $stream
	$script:CheckpointLockPath   = $lockPath
}

function script:Release-CheckpointLock {
	if ($script:CheckpointLockStream) {
		try { $script:CheckpointLockStream.Dispose() } catch {}
		$script:CheckpointLockStream = $null
	}
	if ($script:CheckpointLockPath -and (Test-Path -LiteralPath $script:CheckpointLockPath)) {
		try { Remove-Item -LiteralPath $script:CheckpointLockPath -Force -ErrorAction SilentlyContinue } catch {}
	}
	$script:CheckpointLockPath = $null
}

function Save-CheckpointToDisk {
	<#
	.SYNOPSIS
		Writes current checkpoint data to disk atomically.
	.DESCRIPTION
		Uses temp file + rename pattern for atomic writes to prevent corruption.

		This function SELF-GATES on $script:CheckpointEnabled. Callers are still
		expected to gate at the call site, but if a future caller forgets, this
		guard turns "silently writes a checkpoint when disabled" into a safe no-op.
	#>

	# Self-gate. Do NOT remove without revisiting the corresponding static tests.
	if (-not $script:CheckpointEnabled) {
		return
	}

	if (-not $script:CheckpointPath -or -not $script:CheckpointData) {
		return
	}
	
	try {
		# Update timestamp
		$script:CheckpointData.lastUpdated = (Get-Date).ToUniversalTime().ToString('o')
		
		# Update statistics
		$script:CheckpointData.statistics.partitionsComplete = $script:CheckpointData.partitions.completed.Count
		$script:CheckpointData.statistics.partitionsQueryCreated = $script:CheckpointData.partitions.queryCreated.Count
		$script:CheckpointData.statistics.partitionsRemaining = $script:CheckpointData.partitions.total - 
			$script:CheckpointData.statistics.partitionsComplete - 
			$script:CheckpointData.statistics.partitionsQueryCreated
		
		# Write to temp file first (atomic write pattern)
		$tempPath = "$($script:CheckpointPath).tmp"
		$script:CheckpointData | ConvertTo-Json -Depth 10 | Set-Content -Path $tempPath -Encoding UTF8 -Force
		
		# Remove destination first if it exists (Move-Item -Force doesn't always work on Windows)
		if (Test-Path $script:CheckpointPath) {
			Remove-Item -Path $script:CheckpointPath -Force -ErrorAction SilentlyContinue
		}
		
		# Rename to final (atomic on most filesystems)
		Move-Item -Path $tempPath -Destination $script:CheckpointPath -Force

		# Fabric tier: mirror the full resume artifact set (checkpoint JSON,
		# .pax_incremental/*.jsonl, *_PARTIAL.csv) to a durable OneLake path inside
		# the same try block so either both the local write and the mirror upload
		# succeed or the run aborts. Local and SharePoint tiers keep resume artifacts
		# local-only (those hosts are not ephemeral). See Sync-FabricResumeMirror.
		if ($script:DestTier -and $script:DestTier['Purview'] -eq 'Fabric') {
			Sync-FabricResumeMirror
		}
	}
	catch {
		# Fabric-tier mirror failure must abort: a torn artifact set on the durable
		# mirror would silently corrupt a future resume. Local checkpoint write
		# failures remain a soft warning.
		if ($script:DestTier -and $script:DestTier['Purview'] -eq 'Fabric') {
			throw ("Checkpoint mirror to OneLake failed; aborting to preserve resume integrity: {0}" -f $_.Exception.Message)
		}
		Write-LogHost "  Warning: Failed to save checkpoint: $($_.Exception.Message)" -ForegroundColor Yellow
	}
}

function Save-Checkpoint {
	<#
	.SYNOPSIS
		Updates checkpoint with partition state change and saves to disk.
	.PARAMETER PartitionIndex
		The partition index (1-based).
	.PARAMETER State
		'QueryCreated' or 'Completed'
	.PARAMETER QueryId
		The server-assigned query ID.
	.PARAMETER PartitionStart
		Partition start time (optional - looked up from partitionStatus if not provided).
	.PARAMETER PartitionEnd
		Partition end time (optional - looked up from partitionStatus if not provided).
	.PARAMETER RecordCount
		Number of records (only for Completed state).
	.PARAMETER Force
		Just save current checkpoint state to disk without updating partition info.
	#>
	param(
		[Parameter()]
		[int]$PartitionIndex,
		
		[Parameter()]
		[ValidateSet('QueryCreated', 'Completed')]
		[string]$State,
		
		[Parameter()]
		[string]$QueryId,
		
		[Parameter()]
		[datetime]$PartitionStart,
		
		[Parameter()]
		[datetime]$PartitionEnd,
		
		[Parameter()]
		[int]$RecordCount = 0,
		
		[Parameter()]
		[switch]$Force
	)
	
	if (-not $script:CheckpointData) {
		return
	}
	
	# If -Force is specified, just save current state to disk without updating partition info
	if ($Force) {
		Save-CheckpointToDisk
		return
	}
	
	# For normal calls, require the mandatory parameters
	if (-not $PartitionIndex -or -not $State -or -not $QueryId) {
		Write-Verbose "Save-Checkpoint: Missing required parameters (PartitionIndex, State, QueryId) - skipping"
		return
	}
	
	# Look up partition times from partitionStatus if not provided
	if (-not $PartitionStart -or -not $PartitionEnd) {
		$partitionInfo = $script:partitionStatus[$PartitionIndex]
		if ($partitionInfo -and $partitionInfo.Partition) {
			# The Partition object has PStart and PEnd properties
			if (-not $PartitionStart -and $partitionInfo.Partition.PStart) { $PartitionStart = $partitionInfo.Partition.PStart }
			if (-not $PartitionEnd -and $partitionInfo.Partition.PEnd) { $PartitionEnd = $partitionInfo.Partition.PEnd }
		}
		
		# If still missing, we can't proceed with checkpoint save
		if (-not $PartitionStart -or -not $PartitionEnd) {
			Write-Verbose "Save-Checkpoint: Could not determine partition times for index $PartitionIndex - skipping checkpoint update"
			return
		}
	}
	
	$partitionEntry = @{
		index = $PartitionIndex
		start = $PartitionStart.ToUniversalTime().ToString('o')
		end = $PartitionEnd.ToUniversalTime().ToString('o')
		queryId = $QueryId
	}
	
	if ($State -eq 'QueryCreated') {
		$partitionEntry.createdAt = (Get-Date).ToUniversalTime().ToString('o')
		
		# Add to queryCreated list (if not already there)
		$existing = $script:CheckpointData.partitions.queryCreated | Where-Object { $_.index -eq $PartitionIndex }
		if (-not $existing) {
			$script:CheckpointData.partitions.queryCreated += $partitionEntry
		}
	}
	elseif ($State -eq 'Completed') {
		$partitionEntry.records = $RecordCount
		
		# Remove from queryCreated if present
		$script:CheckpointData.partitions.queryCreated = @(
			$script:CheckpointData.partitions.queryCreated | Where-Object { $_.index -ne $PartitionIndex }
		)
		
		# Add to completed list (if not already there)
		$existing = $script:CheckpointData.partitions.completed | Where-Object { $_.index -eq $PartitionIndex }
		if (-not $existing) {
			$script:CheckpointData.partitions.completed += $partitionEntry
			$script:CheckpointData.statistics.totalRecordsSaved += $RecordCount
		}
	}
	
	# Save to disk
	Save-CheckpointToDisk
}

function Test-CheckpointCompatibility {
	<#
	.SYNOPSIS
		Validates that a parsed checkpoint can safely be resumed by this script version.
	.DESCRIPTION
		Defends against three failure modes:
		  1. Legacy integer `version` outside the supported range (1..2).
		  2. `checkpointSchemaVersion` from a FUTURE major release — warned but allowed
		     when within the same major (forward-compat best effort), rejected on major
		     mismatch.
		  3. `compatibilityMinimumVersion` higher than the running script version — hard
		     reject (the checkpoint explicitly says this script is too old).
		The check is intentionally conservative: it never silently up/down-converts the
		structure on disk, and it always emits actionable recovery guidance.
	.OUTPUTS
		$true  -> safe to resume.
		$false -> incompatible; caller must abort the resume.
	#>
	param(
		[Parameter(Mandatory)] $CheckpointData,
		[Parameter(Mandatory)] [string]$RunningScriptVersion
	)

	# 1) Legacy integer version range (preserves prior behaviour).
	if (-not $CheckpointData.version -or [int]$CheckpointData.version -lt 1 -or [int]$CheckpointData.version -gt 2) {
		Write-LogHost "ERROR: Unsupported checkpoint legacy version: $($CheckpointData.version). Supported range is 1..2." -ForegroundColor Red
		Write-LogHost "  Recovery: start a fresh run without -Resume, or use a checkpoint produced by PAX 1.11.x." -ForegroundColor Yellow
		return $false
	}

	# 2/3) New structured fields are OPTIONAL (older checkpoints predate them). When
	# present, they are authoritative.
	$schemaVer  = [string]$CheckpointData.checkpointSchemaVersion
	$minVerStr  = [string]$CheckpointData.compatibilityMinimumVersion
	$createdBy  = [string]$CheckpointData.createdByVersion

	try { $running = [version]$RunningScriptVersion } catch { $running = $null }
	try { $minVer  = if ($minVerStr) { [version]$minVerStr } else { $null } } catch { $minVer = $null }
	try { $created = if ($createdBy) { [version]$createdBy } else { $null } } catch { $created = $null }

	if ($minVer -and $running -and $running -lt $minVer) {
		Write-LogHost "ERROR: Checkpoint requires PAX >= $minVerStr but running version is $RunningScriptVersion." -ForegroundColor Red
		Write-LogHost "  Recovery: upgrade PAX to a version >= $minVerStr or start a fresh run without -Resume." -ForegroundColor Yellow
		return $false
	}

	if ($schemaVer) {
		# Parse the schema version. Only the leading "major.minor" pair gates compatibility.
		$parts = $schemaVer.Split('.')
		$schemaMajor = 0; [void][int]::TryParse($parts[0], [ref]$schemaMajor)
		if ($schemaMajor -gt 2) {
			Write-LogHost "ERROR: Checkpoint schema major version $schemaMajor is newer than this script supports (max major 2)." -ForegroundColor Red
			Write-LogHost "  Recovery: upgrade PAX or start a fresh run without -Resume." -ForegroundColor Yellow
			return $false
		}
	}

	# Created-by drift is informational only (not all script edits change the on-disk shape).
	if ($created -and $running -and $created -gt $running) {
		Write-LogHost "  [WARN] Checkpoint was produced by PAX $createdBy; running PAX $RunningScriptVersion is older. Resume will proceed but newer fields may be ignored." -ForegroundColor Yellow
	}

	return $true
}

function Read-Checkpoint {
	<#
	.SYNOPSIS
		Loads and validates a checkpoint file.
	.PARAMETER CheckpointPath
		Path to the checkpoint JSON file.
	.OUTPUTS
		$true if valid and loaded, $false if invalid.
	#>
	param(
		[Parameter(Mandatory)]
		[string]$CheckpointPath
	)
	
	if (-not (Test-Path $CheckpointPath)) {
		Write-LogHost "ERROR: Checkpoint file not found: $CheckpointPath" -ForegroundColor Red
		return $false
	}
	
	try {
		$data = Get-Content -Path $CheckpointPath -Raw | ConvertFrom-Json -AsHashtable
		
		# Validate version (supports version 1 and 2)
		if (-not $data.version -or $data.version -gt 2) {
			Write-LogHost "ERROR: Unsupported checkpoint version: $($data.version). This script supports versions 1-2." -ForegroundColor Red
			return $false
		}

		# Structured compatibility check (schema version,
		# compatibilityMinimumVersion, createdByVersion). Hard-rejects checkpoints from
		# the future or from releases that explicitly require a newer PAX.
		if (-not (Test-CheckpointCompatibility -CheckpointData $data -RunningScriptVersion $ScriptVersion)) {
			return $false
		}
		
		# Validate required fields
		if (-not $data.runTimestamp -or -not $data.outputFiles -or -not $data.partitions) {
			Write-LogHost "ERROR: Checkpoint file is missing required fields" -ForegroundColor Red
			return $false
		}
		
		# Get output directory from checkpoint path
		$outputDir = Split-Path $CheckpointPath -Parent
		$partialCsvPath = Join-Path $outputDir $data.outputFiles.partialCsv
		
		# Note: We don't require _PARTIAL.csv to exist - the actual data is in .pax_incremental/*.jsonl files
		# The _PARTIAL.csv is only created when merging at completion, or may not exist yet
		
		# Check for incremental save data if there are completed partitions
		$completedPartitions = @($data.partitionStates.PSObject.Properties | Where-Object { $_.Value.state -eq 'Completed' })
		if ($completedPartitions.Count -gt 0) {
			$incrementalDir = Join-Path $outputDir ".pax_incremental"
			$hasIncrementalData = $false
			$incrementalRecordCount = 0
			
			if (Test-Path $incrementalDir) {
				$jsonlFiles = Get-ChildItem -Path $incrementalDir -Filter "*.jsonl" -ErrorAction SilentlyContinue
				if ($jsonlFiles -and $jsonlFiles.Count -gt 0) {
					$hasIncrementalData = $true
					# Count records in files
					foreach ($file in $jsonlFiles) {
						$incrementalRecordCount += (Get-Content $file.FullName | Measure-Object -Line).Lines
					}
				}
			}
			
			$expectedRecords = ($completedPartitions | ForEach-Object { $_.Value.recordCount } | Measure-Object -Sum).Sum
			
			if (-not $hasIncrementalData) {
				Write-LogHost ""
				Write-LogHost "════════════════════════════════════════════════════════════════════════════════" -ForegroundColor Red
				Write-LogHost "  WARNING: INCREMENTAL DATA MISSING" -ForegroundColor Red
				Write-LogHost "════════════════════════════════════════════════════════════════════════════════" -ForegroundColor Red
				Write-LogHost ""
				Write-LogHost "  Checkpoint shows $($completedPartitions.Count) completed partition(s) with ~$expectedRecords records," -ForegroundColor Yellow
				Write-LogHost "  but the .pax_incremental folder is missing or empty." -ForegroundColor Yellow
				Write-LogHost ""
				Write-LogHost "  Expected location: $incrementalDir" -ForegroundColor White
				Write-LogHost ""
				Write-LogHost "  If you continue, data from completed partitions will be LOST." -ForegroundColor Red
				Write-LogHost "  The remaining partitions will be re-queried, but previous data cannot be recovered." -ForegroundColor Red
				Write-LogHost ""
				Write-LogHost "  OPTIONS:" -ForegroundColor Cyan
				Write-LogHost "    1. Restore the .pax_incremental folder from backup (if available)" -ForegroundColor White
				Write-LogHost "    2. Start a fresh run without -Resume (will re-query all partitions)" -ForegroundColor White
				Write-LogHost "    3. Continue anyway and accept data loss from completed partitions" -ForegroundColor White
				Write-LogHost ""
				Write-LogHost "════════════════════════════════════════════════════════════════════════════════" -ForegroundColor Red
				Write-LogHost ""

				# G-6 noninteractive guard: a noninteractive host (container, ACA Job, scheduled
				# task, CI runner) cannot answer a Read-Host. The original code would hang
				# forever on stdin. Fail-fast with a clear message that points at the only
				# two correct recoveries (restore the incremental folder, or start fresh).
				if (script:Test-IsNonInteractive) {
					Write-LogHost "  Noninteractive host detected (no console available to confirm data loss)." -ForegroundColor Red
					Write-LogHost "  Resume aborted to prevent silent data loss." -ForegroundColor Red
					Write-LogHost "  Recovery: restore the .pax_incremental folder from backup OR re-run without -Resume." -ForegroundColor Yellow
					return $false
				}

				$response = Read-Host "Continue with potential data loss? (yes/no)"
				if ($response -notmatch '^y(es)?$') {
					Write-LogHost "Resume cancelled. Consider starting a fresh run." -ForegroundColor Yellow
					return $false
				}
				Write-LogHost "Continuing with resume despite missing incremental data..." -ForegroundColor Yellow
			} elseif ($incrementalRecordCount -lt ($expectedRecords * 0.9)) {
				# Warn if incremental count is significantly less than expected (allow 10% variance for counting differences)
				Write-LogHost ""
				Write-LogHost "  [WARN] Incremental data may be incomplete:" -ForegroundColor Yellow
				Write-LogHost "         Checkpoint expects ~$expectedRecords records from completed partitions" -ForegroundColor Yellow
				Write-LogHost "         Found $incrementalRecordCount records in .pax_incremental" -ForegroundColor Yellow
				Write-LogHost ""
			}
		}
		
		# Load into script scope
		$script:CheckpointPath = $CheckpointPath
		$script:CheckpointData = $data
		$script:PartialOutputPath = $partialCsvPath
		$script:IsResumeMode = $true
		
		return $true
	}
	catch {
		Write-LogHost "ERROR: Failed to parse checkpoint file: $($_.Exception.Message)" -ForegroundColor Red
		return $false
	}
}

function Find-Checkpoints {
	<#
	.SYNOPSIS
		Discovers checkpoint files in the specified output directory.
	.PARAMETER OutputPath
		Directory to search for checkpoint files.
	.OUTPUTS
		Array of checkpoint info objects sorted by LastUpdated (newest first).
	#>
	param(
		[Parameter(Mandatory)]
		[string]$OutputPath
	)
	
	if (-not (Test-Path $OutputPath)) {
		return @()
	}
	
	$checkpointFiles = Get-ChildItem -Path $OutputPath -Filter ".pax_checkpoint_*.json" -Force -ErrorAction SilentlyContinue
	
	if (-not $checkpointFiles -or $checkpointFiles.Count -eq 0) {
		return @()
	}
	
	$checkpoints = @()
	
	foreach ($file in $checkpointFiles) {
		try {
			$data = Get-Content -Path $file.FullName -Raw | ConvertFrom-Json -AsHashtable
			
			$checkpoints += [PSCustomObject]@{
				Path = $file.FullName
				FileName = $file.Name
				RunTimestamp = $data.runTimestamp
				LastUpdated = script:Parse-DateSafe $data.lastUpdated
				StartDate = if ($data.parameters.startDate) { $d = script:Parse-DateSafe $data.parameters.startDate; if ($d) { $d.ToLocalTime().ToString('yyyy-MM-dd') } else { 'Unknown' } } else { 'Unknown' }
				EndDate = if ($data.parameters.endDate) { $d = script:Parse-DateSafe $data.parameters.endDate; if ($d) { $d.ToLocalTime().ToString('yyyy-MM-dd') } else { 'Unknown' } } else { 'Unknown' }
				PartitionsComplete = $data.statistics.partitionsComplete
				PartitionsTotal = $data.partitions.total
				RecordsSaved = $data.statistics.totalRecordsSaved
			}
		}
		catch {
			# Skip invalid checkpoint files
			continue
		}
	}
	
	# Sort by LastUpdated descending (newest first)
	return $checkpoints | Sort-Object -Property LastUpdated -Descending
}

function Select-Checkpoint {
	<#
	.SYNOPSIS
		Prompts user to select from multiple checkpoint files.
	.PARAMETER Checkpoints
		Array of checkpoint info objects from Find-Checkpoints.
	.OUTPUTS
		Selected checkpoint path, or $null if user quits.
	#>
	param(
		[Parameter(Mandatory)]
		[array]$Checkpoints
	)
	
	Write-Host ""
	Write-Host "════════════════════════════════════════════════════════════════════════════════" -ForegroundColor Cyan
	Write-Host "  Multiple checkpoint files found. Select one to resume:" -ForegroundColor Cyan
	Write-Host "════════════════════════════════════════════════════════════════════════════════" -ForegroundColor Cyan
	Write-Host ""
	
	for ($i = 0; $i -lt $Checkpoints.Count; $i++) {
		$cp = $Checkpoints[$i]
		$num = $i + 1
		Write-Host "  [$num] $($cp.LastUpdated.ToString('yyyy-MM-dd HH:mm')) | $($cp.StartDate) to $($cp.EndDate) | $($cp.PartitionsComplete)/$($cp.PartitionsTotal) partitions | $($cp.RecordsSaved.ToString('N0')) records" -ForegroundColor White
		Write-Host "      $($cp.FileName)" -ForegroundColor DarkGray
		Write-Host ""
	}
	
	Write-Host "  [Q] Quit (do not resume)" -ForegroundColor Yellow
	Write-Host ""

	# G-6 noninteractive guard: cannot prompt for a checkpoint selection on a
	# container/ACA Job/CI runner. Reject explicitly with a recovery hint instead
	# of letting Read-Host hang on stdin. Operators who actually want resume in
	# noninteractive contexts must pass -Resume <explicit-checkpoint-path>.
	if (script:Test-IsNonInteractive) {
		Write-Host "  Noninteractive host detected: cannot prompt to choose among $($Checkpoints.Count) checkpoint(s)." -ForegroundColor Red
		Write-Host "  Re-run with an explicit path: -Resume `"<full-path-to-.pax_checkpoint_*.json>`"" -ForegroundColor Yellow
		Write-Host "  Or run on an interactive host to use the selection menu." -ForegroundColor Yellow
		return $null
	}

	Send-PromptNotification
	while ($true) {
		$choice = Read-Host "  Enter selection (1-$($Checkpoints.Count)) or 'Q' to quit"
		
		if ($choice -eq 'Q' -or $choice -eq 'q') {
			return $null
		}
		
		$selection = 0
		if ([int]::TryParse($choice, [ref]$selection)) {
			if ($selection -ge 1 -and $selection -le $Checkpoints.Count) {
				return $Checkpoints[$selection - 1]
			}
		}
		
		Write-Host "  Invalid selection. Please enter a number 1-$($Checkpoints.Count) or 'Q' to quit." -ForegroundColor Red
	}
}

function Remove-Checkpoint {
	<#
	.SYNOPSIS
		Deletes checkpoint file after successful completion.
	#>
	
	if ($script:CheckpointPath -and (Test-Path $script:CheckpointPath)) {
		try {
			Remove-Item -Path $script:CheckpointPath -Force
		}
		catch {
			Write-LogHost "  Warning: Could not delete checkpoint file: $($_.Exception.Message)" -ForegroundColor Yellow
		}
	}

	# Release the exclusive checkpoint lock acquired at run start.
	script:Release-CheckpointLock

	$script:CheckpointPath = $null
	$script:CheckpointData = $null
}

function Get-PartitionsToProcess {
	<#
	.SYNOPSIS
		Categorizes partitions based on checkpoint state for resume.
	.PARAMETER AllPartitions
		Array of all partition objects for the date range.
	.OUTPUTS
		Hashtable with ToSkip, ToFetchOnly, and ToCreateAndFetch arrays.
	#>
	param(
		[Parameter(Mandatory)]
		[array]$AllPartitions
	)
	
	$result = @{
		ToSkip = @()           # Already completed - skip entirely
		ToFetchOnly = @()      # Query exists on server - just fetch records
		ToCreateAndFetch = @() # Start fresh - create query then fetch
	}
	
	if (-not $script:CheckpointData) {
		# No checkpoint - all partitions need full processing
		$result.ToCreateAndFetch = $AllPartitions
		return $result
	}
	
	$completedIndices = @{}
	$queryCreatedIndices = @{}
	
	# Build lookup tables from checkpoint (use string keys for reliable comparison)
	foreach ($cp in $script:CheckpointData.partitions.completed) {
		$completedIndices["$($cp.index)"] = $cp
	}
	foreach ($qc in $script:CheckpointData.partitions.queryCreated) {
		$queryCreatedIndices["$($qc.index)"] = $qc
	}
	
	# Categorize each partition
	foreach ($partition in $AllPartitions) {
		$idx = "$($partition.Index)"  # Convert to string for reliable comparison
		
		if ($completedIndices.ContainsKey($idx)) {
			$result.ToSkip += $partition
		}
		elseif ($queryCreatedIndices.ContainsKey($idx)) {
			# Add QueryId to partition for fetch-only processing
			$partition | Add-Member -NotePropertyName 'StoredQueryId' -NotePropertyValue $queryCreatedIndices[$idx].queryId -Force
			$result.ToFetchOnly += $partition
		}
		else {
			$result.ToCreateAndFetch += $partition
		}
	}
	
	return $result
}

function Test-ShouldPromptTokenRefresh {
	<#
	.SYNOPSIS
		Checks if token refresh handling is needed.
	.DESCRIPTION
		Reactive detection: Returns true only when a 401 Unauthorized error
		has been detected, indicating the token has actually expired.
		No proactive time-based prompts - only triggers on real auth failures.
		
		For AppRegistration mode, this still returns true on 401 so the
		auth handling block can perform automatic silent token refresh.
		For interactive modes, this triggers a user prompt.
	.OUTPUTS
		$true if auth failure detected and refresh handling is needed, $false otherwise.
	#>
	
	# Reactive detection: Return true when 401 error detected (for ALL auth methods)
	# The auth handling block will determine whether to auto-refresh (AppRegistration)
	# or prompt the user (interactive modes)
	return $script:AuthFailureDetected
}

function Invoke-TokenRefreshPrompt {
	<#
	.SYNOPSIS
		Handles token refresh for interactive auth modes (WebLogin/DeviceCode).
	.DESCRIPTION
		Triggered reactively when a 401 Unauthorized error is detected.
		First attempts silent token refresh (SDK may have valid refresh token cached).
		If silent refresh fails, prompts user to re-authenticate or quit.
	.OUTPUTS
		'Refreshed' - Token refreshed successfully (silent or interactive)
		'Quit' - User chose to exit
	#>
	
	$tokenAge = if ($script:TokenAcquiredTime) { (Get-Date) - $script:TokenAcquiredTime } else { $null }
	
	# ═══════════════════════════════════════════════════════════════════════════
	# NOTE: We intentionally do NOT attempt automatic token refresh here.
	# On Windows, Connect-MgGraph with InteractiveBrowserCredential ALWAYS opens
	# a browser popup. If the user is away, this popup sits waiting, and when
	# they return and press 'R' to re-auth, a SECOND popup appears.
	# By going straight to the user prompt, we ensure only ONE popup when ready.
	# ═══════════════════════════════════════════════════════════════════════════
	
	# ═══════════════════════════════════════════════════════════════════════════
	# Prompt user for interactive re-authentication (single popup, user-initiated)
	# ═══════════════════════════════════════════════════════════════════════════
	
	# Get progress info for display
	$completedCount = if ($script:CheckpointData) { $script:CheckpointData.statistics.partitionsComplete } else { 0 }
	$totalCount = if ($script:CheckpointData) { $script:CheckpointData.partitions.total } else { 0 }
	$recordsSaved = if ($script:CheckpointData) { $script:CheckpointData.statistics.totalRecordsSaved } else { 0 }
	
	Write-Host ""
	Write-Host "════════════════════════════════════════════════════════════════════════════════" -ForegroundColor Red
	Write-Host "  [!]  AUTHENTICATION EXPIRED - Re-authentication Required" -ForegroundColor Red
	Write-Host "════════════════════════════════════════════════════════════════════════════════" -ForegroundColor Red
	Write-Host ""
	Write-Host "  Authentication failure detected (401 Unauthorized)." -ForegroundColor White
	Write-Host "  Your session token has expired. Please re-authenticate to continue." -ForegroundColor White
	Write-Host ""
	if ($tokenAge) {
		Write-Host "  Session duration: $([Math]::Round($tokenAge.TotalMinutes, 0)) minutes" -ForegroundColor Gray
	}
	Write-Host "  Progress: $completedCount/$totalCount partitions complete | $($recordsSaved.ToString('N0')) records saved to disk" -ForegroundColor White
	Write-Host "  Auth method: $($Auth) (interactive)" -ForegroundColor Gray
	Write-Host ""
	Write-Host "    [R] Re-authenticate now (recommended)" -ForegroundColor Green
	Write-Host "    [Q] Quit and save progress (resume later with -Resume)" -ForegroundColor Cyan
	Write-Host ""
	Write-Host "════════════════════════════════════════════════════════════════════════════════" -ForegroundColor Red

	# G-6 noninteractive guard: on a container/ACA Job/CI runner there is nobody at
	# the keyboard to choose R/Q. Auto-choose Q ('quit and save progress'); the
	# operator can resume the checkpoint later from an interactive host. Logging
	# the auto-choice prevents the silent stdin hang the original code would have
	# produced.
	if (script:Test-IsNonInteractive) {
		Write-Host "" -ForegroundColor Yellow
		Write-Host "  Noninteractive host detected: cannot prompt for re-authentication." -ForegroundColor Yellow
		Write-Host "  Auto-selecting [Q] - progress will be saved to the checkpoint." -ForegroundColor Yellow
		Write-Host "  Resume from an interactive host with: -Resume `"$($script:CheckpointPath)`"" -ForegroundColor Yellow
		return 'Quit'
	}

	Send-PromptNotification
	while ($true) {
		$choice = Read-Host "  Enter choice (R/Q)"
		
		switch ($choice.ToUpper()) {
			'R' {
				Write-Host ""
				Write-Host "  Re-authenticating..." -ForegroundColor Cyan
				
				try {
					# Disconnect and reconnect
					Disconnect-MgGraph -ErrorAction SilentlyContinue | Out-Null
					Connect-PurviewAudit -AuthMethod $Auth -UseEOMMode $false
					
					# Update token timing and reset auth failure flags
					$script:TokenAcquiredTime = Get-Date
					$script:AuthFailureDetected = $false
					$script:Auth401MessageShown = $false  # Reset for next auth failure cycle
					
					Write-Host "  Re-authentication successful. Resuming execution..." -ForegroundColor Green
					Write-Host "  Failed partitions will be retried with fresh token." -ForegroundColor Green
					Write-Host ""
					
					return 'Refreshed'
				}
				catch {
					Write-Host "  ✗ Re-authentication failed: $($_.Exception.Message)" -ForegroundColor Red
					Write-Host "  Please try again or quit." -ForegroundColor Yellow
				}
			}
			'Q' {
				Write-Host ""
				Show-CheckpointExitMessage
				return 'Quit'
			}
			default {
				Write-Host "  Invalid choice. Please enter R or Q." -ForegroundColor Red
			}
		}
	}
}

function Merge-IncrementalSaves {
	<#
	.SYNOPSIS
		Merges incremental JSON save files into the main allLogs collection.
	.DESCRIPTION
		Called at the end of execution to consolidate partition data that was
		saved incrementally during execution. In resume mode, only merges data
		from partitions that were skipped (already completed at start of run),
		since partitions completed during this run already have data in memory.
	.PARAMETER AllLogs
		Reference to the synchronized ArrayList to add records to.
	.PARAMETER OutputDirectory
		The output directory containing the .pax_incremental folder.
	.PARAMETER CleanupAfterMerge
		If true, deletes the incremental files after successful merge.
	.PARAMETER OnlyPartitionIndices
		If specified, only merge files for these partition indices.
		Used in resume mode to avoid double-counting data from partitions
		that completed during this run.
	#>
	param(
		[Parameter(Mandatory = $true)]
		[System.Collections.ArrayList]$AllLogs,
		
		[Parameter(Mandatory = $true)]
		[string]$OutputDirectory,
		
		[Parameter(Mandatory = $false)]
		[bool]$CleanupAfterMerge = $true,
		
		[Parameter(Mandatory = $false)]
		[int[]]$OnlyPartitionIndices = $null
	)
	
	$incrementalDir = Join-Path $OutputDirectory ".pax_incremental"
	
	if (-not (Test-Path $incrementalDir)) {
		return 0
	}
	
	$incrementalFiles = Get-ChildItem -Path $incrementalDir -Filter "*.jsonl" -ErrorAction SilentlyContinue
	
	if (-not $incrementalFiles -or $incrementalFiles.Count -eq 0) {
		return 0
	}
	
	$mergedCount = 0
	$filesProcessed = 0
	$filesSkipped = 0
	
	$filterMsg = if ($OnlyPartitionIndices) { " (filtering for partitions: $($OnlyPartitionIndices -join ', '))" } else { "" }
	Write-LogHost "  [MERGE] Found $($incrementalFiles.Count) incremental save files$filterMsg..." -ForegroundColor Cyan
	
	foreach ($file in $incrementalFiles) {
		try {
			# If filtering by partition indices, check if this file matches
			# Filename format: Part{N}_timestamp_qid-{QueryId}_Nrecords.jsonl (recovery files use qid-recovery)
			if ($OnlyPartitionIndices) {
				$partMatch = [regex]::Match($file.Name, '^Part(\d+)_')
				if ($partMatch.Success) {
					$filePartitionIndex = [int]$partMatch.Groups[1].Value
					if ($filePartitionIndex -notin $OnlyPartitionIndices) {
						$filesSkipped++
						# Don't delete - this file is for a partition completed in this run
						continue
					}
				}
			}
			
			# Read JSON Lines (NDJSON) format - one record per line
			$lines = Get-Content -Path $file.FullName -Encoding utf8
			$fileRecordCount = 0
			
			foreach ($line in $lines) {
				if ([string]::IsNullOrWhiteSpace($line)) { continue }
				
				try {
					$record = $line | ConvertFrom-Json
					[void]$AllLogs.Add($record)
					$fileRecordCount++
				} catch {
					# Skip malformed lines but continue processing
					Write-Verbose "Skipped malformed line in $($file.Name)"
				}
			}
			
			$mergedCount += $fileRecordCount
			if ($fileRecordCount -gt 0) { $filesProcessed++ }
			
			if ($CleanupAfterMerge) {
				Remove-Item -Path $file.FullName -Force -ErrorAction SilentlyContinue
			}
		}
		catch {
			Write-LogHost "  [WARN] Failed to merge $($file.Name): $($_.Exception.Message)" -ForegroundColor Yellow
		}
	}
	
	# Clean up directory if empty
	if ($CleanupAfterMerge) {
		$remainingFiles = Get-ChildItem -Path $incrementalDir -ErrorAction SilentlyContinue
		if (-not $remainingFiles -or $remainingFiles.Count -eq 0) {
			Remove-Item -Path $incrementalDir -Force -ErrorAction SilentlyContinue
		}
	}
	
	if ($mergedCount -gt 0) {
		Write-LogHost "  [MERGE] Merged $($mergedCount.ToString('N0')) records from $filesProcessed incremental files" -ForegroundColor Green
	}
	
	return $mergedCount
}

function Merge-IncrementalSaves-Streaming {
	<#
	.SYNOPSIS
		Memory-efficient streaming merge of incremental JSONL files directly to CSV.
	.DESCRIPTION
		Instead of loading all records into memory, this function streams records
		from incremental JSONL files directly to the final CSV output using batched
		writes and explicit garbage collection between files. This prevents memory
		exhaustion when merging millions of records.
	.PARAMETER OutputFile
		The final CSV file path to write merged data to.
	.PARAMETER OutputDirectory
		The output directory containing the .pax_incremental folder.
	.PARAMETER OnlyPartitionIndices
		If specified, only merge files for these partition indices.
	.PARAMETER Columns
		The column schema to use for CSV output. If not specified, uses default 7-column schema.
	.PARAMETER RunTimestamp
		The script run timestamp used to filter incremental files to only those from the current run.
		Prevents stale files from prior runs being merged into the output.
	.RETURNS
		The total number of records merged.
	#>
	param(
		[Parameter(Mandatory = $true)]
		[string]$OutputFile,
		
		[Parameter(Mandatory = $true)]
		[string]$OutputDirectory,
		
		[Parameter(Mandatory = $false)]
		[int[]]$OnlyPartitionIndices = $null,
		
		[Parameter(Mandatory = $false)]
		[string[]]$Columns = $null,
		
		[Parameter(Mandatory = $false)]
		[System.Collections.Generic.HashSet[string]]$ExcludeRecordIds = $null,
		
		[Parameter(Mandatory = $false)]
		[ref]$ActivityCounts = $null,
		
		[Parameter(Mandatory = $false)]
		[string]$RunTimestamp = $null
	)
	
	$incrementalDir = Join-Path $OutputDirectory ".pax_incremental"
	
	if (-not (Test-Path $incrementalDir)) {
		Write-LogHost "  [MERGE-STREAM] No incremental directory found" -ForegroundColor Yellow
		return 0
	}
	
	# Filter by run timestamp to avoid merging stale files from prior runs
	$jsonlFilter = if ($RunTimestamp) { "*_${RunTimestamp}_*.jsonl" } else { "*.jsonl" }
	$allFiles = Get-ChildItem -Path $incrementalDir -Filter $jsonlFilter -ErrorAction SilentlyContinue
	if (-not $allFiles -or $allFiles.Count -eq 0) {
		Write-LogHost "  [MERGE-STREAM] No incremental files found$(if ($RunTimestamp) { " for run $RunTimestamp" })" -ForegroundColor Yellow
		return 0
	}
	
	# Sort files by partition number for consistent output ordering
	$files = $allFiles | Sort-Object { 
		if ($_.Name -match 'Part(\d+)_') { [int]$Matches[1] } else { 999999 } 
	}
	
	# Filter by partition indices if specified
	if ($OnlyPartitionIndices) {
		$files = $files | Where-Object {
			$partMatch = [regex]::Match($_.Name, '^Part(\d+)_')
			if ($partMatch.Success) {
				[int]$partMatch.Groups[1].Value -in $OnlyPartitionIndices
			} else {
				$false
			}
		}
	}
	
	if (-not $files -or @($files).Count -eq 0) {
		Write-LogHost "  [MERGE-STREAM] No matching incremental files for specified partitions" -ForegroundColor Yellow
		return 0
	}
	
	# When multiple JSONL files exist for the same partition (from retries with different QueryIds),
	# keep only the largest file per partition. This prevents duplicate records from partial first attempts
	# being merged alongside the full retry result.
	$filesByPartition = @{}
	foreach ($f in @($files)) {
		if ($f.Name -match '^Part(\d+)_') {
			$pIdx = [int]$Matches[1]
			if (-not $filesByPartition.ContainsKey($pIdx) -or $f.Length -gt $filesByPartition[$pIdx].Length) {
				$filesByPartition[$pIdx] = $f
			}
		}
	}
	$deduplicatedFiles = @($filesByPartition.Values | Sort-Object { if ($_.Name -match 'Part(\d+)_') { [int]$Matches[1] } else { 999999 } })
	$removedFileCount = @($files).Count - $deduplicatedFiles.Count
	if ($removedFileCount -gt 0) {
		Write-LogHost "  [MERGE-STREAM] Removed $removedFileCount duplicate partition file(s) from prior retry attempts — keeping largest per partition" -ForegroundColor DarkYellow
	}
	$files = $deduplicatedFiles
	
	$fileCount = @($files).Count
	Write-LogHost "  [MERGE-STREAM] Streaming $fileCount incremental files to CSV..." -ForegroundColor Cyan
	
	# Use default 8-column schema if not specified (non-explosion mode)
	# Column names match Purview UI audit export: RecordId, CreationDate, RecordType, Operation, UserId, AuditData, AssociatedAdminUnits, AssociatedAdminUnitsNames
	if (-not $Columns) {
		$Columns = @('RecordId', 'CreationDate', 'RecordType', 'Operation', 'UserId', 'AuditData', 'AssociatedAdminUnits', 'AssociatedAdminUnitsNames')
	}
	
	$totalMerged = 0
	$filesProcessed = 0
	$headerWritten = $false
	$batchSize = 5000
	$startTime = Get-Date
	$lastProgressTime = Get-Date
	
	# Track seen RecordIds for deduplication (seed with any in-memory RecordIds already written to CSV)
	$seenIds = if ($ExcludeRecordIds) { New-Object System.Collections.Generic.HashSet[string] ($ExcludeRecordIds) } else { New-Object System.Collections.Generic.HashSet[string] }
	$duplicatesSkipped = 0
	
	foreach ($file in $files) {
		$filesProcessed++
		$partNum = if ($file.Name -match 'Part(\d+)_') { $Matches[1] } else { "?" }
		
		try {
			# Open CSV writer on first file with data
			if (-not $headerWritten) {
				Open-CsvWriter -Path $OutputFile -Columns $Columns
				$headerWritten = $true
			}
			
			# Stream records from this file in batches
			$batch = New-Object System.Collections.Generic.List[object]
			$fileRecords = 0
			
			# Use StreamReader instead of Get-Content pipeline for ~5-10x faster file reading
			$reader = [System.IO.StreamReader]::new($file.FullName, [System.Text.Encoding]::UTF8)
			while ($null -ne ($line = $reader.ReadLine())) {
				if (-not [string]::IsNullOrWhiteSpace($line)) {
					try {
						$record = $line | ConvertFrom-Json
						
						# Deduplicate by RecordId
						$recordId = $null
						if ($record.Identity) { $recordId = $record.Identity }
						elseif ($record.Id) { $recordId = $record.Id }
						elseif ($record.RecordId) { $recordId = $record.RecordId }
						
						if ($recordId -and $seenIds.Contains($recordId)) {
							$script:StreamingMergeDuplicatesSkipped++
							continue  # Skip duplicate — 'continue' works in while loop (was 'return' in ForEach-Object)
						}
						if ($recordId) { [void]$seenIds.Add($recordId) }
						
						# Client-side date-range trimming for streaming path
						if ($script:TrimStartDateUTC -or $script:TrimEndDateUTC) {
							$recDate = script:Parse-DateSafe $record.CreationDate
							if ($recDate) {
								$recDateUtc = $recDate.ToUniversalTime()
								if ($script:TrimStartDateUTC -and $recDateUtc -lt $script:TrimStartDateUTC) { $script:DateTrimCount++; continue }
								if ($script:TrimEndDateUTC   -and $recDateUtc -ge $script:TrimEndDateUTC)   { $script:DateTrimCount++; continue }
							}
						}
						
						# Parse AuditData for Operation if needed
						$auditData = $record.AuditData
						$parsedAudit = if ($record.PSObject.Properties['_ParsedAuditData']) { 
							$record._ParsedAuditData 
						} else { 
							try { $auditData | ConvertFrom-Json -ErrorAction SilentlyContinue } catch { $null } 
						}
						$opValue = if ($parsedAudit -and $parsedAudit.Operation) { $parsedAudit.Operation } else { $record.Operations }
						
						# Track per-activity counts for Activity Type Breakdown
						if ($ActivityCounts -and $opValue) {
							if (-not $ActivityCounts.Value.ContainsKey($opValue)) { $ActivityCounts.Value[$opValue] = 0 }
							$ActivityCounts.Value[$opValue]++
						}
						
						# Create normalized record matching expected schema (column names match Purview UI export)
						$normalizedRecord = [pscustomobject]@{
							RecordId                  = if ($record.RecordId) { $record.RecordId } elseif ($record.Identity) { $record.Identity } elseif ($record.Id) { $record.Id } elseif ($parsedAudit -and $parsedAudit.Id) { $parsedAudit.Id } else { $null }
							CreationDate              = if ($record.CreationDate) { 
								$dt = script:Parse-DateSafe $record.CreationDate; if ($dt) { $dt.ToUniversalTime().ToString('yyyy-MM-ddTHH:mm:ss.fffZ', [System.Globalization.CultureInfo]::InvariantCulture) } else { $record.CreationDate }
							} else { '' }
							RecordType                = $record.RecordType
							Operation                 = $opValue
							UserId                    = if ($record.UserId) { $record.UserId } elseif ($record.UserIds) { $record.UserIds } else { '' }
							AuditData                 = $auditData
							AssociatedAdminUnits      = $(try { if ($parsedAudit.AssociatedAdminUnits) { $parsedAudit.AssociatedAdminUnits } elseif ($record.AssociatedAdminUnits) { $record.AssociatedAdminUnits } else { '' } } catch { '' })
							AssociatedAdminUnitsNames = $(try { if ($parsedAudit.AssociatedAdminUnitsNames) { $parsedAudit.AssociatedAdminUnitsNames } elseif ($record.AssociatedAdminUnitsNames) { $record.AssociatedAdminUnitsNames } else { '' } } catch { '' })
						}
						
						$batch.Add($normalizedRecord)
						$fileRecords++
						
						# Write batch when full
						if ($batch.Count -ge $batchSize) {
							Write-CsvRows -Rows $batch -Columns $Columns
							$totalMerged += $batch.Count
							$batch.Clear()
						}
					} catch {
						# Skip malformed lines
						Write-Verbose "Skipped malformed line in $($file.Name): $($_.Exception.Message)"
					}
				}
			}
			# Dispose StreamReader to release file handle
			if ($reader) { $reader.Dispose(); $reader = $null }
			
			# Flush remaining batch for this file
			if ($batch.Count -gt 0) {
				Write-CsvRows -Rows $batch -Columns $Columns
				$totalMerged += $batch.Count
				$batch.Clear()
			}
			
			# Progress reporting every 30 seconds
			$now = Get-Date
			if (($now - $lastProgressTime).TotalSeconds -ge 30) {
				$elapsed = ($now - $startTime).TotalSeconds
				$rate = if ($elapsed -gt 0) { [int]($totalMerged / $elapsed) } else { 0 }
				Write-LogHost "  [MERGE-STREAM] Progress: $filesProcessed/$fileCount files | $($totalMerged.ToString('N0')) records | ~$rate rec/sec" -ForegroundColor DarkCyan
				$lastProgressTime = $now
			}
			
			# Reduced GC frequency from every file to every 5th file for better throughput
			$batch = $null
			if ($filesProcessed % 5 -eq 0) {
				[GC]::Collect()
				[GC]::WaitForPendingFinalizers()
			}
			
		} catch {
			# Ensure StreamReader is disposed on error to release file handle
			if ($reader) { try { $reader.Dispose() } catch {} ; $reader = $null }
			Write-LogHost "  [WARN] Failed to stream merge $($file.Name): $($_.Exception.Message)" -ForegroundColor Yellow
		}
	}
	
	# Close CSV writer
	if ($headerWritten) {
		Close-CsvWriter
	}
	
	# Final stats
	$totalElapsed = (Get-Date) - $startTime
	$finalRate = if ($totalElapsed.TotalSeconds -gt 0) { [int]($totalMerged / $totalElapsed.TotalSeconds) } else { 0 }
	
	Write-LogHost "  [MERGE-STREAM] Streaming merge complete: $($totalMerged.ToString('N0')) records from $filesProcessed files" -ForegroundColor Green
	Write-LogHost "  [MERGE-STREAM]   Time: $([Math]::Round($totalElapsed.TotalSeconds, 1))s | Rate: $finalRate rec/sec" -ForegroundColor DarkGray
	if ($duplicatesSkipped -gt 0 -or $script:StreamingMergeDuplicatesSkipped -gt 0) {
		$totalDupes = $duplicatesSkipped + $script:StreamingMergeDuplicatesSkipped
		Write-LogHost "  [MERGE-STREAM]   Duplicates skipped: $totalDupes" -ForegroundColor DarkGray
	}
	
	# Clear the HashSet to free memory
	$seenIds.Clear()
	$seenIds = $null
	[GC]::Collect()
	
	return $totalMerged
}

function Show-CheckpointExitMessage {
	<#
	.SYNOPSIS
		Displays checkpoint save confirmation and resume instructions.
	#>
	
	if (-not $script:CheckpointData -or -not $script:CheckpointPath) {
		return
	}
	
	$completedCount = if ($script:CheckpointData.statistics.partitionsComplete) { $script:CheckpointData.statistics.partitionsComplete } else { 0 }
	$queryCreatedCount = if ($script:CheckpointData.statistics.partitionsQueryCreated) { $script:CheckpointData.statistics.partitionsQueryCreated } else { 0 }
	$totalCount = if ($script:CheckpointData.partitions.total) { $script:CheckpointData.partitions.total } else { 0 }
	$remaining = $totalCount - $completedCount - $queryCreatedCount
	$recordsSaved = if ($script:CheckpointData.statistics.totalRecordsSaved) { $script:CheckpointData.statistics.totalRecordsSaved } else { 0 }
	
	Write-Host ""
	Write-Host "════════════════════════════════════════════════════════════════════════════════" -ForegroundColor Green
	Write-Host "  PROGRESS SAVED" -ForegroundColor Green
	Write-Host "════════════════════════════════════════════════════════════════════════════════" -ForegroundColor Green
	Write-Host ""
	# The checkpoint file and the local _PARTIAL file always live on the local
	# scratch path (they are required for -Resume; the checkpoint isn't uploaded
	# until the run completes successfully). Display them as full local paths so
	# the user can copy/paste them into -Resume verbatim.
	#
	# The run log is written to local scratch throughout the run. On successful
	# completion the end-of-run upload sweep pushes it to the remote destination
	# (SP/Fabric); on an interrupted run (Ctrl+C / failure) the upload sweep does
	# NOT fire, so the log lives only at the local scratch path until the next
	# -Resume completes successfully. Always display the literal local path here
	# (consistent with Checkpoint: and Partial data:) so the user can inspect /
	# attach the in-progress log immediately. When a remote destination is bound,
	# print a follow-up "Uploads to:" note so the user knows where the log will
	# land on successful completion.
	Write-Host "  Checkpoint:   $script:CheckpointPath" -ForegroundColor White
	# Live in-progress records stream into <OutputPath>/.pax_incremental/*.jsonl
	# shards as each partition completes. The companion _PARTIAL.csv ($script:PartialOutputPath)
	# is only materialized at end-of-run merge or on successful completion, so it
	# generally does NOT exist on an interrupted Ctrl+C exit. Point the user at
	# the .pax_incremental folder (the actual durable source of partial data); if
	# a _PARTIAL.csv already exists alongside it, list that on a follow-up line.
	$_partialBaseDir = $null
	# Defensive: Split-Path -LiteralPath throws "Parameter set cannot be resolved"
	# when handed $null, an empty string, or a non-string (array / hashtable from a
	# malformed checkpoint outputFiles entry). Coerce to a non-empty string before
	# splitting and swallow any residual parsing failure so the exit banner never
	# crashes after a real upstream error has already been reported.
	$_pop = if ($script:PartialOutputPath) { [string]$script:PartialOutputPath } else { '' }
	if ($_pop -and $_pop.Trim()) {
		try { $_partialBaseDir = Split-Path -LiteralPath $_pop -Parent -ErrorAction Stop } catch { $_partialBaseDir = $null }
	}
	if (-not $_partialBaseDir -and $script:CheckpointPath) {
		$_cpp = [string]$script:CheckpointPath
		if ($_cpp -and $_cpp.Trim()) {
			try { $_partialBaseDir = Split-Path -LiteralPath $_cpp -Parent -ErrorAction Stop } catch { $_partialBaseDir = $null }
		}
	}
	$_incDir = if ($_partialBaseDir) { Join-Path $_partialBaseDir '.pax_incremental' } else { $null }
	if ($_incDir) {
		Write-Host "  Partial data: $_incDir\*.jsonl" -ForegroundColor White
	} else {
		Write-Host "  Partial data: (incremental .jsonl shards under scratch .pax_incremental/)" -ForegroundColor White
	}
	if ($script:PartialOutputPath -and (Test-Path -LiteralPath $script:PartialOutputPath)) {
		Write-Host "                Merged CSV (so far): $script:PartialOutputPath" -ForegroundColor DarkGray
	}
	if ($script:LogFile) {
		Write-Host "  Log file:     $script:LogFile" -ForegroundColor White
		$_logRemoteTarget = $null
		try {
			if ($script:DestTier -and $script:DestTier.ContainsKey('Log') -and $script:DestTier['Log'] -and $script:DestTier['Log'] -ne 'Local') {
				$_logFolder = if ($script:DestParentUrl -and $script:DestParentUrl.ContainsKey('Log') -and $script:DestParentUrl['Log']) {
					$script:DestParentUrl['Log']
				} elseif ($script:DestRaw -and $script:DestRaw.ContainsKey('Log') -and $script:DestRaw['Log']) {
					$script:DestRaw['Log']
				} else { $null }
				if ($_logFolder) {
					$_logLeaf = [System.IO.Path]::GetFileName($script:LogFile)
					$_logRemoteTarget = ($_logFolder.TrimEnd('/','\') + '/' + $_logLeaf)
				}
			}
		} catch {}
		if ($_logRemoteTarget) {
			Write-Host "                (uploads to $_logRemoteTarget on successful completion)" -ForegroundColor DarkGray
		}
	}
	Write-Host "  Records saved: $($recordsSaved.ToString('N0'))" -ForegroundColor White
	# Build the Partitions status line as a single string before emission so the
	# global Write-Host proxy (which mirrors every Write-Host call to the log
	# file as ONE timestamped [INFO] entry regardless of -NoNewline) writes one
	# log line instead of 2-3 fragmented entries. The console output is the same
	# either way — both forms produce an identical
	# "Partitions: X/Y complete[, N queries pending][, M not started]" line —
	# but a multi-call -NoNewline approach produces orphan log lines like
	# ", 1 queries pending" on their own timestamp because -NoNewline only
	# concatenates on the host stream, not in the proxy's Add-Content path.
	$partitionLine = "  Partitions: $completedCount/$totalCount complete"
	if ($queryCreatedCount -gt 0) { $partitionLine += ", $queryCreatedCount queries pending" }
	if ($remaining -gt 0)        { $partitionLine += ", $remaining not started" }
	Write-Host $partitionLine -ForegroundColor White
	Write-Host ""
	Write-Host "  To resume later:" -ForegroundColor Cyan
	# AppRegistration runs require -ClientSecret on every invocation (the secret
	# is never persisted to the checkpoint). Append a placeholder hint so the
	# operator copy/pastes a complete command. Interactive auth modes
	# (WebLogin, DeviceCode) don't need a secret, so the line is unchanged in
	# those cases.
	if ($Auth -eq 'AppRegistration') {
		Write-Host "    -Resume `"$($script:CheckpointPath)`" -ClientSecret '<your client secret>'" -ForegroundColor White
	} else {
		Write-Host "    -Resume `"$($script:CheckpointPath)`"" -ForegroundColor White
	}
	Write-Host ""
	Write-Host "════════════════════════════════════════════════════════════════════════════════" -ForegroundColor Green
}

function Complete-CheckpointRun {
	<#
	.SYNOPSIS
		Finalizes successful run: renames _PARTIAL file, deletes checkpoint.
	.PARAMETER FinalOutputPath
		The final output path (without _PARTIAL).
	#>
	param(
		[Parameter(Mandatory)]
		[string]$FinalOutputPath
	)
	
	# Rename _PARTIAL output (and log) to final names ONLY if the _PARTIAL file still exists.
	# In CSV-split / ExportWorkbook modes the intermediate _PARTIAL.csv may already have
	# been deleted by upstream code paths; in that case skip the rename but STILL proceed
	# with checkpoint deletion below so the checkpoint file is not orphaned.
	if ($script:PartialOutputPath -and (Test-Path $script:PartialOutputPath)) {
		try {
			# Rename _PARTIAL to final
			if (Test-Path $FinalOutputPath) {
				# Final file already exists - add timestamp to avoid overwrite
				$dir = Split-Path $FinalOutputPath -Parent
				$name = [System.IO.Path]::GetFileNameWithoutExtension($FinalOutputPath)
				$ext = [System.IO.Path]::GetExtension($FinalOutputPath)
				$timestamp = Get-Date -Format 'yyyyMMdd_HHmmss'
				$FinalOutputPath = Join-Path $dir "${name}_${timestamp}${ext}"
			}
			
			Move-Item -Path $script:PartialOutputPath -Destination $FinalOutputPath -Force
			
			# Rename log file (remove _PARTIAL suffix)
			$partialLogPath = $script:LogFile
			if ($partialLogPath -and (Test-Path $partialLogPath) -and $partialLogPath -match '_PARTIAL\.log$') {
				$finalLogPath = $partialLogPath -replace '_PARTIAL\.log$', '.log'
				if (Test-Path $finalLogPath) {
					$logDir = Split-Path $finalLogPath -Parent
					$logName = [System.IO.Path]::GetFileNameWithoutExtension($finalLogPath)
					$timestamp = Get-Date -Format 'yyyyMMdd_HHmmss'
					$finalLogPath = Join-Path $logDir "${logName}_${timestamp}.log"
				}
				Move-Item -Path $partialLogPath -Destination $finalLogPath -Force
				$script:LogFile = $finalLogPath
			}
			
			$script:PartialOutputPath = $null
		}
		catch {
			Write-LogHost "  Warning: Could not finalize output file: $($_.Exception.Message)" -ForegroundColor Yellow
		}
	}
	
	# Delete checkpoint (always — caller has determined the run succeeded).
	Remove-Checkpoint
}

function Get-UserLicenseData {
	<#
	.SYNOPSIS
		Fetches user license information from Microsoft Graph API.
	
	.DESCRIPTION
		Queries Graph API for subscribedSkus and builds lookup hashtables for:
		- User license assignments (userId -> list of SKU names)
		- Copilot license detection (userId -> has Copilot license)

		Dynamic Copilot license detection (no hardcoded SKU GUIDs):
		1. From /subscribedSkus, collect every servicePlanId whose servicePlanName matches '*COPILOT*'.
		2. For each user, scan assignedPlans for entries where capabilityStatus == 'Enabled'
		   AND servicePlanId is in the discovered Copilot plan set.
		This honors capability state (admin-disabled service plans are correctly excluded)
		and auto-adapts to any current or future Copilot SKU (M365, EDU, Sales, Finance, GCC, etc.).
		Requires only User.Read.All + Organization.Read.All (no additional permissions).

	.OUTPUTS
		Hashtable with two keys:
		- UserLicenses: @{userId = @('SKU1', 'SKU2')}
		- UserHasCopilot: @{userId = $true/$false}
	#>
	
	Write-LogHost ""
	Write-LogHost "Fetching license data from Microsoft Graph API..." -ForegroundColor Cyan
	
	try {
		# Fetch all subscribed SKUs with assigned user data
		$uri = "https://graph.microsoft.com/v1.0/subscribedSkus"
		$response = Invoke-MgGraphRequest -Method GET -Uri $uri -ErrorAction Stop
		$skus = $response.value
		
		Write-LogHost "  Found $($skus.Count) SKU(s) in tenant" -ForegroundColor Gray

		# Build SKU lookup: skuId -> skuPartNumber
		# Also dynamically discover Copilot service plan IDs by name pattern (no hardcoded GUIDs).
		$skuLookup = @{}
		$copilotPlanIds = New-Object System.Collections.Generic.HashSet[string]

		foreach ($sku in $skus) {
			$skuId = $sku.skuId
			$skuName = $sku.skuPartNumber
			$skuLookup[$skuId] = $skuName
			if ($sku.servicePlans) {
				foreach ($plan in $sku.servicePlans) {
					if ($plan.servicePlanName -and $plan.servicePlanName -like '*COPILOT*' -and $plan.servicePlanId) {
						[void]$copilotPlanIds.Add([string]$plan.servicePlanId)
					}
				}
			}
		}
		Write-LogHost "  Discovered $($copilotPlanIds.Count) Copilot service plan(s) in tenant" -ForegroundColor Gray

		# Build user license hashtables
		$userLicenses = @{}      # userId -> @('SKU1', 'SKU2')
		$userHasCopilot = @{}    # userId -> $true/$false

		# Fetch all users with licenses in batches
		# assignedPlans is required for capability-aware Copilot detection (still under User.Read.All).
		Write-LogHost "  Fetching user license assignments..." -ForegroundColor Gray
		$userUri = "https://graph.microsoft.com/v1.0/users?`$select=id,userPrincipalName,assignedLicenses,assignedPlans&`$top=999"
		$userCount = 0
		$copilotUserCount = 0
		
		do {
			$userResponse = Invoke-MgGraphRequest -Method GET -Uri $userUri -ErrorAction Stop
			$users = $userResponse.value
			
			foreach ($user in $users) {
				$userId = $user.id
				$upn = $user.userPrincipalName

				if (-not $userId -or -not $upn) { continue }

				$userCount++
				$licenses = @()
				$hasCopilot = $false

				# Friendly SKU name list (unchanged): map assignedLicenses[].skuId -> skuPartNumber via $skuLookup
				foreach ($license in $user.assignedLicenses) {
					$skuId = $license.skuId
					$skuName = if ($skuLookup.ContainsKey($skuId)) { $skuLookup[$skuId] } else { $skuId }
					$licenses += $skuName
				}

				# Capability-aware Copilot detection: any assignedPlan that is Enabled AND a Copilot service plan.
				if ($copilotPlanIds.Count -gt 0 -and $user.assignedPlans) {
					foreach ($plan in $user.assignedPlans) {
						if ($plan.capabilityStatus -eq 'Enabled' -and $plan.servicePlanId -and $copilotPlanIds.Contains([string]$plan.servicePlanId)) {
							$hasCopilot = $true
							break
						}
					}
				}

				# Store license data keyed by both ID and UPN for flexible lookup
				if ($licenses.Count -gt 0) {
					$userLicenses[$userId] = $licenses
					$userLicenses[$upn] = $licenses
				}
				
				$userHasCopilot[$userId] = $hasCopilot
				$userHasCopilot[$upn] = $hasCopilot
				
				if ($hasCopilot) {
					$copilotUserCount++
				}
			}
			
			$userUri = $userResponse.'@odata.nextLink'
		} while ($userUri)
		
		Write-LogHost "  Processed $userCount user(s) with license assignments" -ForegroundColor Gray
		Write-LogHost "  Detected $copilotUserCount user(s) with Copilot licenses" -ForegroundColor Green
		Write-LogHost ""
		
		return @{
			UserLicenses = $userLicenses
			UserHasCopilot = $userHasCopilot
		}
	}
	catch {
		Write-LogHost "WARNING: Failed to fetch license data: $($_.Exception.Message)" -ForegroundColor Yellow
		Write-LogHost "         License columns will be empty in export" -ForegroundColor Yellow
		Write-LogHost ""
		
		# Return empty hashtables on failure
		return @{
			UserLicenses = @{}
			UserHasCopilot = @{}
		}
	}
}

function ConvertTo-FlatEntraUsers {
	<#
	.SYNOPSIS
		Flattens Entra user objects into CSV-friendly format.
	
	.DESCRIPTION
		Converts Entra ID user objects with nested properties into flat tabular format.
		Filters out non-user accounts (rooms, resources) based on userType validation.
		Explodes arrays (proxyAddresses, manager) into individual columns.
		
		NOTE: This version excludes the 9 granular Entra license columns from the Graph script.
		License data is added separately via Get-UserLicenseData() in MAC format (assignedLicenses, hasLicense).
	
	.PARAMETER Users
		Array of user objects from Microsoft Graph API (with 35 properties + manager expansion).
	
	.OUTPUTS
		Array of PSCustomObjects with 37 flattened columns (35 user properties + 5 manager columns, no license columns yet).
	#>
	param(
		[Parameter(Mandatory = $true)]
		[array]$Users
	)
	
	$flattenedUsers = @()
	
	foreach ($user in $Users) {
		# Filter: Only include real user accounts (exclude rooms, resources, shared mailboxes)
		# Room and resource mailboxes have specific characteristics:
		# - userType is often null or not "Member"/"Guest"
		# - They typically lack givenName and surname
		# - They often have mail but no userPrincipalName with typical user format
		
		$userTypeValue = $user.userType
		
		# Skip if userType is null/empty (likely a room or resource)
		if ([string]::IsNullOrWhiteSpace($userTypeValue)) {
			continue
		}
		
		# Only include users with userType = "Member" or "Guest"
		# Rooms/resources typically have different userType values or null
		if ($userTypeValue -ne 'Member' -and $userTypeValue -ne 'Guest') {
			continue
		}
		
		# Additional heuristic: Real users typically have either givenName or surname
		# Room mailboxes typically have neither (only displayName)
		# This is not foolproof but combined with userType check, it's quite reliable
		$hasGivenName = -not [string]::IsNullOrWhiteSpace($user.givenName)
		$hasSurname = -not [string]::IsNullOrWhiteSpace($user.surname)
		
		# If user has Member/Guest type but no name components, might be a shared resource
		# Allow through if they have at least givenName OR surname OR if account is enabled
		# (most room mailboxes are enabled but lack name components)
		if (-not $hasGivenName -and -not $hasSurname -and $user.accountEnabled) {
			# Additional check: if they have licenses assigned, likely a real user
			if (-not $user.assignedLicenses -or $user.assignedLicenses.Count -eq 0) {
				# No licenses and no name components - likely a room/resource
				continue
			}
		}
		
		$flatUser = [ordered]@{}
		
		# Core Identity Properties (simple strings)
		$flatUser['userPrincipalName'] = $user.userPrincipalName
		$flatUser['displayName'] = $user.displayName
		$flatUser['id'] = $user.id
		$flatUser['mail'] = $user.mail
		$flatUser['givenName'] = $user.givenName
		$flatUser['surname'] = $user.surname
		
		# Job Properties
		$flatUser['jobTitle'] = $user.jobTitle
		$flatUser['department'] = $user.department
		$flatUser['employeeType'] = $user.employeeType
		$flatUser['employeeId'] = $user.employeeId
		$flatUser['employeeHireDate'] = $user.employeeHireDate
		
		# Location Properties
		$flatUser['officeLocation'] = $user.officeLocation
		$flatUser['city'] = $user.city
		$flatUser['state'] = $user.state
		$flatUser['country'] = $user.country
		$flatUser['postalCode'] = $user.postalCode
		$flatUser['companyName'] = $user.companyName
		
		# Organizational Properties
		$flatUser['employeeOrgData_division'] = if ($user.employeeOrgData) { $user.employeeOrgData.division } else { $null }
		$flatUser['employeeOrgData_costCenter'] = if ($user.employeeOrgData) { $user.employeeOrgData.costCenter } else { $null }
		
		# Status Properties
		$flatUser['accountEnabled'] = $user.accountEnabled
		$flatUser['userType'] = $user.userType
		$flatUser['createdDateTime'] = $user.createdDateTime
		
		# Usage Properties
		$flatUser['usageLocation'] = $user.usageLocation
		$flatUser['preferredLanguage'] = $user.preferredLanguage
		
		# Sync Properties
		$flatUser['onPremisesSyncEnabled'] = $user.onPremisesSyncEnabled
		$flatUser['onPremisesImmutableId'] = $user.onPremisesImmutableId
		$flatUser['externalUserState'] = $user.externalUserState
		
		# Explode proxyAddresses array (Email aliases)
		if ($user.proxyAddresses -and $user.proxyAddresses.Count -gt 0) {
			$primarySMTP = $user.proxyAddresses | Where-Object { $_ -like 'SMTP:*' } | Select-Object -First 1
			$flatUser['proxyAddresses_Primary'] = if ($primarySMTP) { $primarySMTP -replace '^SMTP:', '' } else { $null }
			$flatUser['proxyAddresses_Count'] = $user.proxyAddresses.Count
			$flatUser['proxyAddresses_All'] = ($user.proxyAddresses -join '; ')
		}
		else {
			$flatUser['proxyAddresses_Primary'] = $null
			$flatUser['proxyAddresses_Count'] = 0
			$flatUser['proxyAddresses_All'] = $null
		}
		
		# Handle manager object separately (flatten to individual columns)
		if ($user.manager) {
			$flatUser['manager_id'] = $user.manager.id
			$flatUser['manager_displayName'] = $user.manager.displayName
			$flatUser['manager_userPrincipalName'] = $user.manager.userPrincipalName
			$flatUser['manager_mail'] = $user.manager.mail
			$flatUser['manager_jobTitle'] = $user.manager.jobTitle
		}
		else {
			$flatUser['manager_id'] = $null
			$flatUser['manager_displayName'] = $null
			$flatUser['manager_userPrincipalName'] = $null
			$flatUser['manager_mail'] = $null
			$flatUser['manager_jobTitle'] = $null
		}
		
		# License columns will be added separately by Get-EntraUsersData()
		# using Get-UserLicenseData() to provide MAC-format columns:
		# - assignedLicenses (semicolon-separated SKU names)
		# - hasLicense (Copilot detection boolean)
		
		# =====================================================================
		# Power BI AI-in-One Dashboard 2701 Template Compatibility Columns
		# These alias columns map existing Graph API data to 2701 template column names
		# =====================================================================
		$flatUser['ManagerID'] = $flatUser['manager_id']
		$flatUser['BusinessAreaLabel'] = $flatUser['employeeOrgData_division']
		$flatUser['CountryofEmployment'] = $flatUser['country']
		$flatUser['CompanyCodeLabel'] = $flatUser['companyName']
		$flatUser['CostCentreLabel'] = $flatUser['employeeOrgData_costCenter']
		$flatUser['UserName'] = $flatUser['displayName']
		
		# Viva Insights-specific columns (not available from Microsoft Graph API)
		# These are placeholders for template compatibility - data must come from HR systems
		$flatUser['EffectiveDate'] = $null
		$flatUser['FunctionType'] = $null
		$flatUser['BusinessAreaCode'] = $null
		$flatUser['OrgLevel_3Label'] = $null
		
		# Convert ordered hashtable to PSCustomObject for proper CSV export
		$flattenedUsers += [PSCustomObject]$flatUser
	}
	
	return $flattenedUsers
}

function Get-EntraUsersData {
	<#!
	.SYNOPSIS
		Collects and flattens Entra ID (Azure AD) user directory data and enriches with MAC-format license info.

	.DESCRIPTION
			# New naming: Purview_Audit_CombinedUsageActivity[_EntraUsers]_timestamp.xlsx
			$baseName = "Purview_Audit_CombinedUsageActivity"
			if ($IncludeUserInfo -and -not $UseEOM) { $baseName += "_EntraUsers" }
			$excelDescriptor = if ($IncludeUserInfo -and -not $UseEOM) { 'multi-tab workbook (CombinedActivity + EntraUsers)' } else { 'single-tab workbook' }
			Write-LogHost "Output File: ${outputDir}${baseName}_<timestamp>.xlsx ($excelDescriptor)" -ForegroundColor White
		Filters out non-user principals (rooms/resources) using userType + name heuristics identical to ConvertTo-FlatEntraUsers.
		Flattens users via ConvertTo-FlatEntraUsers, then appends two MAC-aligned columns:
		  • assignedLicenses  (semicolon-separated SKU `skuPartNumber` names)
		  • hasLicense        (Copilot license boolean; renamed from UserHasCopilotLicense)

		License enrichment uses existing Get-UserLicenseData() hashtables (UserLicenses, UserHasCopilot).
		Only called when -IncludeUserInfo is specified (Graph API mode).

	.OUTPUTS
		Array[psobject] of flattened users (30 core columns + 5 manager columns + 2 license columns = 37 total).

	.NOTES
		If Graph API call fails, returns empty array with warning. License enrichment silently skips if lookup missing.
	#>
	param(
		[switch]$Quiet
	)

	$entraUsers = @()
	try {
		if (-not $Quiet) { Write-LogHost "Fetching Entra user directory (35 properties + manager)..." -ForegroundColor Cyan }

		# Properties mirrored from Graph script (excluding license arrays we purposefully omit)
		$entraUserSelect = @(
			'userPrincipalName','displayName','id','mail','givenName','surname','jobTitle','department','employeeType','employeeId','employeeHireDate',
			'officeLocation','city','state','country','postalCode','companyName','accountEnabled','userType','createdDateTime','usageLocation',
			'preferredLanguage','onPremisesSyncEnabled','onPremisesImmutableId','externalUserState','employeeOrgData','proxyAddresses'
		) -join ','

		$baseUri = "https://graph.microsoft.com/v1.0/users?`$select=$entraUserSelect&`$expand=manager&`$top=999"
		$nextLink = $baseUri
		# Generic List accumulator (was $rawUsers = @() with +=). On a mega-tenant
		# (~400K+ users) the array-append pattern is O(n^2) — every += reallocates and
		# copies the whole backing array — which is both slow and memory-heavy. A
		# List[object] with AddRange appends amortized O(1).
		$rawUsers = [System.Collections.Generic.List[object]]::new()
		$loops = 0
		# Scale-aware paging ceiling. With $expand=manager, Graph caps each page far
		# below the requested $top=999 (often ~100 rows/page), so a mega-tenant needs
		# thousands of pages: at the ~100/page floor, 8000 pages covers ~800K users.
		# The old fixed >2000 guard tripped mid-fetch on a ~412K-user tenant. This
		# ceiling still catches a true runaway (e.g. a non-advancing @odata.nextLink).
		$maxPages = 8000
		# Inner try/catch around paging ONLY: on a throttling/network error or the
		# safety-abort throw, keep whatever pages were already collected and fall
		# through to flatten/enrich so a PARTIAL directory is still emitted. The
		# shortfall is flagged so the end-of-run summary and exit code report it
		# instead of masking it behind "Enterprise Export Complete".
		try {
			while ($nextLink) {
				$loops++
				$resp = Invoke-GraphRequest -Uri $nextLink -Method GET -ErrorAction Stop
				if ($resp.value) { $rawUsers.AddRange([object[]]$resp.value) }
				$nextLink = $resp.'@odata.nextLink'
				# Progress heartbeat: large tenants page for several minutes; emit a count
				# every 25 pages so the run is not mistaken for a hang.
				if (-not $Quiet -and ($loops % 25 -eq 0)) {
					Write-LogHost "  ... $($rawUsers.Count) users retrieved so far ($loops pages)" -ForegroundColor DarkGray
				}
				if ($loops -gt $maxPages) { throw "Safety abort: excessive paging (>$maxPages pages)" }
			}
		}
		catch {
			$script:EntraUsersFetchFailed = $true
			$script:EntraUsersFetchError = $_.Exception.Message
			Write-LogHost "WARNING: Entra user directory paging did not complete: $($_.Exception.Message)" -ForegroundColor Yellow
		}

		# If paging collected nothing there is no directory to emit: flag (if not
		# already) and return empty so the writers skip and the summary/exit report it.
		if ($rawUsers.Count -eq 0) {
			if (-not $script:EntraUsersFetchFailed) {
				$script:EntraUsersFetchFailed = $true
				$script:EntraUsersFetchError = 'Graph returned no users for the directory query.'
			}
			return $entraUsers
		}
		# Partial directory: some pages succeeded before a paging failure. Emit what we
		# have (schema-complete via the flatten/enrich below) but mark it partial.
		if ($script:EntraUsersFetchFailed) {
			$script:EntraUsersPartial = $true
			if (-not $Quiet) { Write-LogHost "         Emitting PARTIAL directory: $($rawUsers.Count) users collected before the failure." -ForegroundColor Yellow }
		}

		if (-not $Quiet) { Write-LogHost "  Retrieved $($rawUsers.Count) raw user objects" -ForegroundColor Gray }
		$flattened = ConvertTo-FlatEntraUsers -Users $rawUsers
		if (-not $Quiet) { Write-LogHost "  Flattened to $($flattened.Count) user rows (filtered)" -ForegroundColor Gray }

		# License enrichment (MAC-format columns)
		$licenseData = $script:LicenseData
		foreach ($u in $flattened) {
			$upn = $u.userPrincipalName
			$assignedNames = $null
			$hasCopilot = $false
			if ($licenseData) {
				# lookup by UPN then id for flexibility
				if ($licenseData.UserLicenses.ContainsKey($upn)) {
					$assignedNames = ($licenseData.UserLicenses[$upn] -join ';')
				} elseif ($licenseData.UserLicenses.ContainsKey($u.id)) {
					$assignedNames = ($licenseData.UserLicenses[$u.id] -join ';')
				}
				if ($licenseData.UserHasCopilot.ContainsKey($upn)) {
					$hasCopilot = [bool]$licenseData.UserHasCopilot[$upn]
				} elseif ($licenseData.UserHasCopilot.ContainsKey($u.id)) {
					$hasCopilot = [bool]$licenseData.UserHasCopilot[$u.id]
				}
			}
			Add-Member -InputObject $u -NotePropertyName 'assignedLicenses' -NotePropertyValue $assignedNames -Force
			Add-Member -InputObject $u -NotePropertyName 'hasLicense' -NotePropertyValue $hasCopilot -Force
		}
		$entraUsers = $flattened
		# Validate schema (non-fatal)
		try { Test-EntraUsersSchema -Users $entraUsers -Quiet:$Quiet } catch { }
	}
	catch {
		# Flatten/enrich (or any non-paging) failure. Flag it so the summary + exit
		# code report the shortfall; preserve an inner paging-error reason if one was
		# already captured.
		$script:EntraUsersFetchFailed = $true
		if (-not $script:EntraUsersFetchError) { $script:EntraUsersFetchError = $_.Exception.Message }
		Write-LogHost "WARNING: Failed to collect Entra user directory: $($_.Exception.Message)" -ForegroundColor Yellow
	}
	return $entraUsers
}

# ==============================================
# GRAPH API QUERY FUNCTIONS
# ==============================================
# REST-based audit log query functions for Microsoft Graph Security API

function Test-Is429 {
	<#
	.SYNOPSIS
		Safely detects 429 (Too Many Requests) throttling errors.
	
	.DESCRIPTION
		Provides null-safe detection of 429 throttling responses from Graph API.
		Handles PowerShell 7+ variations where .Response property may be null.
		
		Three-layer fallback strategy:
		1. Check .Response.StatusCode (when Response object exists)
		2. Check .Exception.Response.StatusCode directly (PS7+ pattern)
		3. Parse error message for '429' string (final fallback)
	
	.PARAMETER Exception
		The caught exception object from try/catch block
	
	.OUTPUTS
		$true if 429 throttling detected, $false otherwise
	
	.EXAMPLE
		try {
			Invoke-RestMethod -Uri $uri -Headers $headers
		}
		catch {
			if (Test-Is429 -Exception $_) {
				Start-Sleep -Seconds 60
			}
		}
	#>
	
	param(
		[Parameter(Mandatory = $true)]
		[System.Management.Automation.ErrorRecord]$Exception
	)
	
	# Layer 1: Check .Response.StatusCode (traditional method)
	if ($Exception.Exception.Response -and $Exception.Exception.Response.StatusCode) {
		if ($Exception.Exception.Response.StatusCode -eq 429 -or $Exception.Exception.Response.StatusCode -eq 'TooManyRequests') {
			return $true
		}
	}
	
	# Layer 2: Check .Exception.Response.StatusCode directly (PS7+ sometimes skips wrapper)
	if ($Exception.Exception.Response.StatusCode) {
		if ($Exception.Exception.Response.StatusCode.value__ -eq 429) {
			return $true
		}
	}
	
	# Layer 3: Parse error message as final fallback
	$errorMessage = $Exception.Exception.Message
	if ($errorMessage -match '429' -or $errorMessage -match 'Too Many Requests' -or $errorMessage -match 'TooManyRequests') {
		return $true
	}
	
	return $false
}

function Invoke-GraphAuditQuery {
	<#
	.SYNOPSIS
		Creates a new audit log query in Microsoft Graph Security API.
	
	.DESCRIPTION
		Submits an audit log query request to Microsoft Graph Security API.
		Returns a query ID that can be used to poll for status and retrieve results.
		
		The Graph API uses an asynchronous query model:
		1. Submit query (this function) - returns queryId
		2. Poll query status - wait for "succeeded" state
		3. Retrieve records - paginated results
	
	.PARAMETER DisplayName
		Friendly name for the query (for tracking purposes)
	
	.PARAMETER StartDate
		Start date/time for audit log query (ISO 8601 format)

	.PARAMETER EndDate
		End date/time for audit log query (ISO 8601 format)

	.PARAMETER Operations
		Array of operation types to query (e.g., 'CopilotInteraction')

	.PARAMETER RecordTypes
		Optional record type filters to include in the Graph query body (passthrough).

	.PARAMETER ServiceTypes
		Optional service/workload filters to include in the Graph query body (passthrough).
	
	.OUTPUTS
		Query ID string if successful, $null if failed
	#>
	
	param(
		[Parameter(Mandatory = $true)]
		[string]$DisplayName,
	
		[Parameter(Mandatory = $true)]
		[Alias('FilterStartDateTime')]
		[datetime]$StartDate,
	
		[Parameter(Mandatory = $true)]
		[Alias('FilterEndDateTime')]
		[datetime]$EndDate,
	
		[Parameter(Mandatory = $false)]
		[Alias('OperationFilters')]
		[string[]]$Operations,
	
		[Parameter(Mandatory = $false)]
		[Alias('RecordTypeFilters')]
		[string[]]$RecordTypes,
	
		[Parameter(Mandatory = $false)]
		[Alias('ServiceFilter')]
		[string[]]$ServiceTypes
	)
	
	try {
		# Format dates to ISO 8601 format required by Graph API
		$startDateStr = $StartDate.ToUniversalTime().ToString('yyyy-MM-ddTHH:mm:ss.fffZ', [System.Globalization.CultureInfo]::InvariantCulture)
		$endDateStr = $EndDate.ToUniversalTime().ToString('yyyy-MM-ddTHH:mm:ss.fffZ', [System.Globalization.CultureInfo]::InvariantCulture)
		
		# Build request body
		$body = @{
			displayName = $DisplayName
			filterStartDateTime = $startDateStr
			filterEndDateTime = $endDateStr
		}

		# Fail-safe sanitizer: If operations include M365 usage ops, drop record/service filters
		try {
			$usageOps = $script:m365UsageActivityBundle
			if (-not $usageOps) { $usageOps = $m365UsageActivityBundle }
			$hasUsageOps = $false
			if ($Operations -and $usageOps) {
				$opsLower = @($Operations | ForEach-Object { $_.ToLowerInvariant() })
				$usageLower = @($usageOps | ForEach-Object { $_.ToLowerInvariant() })
				$hasUsageOps = ($opsLower | Where-Object { $usageLower -contains $_ }) | Select-Object -First 1
			}
			if ($hasUsageOps) {
				$RecordTypes = $null
				$ServiceTypes = $null
			}
		} catch { }
		
		# Add operation filters if specified
		if ($Operations -and $Operations.Count -gt 0) {
			$body.operationFilters = @($Operations)
		}

		# Add optional record/service filters (passthrough from caller)
		if ($RecordTypes -and $RecordTypes.Count -gt 0) {
			$body.recordTypeFilters = @($RecordTypes)
		}

		if ($ServiceTypes -and $ServiceTypes.Count -gt 0) {
			$body.serviceFilter = $ServiceTypes[0]
		}
		
		# Log query details for troubleshooting (persisted to run log)
		Write-LogHost "[INFO] Graph API Query Body:" -ForegroundColor Magenta
		if ($Operations -and $Operations.Count -gt 0) {
			Write-LogHost "  operationFilters: $($Operations -join ', ')" -ForegroundColor DarkGray
		}
		if ($RecordTypes -and $RecordTypes.Count -gt 0) {
			Write-LogHost "  recordTypeFilters: $($RecordTypes -join ', ')" -ForegroundColor DarkGray
		}
		if ($ServiceTypes -and $ServiceTypes.Count -gt 0) {
			Write-LogHost "  serviceFilter: $($ServiceTypes[0])" -ForegroundColor DarkGray
		}
		$bodyJson = $body | ConvertTo-Json -Depth 10
		Write-LogHost $bodyJson -ForegroundColor DarkGray
		
		# Submit query via Graph API (auto-detects v1.0 or beta)
		$uri = Get-GraphAuditApiUri -Path 'queries'
		$response = Invoke-MgGraphRequest -Method POST -Uri $uri -Body $body -ErrorAction Stop
		
		if ($response -and $response.id) {
			return $response.id
		}
		else {
			Write-LogHost "WARNING: Graph API query submitted but no ID returned" -ForegroundColor Yellow
			return $null
		}
	}
	catch {
		Write-LogHost "ERROR: Failed to submit Graph audit query: $($_.Exception.Message)" -ForegroundColor Red
		try {
			if ($_.Exception.Response) {
				$respStream = $_.Exception.Response.GetResponseStream()
				if ($respStream) {
					$reader = New-Object System.IO.StreamReader($respStream)
					$body = $reader.ReadToEnd()
					$reader.Dispose()
					if ($body) { Write-LogHost "GRAPH response body: $body" -ForegroundColor DarkGray }
				}
			}
		} catch {}
		return $null
	}
}

function Get-GraphAuditQueryStatus {
	<#
	.SYNOPSIS
		Checks the status of a Graph API audit log query.
	
	.DESCRIPTION
		Polls the Microsoft Graph Security API to check query execution status.
		
		Possible status values:
		- notStarted: Query submitted but not yet processing
		- queued: Query waiting in backend queue for available execution slot
		- running: Query is executing
		- succeeded: Query completed successfully, records ready
		- failed: Query failed
		- cancelled: Query was cancelled
	
	.PARAMETER QueryId
		The query ID returned by Invoke-GraphAuditQuery
	
	.OUTPUTS
		Hashtable with status information: @{ Status='succeeded'; RecordCount=1234 }
		Returns $null if query check fails
	#>
	
	param(
		[Parameter(Mandatory = $true)]
		[string]$QueryId
	)
	
	try {
		$uri = Get-GraphAuditApiUri -Path "queries/$QueryId"
		$response = Invoke-MgGraphRequest -Method GET -Uri $uri -ErrorAction Stop
		
		$result = @{
			QueryId = $QueryId
			Status = $response.status
			RecordCount = 0
		}
		
		# Some status responses include record count
		if ($response.PSObject.Properties.Name -contains 'recordCount') {
			$result.RecordCount = $response.recordCount
		}
		
		return $result
	}
	catch {
		Write-LogHost "ERROR: Failed to get Graph query status: $($_.Exception.Message)" -ForegroundColor Red
		return $null
	}
}

function Get-GraphAuditRecords {
	<#
	.SYNOPSIS
		Retrieves audit log records from a completed Graph API query.
	
	.DESCRIPTION
		Fetches audit log records from Microsoft Graph Security API for a completed query.
		Handles pagination automatically using @odata.nextLink.
		
		Only call this function after confirming query status is "succeeded".
	
	.PARAMETER QueryId
		The query ID returned by Invoke-GraphAuditQuery
	
	.PARAMETER MaxRecords
		Maximum number of records to retrieve (default: unlimited)
	
	.OUTPUTS
		Array of audit log record objects, or empty array if none found
	#>
	
	param(
		[Parameter(Mandatory = $true)]
		[string]$QueryId,
		
		[Parameter(Mandatory = $false)]
		[int]$MaxRecords = 0
	)
	
	try {
		$allRecords = @()
		$uri = Get-GraphAuditApiUri -Path "queries/$QueryId/records"
		
		do {
			$response = Invoke-MgGraphRequest -Method GET -Uri $uri -ErrorAction Stop
			
			if ($response -and $response.value) {
				$allRecords += $response.value
				
				# Check if we've hit the max records limit
				if ($MaxRecords -gt 0 -and $allRecords.Count -ge $MaxRecords) {
					$allRecords = $allRecords | Select-Object -First $MaxRecords
					break
				}
			}
			
			# Check for pagination
			$uri = $response.'@odata.nextLink'
			
		} while ($uri)
		
		return $allRecords
	}
	catch {
		Write-LogHost "ERROR: Failed to retrieve Graph audit records: $($_.Exception.Message)" -ForegroundColor Red
		return @()
	}
}

# ==============================================
# DATA NORMALIZATION FUNCTION
# ==============================================
# Converts Graph API audit records to EOM-compatible schema

function ConvertFrom-GraphAuditRecord {
	<#
	.SYNOPSIS
		Normalizes Graph API audit records to match EOM cmdlet output schema.
	
	.DESCRIPTION
		Transforms Microsoft Graph Security API audit log records into the same
		structure as Search-UnifiedAuditLog cmdlet output. This ensures the
		existing explosion logic works identically regardless of data source.
		
		Graph API Schema → EOM Schema Mapping:
		- auditLogRecordType → RecordType
		- operation → Operations  
		- createdDateTime → CreationDate
		- auditData → AuditData (JSON string)
		- userPrincipalName → UserIds
		- id → Identity (unique record identifier)
	
	.PARAMETER GraphRecords
		Array of audit log records from Graph API (Get-GraphAuditRecords output)
	
	.OUTPUTS
		Array of normalized records matching EOM schema structure
	#>
	
	param(
		[Parameter(Mandatory = $true)]
		[AllowEmptyCollection()]
		[array]$GraphRecords
	)
	
	if (-not $GraphRecords -or $GraphRecords.Count -eq 0) {
		return @()
	}
	
	$normalized = @()
	
	foreach ($record in $GraphRecords) {
		try {
			# Create EOM-compatible object structure
			$eomRecord = [PSCustomObject]@{
				RecordType   = $null
				CreationDate = $null
				UserIds      = $null
				Operations   = $null
				AuditData    = '{}'
			}
			# Map: auditLogRecordType → RecordType
			if ($record.PSObject.Properties.Name -contains 'auditLogRecordType') {
				$eomRecord.RecordType = $record.auditLogRecordType
			}
			
			# Map: createdDateTime → CreationDate
			if ($record.PSObject.Properties.Name -contains 'createdDateTime') {
				try {
					$eomRecord.CreationDate = script:Parse-DateSafe $record.createdDateTime
				}
				catch {
					$eomRecord.CreationDate = $record.createdDateTime
				}
			}
			
			# Map: userPrincipalName → UserIds
			if ($record.PSObject.Properties.Name -contains 'userPrincipalName') {
				$eomRecord.UserIds = $record.userPrincipalName
			}
			
			# Map: operation → Operations
			if ($record.PSObject.Properties.Name -contains 'operation') {
				$eomRecord.Operations = $record.operation
			}
			
			# Map: id → Identity (unique identifier)
			if ($record.PSObject.Properties.Name -contains 'id') {
				$eomRecord.Identity = $record.id
			}
			
			# Map: auditData → AuditData (must be JSON string for explosion logic)
			# PERF: Also store _ParsedAuditData to avoid re-parsing during explosion
			if ($record.PSObject.Properties.Name -contains 'auditData') {
				$auditDataObj = $record.auditData
				
				# Store the already-parsed object for explosion optimization
				$eomRecord | Add-Member -NotePropertyName '_ParsedAuditData' -NotePropertyValue $auditDataObj -Force
				
				# If auditData is already an object, convert to JSON string
				if ($auditDataObj -is [string]) {
					$eomRecord.AuditData = $auditDataObj
					# String means it wasn't pre-parsed, clear _ParsedAuditData
					$eomRecord._ParsedAuditData = $null
				}
				else {
					# Convert object to JSON string (explosion logic expects string)
					try {
						$eomRecord.AuditData = ($auditDataObj | ConvertTo-Json -Depth 100 -Compress)
					}
					catch {
						Write-LogHost "WARNING: Failed to serialize auditData for record $($eomRecord.Identity)" -ForegroundColor Yellow
						$eomRecord.AuditData = '{}'
						$eomRecord._ParsedAuditData = $null
					}
				}
			}
			else {
				# No auditData present - create minimal valid JSON
				$eomRecord.AuditData = '{}'
			}
			
			$normalized += $eomRecord
		}
		catch {
			Write-LogHost "WARNING: Failed to normalize Graph record: $($_.Exception.Message)" -ForegroundColor Yellow
			# Continue processing remaining records
		}
	}
	
	return $normalized
}

# =============================================================================
# MICROSOFT AGENT 365 ENRICHMENT FUNCTIONS
# =============================================================================
# Self-contained section. All functions are no-ops unless -IncludeAgent365Info
# or -OnlyAgent365Info is set. Reuses existing Graph SDK plumbing
# (Invoke-MgGraphRequest, Connect-MgGraph, token-refresh helpers, retry helpers).
# Output schema must exactly match temp/Synthetic_Agent365_May2026.csv (28 cols).
# Empty cells are intentional when the API does not return a value (no fabrication).
# Reference: https://learn.microsoft.com/en-us/microsoft-agent-365/admin/graph-api
# =============================================================================

# Module-scope caches populated during the Agent 365 phase.
$script:Agent365FrontierAvailable = $null   # $true / $false / $null = untested
$script:Agent365DeveloperCache    = @{}     # appId/displayName -> resolved name
$script:Agent365AuditEnrichment   = @{}     # titleId/appId      -> @{ Created=...; CreatedBy=... }
$script:Agent365InteractiveCtx    = $false  # set $true after secondary interactive sign-in (AppReg path)
$script:Agent365PreAuthCompleted  = $false  # set $true after eager up-front Agent 365 sign-in (AppReg + Agent365 combo)

function Get-Agent365PackagesUri {
	param([Parameter(Mandatory = $false)][string]$PackageId = '')
	# Microsoft Agent 365 / Copilot package management API is currently published at /beta only.
	# When/if the endpoint is also published at /v1.0, switch this constant.
	$base = 'https://graph.microsoft.com/beta/copilot/admin/catalog/packages'
	if ([string]::IsNullOrWhiteSpace($PackageId)) { return $base }
	return ($base + '/' + [System.Uri]::EscapeDataString($PackageId))
}

function Connect-Agent365InteractiveContext {
	<#
	.SYNOPSIS
		Establishes (or restores) a delegated Microsoft Graph context for the Agent 365 phase
		when -Auth AppRegistration is in use (which cannot satisfy the Agent Package
		Management API's user-bound role requirement).

		Idempotent: safe to call multiple times. After Invoke-Agent365EarlyInteractiveSignIn
		has run once at startup, subsequent calls re-issue Connect-MgGraph -Scopes which
		normally completes silently from MSAL token cache (no second prompt).
	#>
	if ($Auth -ne 'AppRegistration') { return $true }   # all other modes already have the right scopes

	$agent365Scopes = @('CopilotPackages.Read.All', 'Application.Read.All')

	if ($script:Agent365PreAuthCompleted) {
		# Token already acquired earlier in this run; restore the delegated context silently.
		Write-LogHost ""
		Write-LogHost "  Restoring Agent 365 interactive context (using cached credentials from earlier sign-in)..." -ForegroundColor Cyan
	} else {
		Write-LogHost ""
		Write-LogHost "=== Phase 2: Agent 365 - Interactive sign-in ===" -ForegroundColor Cyan
		Write-LogHost "  Reason: Agent 365 endpoint has no app-only Graph scope." -ForegroundColor Gray
		Write-LogHost "  Requesting DELEGATED scopes:" -ForegroundColor White
		Write-LogHost ("    [Delegated] {0}" -f ($agent365Scopes -join ', ')) -ForegroundColor Yellow
		Write-LogHost "  Required Entra role on signed-in user:" -ForegroundColor White
		Write-LogHost "    [Role]      AI Administrator  -OR-  Global Administrator" -ForegroundColor Yellow
		Write-LogHost "  (Without the role, Graph returns 403 even after consent.)" -ForegroundColor Gray
		Write-LogHost ""
	}
	try {
		# Connect-MgGraph with new -Scopes establishes a delegated context layered
		# on top of the existing AppReg context; no manual disconnect needed.
		Connect-MgGraph -Scopes $agent365Scopes -NoWelcome -ErrorAction Stop
		$script:Agent365InteractiveCtx = $true
		if ($script:Agent365PreAuthCompleted) {
			Write-LogHost "  Interactive context restored (no prompt needed)." -ForegroundColor Green
		} else {
			Write-LogHost "  Interactive context established." -ForegroundColor Green
			# Dual-context runs deferred the Phase 1 Tenant/Account/Scopes display so we can
			# emit BOTH phases together now that Phase 2 (delegated) is also live.
			if ($script:DeferAuthContextDisplay -and $script:Phase1Context) {
				try {
					$delegCtx = Get-MgContext
					Write-LogHost ""
					Write-LogHost "  Effective auth context (dual-mode):" -ForegroundColor White
					Write-LogHost "    Phase 1 (Audit / EntraUsers / M365) - APP-ONLY (AppRegistration):" -ForegroundColor Gray
					Write-LogHost "      Tenant ID: $($script:Phase1Context.TenantId)" -ForegroundColor Gray
					Write-LogHost "      Account:   (app-only / AppRegistration - no interactive user)" -ForegroundColor Gray
					Write-LogHost "      Scopes:    $($script:Phase1Context.GrantedRequired -join ', ')" -ForegroundColor Gray
					Write-LogHost "    Phase 2 (Agent 365 catalog) - DELEGATED (interactive sign-in):" -ForegroundColor Gray
					if ($delegCtx) {
						Write-LogHost "      Tenant ID: $($delegCtx.TenantId)" -ForegroundColor Gray
						$delegAcct = Get-MaskedUsername -Username $delegCtx.Account
						if ([string]::IsNullOrWhiteSpace($delegAcct)) { $delegAcct = '(unknown)' }
						Write-LogHost "      Account:   $delegAcct" -ForegroundColor Gray
						$delegGranted = @($agent365Scopes | Where-Object { $delegCtx.Scopes -contains $_ })
						Write-LogHost "      Scopes:    $($delegGranted -join ', ')" -ForegroundColor Gray
					} else {
						Write-LogHost "      (delegated context not retrievable)" -ForegroundColor Gray
					}
					Write-LogHost ""
					$script:DeferAuthContextDisplay = $false
				} catch { }
			}
		}
		return $true
	} catch {
		Write-LogHost ("  ERROR: Interactive sign-in for Agent 365 failed: {0}" -f $_.Exception.Message) -ForegroundColor Red
		return $false
	}
}

function Invoke-Agent365EarlyInteractiveSignIn {
	<#
	.SYNOPSIS
		Eager up-front interactive sign-in for the Agent 365 phase.

	.DESCRIPTION
		When -Auth AppRegistration is combined with -IncludeAgent365Info, the Agent 365
		phase requires a separate DELEGATED user sign-in (no app-only scope exists).
		Without this helper, the user would only see the interactive prompt AFTER the
		audit phase finishes - which can be hours into the run on large tenants.

		This function performs the interactive prompt immediately after the Phase 1
		AppReg connection is established, then probes the Agent 365 endpoint to validate
		tenant enrollment + caller role, then restores the AppReg context for Phase 1.
		The MSAL token cache lets the deferred Phase 2 re-Connect happen silently.

	.OUTPUTS
		$true  - early sign-in succeeded (or not applicable for this run)
		$false - early sign-in failed; caller should treat Agent 365 phase as unavailable
	#>
	if ($Auth -ne 'AppRegistration') { return $true }
	if (-not ($IncludeAgent365Info -or $OnlyAgent365Info)) { return $true }
	if ($script:Agent365PreAuthCompleted) { return $true }

	Write-LogHost ""
	Write-LogHost "+----------------------------------------------------------------------+" -ForegroundColor Cyan
	Write-LogHost "|  Eager Agent 365 sign-in (Phase 2 prompt up-front)                   |" -ForegroundColor Cyan
	Write-LogHost "+----------------------------------------------------------------------+" -ForegroundColor Cyan
	Write-LogHost "|  Prompting NOW so you do not have to babysit the run. After you      |" -ForegroundColor Cyan
	Write-LogHost "|  sign in, Phase 1 (audit, app-only) starts and runs unattended.      |" -ForegroundColor Cyan
	Write-LogHost "|  Phase 2 (Agent 365) reuses the cached delegated token at end of run.|" -ForegroundColor Cyan
	Write-LogHost "+----------------------------------------------------------------------+" -ForegroundColor Cyan

	# Step 1: prompt for delegated credentials and switch to interactive context.
	if (-not (Connect-Agent365InteractiveContext)) {
		Write-LogHost "  Eager Agent 365 sign-in failed; the Agent 365 phase will be skipped at end of run." -ForegroundColor Red
		$script:Agent365FrontierAvailable = $false
		return $false
	}

	# Step 2: probe the Frontier endpoint while the interactive context is active.
	#         This validates tenant enrollment + AI Admin/Global Admin role NOW,
	#         instead of after a long audit run.
	Write-LogHost "  Validating Agent 365 endpoint access (Frontier program + role)..." -ForegroundColor Gray
	$frontierOk = Test-Agent365FrontierAccess
	if (-not $frontierOk) {
		Write-LogHost "  Agent 365 endpoint is not accessible from this tenant/user." -ForegroundColor Yellow
		Write-LogHost "  The Agent 365 phase will be skipped, but the run will continue with audit data." -ForegroundColor Yellow
		# leave $script:Agent365FrontierAvailable = $false so Invoke-Agent365Phase short-circuits
	}

	# Step 3: mark pre-auth complete BEFORE swapping back, so Phase 2 knows to use
	#         abbreviated messaging when it re-establishes the delegated context.
	$script:Agent365PreAuthCompleted = $true

	# Step 4: restore the AppReg (app-only) context for Phase 1 audit work.
	#         CRITICAL: do NOT use Invoke-TokenRefresh here - it calls Disconnect-MgGraph
	#         first, which wipes the in-memory MSAL cache for the delegated context we
	#         just established. That would force a SECOND interactive prompt at end of run.
	#         Instead, call Connect-MgGraph directly for the AppReg credentials; the SDK
	#         replaces the active context in place and the delegated MSAL cache survives.
	Write-LogHost "  Restoring app-only context for Phase 1 (audit)..." -ForegroundColor Gray
	$restored = $false
	try {
		if ($script:AuthConfig.ClientSecret) {
			$cred = New-Object System.Management.Automation.PSCredential($script:AuthConfig.ClientId, $script:AuthConfig.ClientSecret)
			Connect-MgGraph -TenantId $script:AuthConfig.TenantId -ClientSecretCredential $cred -NoWelcome -ErrorAction Stop
			$restored = $true
		} elseif ($script:AuthConfig.CertObject) {
			Connect-MgGraph -TenantId $script:AuthConfig.TenantId -ClientId $script:AuthConfig.ClientId -Certificate $script:AuthConfig.CertObject -NoWelcome -ErrorAction Stop
			$restored = $true
		} elseif ($script:AuthConfig.CertThumbprint) {
			Connect-MgGraph -TenantId $script:AuthConfig.TenantId -ClientId $script:AuthConfig.ClientId -CertificateThumbprint $script:AuthConfig.CertThumbprint -NoWelcome -ErrorAction Stop
			$restored = $true
		}
	} catch {
		Write-LogHost ("  ERROR: Could not restore app-only context after Agent 365 sign-in: {0}" -f $_.Exception.Message) -ForegroundColor Red
	}
	if (-not $restored) {
		Write-LogHost "  ERROR: No AppRegistration credentials available to restore Phase 1 context." -ForegroundColor Red
		throw "Failed to restore AppRegistration context after early Agent 365 sign-in."
	}
	# Refresh the shared token state so Phase 1 thread jobs use the new app-only token.
	$tokenInfo = Get-GraphAccessTokenWithExpiry
	if ($tokenInfo) {
		$script:SharedAuthState.Token = $tokenInfo.Token
		$script:SharedAuthState.ExpiresOn = $tokenInfo.ExpiresOn
		$script:SharedAuthState.LastRefresh = Get-Date
		$script:AuthConfig.TokenIssueTime = Get-Date
	}
	Write-LogHost "  App-only context restored. Phase 1 will run unattended." -ForegroundColor Green
	Write-LogHost ""
	return $true
}

function Test-Agent365FrontierAccess {
	<#
	.SYNOPSIS
		Probes the Agent Package Management API with a minimal GET to confirm
		tenant enrollment in the Frontier program and adequate caller role.
	.OUTPUTS
		$true  - access confirmed; agent phase may proceed
		$false - access denied (403/404 or unsupported); banner 7d printed; phase skipped
	#>
	if ($null -ne $script:Agent365FrontierAvailable) { return $script:Agent365FrontierAvailable }

	$uri = (Get-Agent365PackagesUri) + '?$top=1'
	try {
		$null = Invoke-MgGraphRequest -Method GET -Uri $uri -ErrorAction Stop
		$script:Agent365FrontierAvailable = $true
		return $true
	} catch {
		$status = $null
		try { if ($_.Exception.Response) { $status = [int]$_.Exception.Response.StatusCode } } catch {}
		if ($status -in @(401,403,404)) {
			Write-LogHost "" 
			Write-LogHost "+----------------------------------------------------------------------+" -ForegroundColor Yellow
			Write-LogHost "|  Microsoft Agent 365 - Tenant not enrolled in Frontier program       |" -ForegroundColor Yellow
			Write-LogHost "+----------------------------------------------------------------------+" -ForegroundColor Yellow
			Write-LogHost ("|  The Agent Package Management API returned HTTP {0,-3}, indicating     |" -f $status) -ForegroundColor Yellow
			Write-LogHost "|  this tenant is not enrolled in the Microsoft Agent 365 Frontier    |" -ForegroundColor Yellow
			Write-LogHost "|  program (or the signed-in user lacks AI Admin / Global Admin role). |" -ForegroundColor Yellow
			Write-LogHost "|  The Agent 365 CSV will be skipped for this run.                    |" -ForegroundColor Yellow
			Write-LogHost "|                                                                      |" -ForegroundColor Yellow
			Write-LogHost "|  Reference:                                                          |" -ForegroundColor Yellow
			Write-LogHost "|  https://learn.microsoft.com/en-us/microsoft-agent-365/admin/graph-api|" -ForegroundColor Yellow
			Write-LogHost "+----------------------------------------------------------------------+" -ForegroundColor Yellow
			Write-LogHost ""
		} else {
			Write-LogHost ("  Agent 365 probe failed (HTTP {0}): {1}" -f ($status, $_.Exception.Message)) -ForegroundColor Red
		}
		$script:Agent365FrontierAvailable = $false
		return $false
	}
}

function Get-Agent365Packages {
	<#
	.SYNOPSIS
		Returns all Agent 365 catalog packages (list view) with paging.
	#>
	$results = New-Object System.Collections.Generic.List[object]
	$uri = Get-Agent365PackagesUri
	$pageNum = 0
	while ($uri) {
		$pageNum++
		try {
			Refresh-GraphTokenIfNeeded -ErrorAction SilentlyContinue
		} catch {}
		try {
			$resp = Invoke-MgGraphRequest -Method GET -Uri $uri -ErrorAction Stop
		} catch {
			Write-LogHost ("  WARNING: Agent 365 list page {0} failed: {1}" -f $pageNum, $_.Exception.Message) -ForegroundColor Yellow
			break
		}
		if ($resp -and $resp.value) {
			foreach ($p in $resp.value) { [void]$results.Add($p) }
		}
		$uri = $resp.'@odata.nextLink'
		if ($pageNum -gt 500) {
			Write-LogHost "  WARNING: Agent 365 paging safety abort (>500 pages)" -ForegroundColor Yellow
			break
		}
	}
	return $results.ToArray()
}

function Get-Agent365PackageDetail {
	<#
	.SYNOPSIS
		Returns the full detail object for a single agent package, including elementDetails.
	#>
	param([Parameter(Mandatory = $true)][string]$PackageId)
	$uri = Get-Agent365PackagesUri -PackageId $PackageId
	try {
		Refresh-GraphTokenIfNeeded -ErrorAction SilentlyContinue
	} catch {}
	try {
		return Invoke-MgGraphRequest -Method GET -Uri $uri -ErrorAction Stop
	} catch {
		Write-LogHost ("  WARNING: Agent 365 detail fetch failed for '{0}': {1}" -f $PackageId, $_.Exception.Message) -ForegroundColor Yellow
		return $null
	}
}

function Resolve-Agent365DeveloperName {
	<#
	.SYNOPSIS
		Resolves a developer/publisher name. Tries package's developer.name first,
		falls back to /applications + /owners lookup keyed on appId. Cached.
	#>
	param(
		[Parameter(Mandatory = $false)][string]$DeveloperName,
		[Parameter(Mandatory = $false)][string]$AppId
	)
	if ($DeveloperName) { return $DeveloperName }
	if (-not $AppId) { return '' }
	if ($script:Agent365DeveloperCache.ContainsKey($AppId)) {
		return $script:Agent365DeveloperCache[$AppId]
	}
	$resolved = ''
	try {
		$appUri = "https://graph.microsoft.com/v1.0/applications?`$filter=appId eq '$AppId'&`$select=id,displayName,publisherDomain"
		$appResp = Invoke-MgGraphRequest -Method GET -Uri $appUri -ErrorAction Stop
		if ($appResp -and $appResp.value -and $appResp.value.Count -gt 0) {
			$app = $appResp.value[0]
			if ($app.publisherDomain) { $resolved = $app.publisherDomain }
			elseif ($app.displayName) { $resolved = $app.displayName }
			# Optional owner lookup (first owner UPN) only if still blank
			if (-not $resolved -and $app.id) {
				try {
					$ownerUri = "https://graph.microsoft.com/v1.0/applications/$($app.id)/owners?`$select=userPrincipalName,displayName"
					$ownerResp = Invoke-MgGraphRequest -Method GET -Uri $ownerUri -ErrorAction Stop
					if ($ownerResp -and $ownerResp.value -and $ownerResp.value.Count -gt 0) {
						$resolved = $ownerResp.value[0].displayName
						if (-not $resolved) { $resolved = $ownerResp.value[0].userPrincipalName }
					}
				} catch { }
			}
		}
	} catch {
		# Application.Read.All may not be granted; degrade gracefully (no fabrication).
	}
	$script:Agent365DeveloperCache[$AppId] = $resolved
	return $resolved
}

function Get-Agent365AuditEnrichment {
	<#
	.SYNOPSIS
		Runs a single narrow Graph audit query to retrieve agent create/publish events
		and returns a hashtable keyed on agent id (titleId/appId/lower-cased displayName)
		with @{ Created = [datetime]; CreatedBy = [string] }. Skipped when -OnlyAgent365Info.
	.NOTES
		Best-effort enrichment. If the audit query fails or returns no records, both
		fields stay blank in the output (no fabrication).
	#>
	$enrichment = @{}
	if ($OnlyAgent365Info) { return $enrichment }
	if (-not $script:GraphConnected -and -not (Get-MgContext -ErrorAction SilentlyContinue)) { return $enrichment }

	# Resolve time window: prefer main-run StartDate/EndDate; else last 30 days.
	$rangeStart = $null; $rangeEnd = $null
	try {
		if ($StartDate) { $rangeStart = [datetime]::ParseExact($StartDate, 'yyyy-MM-dd', [System.Globalization.CultureInfo]::InvariantCulture) }
		if ($EndDate)   { $rangeEnd   = [datetime]::ParseExact($EndDate,   'yyyy-MM-dd', [System.Globalization.CultureInfo]::InvariantCulture) }
	} catch {}
	if (-not $rangeStart) { $rangeStart = (Get-Date).ToUniversalTime().AddDays(-30) }
	if (-not $rangeEnd)   { $rangeEnd   = (Get-Date).ToUniversalTime() }

	# Operation set covering agent/app create/publish/install. Conservative; missing
	# operations simply mean blank columns for affected agents.
	$ops = @(
		'AppCatalogPublishedAppCreated',
		'AppCatalogPublishedAppUpdated',
		'AgentCreated',
		'AgentPublished',
		'CopilotAgentInstalled'
	)

	Write-LogHost "  Running narrow audit query for Agent 365 enrichment (Date created / Created by)..." -ForegroundColor DarkGray
	$queryId = $null
	try {
		$queryId = Invoke-GraphAuditQuery `
			-DisplayName ("PAX_Agents365_Enrichment_{0}" -f (Get-Date -Format 'yyyyMMddHHmmss')) `
			-StartDate $rangeStart `
			-EndDate $rangeEnd `
			-Operations $ops
	} catch {
		Write-LogHost ("  WARNING: Agent 365 enrichment query submit failed: {0}" -f $_.Exception.Message) -ForegroundColor Yellow
		return $enrichment
	}
	if (-not $queryId) {
		Write-LogHost "  WARNING: Agent 365 enrichment query did not return a query id; columns will be blank." -ForegroundColor Yellow
		return $enrichment
	}

	# Poll for query completion. Fortune-500 tenants routinely take 30-90 minutes
	# for audit queries even on narrow operation/time filters. Use the same
	# tolerance window the main audit phase uses (-MaxNetworkOutageMinutes is for
	# transport errors only; query-completion timeout is a separate, longer cap).
	# 4 hours is the documented Graph audit query SLA upper bound.
	$pollTimeoutMinutes = 240
	$pollDeadline = (Get-Date).AddMinutes($pollTimeoutMinutes)
	$pollIntervalSeconds = 15
	$lastLoggedMinute = -1
	$status = $null
	Write-LogHost ("  Polling enrichment query (timeout {0} min, refresh-token aware)..." -f $pollTimeoutMinutes) -ForegroundColor DarkGray
	while ((Get-Date) -lt $pollDeadline) {
		Start-Sleep -Seconds $pollIntervalSeconds
		try { Refresh-GraphTokenIfNeeded -ErrorAction SilentlyContinue } catch {}
		try { $status = Get-GraphAuditQueryStatus -QueryId $queryId } catch { $status = $null }
		if ($status -and $status.Status -in @('succeeded','failed','cancelled')) { break }
		# Heartbeat once per minute to keep long polls visible in logs.
		$elapsedMin = [int]((Get-Date) - $pollDeadline.AddMinutes(-$pollTimeoutMinutes)).TotalMinutes
		if ($elapsedMin -ne $lastLoggedMinute -and ($elapsedMin % 5) -eq 0) {
			$lastLoggedMinute = $elapsedMin
			$st = if ($status -and $status.Status) { $status.Status } else { 'pending' }
			Write-LogHost ("    ... {0} min elapsed, status={1}" -f $elapsedMin, $st) -ForegroundColor DarkGray
		}
		# Gentle backoff: 15s -> 30s -> 60s after 2 and 10 minutes respectively.
		if ($elapsedMin -ge 10 -and $pollIntervalSeconds -lt 60) { $pollIntervalSeconds = 60 }
		elseif ($elapsedMin -ge 2 -and $pollIntervalSeconds -lt 30) { $pollIntervalSeconds = 30 }
	}
	if (-not $status -or $status.Status -ne 'succeeded') {
		Write-LogHost ("  WARNING: Agent 365 enrichment query did not succeed (status={0}); columns will be blank." -f ($status.Status)) -ForegroundColor Yellow
		return $enrichment
	}

	$records = @()
	try { $records = Get-GraphAuditRecords -QueryId $queryId } catch { $records = @() }
	if (-not $records -or $records.Count -eq 0) { return $enrichment }

	foreach ($rec in $records) {
		try {
			$auditObj = $null
			if ($rec.PSObject.Properties.Name -contains 'auditData') { $auditObj = $rec.auditData }
			if ($auditObj -is [string]) { try { $auditObj = $auditObj | ConvertFrom-Json -ErrorAction Stop } catch { $auditObj = $null } }
			$created = $null
			if ($rec.PSObject.Properties.Name -contains 'createdDateTime' -and $rec.createdDateTime) {
				try { $created = [datetime]$rec.createdDateTime } catch {}
			}
			$createdBy = $null
			if ($rec.PSObject.Properties.Name -contains 'userPrincipalName' -and $rec.userPrincipalName) {
				$createdBy = [string]$rec.userPrincipalName
			}
			# Pull keys from auditData defensively (preview schema may shift).
			$keys = New-Object System.Collections.Generic.List[string]
			if ($auditObj) {
				foreach ($p in 'TitleId','titleId','AppId','appId','PackageId','packageId','TeamsAppId','teamsAppId','DisplayName','displayName','Name','name') {
					try { if ($auditObj.$p) { [void]$keys.Add(([string]$auditObj.$p).ToLowerInvariant()) } } catch {}
				}
			}
			foreach ($k in $keys) {
				if (-not $enrichment.ContainsKey($k)) {
					$enrichment[$k] = @{ Created = $created; CreatedBy = $createdBy }
				}
			}
		} catch { continue }
	}
	Write-LogHost ("  Audit enrichment matched {0} agent identifier key(s)." -f $enrichment.Keys.Count) -ForegroundColor DarkGray
	return $enrichment
}

function ConvertTo-Agent365Row {
	<#
	.SYNOPSIS
		Maps one package detail object to the exact 28-column synthetic schema.
		Empty cells stay empty when fields are absent (no fabrication).
	#>
	param(
		[Parameter(Mandatory = $true)][object]$Package,
		[Parameter(Mandatory = $false)][hashtable]$AuditEnrichment
	)
	function _g { param($obj, [string[]]$names) foreach ($n in $names) { try { if ($null -ne $obj.$n -and "$($obj.$n)" -ne '') { return $obj.$n } } catch {} } return '' }
	function _gb { param($obj, [string[]]$names) foreach ($n in $names) { try { if ($null -ne $obj.$n) { return [bool]$obj.$n } } catch {} } return '' }
	function _join { param($v, [string]$sep) if ($null -eq $v) { return '' }; if ($v -is [System.Collections.IEnumerable] -and -not ($v -is [string])) { return (@($v) -join $sep) } else { return [string]$v } }
	function _fmtDate { param($v) if (-not $v) { return '' }; try { return ([datetime]$v).ToUniversalTime().ToString('yyyy-MM-dd HH:mm:ssZ') } catch { return [string]$v } }

	$elem = $null
	try { $elem = $Package.elementDetails } catch {}

	$titleIdRaw = (_g $Package @('id','titleId','packageId'))
	$titleId = ''
	if ($titleIdRaw) { $titleId = if ($titleIdRaw -match '^T_') { [string]$titleIdRaw } else { 'T_' + [string]$titleIdRaw } }

	# Audit enrichment lookup (lowercase keys). Try titleId raw, appId, displayName.
	$dateCreated = ''
	$createdBy   = ''
	if ($AuditEnrichment) {
		$probeKeys = @()
		if ($titleIdRaw) { $probeKeys += ([string]$titleIdRaw).ToLowerInvariant() }
		$appIdProbe = (_g $Package @('appId','applicationId'))
		if ($appIdProbe) { $probeKeys += ([string]$appIdProbe).ToLowerInvariant() }
		$dispProbe = (_g $Package @('displayName','name'))
		if ($dispProbe) { $probeKeys += ([string]$dispProbe).ToLowerInvariant() }
		foreach ($k in $probeKeys) {
			if ($AuditEnrichment.ContainsKey($k)) {
				$hit = $AuditEnrichment[$k]
				if ($hit.Created)   { $dateCreated = (_fmtDate $hit.Created) }
				if ($hit.CreatedBy) { $createdBy   = [string]$hit.CreatedBy }
				break
			}
		}
	}
	# Fallback to package's own createdDateTime if audit didn't supply one
	if (-not $dateCreated) {
		$pkgCreated = (_g $Package @('createdDateTime','createdDate'))
		if ($pkgCreated) { $dateCreated = (_fmtDate $pkgCreated) }
	}

	$developer = Resolve-Agent365DeveloperName -DeveloperName (_g $Package @('developer.name')) -AppId (_g $Package @('appId','applicationId'))
	# fallback: try direct nested object access
	if (-not $developer) {
		try { if ($Package.developer -and $Package.developer.name) { $developer = [string]$Package.developer.name } } catch {}
	}

	[PSCustomObject][ordered]@{
		'Name'                                  = (_g $Package @('displayName','name'))
		'Supported in'                          = (_join (_g $Package @('supportedHosts','supportedClients')) ';')
		'Date created'                          = $dateCreated
		'Developer Name'                        = $developer
		'Type'                                  = (_g $Package @('agentType','type'))
		'Version'                               = (_g $Package @('version'))
		'Availability'                          = (_g $Package @('availability','allowedUsersAndGroups'))
		'Created by'                            = $createdBy
		'Description'                           = (_g $Package @('description'))
		'Created in'                            = (_g $Package @('source','origin','createdIn'))
		'Last updated'                          = (_fmtDate (_g $Package @('lastModifiedDateTime','lastUpdatedDateTime')))
		'Custom actions'                        = (_g $elem @('customActions'))
		'Title ID'                              = $titleId
		'Sensitivity'                           = (_g $Package @('sensitivity'))
		'Can read OneDrive and Sharepoint items'= (_gb $elem @('canReadOneDriveAndSharepointItems'))
		'OneDrive and Sharepoint items'         = (_g $elem @('oneDriveAndSharepointItems'))
		'Can read OneDrive files'               = (_gb $elem @('canReadOneDriveFiles'))
		'OneDrive files'                        = (_g $elem @('oneDriveFiles'))
		'OneDrive sites'                        = (_g $elem @('oneDriveSites'))
		'Can read Sharepoint sites and files'   = (_gb $elem @('canReadSharepointSitesAndFiles'))
		'Sharepoint files'                      = (_g $elem @('sharepointFiles'))
		'Sharepoint sites'                      = (_g $elem @('sharepointSites'))
		'Can extend to Graph connector'         = (_gb $elem @('canExtendToGraphConnector'))
		'Graph connector details'               = (_g $elem @('graphConnectorDetails'))
		'Can generate images using user prompt' = (_gb $elem @('canGenerateImagesUsingUserPrompt'))
		'Can use code interpreter'              = (_gb $elem @('canUseCodeInterpreter'))
		'Contains uploaded files'               = (_gb $elem @('containsUploadedFiles'))
		'Uploaded files'                        = (_g $elem @('uploadedFiles'))
	}
}

function Export-Agent365Csv {
	<#
	.SYNOPSIS
		Writes the Agent 365 CSV (UTF-8 BOM) to OutputPath using the run timestamp.
	.DESCRIPTION
		When -AppendAgent365Info <target.csv> is in effect, this function pre-reads the
		target CSV and union-merges its rows with the current API-derived rows: the
		current run's row wins on AgentId conflicts (freshest metadata) and any
		target-only AgentId is carried forward (departed agents are not dropped).
	.OUTPUTS
		Full path to written file, or $null if no rows.
	#>
	param(
		[Parameter(Mandatory = $true)][AllowEmptyCollection()][object[]]$Rows
	)
	if (-not $Rows -or $Rows.Count -eq 0) {
		Write-LogHost "  Agent 365: no rows to write." -ForegroundColor Yellow
		return $null
	}

	# Union-merge with -AppendAgent365Info target when set. Failures here are
	# non-fatal — fall back to current-run rows only.
	$rowsToWrite = [System.Collections.Generic.List[object]]::new()
	foreach ($r in $Rows) { [void]$rowsToWrite.Add($r) }
	if ($AppendAgent365Info -and (Test-Path -LiteralPath $AppendAgent365Info -PathType Leaf)) {
		try {
			$currentAgentIds = New-Object System.Collections.Generic.HashSet[string]
			foreach ($r in $Rows) {
				$aid = $null
				try { $aid = [string]$r.AgentId } catch {}
				if ($aid) { [void]$currentAgentIds.Add($aid) }
			}
			$targetRows = @(Import-Csv -LiteralPath $AppendAgent365Info -Encoding UTF8)
			$carried = 0
			foreach ($tr in $targetRows) {
				$aid = $null
				try { $aid = [string]$tr.AgentId } catch {}
				if (-not $aid) { continue }
				if (-not $currentAgentIds.Contains($aid)) {
					[void]$rowsToWrite.Add($tr)
					$carried++
				}
			}
			Write-LogHost ("  -AppendAgent365Info: carried {0:N0} departed agent(s) from '{1}'; current run contributed {2:N0}." -f $carried, $AppendAgent365Info, $Rows.Count) -ForegroundColor DarkCyan
		}
		catch {
			Write-LogHost ("  WARNING: -AppendAgent365Info merge failed ({0}); writing current-run rows only." -f $_.Exception.Message) -ForegroundColor Yellow
		}
	}

	$ts = $global:ScriptRunTimestamp
	if (-not $ts) { $ts = (Get-Date).ToString('yyyyMMdd_HHmmss') }
	# Per-data-type destination. If -OutputPathAgent365Info resolves to a Local
	# folder or file form, route the catalog there; otherwise inherit $OutputPath. Remote
	# tiers (SharePoint/Fabric) continue to write to the scratch dir and upload from there.
	$agentOutDir = $OutputPath
	# Effective basename (honors -AppendAgent365Info target leaf so the merged file
	# produced this run can be uploaded back over the original remote URL \u2014 matched
	# by the upload sweep's Append-leaf filter).
	$agentBasename = (& $script:GetEffectiveAgent365Basename)
	try {
		$dt = script:Resolve-DataTypePaths -DataType 'Agent365Info' -DefaultBasename $agentBasename
		if ($dt -and $dt.IsBound -and $dt.Tier -eq 'Local') {
			$agentOutDir = $dt.EffectiveDir
			if ($dt.Basename) { $agentBasename = $dt.Basename }
			if (-not (Test-Path -LiteralPath $agentOutDir -PathType Container)) {
				New-Item -Path $agentOutDir -ItemType Directory -Force | Out-Null
			}
		}
	} catch {}
	$outFile = Join-Path $agentOutDir $agentBasename
	try {
		# Atomic write — Save-CsvAtomic uses temp+rename so a Ctrl+C / OOM-kill mid-write
		# cannot leave a half-formed Agent365 CSV in the operator's output folder.
		Save-CsvAtomic -InputObject ($rowsToWrite.ToArray()) -Path $outFile -NoTypeInformation -Encoding UTF8
		Write-LogHost ("  Agent 365 CSV written: {0} ({1} rows)" -f (Get-DisplayPath -LocalPath $outFile), $rowsToWrite.Count) -ForegroundColor Green
		return $outFile
	} catch {
		Write-LogHost ("  ERROR: Failed to write Agent 365 CSV: {0}" -f $_.Exception.Message) -ForegroundColor Red
		return $null
	}
}

function Add-Agent365WorkbookTab {
	<#
	.SYNOPSIS
		Appends an 'Agents365' worksheet to the existing workbook (after EntraUsers tab).
		No-op when -ExportWorkbook is not set or ImportExcel is unavailable.
	#>
	param(
		[Parameter(Mandatory = $true)][string]$WorkbookPath,
		[Parameter(Mandatory = $true)][AllowEmptyCollection()][object[]]$Rows
	)
	if (-not $ExportWorkbook) { return }
	if (-not $Rows -or $Rows.Count -eq 0) { return }
	if (-not (Get-Module -ListAvailable -Name ImportExcel)) {
		Write-LogHost "  Agent 365: ImportExcel not available; skipping workbook tab." -ForegroundColor Yellow
		return
	}
	try {
		Import-Module ImportExcel -Force -ErrorAction Stop
		$Rows | Export-Excel -Path $WorkbookPath -WorksheetName 'Agents365' -AutoSize -BoldTopRow -FreezeTopRow -ErrorAction Stop
		Write-LogHost ("  Agent 365 worksheet appended to: {0}" -f (Get-DisplayPath -LocalPath $WorkbookPath)) -ForegroundColor Green
	} catch {
		Write-LogHost ("  WARNING: Could not append Agents365 worksheet: {0}" -f $_.Exception.Message) -ForegroundColor Yellow
	}
}

function Invoke-Agent365Phase {
	<#
	.SYNOPSIS
		Top-level orchestrator for the Agent 365 phase. Called once from the main
		flow when -IncludeAgent365Info or -OnlyAgent365Info is set. No-op otherwise.
	.OUTPUTS
		Hashtable: @{ CsvPath = <string|$null>; Rows = <array> }
	#>
	if (-not ($IncludeAgent365Info -or $OnlyAgent365Info)) { return @{ CsvPath = $null; Rows = @() } }

	Write-LogHost "" 
	Write-LogHost "============================================================" -ForegroundColor Cyan
	Write-LogHost " Microsoft Agent 365 enrichment phase" -ForegroundColor Cyan
	Write-LogHost "============================================================" -ForegroundColor Cyan

	# AppRegistration path: ensure the eager up-front delegated sign-in succeeded.
	# (Connect-Agent365InteractiveContext is idempotent and will silently restore
	# the cached delegated context here when Invoke-Agent365EarlyInteractiveSignIn
	# already ran at startup.)
	if ($Auth -eq 'AppRegistration') {
		# If the eager sign-in already determined Frontier is unavailable (401/403/404),
		# do NOT prompt again - the agent phase is permanently skipped for this run.
		if ($script:Agent365PreAuthCompleted -and $script:Agent365FrontierAvailable -eq $false) {
			Write-LogHost "  Agent 365 phase skipped (tenant not enrolled / role missing - detected at startup)." -ForegroundColor Yellow
			return @{ CsvPath = $null; Rows = @() }
		}
		if (-not (Connect-Agent365InteractiveContext)) {
			Write-LogHost "  Agent 365 phase aborted (interactive sign-in failed)." -ForegroundColor Red
			return @{ CsvPath = $null; Rows = @() }
		}
	}

	# Frontier probe (prints banner 7d on 401/403/404 and returns false).
	if (-not (Test-Agent365FrontierAccess)) {
		return @{ CsvPath = $null; Rows = @() }
	}

	# Audit enrichment (skipped when -OnlyAgent365Info).
	$script:Agent365AuditEnrichment = Get-Agent365AuditEnrichment

	# List + per-package detail
	Write-LogHost "  Listing Agent 365 packages..." -ForegroundColor DarkGray
	$listed = Get-Agent365Packages
	if (-not $listed -or $listed.Count -eq 0) {
		Write-LogHost "  No Agent 365 packages returned by the catalog." -ForegroundColor Yellow
		return @{ CsvPath = $null; Rows = @() }
	}
	Write-LogHost ("  {0} package(s) listed; fetching details..." -f $listed.Count) -ForegroundColor DarkGray

	$rows = New-Object System.Collections.Generic.List[object]
	$idx = 0
	foreach ($p in $listed) {
		$idx++
		$pid = $null
		try { $pid = $p.id } catch {}
		if (-not $pid) { try { $pid = $p.titleId } catch {} }
		if (-not $pid) { continue }
		$detail = Get-Agent365PackageDetail -PackageId $pid
		if (-not $detail) { continue }
		try {
			$row = ConvertTo-Agent365Row -Package $detail -AuditEnrichment $script:Agent365AuditEnrichment
			[void]$rows.Add($row)
		} catch {
			Write-LogHost ("  WARNING: Row build failed for package '{0}': {1}" -f $pid, $_.Exception.Message) -ForegroundColor Yellow
		}
		if (($idx % 25) -eq 0) {
			Write-LogHost ("    ... {0}/{1} packages processed" -f $idx, $listed.Count) -ForegroundColor DarkGray
		}
	}

	$csvPath = Export-Agent365Csv -Rows $rows.ToArray()
	return @{ CsvPath = $csvPath; Rows = $rows.ToArray() }
}

