$script:adaptiveThroughputBaseline = $null
$script:adaptiveLowLatencyStreak = 0
$script:consecutiveBlockFailures = 0
$script:circuitBreakerOpen = $false
$script:circuitBreakerOpenUntil = $null

function Get-BackoffDelaySeconds {
	param(
		[Parameter(Mandatory)][int]$Attempt,
		[Parameter(Mandatory)][double]$BaseSeconds,
		[Parameter(Mandatory)][int]$MaxSeconds
	)
	if ($Attempt -lt 1) { return 0 }
	$raw = $BaseSeconds * [math]::Pow(2, ($Attempt - 1))
	return [math]::Min($MaxSeconds, $raw)
}

function Test-CircuitBreakerTrip {
	param(
		[Parameter(Mandatory)][int]$ConsecutiveFailures,
		[Parameter(Mandatory)][int]$Threshold
	)
	return ($ConsecutiveFailures -ge $Threshold)
}

$JsonDepth = 60
$FlatDepthStandard = 6
$FlatDepthDeep = 120
$ExplosionPerRecordRowCap = 1000
$script:TenantPrimaryDomain = $null
if (-not $script:TenantId) { $script:TenantId = $null }
$script:TenantIndicators = @()
$ForcedRawInputCsvExplosion = $false

# Auth config storage for token refresh (AppRegistration mode)
$script:AuthConfig = @{
	Method = $null
	TenantId = $null
	ClientId = $null
	ClientSecret = $null  # SecureString
	CertThumbprint = $null
	CertPath = $null
	CertPassword = $null  # SecureString
	CertStoreLocation = 'CurrentUser'
	TokenIssueTime = $null
	CanReauthenticate = $false
}

# Shared auth state for thread job token refresh (synchronized hashtable for cross-thread access)
# Thread jobs read Token from this hashtable; main thread updates it proactively before expiry
$script:SharedAuthState = [hashtable]::Synchronized(@{
	Token = $null
	ExpiresOn = $null
	LastRefresh = $null
	RefreshCount = 0
	AuthMethod = $null
})

# Azure (Fabric/OneLake) storage-audience token state. Independent of Graph because
# OneLake DFS uses a separate audience (https://storage.azure.com/) and a separate SDK
# (Az.Accounts), with its own MSAL token cache. Mirrors $script:SharedAuthState shape so
# the refresh code paths read uniformly. Single-thread access (uploads run on main thread),
# so a regular hashtable is sufficient.
$script:AzAuthState = @{
	Token              = $null
	ExpiresOn          = $null   # UTC DateTime
	AcquiredAt         = $null   # local DateTime, used for age-cap proactive refresh
	LastRefresh        = $null
	LastRefreshAttempt = $null   # cooldown anchor
	RefreshCount       = 0
	AuthMethod         = $null   # 'ManagedIdentity' | 'AppRegistration' | 'Interactive'
}

# Checkpoint/Resume state for long-running operations
$script:CheckpointPath = $null              # Path to checkpoint JSON file
$script:CheckpointData = $null              # Loaded/active checkpoint object
$script:IsResumeMode = $false               # Whether we're resuming from checkpoint
$script:PartialOutputPath = $null           # Path to _PARTIAL.csv file during execution
$script:OriginallySkippedPartitionIndices = @()  # Partition indices that were already completed before this run (for resume mode)
$script:StreamingMergeDuplicatesSkipped = 0      # Count of duplicate records removed during streaming merge
$script:StreamingMergeDataLoss = $false          # Whether streaming merge detected missing partition data

# Token expiration detection (reactive - triggers on 401 Unauthorized)
$script:TokenAcquiredTime = $null           # When current token was obtained
$script:AuthFailureDetected = $false        # Set to $true when 401 error detected - triggers reauth prompt
$script:Auth401MessageShown = $false        # Suppresses duplicate 401 error messages (reset after successful reauth)
$script:AuthPromptInProgress = $false       # Debounce flag - prevents multiple auth prompts from triggering simultaneously

# PowerShell version detection for parallel processing features
$script:IsPS7 = ($PSVersionTable.PSVersion.Major -ge 7)

if ($RAWInputCSV) { $ForcedRawInputCsvExplosion = $true }

$script:RegexTrueFalse = [regex]::new('^(?i:true|false)$', [System.Text.RegularExpressions.RegexOptions]::Compiled)
$script:RegexYes1 = [regex]::new('^(?i:yes|1)$', [System.Text.RegularExpressions.RegexOptions]::Compiled)
$script:RegexNo0 = [regex]::new('^(?i:no|0)$', [System.Text.RegularExpressions.RegexOptions]::Compiled)
$script:LocaleDateParsingNotified = $false

function script:Parse-DateSafe {
	<#
	.SYNOPSIS
		Culture-invariant date parsing that handles Purview API date formats.
	.DESCRIPTION
		Purview API returns dates in US format (M/d/yyyy HH:mm:ss) regardless of client locale.
		This function safely parses such dates on systems with non-US regional settings (e.g., UK).
	#>
	param([Parameter(Mandatory=$false)][AllowNull()][AllowEmptyString()]$DateValue)
	
	# Log once when running under non-US locale
	if (-not $script:LocaleDateParsingNotified) {
		$script:LocaleDateParsingNotified = $true
		$currentCulture = [System.Threading.Thread]::CurrentThread.CurrentCulture.Name
		if ($currentCulture -and $currentCulture -ne 'en-US') {
			Write-LogHost "  [DATE] Locale-aware date parsing active (Culture: $currentCulture)" -ForegroundColor DarkCyan
		}
	}
	
	# Already a DateTime? Return as-is
	if ($DateValue -is [datetime]) { return $DateValue }
	
	# Null or empty? Return null
	if ([string]::IsNullOrWhiteSpace($DateValue)) { return $null }
	
	$dateStr = [string]$DateValue
	
	# Try ISO 8601 formats first (most common from properly-formatted API responses)
	$isoFormats = @(
		'yyyy-MM-ddTHH:mm:ss.fffffffK',
		'yyyy-MM-ddTHH:mm:ss.fffK',
		'yyyy-MM-ddTHH:mm:ssK',
		'yyyy-MM-ddTHH:mm:ss.fffffff',
		'yyyy-MM-ddTHH:mm:ss.fffZ',
		'yyyy-MM-ddTHH:mm:ssZ',
		'yyyy-MM-ddTHH:mm:ss.fff',
		'yyyy-MM-ddTHH:mm:ss',
		'yyyy-MM-dd HH:mm:ss.fff',
		'yyyy-MM-dd HH:mm:ss',
		'yyyy-MM-dd'
	)
	
	foreach ($fmt in $isoFormats) {
		try {
			return [datetime]::ParseExact($dateStr, $fmt, [System.Globalization.CultureInfo]::InvariantCulture, [System.Globalization.DateTimeStyles]::AdjustToUniversal)
		}
		catch { }
	}
	
	# Try US formats explicitly (what Purview actually returns - causes UK locale issues)
	$usFormats = @(
		'M/d/yyyy HH:mm:ss',
		'M/d/yyyy h:mm:ss tt',
		'M/d/yyyy H:mm:ss',
		'MM/dd/yyyy HH:mm:ss',
		'M/d/yyyy',
		'MM/dd/yyyy'
	)
	
	foreach ($fmt in $usFormats) {
		try {
			return [datetime]::ParseExact($dateStr, $fmt, [System.Globalization.CultureInfo]::InvariantCulture)
		}
		catch { }
	}
	
	# Last resort: use InvariantCulture with Parse
	try {
		return [datetime]::Parse($dateStr, [System.Globalization.CultureInfo]::InvariantCulture)
	}
	catch {
		return $null
	}
}

function script:Format-DatePurviewFast($dt) {
	if (-not $dt) { return '' }
	try {
		if ($dt -is [datetime]) { 
			return $dt.ToUniversalTime().ToString('yyyy-MM-ddTHH:mm:ss.fffZ', [System.Globalization.CultureInfo]::InvariantCulture)
		}
		else { 
			$p = script:Parse-DateSafe $dt
			if ($null -eq $p) { return '' }
			return $p.ToUniversalTime().ToString('yyyy-MM-ddTHH:mm:ss.fffZ', [System.Globalization.CultureInfo]::InvariantCulture)
		}
	}
	catch { return '' }
}

function script:BoolTFFast($v) {
	if ($null -eq $v) { return '' }
	if ($v -is [bool]) { return $v.ToString().ToUpper() }
	$vStr = [string]$v
	if ($script:RegexTrueFalse.IsMatch($vStr)) { return $vStr.ToUpper() }
	if ($script:RegexYes1.IsMatch($vStr)) { return 'TRUE' }
	if ($script:RegexNo0.IsMatch($vStr)) { return 'FALSE' }
	return $vStr
}

# Apply FlatDepth override (if provided)
try {
	if ($PSBoundParameters.ContainsKey('FlatDepth')) {
		$FlatDepthDeep = $FlatDepth
		$FlatDepthStandard = [int][Math]::Min($FlatDepth, $FlatDepthStandard)
	}
} catch {}

function script:ToJsonIfObjectFast($v) {
	if ($null -eq $v) { return '' }
	if (Test-ScalarValue $v) { return $v }
	try { return ($v | ConvertTo-Json -Depth $JsonDepth -Compress) }
	catch { return [string]$v }
}

function script:GetArrayFast($parent, [string]$name) {
	$val = Get-SafeProperty $parent $name
	if ($null -eq $val) { return @() }
	if ($val -is [System.Collections.IEnumerable] -and -not ($val -is [string])) {
		return @($val)
	}
	return @($val)
}

$effectiveExplodeForProgress = ($ExplodeDeep -or $ExplodeArrays -or $ForcedRawInputCsvExplosion)

# MEMORY MANAGEMENT: Resolve MaxMemoryMB (-1 = auto 75% of system RAM, 0 = disabled, >0 = explicit limit)
$script:ResolvedMaxMemoryMB = $MaxMemoryMB
if ($MaxMemoryMB -eq -1) {
	# Auto-detect: use 75% of total physical memory
	try {
		$totalRAM = [math]::Round((Get-CimInstance -ClassName Win32_ComputerSystem -ErrorAction SilentlyContinue).TotalPhysicalMemory / 1MB, 0)
		$script:ResolvedMaxMemoryMB = [math]::Round($totalRAM * 0.75, 0)
		Write-LogHost "Memory management: Auto-detected ${totalRAM}MB total RAM -> limit set to $($script:ResolvedMaxMemoryMB)MB (75%)" -ForegroundColor Cyan
	} catch {
		# Fallback if CIM fails (e.g., Linux/macOS)
		$script:ResolvedMaxMemoryMB = 4096
		Write-LogHost "Memory management: Could not detect system RAM, defaulting to 4096MB limit" -ForegroundColor Yellow
	}
} elseif ($MaxMemoryMB -eq 0) {
	$script:ResolvedMaxMemoryMB = 0
	Write-LogHost "Memory management: DISABLED (-MaxMemoryMB 0)" -ForegroundColor DarkGray
}

# Memory flush mode: enabled when ResolvedMaxMemoryMB > 0 AND explosion is disabled (explosion needs full $allLogs in memory)
$script:memoryFlushEnabled = ($script:ResolvedMaxMemoryMB -gt 0) -and (-not $ExplodeDeep) -and (-not $ExplodeArrays) -and (-not $ForcedRawInputCsvExplosion)
$script:memoryFlushed = $false  # Track if we've flushed $allLogs during this run (affects export path)
$enableParallelSwitchUsed = $EnableParallel.IsPresent
if ($enableParallelSwitchUsed) { $ParallelMode = 'On' }

function Get-ParallelActivationDecision {
	param(
		[array]$QueryPlan,
		[string]$ParallelMode,
		[int]$MaxParallelGroups,
		[int]$MaxConcurrency
	)
	$ps7 = ($PSVersionTable.PSVersion.Major -ge 7)
	$totalGroups = $QueryPlan.Count
	$totalActivities = ($QueryPlan | ForEach-Object { $_.Activities.Count } | Measure-Object -Sum).Sum
	# Auto parallel eligibility heuristic: allow auto parallel when there's at least one group
	# AND either >1 group OR a single group whose planned concurrency would yield >1 partition.
	# (Single-activity multi-partition scenarios — e.g., CopilotInteraction with 3 partitions —
	# also benefit from parallelism.)
	$singleGroupMultiPartition = ($totalGroups -eq 1) -and ($QueryPlan[0].Concurrency -gt 1)
	$autoEligible = $ps7 -and ($MaxParallelGroups -gt 0) -and ($MaxConcurrency -gt 1) -and ($totalGroups -ge 1) -and (($totalGroups -gt 1) -or $singleGroupMultiPartition)

	switch ($ParallelMode) {
		'On' {
			return @{ Enabled = ($ps7 -and $MaxParallelGroups -gt 0 -and $MaxConcurrency -gt 0); Reason = if ($ps7) { 'Forced On' } else { 'PS < 7 (cannot parallel)' }; AutoEligible = $autoEligible }
		}
		'Auto' {
			return @{ Enabled = $autoEligible; Reason = if ($autoEligible) { 'Auto criteria met' } else { 'Auto criteria not met' }; AutoEligible = $autoEligible }
		}
		default {
			return @{ Enabled = $false; Reason = 'Mode Off'; AutoEligible = $autoEligible }
		}
	}
}

$weights = if ($effectiveExplodeForProgress) { @{ Query = 0.30; Explosion = 0.60; Export = 0.10 } } else { @{ Query = 0.80; Explosion = 0.00; Export = 0.20 } }
if ($RAWInputCSV) {
	try {
		$weights = @{ Parsing = 0.10; Query = 0.0; Explosion = 0.80; Export = 0.10 }
	}
	catch {}
}
$script:originalWeights = $weights.Clone()
$script:progressState = @{ Weights = $weights; Phase = 'Query'; Parsing = @{Current = 0; Total = 0 }; Query = @{Current = 0; Total = 0 }; Explode = @{Current = 0; Total = 0 }; Export = @{Current = 0; Total = 1 } }
function Set-ProgressPhase { param([ValidateSet('Parsing', 'Query', 'Explosion', 'Export', 'Complete')] [string]$Phase, [string]$Status = ''); $script:progressState.Phase = $Phase; Update-Progress -Status $Status }
function Update-Progress {
	param(
		[string]$Status = '',
		[int]$BatchCurrent = 0,
		[int]$BatchTotal = 0,
		[int]$BatchRangeStart = 0,
		[int]$BatchRangeEnd = 0,
		[int]$BatchStartPercent = 0,
		[int]$BatchEndPercent = 0,
		[bool]$BatchTotalIsEstimate = $false
	)
	$w = $script:progressState.Weights; $ps = $script:progressState.Parsing; $qs = $script:progressState.Query; $es = $script:progressState.Explode; $xs = $script:progressState.Export
	$pPct = if ($ps.Total -gt 0 -and $w.ContainsKey('Parsing') -and $w.Parsing -gt 0) { [double]$ps.Current / [double]$ps.Total } else { 0.0 }
	$qPct = if ($qs.Total -gt 0) { [double]$qs.Current / [double]$qs.Total } else { 0.0 }
	$ePct = if ($es.Total -gt 0 -and $w.Explosion -gt 0) { [double]$es.Current / [double]$es.Total } else { 0.0 }
	$xPct = if ($xs.Total -gt 0) { [double]$xs.Current / [double]$xs.Total } else { 0.0 }
	# Zero-record weighting: emphasize Query progression when no records retrieved yet
	if ($script:progressState.Phase -eq 'Query' -and ($script:metrics.TotalRecordsFetched -eq 0)) {
		$w.Query = 1.0; $w.Explosion = 0.0; $w.Export = 0.0; if ($w.ContainsKey('Parsing')) { $w.Parsing = 0.0 }
	}
	# Restoration: Once at least one record has been fetched, revert weights if they were temporarily overridden.
	elseif ($script:progressState.Phase -eq 'Query' -and ($script:metrics.TotalRecordsFetched -gt 0)) {
		if ($script:originalWeights -and $w.Query -eq 1.0 -and $w.Explosion -eq 0.0 -and $w.Export -eq 0.0) {
			foreach ($key in $script:originalWeights.Keys) { $w[$key] = $script:originalWeights[$key] }
		}
	}
	# Calculate phase-specific progress details
	$phase = $script:progressState.Phase
	$pDetail = if ($w.ContainsKey('Parsing') -and $w.Parsing -gt 0 -and $ps.Total -gt 0) { "{0}/{1}({2}%)" -f $ps.Current, $ps.Total, ([int]([Math]::Round($pPct * 100))) } else { '' }
	$qDetail = if ($w.Query -gt 0 -and $qs.Total -gt 0) { "{0}/{1}({2}%)" -f $qs.Current, $qs.Total, ([int]([Math]::Round($qPct * 100))) } else { '' }
	if ($BatchRangeStart -ge 1 -and $BatchRangeEnd -ge 1 -and $es.Total -gt 0) {
		if ($BatchStartPercent -ge 0 -and $BatchEndPercent -gt 0) {
			$batchTotalDisplay = if ($BatchTotalIsEstimate) { "~$BatchTotal" } else { "$BatchTotal" }
			$batchInfo = if ($BatchTotal -ge 1) { " Batch: {0}/{1}({2}%-{3}%)" -f $BatchCurrent, $batchTotalDisplay, $BatchStartPercent, $BatchEndPercent } else { '' }
		}
		else {
			$batchPct = if ($BatchTotal -gt 0 -and $BatchCurrent -gt 0) { [int]([Math]::Round(([double]$BatchCurrent / [double]$BatchTotal) * 100)) } else { 0 }
			$batchTotalDisplay = if ($BatchTotalIsEstimate) { "~$BatchTotal" } else { "$BatchTotal" }
			$batchInfo = if ($BatchTotal -ge 1) { " Batch: {0}/{1}({2}%)" -f $BatchCurrent, $batchTotalDisplay, $batchPct } else { '' }
		}
		$explosionCounts = "Records {0}-{1}/{2}{3}" -f $BatchRangeStart, $BatchRangeEnd, $es.Total, $batchInfo
	}
	elseif ($BatchTotal -ge 1) {
		$batchPct = if ($BatchTotal -gt 0 -and $BatchCurrent -gt 0) { [int]([Math]::Round(([double]$BatchCurrent / [double]$BatchTotal) * 100)) } else { 0 }
		$batchTotalDisplay = if ($BatchTotalIsEstimate) { "~$BatchTotal" } else { "$BatchTotal" }
		$batchInfo = " Batch: {0}/{1}({2}%)" -f $BatchCurrent, $batchTotalDisplay, $batchPct
		$explosionCounts = if ($es.Total -gt 0) { "Records {0}/{1}{2}" -f $es.Current, $es.Total, $batchInfo } else { "0/0" }
	}
	else {
		$explosionCounts = if ($es.Total -gt 0) { "{0}/{1}({2}%)" -f $es.Current, $es.Total, ([int]([Math]::Round($ePct * 100))) } else { '0/0' }
	}
	$eDetail = if ($w.Explosion -gt 0) {
		if ($phase -eq 'Explosion') {
			" | $explosionCounts"
		}
		else {
			" | Explosion: $explosionCounts"
		}
	}
	else { '' }
	$batchDetail = ''
	$xDetail = if ($xs.Total -gt 0) { " | Export: {0}/{1}({2}%)" -f $xs.Current, $xs.Total, ([int]([Math]::Round($xPct * 100))) } else { ' | Export: 0/0' }
	$parsingLabel = 'Pre-parsing JSON'
	if (($AgentId -or $AgentsOnly -or $ExcludeAgents -or $PromptFilter) -and $phase -eq 'Parsing') {
		$parsingLabel = 'Pre-parsing + Filtering'
	}
	$phasePrefix = switch ($phase) { 'Parsing' { $parsingLabel } 'Query' { 'Query' } 'Explosion' { 'Explosion' } 'Export' { 'Export' } 'Complete' { 'Complete' } default { $phase } }
	if ($phase -eq 'Parsing' -and $pDetail) {
		$composite = "${phasePrefix}: $pDetail$eDetail$batchDetail$xDetail"
	}
	elseif ($phase -eq 'Explosion' -and -not $qDetail) {
		$composite = "Explosion: $explosionCounts$batchDetail$xDetail"
	}
	else {
		$composite = if ($qDetail) { "${phasePrefix}: $qDetail$eDetail$batchDetail$xDetail" } else { "${phasePrefix}:$eDetail$batchDetail$xDetail" }
	}
	$statusText = if ($Status) { "$Status :: $composite" } else { $composite }
	if ($statusText.Length -gt 180) { $statusText = $statusText.Substring(0, 177) + '...' }
	# Placeholder for progress display compatibility
}
function Complete-Progress { 
	# Placeholder for progress display compatibility
}

# Lightweight explicit progress tick to ensure visual movement in long zero-record scenarios.
function Write-ProgressTick {
	# Placeholder for progress display compatibility
}

$script:learnedActivityBlockSize = @{}
$script:globalLearnedBlockSize = $BlockHours

function Get-QueryPlan {
	param([string[]]$RequestedActivities)
	# Normalize and deduplicate (DSPM logic already handled fallback, so no default here)
	$normalized = @(); foreach ($a in $RequestedActivities) { if ($a -and -not ($normalized -contains $a)) { $normalized += $a } }
	# If still empty after DSPM logic, something went wrong - but DSPM validation should prevent this
	if ($normalized.Count -eq 0) { 
		Write-Host "ERROR: No activity types provided to Get-QueryPlan. This should not happen after DSPM validation." -ForegroundColor Red
		exit 1
	}
	$plan = @(); $i = 0
	
	# DUAL-MODE QUERY PLANNING:
	# Graph API mode: Combine all activity types into single group (Graph API accepts multiple operationFilters)
	# EOM mode: Separate groups per activity type (Search-UnifiedAuditLog performs better with single activity)
	if (-not $UseEOM) {
		# Graph API mode: Single group with all activities combined
		$plan += @{ 
			Name = "Combined: $($normalized -join ', ')"; 
			Group = 'GraphCombined'; 
			Activities = $normalized; 
			Concurrency = $MaxConcurrency 
		}
	}
	else {
		# EOM mode: One group per activity type (sequential processing)
		foreach ($a in $normalized) {
			$i++
			$plan += @{ 
				Name = "Activity: $a"; 
				Group = 'EOM_Sequential'; 
				Activities = @($a); 
				Concurrency = $MaxConcurrency 
			}
		}
	}
	return $plan
}

function Update-LearnedBlockSize {
	param([string]$ActivityType, [double]$BlockHours, [int]$RecordCount, [bool]$Success)
	if ($Success) {
		if ($RecordCount -eq $ResultSize) {
			$newSize = [Math]::Max(0.083333, $BlockHours * 0.5)
			$script:learnedActivityBlockSize[$ActivityType] = $newSize
			$script:globalLearnedBlockSize = [Math]::Min($script:globalLearnedBlockSize, $newSize)
			Write-LogHost "    → Learned: Reducing block size to $([math]::Round($newSize,2))h due to limit hit" -ForegroundColor Magenta
		}
		elseif ($RecordCount -gt ($ResultSize * 0.8)) {
			$newSize = [Math]::Max(0.083333, $BlockHours * 0.7)
			$script:learnedActivityBlockSize[$ActivityType] = $newSize
			Write-LogHost "    → Learned: Reducing block size to $([math]::Round($newSize,2))h (high volume: $RecordCount records)" -ForegroundColor Magenta
		}
		elseif ($RecordCount -lt ($ResultSize * 0.1)) {
			$newSize = [Math]::Min(24.0, $BlockHours * 1.5)
			$script:learnedActivityBlockSize[$ActivityType] = $newSize
			Write-LogHost "    → Learned: Increasing block size to $([math]::Round($newSize,2))h (low volume: $RecordCount records)" -ForegroundColor Magenta
		}
		elseif ($RecordCount -lt ($ResultSize * 0.05)) {
			$newSize = [Math]::Min(24.0, $BlockHours * 2.0)
			$script:learnedActivityBlockSize[$ActivityType] = $newSize
			Write-LogHost "    → Learned: Increasing block size to $([math]::Round($newSize,2))h (very low volume: $RecordCount records)" -ForegroundColor Magenta
		}
	} else {
		$newSize = [Math]::Max(0.083333, $BlockHours * 0.5)
		$script:learnedActivityBlockSize[$ActivityType] = $newSize
		$script:globalLearnedBlockSize = [Math]::Min($script:globalLearnedBlockSize, $newSize)
		Write-LogHost "    → Learned: Reducing block size to $([math]::Round($newSize,2))h due to failure" -ForegroundColor Magenta
	}
}
function Get-NextSmallerBlockSize { param([double]$CurrentSize) return [Math]::Max(0.001389, $CurrentSize / 2) }  # Min 2 minutes

function Get-OptimalBlockSize { param([string]$ActivityType) if ($script:learnedActivityBlockSize.ContainsKey($ActivityType)) { return $script:learnedActivityBlockSize[$ActivityType] } elseif ($script:globalLearnedBlockSize -ne $BlockHours) { return $script:globalLearnedBlockSize } else { return $BlockHours } }

function Invoke-ActivityTimeWindowProcessing { 
	param(
		[Parameter(Mandatory = $true)][string]$ActivityType, 
		[Parameter(Mandatory = $true)][datetime]$StartDate, 
		[Parameter(Mandatory = $true)][datetime]$EndDate,
		[int]$PartitionIndex = 1,
		[int]$TotalPartitions = 1,
		[bool]$UseEOMMode = $false
	) 
    
	Write-Host "Processing $ActivityType (partition $PartitionIndex/$TotalPartitions) from $($StartDate.ToString('yyyy-MM-dd HH:mm')) to $($EndDate.ToString('yyyy-MM-dd HH:mm'))..." -ForegroundColor White
	$blockHours = Get-OptimalBlockSize -ActivityType $ActivityType
	Write-Host "  Using initial block size: $blockHours hours" -ForegroundColor DarkCyan
    
	$allResults = New-Object System.Collections.ArrayList
	$current = $StartDate
	$blockNumber = 1
    
	while ($current -lt $EndDate) { 
		# Show progress BEFORE block processing to ensure visibility (before log output clears it)
		Write-ProgressTick
		
		if ($script:circuitBreakerOpen) {
			if ($script:circuitBreakerOpenUntil -and (Get-Date) -lt $script:circuitBreakerOpenUntil) {
				Write-LogHost "    Circuit breaker OPEN until $($script:circuitBreakerOpenUntil.ToString('HH:mm:ss')) – skipping remaining blocks for $ActivityType" -ForegroundColor Red
				break
			} else {
				$script:circuitBreakerOpen = $false
				$script:consecutiveBlockFailures = 0
				Write-LogHost "    Circuit breaker cooldown elapsed – resuming block processing" -ForegroundColor DarkGreen
			}
		}
		if ($script:learnedActivityBlockSize.ContainsKey($ActivityType)) {
			$blockHours = $script:learnedActivityBlockSize[$ActivityType]
		}
        
		$blockEnd = $current.AddHours($blockHours)
		if ($blockEnd -gt $EndDate) { $blockEnd = $EndDate }
        
		$actualBlockHours = [math]::Round(($blockEnd - $current).TotalHours, 2)
		Write-Host "  Block $blockNumber`: $($current.ToString('yyyy-MM-dd HH:mm')) to $($blockEnd.ToString('yyyy-MM-dd HH:mm')) ($($actualBlockHours)h)" -ForegroundColor Yellow
        
		try { 
			$results = Invoke-PurviewAuditQuery -StartDate $current -EndDate $blockEnd -Operations $ActivityType -ResultSize $ResultSize -UserIds $script:targetUsers -UseEOMMode $UseEOMMode
            
			if ($results -and $results.Count -gt 0) { 
				# Safe add - handle both array and single object
				if ($results -is [Array]) {
					foreach ($item in $results) { [void]$allResults.Add($item) }
				} else {
					[void]$allResults.Add($results)
				}
				Write-Host "    Added $($results.Count) records (total: $($allResults.Count))" -ForegroundColor Green
				Update-LearnedBlockSize -ActivityType $ActivityType -BlockHours $actualBlockHours -RecordCount $results.Count -Success $true
				$script:consecutiveBlockFailures = 0
			} 
			else { 
				Write-Host "    No records found in this block" -ForegroundColor Gray
				$script:consecutiveBlockFailures = 0
			} 
		} 
		catch { 
			Write-Host "    Block failed: $($_.Exception.Message)" -ForegroundColor Red
			Update-LearnedBlockSize -ActivityType $ActivityType -BlockHours $actualBlockHours -RecordCount 0 -Success $false
			$script:consecutiveBlockFailures++
			$attemptNum = $script:consecutiveBlockFailures
			$expDelay = [math]::Min($BackoffMaxSeconds, $BackoffBaseSeconds * [math]::Pow(2, ($attemptNum - 1)))
			$jitterMs = Get-Random -Minimum 150 -Maximum 750
			$totalDelaySec = [math]::Round($expDelay,2) + [math]::Round($jitterMs/1000,2)
			try { $script:metrics.BackoffTotalDelaySeconds += $totalDelaySec } catch {}
			Write-LogHost "    Reliability: Backoff delay $([math]::Round($expDelay,2))s + jitter $([math]::Round($jitterMs/1000,2))s (attempt $attemptNum)" -ForegroundColor DarkYellow
			Start-Sleep -Seconds ([int][math]::Ceiling($expDelay))
			Start-Sleep -Milliseconds $jitterMs
			if ($script:consecutiveBlockFailures -ge $CircuitBreakerThreshold) {
				$script:circuitBreakerOpen = $true
				$script:circuitBreakerOpenUntil = (Get-Date).AddSeconds($CircuitBreakerCooldownSeconds)
				try { $script:metrics.CircuitBreakerTrips++ } catch {}
				Write-LogHost "    CIRCUIT BREAKER TRIPPED after $script:consecutiveBlockFailures consecutive block failures – cooling down for $CircuitBreakerCooldownSeconds seconds (until $($script:circuitBreakerOpenUntil.ToString('HH:mm:ss')))" -ForegroundColor Magenta
				break
			}
			if ($blockHours -gt 0.5) { 
				$smallerBlockHours = Get-NextSmallerBlockSize -CurrentSize $blockHours
				Write-Host "    Retrying with smaller $smallerBlockHours hour block..." -ForegroundColor Yellow
                
				try { 
					$blockEnd = $current.AddHours($smallerBlockHours)
					if ($blockEnd -gt $EndDate) { $blockEnd = $EndDate }
                    
					$results = Invoke-PurviewAuditQuery -StartDate $current -EndDate $blockEnd -Operations $ActivityType -ResultSize $ResultSize -UserIds $script:targetUsers -UseEOMMode $UseEOMMode
                    
					if ($results -and $results.Count -gt 0) { 
						# Safe add - handle both array and single object
						if ($results -is [Array]) {
							foreach ($item in $results) { [void]$allResults.Add($item) }
						} else {
							[void]$allResults.Add($results)
						}
						Write-Host "      Smaller block succeeded: $($results.Count) records" -ForegroundColor Green
						Update-LearnedBlockSize -ActivityType $ActivityType -BlockHours $smallerBlockHours -RecordCount $results.Count -Success $true
						$blockHours = $smallerBlockHours
						$script:consecutiveBlockFailures = 0
					} 
				} 
				catch { 
					Write-Host "      Smaller block also failed: $($_.Exception.Message)" -ForegroundColor Red
					$script:consecutiveBlockFailures++
					$attemptNum = $script:consecutiveBlockFailures
					$expDelay = [math]::Min($BackoffMaxSeconds, $BackoffBaseSeconds * [math]::Pow(2, ($attemptNum - 1)))
					$jitterMs = Get-Random -Minimum 150 -Maximum 750
					$totalDelaySec = [math]::Round($expDelay,2) + [math]::Round($jitterMs/1000,2)
					try { $script:metrics.BackoffTotalDelaySeconds += $totalDelaySec } catch {}
					Write-LogHost "      Reliability: Backoff delay $([math]::Round($expDelay,2))s + jitter $([math]::Round($jitterMs/1000,2))s (attempt $attemptNum)" -ForegroundColor DarkYellow
					Start-Sleep -Seconds ([int][math]::Ceiling($expDelay))
					Start-Sleep -Milliseconds $jitterMs
					if ($script:consecutiveBlockFailures -ge $CircuitBreakerThreshold) {
						$script:circuitBreakerOpen = $true
						$script:circuitBreakerOpenUntil = (Get-Date).AddSeconds($CircuitBreakerCooldownSeconds)
						try { $script:metrics.CircuitBreakerTrips++ } catch {}
						Write-LogHost "      CIRCUIT BREAKER TRIPPED after $script:consecutiveBlockFailures consecutive block failures – cooling down for $CircuitBreakerCooldownSeconds seconds (until $($script:circuitBreakerOpenUntil.ToString('HH:mm:ss')))" -ForegroundColor Magenta
						break
					}
				} 
			} 
		} 
        
		try { 
			if ($script:progressState.Query.Current -ge $script:progressState.Query.Total) { 
				$script:progressState.Query.Total += 1
			} 
			$script:progressState.Query.Current += 1
			$script:progressBlocksCompleted = ($script:progressBlocksCompleted + 1)
			$script:progressBlockHoursSum = ($script:progressBlockHoursSum + $actualBlockHours)
			if ($script:progressBlocksCompleted -gt 0) {
				# --- Progress Estimation Logic (multi-partition accurate) ---
				#   1. Estimate remaining blocks in the CURRENT partition.
				#   2. Add an estimate for yet-to-start partitions based on the average blocks/partition so far.
				#   3. Enforce a monotonic (non-decreasing) Query.Total so percent cannot jump to 100% early.
				# This prevents Query.Total from shrinking between partitions and reporting premature 100%
				# completion when later partitions have not yet started.
				$avgBlock = $script:progressBlockHoursSum / $script:progressBlocksCompleted
				$elapsedHours = $script:progressBlockHoursSum
				$currentPartitionRangeHours = ($EndDate - $StartDate).TotalHours
				$remainingHoursCurrentPartition = [Math]::Max(0.0, $currentPartitionRangeHours - $elapsedHours)
				$remainingBlocksEstCurrent = if ($avgBlock -gt 0) { [Math]::Ceiling($remainingHoursCurrentPartition / $avgBlock) } else { 0 }
				$remainingPartitions = if ($TotalPartitions -gt $PartitionIndex) { $TotalPartitions - $PartitionIndex } else { 0 }
				$avgBlocksPerCompletedPartition = if ($PartitionIndex -gt 0) { [double]$script:progressBlocksCompleted / [double]$PartitionIndex } else { [double]$script:progressBlocksCompleted }
				$futurePartitionBlocksEst = if ($remainingPartitions -gt 0 -and $avgBlocksPerCompletedPartition -gt 0) { [int][Math]::Ceiling($avgBlocksPerCompletedPartition * $remainingPartitions) } else { 0 }
				$newCalcGlobal = $script:progressBlocksCompleted + $remainingBlocksEstCurrent + $futurePartitionBlocksEst
				# Apply optional smoothing but NEVER allow total to decrease (monotonic total).
				if ($ProgressSmoothingAlpha -gt 0 -and $script:progressState.Query.Total -gt 0) {
					$smoothed = [int]([Math]::Round(($ProgressSmoothingAlpha * $newCalcGlobal) + ((1 - $ProgressSmoothingAlpha) * $script:progressState.Query.Total)))
					$newTotalCandidate = [Math]::Max($script:progressState.Query.Total, $smoothed, $newCalcGlobal)
				} else {
					$newTotalCandidate = [Math]::Max($script:progressState.Query.Total, $newCalcGlobal)
				}
				$script:progressState.Query.Total = [Math]::Max($script:progressState.Query.Total, $newTotalCandidate, $script:progressBlocksCompleted)
			}
			Update-Progress
			# Explicit tick for visibility even if Update-Progress weighting collapses.
			Write-ProgressTick
		} 
		catch {}
        
		$current = $blockEnd
		$blockNumber++
	} 
    
	Write-Host "  Completed $ActivityType (partition $PartitionIndex/$TotalPartitions)`: $($allResults.Count) total records" -ForegroundColor Green
	return $allResults.ToArray()
}

# Note: Write-Log and Write-LogHost are defined earlier in the script (near line 670)

function Open-CsvWriter {
	param([string]$Path, [string[]]$Columns)
	$enc = New-Object System.Text.UTF8Encoding($false)
	# OPTIMIZATION: Use 1MB StreamWriter buffer (default is 1KB) to reduce write syscalls
	$script:PAX_CsvWriter = [System.IO.StreamWriter]::new($Path, $false, $enc, 1048576)
	$escapedCols = New-Object System.Collections.Generic.List[string]
	foreach ($col in $Columns) {
		$c = [string]$col
		$needsQuote = ($c -match '[",\r\n]') -or $c.StartsWith(' ') -or $c.EndsWith(' ')
		$escaped = $c -replace '"', '""'
		if ($needsQuote) { $escaped = '"' + $escaped + '"' }
		$escapedCols.Add($escaped) | Out-Null
	}
	$script:PAX_CsvWriter.WriteLine(($escapedCols -join ','))
}
function Close-CsvWriter { if ($script:PAX_CsvWriter) { try { $script:PAX_CsvWriter.Flush(); $script:PAX_CsvWriter.Dispose() } catch {}; Remove-Variable PAX_CsvWriter -Scope Script -ErrorAction SilentlyContinue } }
function Write-CsvRows {
	param([System.Collections.IEnumerable]$Rows, [string[]]$Columns)
	if (-not $Rows) { return }
	if (-not $script:PAX_CsvWriter) { throw "CSV writer not initialized" }
	
	# Pre-compile regex once (not per-cell) for significant performance gain
	$needsQuotePattern = [regex]::new('[",\r\n]', [System.Text.RegularExpressions.RegexOptions]::Compiled)
	
	# OPTIMIZATION: Pre-allocate larger buffer (4MB) to reduce write syscalls
	$sb = New-Object System.Text.StringBuilder(4194304)
	$colCount = $Columns.Count
	$fieldValues = New-Object string[] $colCount  # Reuse array instead of creating List per row
	
	# OPTIMIZATION: Build column index lookup table for O(1) access by name
	# This eliminates per-cell string lookups which were the main bottleneck
	$columnIndex = @{}
	for ($i = 0; $i -lt $colCount; $i++) {
		$columnIndex[$Columns[$i]] = $i
	}
	
	foreach ($row in $Rows) {
		if ($null -eq $row) { continue }
		
		# Reset field values (faster than creating new array)
		for ($i = 0; $i -lt $colCount; $i++) { $fieldValues[$i] = "" }
		
		# For hashtables, iterate keys and map to column index (much faster than iterating columns)
		if ($row -is [hashtable]) {
			foreach ($key in $row.Keys) {
				if ($columnIndex.ContainsKey($key)) {
					$idx = $columnIndex[$key]
					$val = $row[$key]
					
					if ($null -eq $val) { continue }
					
					# Handle arrays/collections
					if ($val -is [System.Collections.IEnumerable] -and -not ($val -is [string])) { 
						try { $val = ($val | ForEach-Object { if ($_ -ne $null) { [string]$_ } else { '' } }) -join ';' } catch { $val = [string]$val } 
					}
					
					$s = [string]$val
					# Use pre-compiled regex and avoid method calls where possible
					if ($s.Length -gt 0 -and ($needsQuotePattern.IsMatch($s) -or $s[0] -eq ' ' -or $s[$s.Length - 1] -eq ' ')) { 
						$s = '"' + ($s -replace '"', '""') + '"' 
					}
					$fieldValues[$idx] = $s
				}
			}
		} else {
			# OPTIMIZED: For PSObjects, iterate only populated properties (not all columns)
			# This reduces iterations from ~163 columns to ~50 actual properties per row
			foreach ($prop in $row.PSObject.Properties) {
				$key = $prop.Name
				if (-not $columnIndex.ContainsKey($key)) { continue }
				
				$idx = $columnIndex[$key]
				$val = $prop.Value
				
				if ($null -eq $val) { continue }
				
				# Handle arrays/collections
				if ($val -is [System.Collections.IEnumerable] -and -not ($val -is [string])) { 
					try { $val = ($val | ForEach-Object { if ($_ -ne $null) { [string]$_ } else { '' } }) -join ';' } catch { $val = [string]$val } 
				}
				
				$s = [string]$val
				if ($s.Length -gt 0 -and ($needsQuotePattern.IsMatch($s) -or $s[0] -eq ' ' -or $s[$s.Length - 1] -eq ' ')) { 
					$s = '"' + ($s -replace '"', '""') + '"' 
				}
				$fieldValues[$idx] = $s
			}
		}
		
		[void]$sb.AppendLine(($fieldValues -join ','))
		# Flush at 4MB (increased from 1MB to reduce write syscalls)
		if ($sb.Length -gt 4194304) {
			$script:PAX_CsvWriter.Write($sb.ToString())
			[void]$sb.Clear()
		}
	}
	if ($sb.Length -gt 0) { $script:PAX_CsvWriter.Write($sb.ToString()) }
}

function Test-AgentFilter {
	param(
		[Parameter(Mandatory = $true)]
		$ParsedAuditData,
		[string[]]$AgentIdFilter,
		[bool]$AgentsOnlyFilter
	)
	if (-not $AgentIdFilter -and -not $AgentsOnlyFilter) {
		return $true
	}
	$recordAgentId = $null
	try {
		if ($ParsedAuditData.AgentId) {
			$recordAgentId = [string]$ParsedAuditData.AgentId
		}
	}
	catch {
		return $false
	}
	if ($AgentsOnlyFilter) {
		if ([string]::IsNullOrWhiteSpace($recordAgentId)) {
			return $false
		}
		if (-not $AgentIdFilter) {
			return $true
		}
	}
	if ($AgentIdFilter) {
		if ([string]::IsNullOrWhiteSpace($recordAgentId)) {
			return $false
		}
		foreach ($filterId in $AgentIdFilter) {
			if ($recordAgentId -eq $filterId) {
				return $true
			}
		}
		return $false
	}
	return $true
}

# Ensure output directory exists
if (-not (Test-Path $OutputPath)) { New-Item -Path $OutputPath -ItemType Directory -Force | Out-Null }

# Generate output filename with proper extension
$fileExtension = if ($ExportWorkbook) { "xlsx" } else { "csv" }
$filePrefix = "Purview_Audit"

# Determine initial combine mode (needed early for filename decision)
$isCsv = (-not $ExportWorkbook)
$initialCsvCombine = if ($RAWInputCSV -and $isCsv) { $true } elseif ($isCsv) { $CombineOutput.IsPresent } else { $false }

# Predict the combined-audit CSV leaf name upfront. When the run is gated to a
# single activity type ($ActivityTypes count == 1 and -IncludeM365Usage is NOT
# expanding the set), name the file Purview_Audit_UsageActivity_<Type>_<ts>.csv
# directly so the log file (derived from $OutputFile basename) matches. The
# post-export dynamic single-activity downgrade is a secondary safety net for
# runs where the resulting data happens to contain only one activity type.
$_combinedAuditLeaf = "Purview_Audit_UsageActivity_CombinedActivityTypes_$global:ScriptRunTimestamp.csv"
if ($ActivityTypes -and @($ActivityTypes).Count -eq 1 -and -not $IncludeM365Usage) {
	$_onlyActivityType = [string]$ActivityTypes[0]
	if (-not [string]::IsNullOrWhiteSpace($_onlyActivityType)) {
		$_safeActivityType = $_onlyActivityType -replace '[\\/:*?"<>|]', '_'
		$_combinedAuditLeaf = "Purview_Audit_UsageActivity_${_safeActivityType}_$global:ScriptRunTimestamp.csv"
	}
}

# Determine script mode for logging and validation
$scriptMode = if ($RAWInputCSV) {
	"Replay (RAWInputCSV)"
} elseif ($ExplodeDeep) {
	"Deep Column Explosion (-ExplodeDeep)"
} elseif ($ExplodeArrays -or $ForcedRawInputCsvExplosion) {
	if ($ForcedRawInputCsvExplosion -and -not $ExplodeArrays.IsPresent -and -not $ExplodeDeep.IsPresent) { "Array Explosion (-ExplodeArrays, RAWInput implied)" } else { "Array Explosion (-ExplodeArrays)" }
} else {
	"Standard (1:1, no explosion)"
}

# Resolve OutputFile path
# OnlyUserInfo mode: Output file is EntraUsers_MAClicensing (log file will match)
if ($OnlyUserInfo) {
	$fileExtension = if ($ExportWorkbook) { "xlsx" } else { "csv" }
	$OutputFile = Join-Path $OutputPath "EntraUsers_MAClicensing_$global:ScriptRunTimestamp.$fileExtension"
}
elseif ($AppendFile) {
	# User provided filename, full local path, or remote (SharePoint/Fabric) URL.
	# Classify the form BEFORE doing any path join — IsPathRooted returns $false
	# for "https://..." which would cause Join-Path to mangle the URL into the
	# local scratch dir. The remote pre-flight downstream pulls the remote file
	# into local scratch and then redirects $AppendFile to that local copy.
	$appendInputTier = if (Get-Command -Name Get-PathTier -ErrorAction SilentlyContinue) {
		# Suppress Get-PathTier's exit-on-invalid behaviour for relative filenames
		# by short-circuiting based on form first.
		if ($AppendFile -match '^https?://') { Get-PathTier $AppendFile -SwitchName 'AppendFile' }
		elseif ([System.IO.Path]::IsPathRooted($AppendFile)) { 'Local' }
		else { 'Local' }   # relative filename → resolves under $OutputPath (Local)
	} else { 'Local' }

	# Rollup-output detection. The embedded Python processors emit rollup outputs
	# with one of the following suffixes on the original raw stem (the M365Bundle
	# processor appends a current-run timestamp; the CopilotInteraction processor
	# does not):
	#   CopilotInteraction processor    : '<purview_stem>_Interactions.csv'
	#                                     '<entra_stem>_Users.csv'
	#   M365Bundle processor (rollup)   : '<purview_stem>_Rollup_<YYYYMMDD_HHMMSS>.csv'
	#                                     '<purview_stem>_UserStats_<YYYYMMDD_HHMMSS>.csv'
	#                                     '<purview_stem>_SessionCohort_<YYYYMMDD_HHMMSS>.csv'
	#                                     '<purview_stem>_SessionStats_<YYYYMMDD_HHMMSS>.csv'
	#   M365Bundle processor (event)    : '<purview_stem>_Exploded.csv'
	# When the user passes any such file as -AppendFile UNDER -Rollup / -RollupPlusRaw
	# (or under -IncludeM365Usage event-level mode), they are pointing at the previous
	# run's ROLLUP/EXPLOSION target — NOT at a raw Purview audit CSV. The raw audit
	# writer must NOT be re-pointed to the rollup leaf, or it will overwrite the
	# rollup target with raw audit rows and produce zero actual raw output (defeating
	# the whole point of -RollupPlusRaw). Instead: keep $OutputFile on its natural
	# timestamped raw-audit name, and let -AppendFile flow through downstream:
	#   • CopilotInteraction: seed-map source merged inside Python.
	#   • M365Bundle (rollup): union-merged PS-side via Merge-M365RollupCsv after
	#     the processor emits its timestamped Rollup; sidecars are then regenerated
	#     from the merged union via --rebuild-sidecars-from-rollup.
	#   • M365Bundle (event): --exclude-record-ids source for de-duplication.
	$appendLeaf = [System.IO.Path]::GetFileName($AppendFile)
	# Rollup-shape match accepts both the anchored '<stem>_<Suffix>.csv' shape
	# (typical for customer-renamed long-lived targets) and the timestamped
	# '<stem>_<Suffix>_<YYYYMMDD_HHMMSS>.csv' shape (when the customer points
	# AppendFile at a previous run's raw output without renaming).
	$appendIsRollupShaped = ($appendLeaf -match '_(Interactions|Rollup|UserStats|SessionCohort|Exploded)(?:_\d{8}_\d{6})?\.csv$')
	# The embedded Python processor only runs under -Rollup / -RollupPlusRaw.
	# Outside those switches a rollup-shaped leaf is just a coincidence (the user
	# is presumably appending to a real raw-audit CSV that happens to share the
	# suffix), so leave the legacy raw-append behaviour intact in that case.
	$rollupActive = ($Rollup -or $RollupPlusRaw)
	$treatAppendAsRollupTarget = ($appendIsRollupShaped -and $rollupActive)

	# M365 rollup-mode leaf validation. When -IncludeM365Usage is set with -Rollup
	# or -RollupPlusRaw, the embedded M365Bundle processor produces 4 outputs
	# ('<stem>_Rollup_<ts>.csv', '<stem>_UserStats_<ts>.csv', '<stem>_SessionCohort_<ts>.csv',
	# '<stem>_SessionStats_<ts>.csv'). Only the Rollup file supports the union-merge
	# semantic as the AppendFile anchor (PS-side via Merge-M365RollupCsv);
	# UserStats, SessionCohort, and SessionStats are recomputed/merged sidecars
	# anchored off the AppendFile leaf stem at the post-processor regen step.
	# Pointing -AppendFile at a sidecar (or at a CopilotInteraction _Interactions
	# leaf, or at an M365 event-level _Exploded leaf) would either silently feed
	# the processor the wrong schema or anchor sidecars at the wrong stem, so we
	# reject upfront with a leaf-specific error.
	if ($IncludeM365Usage -and $rollupActive) {
		$m365LeafErr = $null
		if      ($appendLeaf -match '_UserStats(?:_\d{8}_\d{6})?\.csv$')     { $m365LeafErr = "'_UserStats.csv' is a recomputed sidecar of the M365 rollup; it cannot be the merge anchor." }
		elseif  ($appendLeaf -match '_SessionCohort(?:_\d{8}_\d{6})?\.csv$') { $m365LeafErr = "'_SessionCohort.csv' is a recomputed sidecar of the M365 rollup; it cannot be the merge anchor." }
		elseif  ($appendLeaf -match '_SessionStats(?:_\d{8}_\d{6})?\.csv$')  { $m365LeafErr = "'_SessionStats.csv' is a recomputed sidecar of the M365 rollup; it cannot be the merge anchor." }
		elseif  ($appendLeaf -match '_Interactions(?:_\d{8}_\d{6})?\.csv$')  { $m365LeafErr = "'_Interactions.csv' is the CopilotInteraction rollup shape, not M365. Remove -IncludeM365Usage or supply a '_Rollup.csv' leaf." }
		elseif  ($appendLeaf -match '_Exploded(?:_\d{8}_\d{6})?\.csv$')      { $m365LeafErr = "'_Exploded.csv' is the M365 event-level output. To append under -Rollup/-RollupPlusRaw you need a '_Rollup.csv' anchor (event-level append via --exclude-record-ids is not currently exposed through -AppendFile)." }
		elseif  ($appendLeaf -notmatch '_Rollup(?:_\d{8}_\d{6})?\.csv$')     { $m365LeafErr = "Under -IncludeM365Usage with -Rollup/-RollupPlusRaw the -AppendFile leaf must end in '_Rollup.csv' or '_Rollup_<YYYYMMDD_HHMMSS>.csv' (the M365 rollup anchor). The UserStats, SessionCohort, and SessionStats sidecars are derived from the anchor stem and overwritten in-place." }
		if ($m365LeafErr) {
			Write-Host ""                                                                                                                                                                                  -ForegroundColor Red
			Write-Host ("ERROR: -AppendFile leaf '{0}' is not valid in this mode: {1}" -f $appendLeaf, $m365LeafErr)                                                                                          -ForegroundColor Red
			Write-Host ""                                                                                                                                                                                  -ForegroundColor Yellow
			Write-Host  "Expected: a '_Rollup.csv' or '_Rollup_<YYYYMMDD_HHMMSS>.csv' leaf (filename, full local path, or remote URL)."                                                                       -ForegroundColor Yellow
			Write-Host  "Example:  -AppendFile 'Purview_Audit_UsageActivity_CombinedActivityTypes_20260101_120000_Rollup.csv'"                                                                                -ForegroundColor Yellow
			Write-Host ""                                                                                                                                                                                  -ForegroundColor Yellow
			Write-Host  "If you do not yet have a Rollup target on the destination, run once WITHOUT -AppendFile to produce the initial timestamped Rollup (plus its UserStats / SessionCohort / SessionStats sidecars)," -ForegroundColor Gray
			Write-Host  "then point -AppendFile at that Rollup on subsequent runs (keep the timestamp or rename — both shapes are accepted)."                                                                -ForegroundColor Gray
			exit 1
		}
	}

	if ($treatAppendAsRollupTarget) {
		# Raw audit CSV uses the precomputed combined-audit leaf — which is the
		# single-activity name when $ActivityTypes is exactly one type, otherwise
		# CombinedActivityTypes. The post-export dynamic downgrade is suppressed
		# under -AppendFile, so the upfront prediction is what the log file (and
		# the final raw artifact) inherit.
		$OutputFile = Join-Path $OutputPath $_combinedAuditLeaf
	}
	elseif ($appendInputTier -eq 'SharePoint' -or $appendInputTier -eq 'Fabric') {
		# Remote URL: the final $OutputFile is the local scratch path the remote
		# pre-flight will populate (Join-Path $OutputPath (GetFileName URL)).
		$remoteName = [System.IO.Path]::GetFileName($AppendFile)
		$OutputFile = Join-Path $OutputPath $remoteName
	}
	elseif ([System.IO.Path]::IsPathRooted($AppendFile)) {
		# Full local path provided
		$OutputFile = $AppendFile
	} else {
		# Relative filename - combine with OutputPath
		$OutputFile = Join-Path $OutputPath $AppendFile
	}

	# Validate file exists. For Local-tier outputs this is a direct Test-Path. For
	# SharePoint / Fabric URLs, defer the existence check to the remote helpers
	# downstream (the remote pre-flight at Connect time will pull the file into
	# scratch; if the source does not exist there, the pull will raise a clear
	# remote error).
	# Skip the existence check entirely when we've routed AppendFile to the rollup
	# processor — $OutputFile is now a fresh raw-audit path the writer will create,
	# and the AppendFile target's existence is verified by the rollup pre-seed
	# block (Test-Path -LiteralPath $AppendFile in the rollup setup downstream).
	if (-not $treatAppendAsRollupTarget -and $appendInputTier -eq 'Local' -and -not (Test-Path $OutputFile)) {
		Write-Host "ERROR: Cannot append to file - file does not exist: $OutputFile" -ForegroundColor Red
		Write-Host "" -ForegroundColor Yellow
		Write-Host "The file must exist before you can append to it." -ForegroundColor Yellow
		Write-Host "Either:" -ForegroundColor Green
		Write-Host "  1. Create the file first by running without -AppendFile" -ForegroundColor Green
		Write-Host "  2. Verify the path and filename are correct" -ForegroundColor Green
		exit 1
	}

	# Note: Column validation happens after banner display
}
elseif ($ExportWorkbook) {
	# Excel workbook mode - determine final filename upfront so log file matches
	if ($CombineOutput) {
		# Single-tab workbook
		if ($IncludeUserInfo -and -not $UseEOM) {
			$OutputFile = Join-Path $OutputPath "Purview_Audit_CombinedUsageActivity_EntraUsers_MAClicensing_$global:ScriptRunTimestamp.xlsx"
		} else {
			$OutputFile = Join-Path $OutputPath "Purview_Audit_CombinedUsageActivity_$global:ScriptRunTimestamp.xlsx"
		}
	} else {
		# Multi-tab workbook
		$OutputFile = Join-Path $OutputPath "Purview_Audit_MultiTab_$global:ScriptRunTimestamp.xlsx"
	}
} elseif ($isCsv -and $initialCsvCombine) {
	# CSV combined-activity naming; EntraUsers exported separately.
	# Use the precomputed combined-audit leaf: when $ActivityTypes contains exactly
	# one type (and -IncludeM365Usage is not expanding the set), the leaf is
	# Purview_Audit_UsageActivity_<Type>_<ts>.csv so the log file (derived from
	# $OutputFile basename downstream) matches. Otherwise it is CombinedActivityTypes,
	# and the post-export dynamic single-activity downgrade renames the file (and
	# updates $OutputFile) when the actual data ends up containing a single type.
	$OutputFile = Join-Path $OutputPath $_combinedAuditLeaf
} else {
	$OutputFile = Join-Path $OutputPath "${filePrefix}_$global:ScriptRunTimestamp.$fileExtension"
}

# -Deidentify data-consistency guard. Refuse to mix deidentified and raw data in an append
# target (corrupts user joins / distinct counts), and refuse a NON-rollup append into an
# already-deidentified file (the whole-file post-pass would re-hash existing rows). Runs for
# any -AppendFile / -AppendUserInfo, in both deid and non-deid runs. Local targets only;
# remote (SharePoint/Fabric) append URLs are validated downstream after scratch download.
if ($AppendFile -or $AppendUserInfo) {
	$_deidResolve = {
		param([string]$p)
		if ([string]::IsNullOrWhiteSpace($p) -or $p -match '^https?://') { return $null }
		if ([System.IO.Path]::IsPathRooted($p)) { return $p }
		return (Join-Path $OutputPath $p)
	}
	$_deidGuardTargets = @()
	if ($AppendFile) {
		# Rollup appends target the user's rollup file ($AppendFile); non-rollup targets $OutputFile.
		$_afTarget = if ($Rollup -or $RollupPlusRaw) { & $_deidResolve $AppendFile } else { $OutputFile }
		if ($_afTarget) { $_deidGuardTargets += @{ Path = $_afTarget; Label = '-AppendFile' } }
	}
	if ($AppendUserInfo) {
		$_auiTarget = & $_deidResolve $AppendUserInfo
		if ($_auiTarget) { $_deidGuardTargets += @{ Path = $_auiTarget; Label = '-AppendUserInfo' } }
	}
	if ($_deidGuardTargets.Count -gt 0) {
		try {
			Assert-PaxDeidAppendConsistency -Targets $_deidGuardTargets -IsRollup ([bool]($Rollup -or $RollupPlusRaw))
		} catch {
			Write-Host "" -ForegroundColor Red
			Write-Host ("ERROR: {0}" -f $_.Exception.Message) -ForegroundColor Red
			exit 1
		}
	}
}

# Ensure output directory exists after possible OutputPath override
if (-not (Test-Path $OutputPath)) { New-Item -Path $OutputPath -ItemType Directory -Force | Out-Null }

# When ExportWorkbook mode, set up intermediate CSV path (OutputFile stays as final .xlsx for log naming)
if ($ExportWorkbook -and -not $AppendFile) {
	# CSV intermediate file uses same base name but .csv extension
	$script:CsvOutputFile = Join-Path $OutputPath ([System.IO.Path]::GetFileNameWithoutExtension($OutputFile) + ".csv")
} else {
	$script:CsvOutputFile = $OutputFile
}

# ============================================================
# CHECKPOINT SYSTEM: Initialize for new runs or set paths for resume
# ============================================================
# Checkpoint is enabled for ALL auth modes (AppRegistration, WebLogin, DeviceCode)
# Enables resume after Ctrl+C, network interruptions, system restarts, or any failure
$script:CheckpointEnabled = (-not $RAWInputCSV) -and (-not $OnlyUserInfo)

# NOTE: Use $ResumeSpecified here (set early via RemainingArgs parsing) rather than $script:IsResumeMode
# which is only set later during resume detection. This skips new checkpoint creation when -Resume is specified.
if ($ResumeSpecified) {
	# Resume mode: checkpoint paths will be set later during resume detection
	# Skip all checkpoint initialization here - it will be handled in the resume detection block
	$script:FinalOutputPath = $null  # Will be set during resume
	$script:PartialOutputPath = $null  # Will be set during resume
	# Also skip log file setup - will be set after checkpoint is loaded
	$script:DeferLogFileSetup = $true
}
elseif ($script:CheckpointEnabled) {
	# New run with checkpoint enabled: Add _PARTIAL suffix
	$script:FinalOutputPath = $OutputFile
	$dir = Split-Path $OutputFile -Parent
	$baseName = [System.IO.Path]::GetFileNameWithoutExtension($OutputFile)
	$ext = [System.IO.Path]::GetExtension($OutputFile)
	$script:PartialOutputPath = Join-Path $dir "${baseName}_PARTIAL${ext}"
	$OutputFile = $script:PartialOutputPath
	# For ExportWorkbook mode, CsvOutputFile must use .csv extension (not .xlsx from PartialOutputPath)
	if ($ExportWorkbook) {
		$script:CsvOutputFile = Join-Path $dir "${baseName}_PARTIAL.csv"
	} else {
		$script:CsvOutputFile = $script:PartialOutputPath
	}
	
	# Initialize checkpoint file for this run with ALL parameters for complete state restoration
	$baseFileName = Split-Path $script:FinalOutputPath -Leaf
	$allParams = @{
		# Date range
		StartDate = $StartDate
		EndDate = $EndDate
		# Activity/Record filtering
		ActivityTypes = $ActivityTypes
		RecordTypes = $RecordTypes
		ServiceTypes = $ServiceTypes
		UserIds = $UserIds
		GroupNames = $GroupNames
		# Agent filtering
		AgentId = $AgentId
		AgentsOnly = $AgentsOnly.IsPresent
		ExcludeAgents = $ExcludeAgents.IsPresent
		# Prompt filtering
		PromptFilter = $PromptFilter
		# Schema/Explosion
		ExplodeArrays = $ExplodeArrays.IsPresent
		ExplodeDeep = $ExplodeDeep.IsPresent
		FlatDepth = $FlatDepth
		StreamingSchemaSample = $StreamingSchemaSample
		StreamingChunkSize = $StreamingChunkSize
		# M365/User info
		IncludeM365Usage = $IncludeM365Usage.IsPresent
		IncludeUserInfo = $IncludeUserInfo.IsPresent
		IncludeCopilotInteraction = $IncludeCopilotInteraction.IsPresent
		ExcludeCopilotInteraction = $ExcludeCopilotInteraction.IsPresent
		IncludeAgent365Info = $IncludeAgent365Info.IsPresent
		OnlyAgent365Info = $OnlyAgent365Info.IsPresent
		# Partitioning
		BlockHours = $BlockHours
		PartitionHours = $PartitionHours
		MaxPartitions = $MaxPartitions
		# Output
		ExportWorkbook = $ExportWorkbook.IsPresent
		CombineOutput = $CombineOutput.IsPresent
		Deidentify = $Deidentify.IsPresent
		# FillerLabel: resolved hierarchy-filler mode (none|self|manager|fixed) + literal label.
		FillerLabel = $script:HierarchyFillMode
		FillerLabelText = $script:HierarchyFillLabel
		# uploads to the original destinations — without these, Initialize-CheckpointForNewRun
		# persists empty strings and the resume restore has nothing to rehydrate).
		OutputPathUserInfo = $OutputPathUserInfo
		OutputPathAgent365Info = $OutputPathAgent365Info
		OutputPathLog = $OutputPathLog
		AppendFile = $AppendFile
		AppendUserInfo = $AppendUserInfo
		AppendAgent365Info = $AppendAgent365Info
		# Rollup mode (required so the resume restore re-arms -Rollup / -RollupPlusRaw
		# correctly; without these the post-processor falls back to '-Rollup' semantics
		# and deletes the raw EntraUsers CSV that -RollupPlusRaw is supposed to preserve).
		Rollup = $Rollup.IsPresent
		RollupPlusRaw = $RollupPlusRaw.IsPresent
		Dashboard = $Dashboard
		# Auth (no secrets)
		Auth = $Auth
		TenantId = $TenantId
		ClientId = $ClientId
		# Other
		ResultSize = $ResultSize
		MaxConcurrency = $MaxConcurrency
		MaxMemoryMB = $MaxMemoryMB
		ExplosionThreads = $ExplosionThreads
		UseEOM = $UseEOM.IsPresent
		AutoCompleteness = $AutoCompleteness.IsPresent
		IncludeTelemetry = $IncludeTelemetry.IsPresent
	}
	Initialize-CheckpointForNewRun -OutputPath $OutputPath -BaseOutputFileName $baseFileName -RunTimestamp $global:ScriptRunTimestamp -StartDate (script:Parse-DateSafe $StartDate) -EndDate (script:Parse-DateSafe $EndDate) -AllParameters $allParams | Out-Null
}
else {
	# No checkpoint needed (AppRegistration mode or RAWInputCSV or OnlyUserInfo)
	$script:FinalOutputPath = $OutputFile
	$script:PartialOutputPath = $null
}

# Update LogFile to match OutputFile base name (extension swapped to .log).
# When -OutputPathLog is bound to a Local path or Fabric Files/ URL, route the log
# there instead. Remote tiers (SharePoint/Fabric) for the audit destination still
# write the log to scratch and the existing run-finalization path uploads from there.
# Skip for resume mode - log file will be set after checkpoint is loaded
if (-not $script:DeferLogFileSetup) {
	$logBaseName = [System.IO.Path]::GetFileNameWithoutExtension($OutputFile)
	# Under non-rollup -AppendFile, $OutputFile is the customer's AppendFile target
	# (or the _PARTIAL variant of it under checkpoint mode), so deriving the log
	# basename from it would (a) inherit the target's ORIGINAL creation timestamp
	# and (b) inherit the target's per-activity-type suffix (e.g.
	# "_UsageActivity_CopilotInteraction") that the standard non-append path
	# does NOT put in the log filename. Non-append runs name their log
	# ${filePrefix}_<currentTs>.log (i.e. Purview_Audit_<currentTs>.log) — derived
	# from the initial pre-splitter $OutputFile basename which itself starts as
	# ${filePrefix}_<currentTs>.csv before the per-activity splitter renames its
	# outputs to the long form. Match that canonical convention here so the
	# append run's log file is named identically to the non-append run's log:
	# the run log is a per-run artifact and is decoupled from the AppendFile
	# target CSV's leaf identity. The _PARTIAL suffix convention (stripped at
	# successful run-completion) is preserved.
	if ($AppendFile -and -not ($Rollup -or $RollupPlusRaw)) {
		$_hadPartialSuffix = ($logBaseName -match '_PARTIAL$')
		$_currentRunTs = [string]$global:ScriptRunTimestamp
		$_canonicalPfx = if ($filePrefix) { [string]$filePrefix } else { 'Purview_Audit' }
		$_canonicalLogBase = if ($_currentRunTs) { "${_canonicalPfx}_${_currentRunTs}" } else { $_canonicalPfx }
		$logBaseName = if ($_hadPartialSuffix) { "${_canonicalLogBase}_PARTIAL" } else { $_canonicalLogBase }
	}
	$logDir = Split-Path $OutputFile -Parent
	try {
		$dtL = script:Resolve-DataTypePaths -DataType 'Log' -DefaultBasename ("{0}.log" -f $logBaseName)
		if ($dtL -and $dtL.IsBound -and $dtL.Tier -eq 'Local') {
			$logDir = $dtL.EffectiveDir
			if ($dtL.Basename) { $logBaseName = [System.IO.Path]::GetFileNameWithoutExtension($dtL.Basename) }
			if (-not (Test-Path -LiteralPath $logDir -PathType Container)) {
				New-Item -Path $logDir -ItemType Directory -Force | Out-Null
			}
		}
	} catch {}
	$finalLogFile = Join-Path $logDir ("{0}.log" -f $logBaseName)

	# Bootstrap-log migration: if the current
	# $script:LogFile is a bootstrap temp-path file, move its contents to the
	# resolved final location so the entire run (including pre-resolution
	# entries) lands in one file. Falls back to copy+delete if Move-Item
	# can't cross a volume boundary.
	if ($script:LogFileIsBootstrap -and $script:LogFile -and (Test-Path -LiteralPath $script:LogFile)) {
		try {
			if (-not (Test-Path -LiteralPath $logDir -PathType Container)) {
				New-Item -Path $logDir -ItemType Directory -Force | Out-Null
			}
			Move-Item -LiteralPath $script:LogFile -Destination $finalLogFile -Force -ErrorAction Stop
		} catch {
			try {
				$bootstrapContent = Get-Content -LiteralPath $script:LogFile -Raw -ErrorAction Stop
				Set-Content -LiteralPath $finalLogFile -Value $bootstrapContent -Encoding UTF8 -ErrorAction Stop
				Remove-Item -LiteralPath $script:LogFile -Force -ErrorAction SilentlyContinue
			} catch {
				Microsoft.PowerShell.Utility\Write-Host ("WARNING: Could not migrate bootstrap log to final location ({0} -> {1}): {2}" -f $script:LogFile, $finalLogFile, $_.Exception.Message) -ForegroundColor Yellow
			}
		}
		$script:LogFileIsBootstrap = $false
	}

	$script:LogFile = $finalLogFile
	$LogFile = $script:LogFile
}

# Flush buffered logs now that log file is finalized (skip for resume - will flush after checkpoint load)
if ($script:LogBuffer -and $script:LogBuffer.Count -gt 0) {
	foreach ($entry in $script:LogBuffer) {
		try { Add-Content -Path $script:LogFile -Value $entry -Encoding UTF8 -ErrorAction SilentlyContinue } catch {}
	}
	$script:LogBuffer.Clear()
}

# Note: $scriptMode already defined earlier for validation - reformat for display consistency
$scriptModeDisplay = if ($ExplodeDeep) { "Deep Column Explosion" } elseif ($ExplodeArrays -or $ForcedRawInputCsvExplosion) { if ($ForcedRawInputCsvExplosion -and -not $ExplodeArrays.IsPresent -and -not $ExplodeDeep.IsPresent) { "Array Explosion (RAWInput implied)" } else { "Array Explosion" } } else { "Standard (1:1)" }

# Clean display names — strip _PARTIAL suffix so the startup banner always shows the expected final filename.
# Then route through Get-DisplayPath so remote -OutputPath* runs show the remote
# destination URL (where the artifact actually lives after upload), not the local scratch path.
$displayOutputFile = $OutputFile -replace '_PARTIAL(?=\.[^.]+$)', ''
$displayLogFile    = $LogFile    -replace '_PARTIAL(?=\.log$)',    ''
$displayOutputFile = Get-DisplayPath -LocalPath $displayOutputFile
$displayLogFile    = Get-DisplayPath -LocalPath $displayLogFile

# Skip banner output to log file in resume mode (log file not set yet - will be set after checkpoint loads)
if (-not $script:DeferLogFileSetup) {
@"
=== Portable Audit eXporter (PAX) - Purview Audit Log Exporter ===
Script Start Time (UTC): $((Get-Date).ToUniversalTime().ToString('yyyy-MM-dd HH:mm:ss')) UTC
Script Version: v$ScriptVersion
Mode: $scriptModeDisplay
Date Range: $(if ($RAWInputCSV) { if ([string]::IsNullOrWhiteSpace($StartDate) -and [string]::IsNullOrWhiteSpace($EndDate)) { 'Full CSV (no date filter)' } else { "$StartDate (inclusive) to $EndDate (exclusive) (filters)" } } else { "$StartDate (inclusive) to $EndDate (exclusive)" })
Output File: $displayOutputFile
Log File: $displayLogFile
========================================================

"@ | Out-File -FilePath $LogFile -Encoding UTF8 -Append
}


# Fast-path: ensure M365 usage bundle is applied before output summary in raw/replay scenarios
if ($IncludeM365Usage -and -not ($PSBoundParameters.ContainsKey('ActivityTypes'))) {
	$ActivityTypes = @($m365UsageActivityBundle + $copilotBaseActivityType) | Select-Object -Unique
	# Activity types will be displayed in "Activity Types for This Run" section
}

# Display active mode (Replay, EOM, or Graph API)
# Resume: suppress the parse-time mode/permissions/rollup/start/mode banner.
# On -Resume only the bootstrap log path, $Auth=WebLogin default, and a NEW
# $startTimeStamp are in scope at this point — the real values are restored
# AFTER this block by Read-Checkpoint. The resume restore block and the
# post-restore Parameter Snapshot print the authoritative auth context, file
# paths, and timestamps. Without this gate the early banner shows
# DELEGATED / WebLogin / bootstrap-log / new-timestamp on every resume run.
if (-not $ResumeSpecified) {
Write-LogHost ""
if ($RAWInputCSV) {
	Write-LogHost "═══════════════════════════════════════════════════════" -ForegroundColor Cyan
	Write-LogHost "  REPLAY MODE: Offline CSV (no service connections)" -ForegroundColor Cyan
	Write-LogHost "═══════════════════════════════════════════════════════" -ForegroundColor Cyan
	Write-LogHost "  Source: $RAWInputCSV" -ForegroundColor White
	Write-LogHost "  Explosion: $scriptModeDisplay" -ForegroundColor White
	Write-LogHost "═══════════════════════════════════════════════════════" -ForegroundColor Cyan
}
elseif ($UseEOM) {
	Write-LogHost "═══════════════════════════════════════════════════════" -ForegroundColor Cyan
	Write-LogHost "  QUERY MODE: Exchange Online Management" -ForegroundColor Cyan
	Write-LogHost "═══════════════════════════════════════════════════════" -ForegroundColor Cyan
	Write-LogHost "  API Method:       Search-UnifiedAuditLog cmdlet" -ForegroundColor White
	Write-LogHost "  Module:           ExchangeOnlineManagement" -ForegroundColor White
	Write-LogHost "  Authentication:   $Auth" -ForegroundColor White
	Write-LogHost "  Parallel Support: DISABLED (serial-only processing)" -ForegroundColor Yellow
	Write-LogHost "  Permissions:      Exchange Online RBAC roles required" -ForegroundColor White
	Write-LogHost "                    (View-Only Audit Logs, Compliance Management)" -ForegroundColor Gray
	Write-LogHost "═══════════════════════════════════════════════════════" -ForegroundColor Cyan
}
else {
	# Determine effective auth context(s) for this run:
	#   - audit phase context (app-only or delegated)
	#   - agent 365 phase context (always delegated when -IncludeAgent365Info / -OnlyAgent365Info)
	# When -Auth AppRegistration is combined with Agent 365, BOTH contexts apply (sequentially).
	# ManagedIdentity is treated as app-only (Connect-MgGraph -Identity uses application permissions
	# from the user-assigned MI's service principal); it cannot satisfy Agent 365 (no interactive user).
	$isAppOnlyAuth   = ($Auth -eq 'AppRegistration' -or $Auth -eq 'ManagedIdentity')
	$isManagedId     = ($Auth -eq 'ManagedIdentity')
	$auditContextLbl = if ($isManagedId) { 'APP-ONLY (managed identity / application permissions)' }
					   elseif ($isAppOnlyAuth) { 'APP-ONLY (application permissions)' }
					   else { 'DELEGATED (interactive user sign-in)' }
	$dualContextRun  = ($Auth -eq 'AppRegistration') -and ($IncludeAgent365Info -or $OnlyAgent365Info)

	Write-LogHost "═══════════════════════════════════════════════════════" -ForegroundColor Green
	Write-LogHost "  QUERY MODE: Microsoft Graph Security API (Default)" -ForegroundColor Green
	Write-LogHost "═══════════════════════════════════════════════════════" -ForegroundColor Green
	Write-LogHost "  API Method:       REST-based audit log queries" -ForegroundColor White
	Write-LogHost "  Module:           Microsoft.Graph.Security" -ForegroundColor White
	Write-LogHost "  Authentication:   $Auth (OAuth 2.0)" -ForegroundColor White
	$parallelStatus = if ($PSVersionTable.PSVersion.Major -ge 7) { "AVAILABLE (PowerShell 7+)" } else { "LIMITED (PowerShell 5.1 detected)" }
	Write-LogHost "  Parallel Support: $parallelStatus" -ForegroundColor Green

	# ---- Auth Context summary ----
	Write-LogHost "" -ForegroundColor White
	if ($dualContextRun) {
		Write-LogHost "  Auth Context:     DUAL-CONTEXT RUN" -ForegroundColor Yellow
		Write-LogHost "                      Phase 1 (Audit):     $auditContextLbl" -ForegroundColor White
		Write-LogHost "                      Phase 2 (Agent 365): DELEGATED (interactive sign-in)" -ForegroundColor White
		Write-LogHost "                    Reason: -Auth AppRegistration cannot satisfy the Agent 365" -ForegroundColor Gray
		Write-LogHost "                    endpoint (no app-only Graph scope exists). The Phase 2" -ForegroundColor Gray
		Write-LogHost "                    interactive sign-in is requested UP-FRONT (immediately after" -ForegroundColor Gray
		Write-LogHost "                    Phase 1 connects) so the run can proceed unattended afterward." -ForegroundColor Gray
	} else {
		Write-LogHost "  Auth Context:     $auditContextLbl" -ForegroundColor White
	}

	# ---- Permissions list ----
	Write-LogHost "" -ForegroundColor White
	Write-LogHost "  Permissions Required for THIS run:" -ForegroundColor White
	Write-LogHost "                    (Yellow = required this run; DarkGray = not needed this run)" -ForegroundColor Gray

	# Build conditional Tag legend so only relevant tags are shown:
	#   [App-only]   appears under -Auth AppRegistration OR -Auth ManagedIdentity (both are app-only)
	#   [Delegated]  appears under any non-app-only auth, OR under AppRegistration + Agent 365
	#                (Agent 365 always uses delegated scopes even when audit is app-only)
	#   [Role]       appears only when Agent 365 is in this run (it is the only section that needs a role)
	#   [Azure RBAC] appears only when an -OutputPath* value is a OneLake URL (Fabric uses storage RBAC, not Graph)
	$tagLegendLines = New-Object System.Collections.Generic.List[string]
	if ($isAppOnlyAuth) {
		if ($isManagedId) {
			$tagLegendLines.Add('[App-only]   = application permission on managed identity service principal')
		} else {
			$tagLegendLines.Add('[App-only]   = grant on app registration as Application permission')
		}
	}
	if ((-not $isAppOnlyAuth) -or $IncludeAgent365Info -or $OnlyAgent365Info) {
		$tagLegendLines.Add('[Delegated]  = consented at interactive sign-in')
	}
	if ($IncludeAgent365Info -or $OnlyAgent365Info) {
		$tagLegendLines.Add('[Role]       = Entra directory role on signed-in user')
	}
	if ($script:RemoteOutputMode -eq 'Fabric') {
		$tagLegendLines.Add('[Azure RBAC] = Azure role assignment on Fabric workspace (not a Graph scope)')
	}
	if ($tagLegendLines.Count -gt 0) {
		Write-LogHost ("                    Tag legend:  {0}" -f $tagLegendLines[0]) -ForegroundColor Gray
		for ($legendIdx = 1; $legendIdx -lt $tagLegendLines.Count; $legendIdx++) {
			Write-LogHost ("                                 {0}" -f $tagLegendLines[$legendIdx]) -ForegroundColor Gray
		}
	}

	# Audit phase scopes (use the audit context tag)
	$auditTag = if ($isAppOnlyAuth) { '[App-only] ' } else { '[Delegated]' }
	if (-not $OnlyUserInfo -and -not $OnlyAgent365Info) {
		Write-LogHost "" -ForegroundColor White
		Write-LogHost "                    Audit query (REQUIRED - this run reads audit logs):" -ForegroundColor White
		Write-LogHost ("                      {0} AuditLogsQuery.Read.All        (umbrella - all audit record types)" -f $auditTag) -ForegroundColor Yellow
	} else {
		$auditSkipReason = if ($OnlyAgent365Info) { '-OnlyAgent365Info' } else { '-OnlyUserInfo' }
		Write-LogHost "" -ForegroundColor White
		Write-LogHost ("                    Audit query (NOT NEEDED - {0} skips audit queries):" -f $auditSkipReason) -ForegroundColor White
		Write-LogHost ("                      {0} AuditLogsQuery.Read.All        (umbrella - all audit record types)" -f $auditTag) -ForegroundColor DarkGray
	}

	# M365 usage bundle (audit context)
	if ($IncludeM365Usage) {
		Write-LogHost "" -ForegroundColor White
		Write-LogHost "                    M365 usage bundle (REQUIRED - because -IncludeM365Usage is set):" -ForegroundColor White
		Write-LogHost ("                      {0} AuditLogsQuery-Exchange.Read.All" -f $auditTag) -ForegroundColor Yellow
		Write-LogHost ("                      {0} AuditLogsQuery-SharePoint.Read.All" -f $auditTag) -ForegroundColor Yellow
		Write-LogHost ("                      {0} AuditLogsQuery-OneDrive.Read.All" -f $auditTag) -ForegroundColor Yellow
	} else {
		Write-LogHost "" -ForegroundColor White
		Write-LogHost "                    M365 usage bundle (only required with -IncludeM365Usage):" -ForegroundColor White
		Write-LogHost ("                      {0} AuditLogsQuery-Exchange.Read.All" -f $auditTag) -ForegroundColor DarkGray
		Write-LogHost ("                      {0} AuditLogsQuery-SharePoint.Read.All" -f $auditTag) -ForegroundColor DarkGray
		Write-LogHost ("                      {0} AuditLogsQuery-OneDrive.Read.All" -f $auditTag) -ForegroundColor DarkGray
	}

	# Entra directory + license enrichment (audit context)
	if ($IncludeUserInfo -or $OnlyUserInfo) {
		$userInfoTrigger = if ($OnlyUserInfo) { '-OnlyUserInfo' } else { '-IncludeUserInfo' }
		Write-LogHost "" -ForegroundColor White
		Write-LogHost ("                    Entra directory + license enrichment (REQUIRED - {0} is set):" -f $userInfoTrigger) -ForegroundColor White
		Write-LogHost ("                      {0} User.Read.All                  (read /users)" -f $auditTag) -ForegroundColor Yellow
		Write-LogHost ("                      {0} Organization.Read.All          (read /subscribedSkus)" -f $auditTag) -ForegroundColor Yellow
	} else {
		Write-LogHost "" -ForegroundColor White
		Write-LogHost "                    Entra directory + license enrichment (only required with -IncludeUserInfo or -OnlyUserInfo):" -ForegroundColor White
		Write-LogHost ("                      {0} User.Read.All                  (read /users)" -f $auditTag) -ForegroundColor DarkGray
		Write-LogHost ("                      {0} Organization.Read.All          (read /subscribedSkus)" -f $auditTag) -ForegroundColor DarkGray
	}

	# Group expansion (audit context)
	if ($GroupNames -and $GroupNames.Count -gt 0) {
		Write-LogHost "" -ForegroundColor White
		Write-LogHost "                    Group expansion (REQUIRED - because -GroupNames is set):" -ForegroundColor White
		Write-LogHost ("                      {0} GroupMember.Read.All           (read /groups + /groups/{{id}}/members)" -f $auditTag) -ForegroundColor Yellow
	} else {
		Write-LogHost "" -ForegroundColor White
		Write-LogHost "                    Group expansion (only required with -GroupNames):" -ForegroundColor White
		Write-LogHost ("                      {0} GroupMember.Read.All           (read /groups + /groups/{{id}}/members)" -f $auditTag) -ForegroundColor DarkGray
	}

	# Remote output - SharePoint (audit context: same Graph token reused for SP drives API)
	if ($script:RemoteOutputMode -eq 'SharePoint') {
		Write-LogHost "" -ForegroundColor White
		Write-LogHost "                    Remote output - SharePoint (REQUIRED - because -OutputPath resolves to a SharePoint URL):" -ForegroundColor White
		Write-LogHost ("                      {0} Sites.ReadWrite.All            (resolve site/drive via /sites + /drives)" -f $auditTag) -ForegroundColor Yellow
		Write-LogHost ("                      {0} Files.ReadWrite.All            (PUT/createUploadSession to /drives/{{id}}/items)" -f $auditTag) -ForegroundColor Yellow
		Write-LogHost "                    Destination user/identity ALSO needs at least Member access on the" -ForegroundColor Gray
		Write-LogHost "                    target SharePoint site (granted via SharePoint, not Graph)." -ForegroundColor Gray
	} else {
		Write-LogHost "" -ForegroundColor White
		Write-LogHost "                    Remote output - SharePoint (only required when an -OutputPath* value is a SharePoint URL):" -ForegroundColor White
		Write-LogHost ("                      {0} Sites.ReadWrite.All            (resolve site/drive via /sites + /drives)" -f $auditTag) -ForegroundColor DarkGray
		Write-LogHost ("                      {0} Files.ReadWrite.All            (PUT/createUploadSession to /drives/{{id}}/items)" -f $auditTag) -ForegroundColor DarkGray
	}

	# Remote output - Fabric / OneLake (separate token: storage.azure.com audience via Az.Accounts;
	# Azure RBAC, not Graph scopes — this is the only section that uses the [Azure RBAC] tag)
	if ($script:RemoteOutputMode -eq 'Fabric') {
		Write-LogHost "" -ForegroundColor White
		Write-LogHost "                    Remote output - Fabric/OneLake (REQUIRED - because -OutputPath resolves to a OneLake URL):" -ForegroundColor White
		Write-LogHost "                      [Azure RBAC] Storage Blob Data Contributor on the Fabric workspace" -ForegroundColor Yellow
		Write-LogHost "                                   (assign at workspace scope to the audit identity)" -ForegroundColor Yellow
		Write-LogHost "                      [Azure RBAC] Contributor on the Fabric workspace (Fabric portal)" -ForegroundColor Yellow
		Write-LogHost "                                   (Workspace settings -> Manage access; required by some" -ForegroundColor Yellow
		Write-LogHost "                                    tenants for OneLake DFS write access)" -ForegroundColor Yellow
		Write-LogHost "                    NOTE: OneLake uses an INDEPENDENT token (audience https://storage.azure.com/)" -ForegroundColor Gray
		Write-LogHost "                    acquired via Az.Accounts. Microsoft Graph scopes do NOT apply here." -ForegroundColor Gray
	} else {
		Write-LogHost "" -ForegroundColor White
		Write-LogHost "                    Remote output - Fabric/OneLake (only required when an -OutputPath* value is a OneLake URL):" -ForegroundColor White
		Write-LogHost "                      [Azure RBAC] Storage Blob Data Contributor on Fabric workspace" -ForegroundColor DarkGray
		Write-LogHost "                      [Azure RBAC] Contributor on Fabric workspace (Fabric portal)" -ForegroundColor DarkGray
	}

	# Managed identity advisory - shown only under -Auth ManagedIdentity
	if ($isManagedId) {
		Write-LogHost "" -ForegroundColor White
		Write-LogHost "                    Managed identity bootstrap (REQUIRED - because -Auth ManagedIdentity is set):" -ForegroundColor White
		Write-LogHost "                      All scopes above must be ADMIN-CONSENTED on the managed identity's" -ForegroundColor Yellow
		Write-LogHost "                      service principal as APPLICATION permissions (not delegated). One-time" -ForegroundColor Yellow
		Write-LogHost "                      bootstrap via fabric_resources/.../Prereqs/Grant-PAXPermissions.ps1." -ForegroundColor Yellow
		if ($env:AZURE_CLIENT_ID) {
			Write-LogHost ("                      AZURE_CLIENT_ID is set: {0}" -f $env:AZURE_CLIENT_ID) -ForegroundColor Gray
		} else {
			Write-LogHost "                      AZURE_CLIENT_ID is NOT set; system-assigned MI will be used (if any)." -ForegroundColor Gray
		}
	}

	# Agent 365 enrichment - ALWAYS uses delegated scopes; ALSO requires Entra role.
	# Suppressed from the permissions table while the Agent 365 switches are parked at
	# the temporarily-disabled gate. Restore this block when the switches are re-enabled.
	<#
	if ($IncludeAgent365Info -or $OnlyAgent365Info) {
		$agent365Trigger = if ($OnlyAgent365Info) { '-OnlyAgent365Info' } else { '-IncludeAgent365Info' }
		Write-LogHost "" -ForegroundColor White
		Write-LogHost ("                    Agent 365 enrichment (REQUIRED - {0} is set):" -f $agent365Trigger) -ForegroundColor White
		if ($dualContextRun) {
			Write-LogHost "                    NOTE: Performed in a SEPARATE delegated context (Phase 2)," -ForegroundColor Gray
			Write-LogHost "                          prompted UP-FRONT immediately after Phase 1 connects." -ForegroundColor Gray
			Write-LogHost "                          Your app registration is NOT used for these scopes." -ForegroundColor Gray
		}
		Write-LogHost "                      [Delegated] CopilotPackages.Read.All     (read /copilot/admin/catalog/packages)" -ForegroundColor Yellow
		Write-LogHost "                      [Delegated] Application.Read.All         (resolve developer/owner via /applications)" -ForegroundColor Yellow
		Write-LogHost "                      [Role]      AI Administrator              (preferred - least privilege)" -ForegroundColor Yellow
		Write-LogHost "                                  -- OR --" -ForegroundColor Gray
		Write-LogHost "                      [Role]      Global Administrator          (alternative)" -ForegroundColor Yellow
		Write-LogHost "                    The signed-in user MUST hold the Entra directory role above;" -ForegroundColor Gray
		Write-LogHost "                    delegated Graph consent ALONE is not sufficient (returns 403)." -ForegroundColor Gray
	} else {
		Write-LogHost "" -ForegroundColor White
		Write-LogHost "                    Agent 365 enrichment (only required with -IncludeAgent365Info or -OnlyAgent365Info):" -ForegroundColor White
		Write-LogHost "                      [Delegated] CopilotPackages.Read.All     (read /copilot/admin/catalog/packages)" -ForegroundColor DarkGray
		Write-LogHost "                      [Delegated] Application.Read.All         (resolve developer/owner via /applications)" -ForegroundColor DarkGray
		Write-LogHost "                      [Role]      AI Administrator OR Global Administrator (signed-in user)" -ForegroundColor DarkGray
	}
	#>

	Write-LogHost "═══════════════════════════════════════════════════════" -ForegroundColor Green
}
Write-LogHost ""

# Per-data-type destination banner. Emitted whenever any -OutputPath* switch was supplied,
# or whenever the inferred Purview destination is remote (SP/Fabric). Shows resolved tier,
# full destination, and append surface for each data type in scope. Sits between the
# permissions banner and the rollup banner so users can see at a glance where each
# customer-visible artifact (CSV/XLSX/log) will land.
$anyDestBound = $false
foreach ($k in @('Purview','UserInfo','Agent365Info','Log')) {
	if ($script:DestIsBound.ContainsKey($k) -and $script:DestIsBound[$k]) { $anyDestBound = $true; break }
}
# Bound -Append* values are destination bindings too — they tell the
# run where the canonical artifact lives. Treat them as such so the banner doesn't
# go silent on a pure -AppendFile/-AppendUserInfo/-AppendAgent365Info run with no
# -OutputPath* in scope.
if (-not $anyDestBound -and ($AppendFile -or $AppendUserInfo -or $AppendAgent365Info)) {
	$anyDestBound = $true
}
if ($script:RemoteOutputMode -ne 'None' -or $anyDestBound) {
	$scratchDirDisplay  = if ($OutputPath.Length -le 70) { $OutputPath } else { $OutputPath.Substring(0, 67) + '...' }
	$bannerHeader = if ($script:RemoteOutputMode -ne 'None') { "REMOTE OUTPUT MODE: $script:RemoteOutputMode" } else { 'OUTPUT DESTINATIONS' }
	Write-LogHost "═══════════════════════════════════════════════════════" -ForegroundColor Cyan
	Write-LogHost ("  {0}" -f $bannerHeader) -ForegroundColor Cyan
	Write-LogHost "═══════════════════════════════════════════════════════" -ForegroundColor Cyan
	if ($script:RemoteOutputMode -ne 'None') {
		# Top-line destination URL removed: per-data-type rows below carry the
		# authoritative destination for each stream (which may differ across
		# streams even within a single tier). Keep only auth + scratch dir here.
		Write-LogHost ("    Auth        : {0}" -f $Auth) -ForegroundColor White
		Write-LogHost "    Scratch dir : $scratchDirDisplay" -ForegroundColor White
	}
	# Per-data-type rows (one line per data type in scope).
	$dataTypeRows = @(
		@{ Key = 'Purview'      ; Label = 'Purview audit  '; ScopeCondition = $true ; AppendVar = $AppendFile ; AppendName = 'AppendFile' },
		@{ Key = 'UserInfo'     ; Label = 'EntraUsers CSV '; ScopeCondition = ($IncludeUserInfo -or $OnlyUserInfo) ; AppendVar = $AppendUserInfo ; AppendName = 'AppendUserInfo' },
		@{ Key = 'Agent365Info' ; Label = 'Agent 365 CSV  '; ScopeCondition = ($IncludeAgent365Info -or $OnlyAgent365Info) ; AppendVar = $AppendAgent365Info ; AppendName = 'AppendAgent365Info' },
		@{ Key = 'Log'          ; Label = 'Run log        '; ScopeCondition = $true ; AppendVar = $null ; AppendName = $null }
	)
	# Always emit the per-data-type rows when the banner shows at all
	# (a run with only -OutputPath — no per-stream override and no Append* — must
	# still show what each stream resolves to).
	Write-LogHost "" -ForegroundColor White
	Write-LogHost "    Per-data-type destinations:" -ForegroundColor White
	foreach ($row in $dataTypeRows) {
		if (-not $row.ScopeCondition) { continue }
		$tier = if ($script:DestTier.ContainsKey($row.Key)) { $script:DestTier[$row.Key] }
		        elseif ($row.Key -eq 'Purview' -and $script:DestTier.ContainsKey('Purview')) { $script:DestTier['Purview'] }
		        elseif ($row.Key -eq 'Log' -and $script:DestTier.ContainsKey('Purview')) {
		            # Log inherits the Purview tier when -OutputPathLog wasn't bound — the
		            # log lives in the Purview scratch dir (Local) or is uploaded alongside
		            # the audit CSV on remote runs.
		            $script:DestTier['Purview']
		        }
		        else { '(default)' }
		# Path resolution: prefer the bound Append target (it IS the destination
		# when -Append* is set), then a resolved FILE URL per row, then sensible
		# defaults.
		#
		# Every row renders as <folder>/<expected-leaf> via Get-DisplayPath (or a
		# pattern leaf in per-activity-split mode where the leaf varies by
		# ActivityType), so adjacent rows in the same banner stay internally
		# consistent (file URL on every row, not a mix of folder + file URLs)
		# and give customers a verifiable destination per stream. The Run log
		# row uses the same Get-DisplayPath transform via $displayLogFile so the
		# banner and the 'Log File:' preamble agree on the final destination.
		$path = if ($row.AppendName -and $row.AppendVar) { $row.AppendVar }
		        elseif ($row.Key -eq 'Purview') {
		            if ($OutputFile) {
		                # Single-CSV cases: -CombineOutput on, OR a single-activity-type
		                # run (where the file leaf is fully determined). In both cases
		                # $OutputFile is the authoritative source for the final leaf.
		                $_isSingleActivity = ($ActivityTypes -and @($ActivityTypes).Count -eq 1)
		                if ($CombineOutput -or $_isSingleActivity) {
		                    $_pvFinal = $OutputFile -replace '_PARTIAL(?=\.[^.]+$)', ''
		                    Get-DisplayPath -LocalPath $_pvFinal
		                }
		                else {
		                    # Per-activity split: leaf varies by ActivityType — show a
		                    # pattern URL so customers see the naming shape and the
		                    # folder, just like the existing 'Output Files: ...' line.
		                    $_outDir = Split-Path $OutputFile -Parent
		                    $_dispDir = (Get-DisplayPath -LocalPath $_outDir -Directory).TrimEnd('/','\')
		                    $_ts = [System.IO.Path]::GetFileNameWithoutExtension($OutputFile) -replace '.*_(\d{8}_\d{6}).*', '$1'
		                    "${_dispDir}/Purview_Audit_UsageActivity_<ActivityType>_${_ts}.csv"
		                }
		            }
		            elseif ($script:DestRaw.ContainsKey('Purview')) { $script:DestRaw['Purview'] }
		            else { '(inherits -OutputPath)' }
		        }
		        elseif ($row.Key -eq 'UserInfo') {
		            # Honor -OutputPathUserInfo (or an Append-side promotion of DestRaw) when bound;
		            # otherwise inherit -OutputPath. Without consulting Resolve-DataTypePaths the
		            # banner unconditionally joined the EntraUsers leaf onto $OutputFile's parent
		            # (the Purview -OutputPath dir), masking any -OutputPathUserInfo override that
		            # the runtime writer correctly routed to.
		            $_uiDt = script:Resolve-DataTypePaths -DataType 'UserInfo' -DefaultBasename (& $script:GetEffectiveEntraBasename)
		            if ($_uiDt -and $_uiDt.IsBound -and $_uiDt.Tier -eq 'Local') {
		                Get-DisplayPath -LocalPath (Join-Path $_uiDt.EffectiveDir $_uiDt.Basename)
		            }
		            elseif ($_uiDt -and $_uiDt.IsBound) {
		                # Remote per-stream override (Fabric / SharePoint URL) — surface the resolved file URL.
		                ($_uiDt.EffectiveDir.TrimEnd('/') + '/' + $_uiDt.Basename)
		            }
		            elseif ($OutputFile -and $script:GetEffectiveEntraBasename) {
		                $_entraLeaf  = & $script:GetEffectiveEntraBasename
		                $_entraLocal = Join-Path (Split-Path $OutputFile -Parent) $_entraLeaf
		                Get-DisplayPath -LocalPath $_entraLocal
		            }
		            elseif ($script:DestRaw.ContainsKey('UserInfo')) { $script:DestRaw['UserInfo'] }
		            else { '(inherits -OutputPath)' }
		        }
		        elseif ($row.Key -eq 'Agent365Info') {
		            # Symmetric fix to the UserInfo branch above: honor -OutputPathAgent365Info
		            # (or an Append-side promotion) before falling back to the Purview -OutputPath dir.
		            $_a365Dt = script:Resolve-DataTypePaths -DataType 'Agent365Info' -DefaultBasename (& $script:GetEffectiveAgent365Basename)
		            if ($_a365Dt -and $_a365Dt.IsBound -and $_a365Dt.Tier -eq 'Local') {
		                Get-DisplayPath -LocalPath (Join-Path $_a365Dt.EffectiveDir $_a365Dt.Basename)
		            }
		            elseif ($_a365Dt -and $_a365Dt.IsBound) {
		                ($_a365Dt.EffectiveDir.TrimEnd('/') + '/' + $_a365Dt.Basename)
		            }
		            elseif ($OutputFile -and $script:GetEffectiveAgent365Basename) {
		                $_a365Leaf  = & $script:GetEffectiveAgent365Basename
		                $_a365Local = Join-Path (Split-Path $OutputFile -Parent) $_a365Leaf
		                Get-DisplayPath -LocalPath $_a365Local
		            }
		            elseif ($script:DestRaw.ContainsKey('Agent365Info')) { $script:DestRaw['Agent365Info'] }
		            else { '(inherits -OutputPath)' }
		        }
		        elseif ($row.Key -eq 'Log') {
		            # Surface the resolved log destination URL (or final local path),
		            # NOT the local _PARTIAL scratch path. $script:LogFile is the
		            # _PARTIAL working copy throughout the run; strip the suffix and
		            # pass through Get-DisplayPath so remote-mode banners show the
		            # SharePoint / OneLake URL the log will land at — matching the
		            # 'Log File:' preamble line which uses the same transform via
		            # $displayLogFile. ($script:LogFile is not yet resolved to its
		            # final path at this point; only the local _PARTIAL copy exists
		            # until end-of-run upload + rename.)
		            if ($script:LogFile) {
		                $_logFinal = $script:LogFile -replace '_PARTIAL(?=\.log$)', ''
		                Get-DisplayPath -LocalPath $_logFinal
		            }
		            elseif ($script:RemoteOutputMode -ne 'None') { "Files/pax_run_logs/$($global:ScriptRunTimestamp)/" }
		            else { $OutputPath }
		        }
		        else { '(inherits -OutputPath)' }
		# Never truncate. Customers need the full URL for verification and copy-paste.
		$pathDisplay = $path
		$appendMarker = ''
		if ($row.AppendName -and $row.AppendVar) {
			# Single consistent marker across all tiers / both first-time and
			# subsequent appends. Init-vs-not distinction was inconsistent across
			# tiers (Local could Test-Path, Remote could not) and produced mixed
			# '[append-init:...]' / '[append:...]' tags within a single banner.
			$appendMarker = " [append:$($row.AppendName)]"
		}
		Write-LogHost ("      {0} [{1,-10}] {2}{3}" -f $row.Label, $tier, $pathDisplay, $appendMarker) -ForegroundColor White
	}
	# Per-tier truth in the Behavior summary. The Log stream in particular may
	# stay local even on a remote-mode run (only the Purview/UserInfo/Agent365
	# streams have remote bindings here).
	if ($script:RemoteOutputMode -ne 'None') {
		Write-LogHost "" -ForegroundColor White
		Write-LogHost "    Behavior    : Each stream is written to the tier shown above. Remote streams" -ForegroundColor White
		Write-LogHost "                  are staged in scratch and uploaded at run completion." -ForegroundColor White
	}
	Write-LogHost "═══════════════════════════════════════════════════════" -ForegroundColor Cyan
	Write-LogHost ""
}

# One-time legend explaining the Append/Merge tally vocabulary used by the
# various 'EntraUsers append-merge complete:' / 'Rollup: -AppendUserInfo
# merge:' / 'Rollup: -AppendFile merge:' lines emitted later in the run.
# The label 'Departed' in particular can mislead a casual reader into thinking
# rows were REMOVED from the file — they are not; 'Departed' rows are carried
# forward into the union with In_Latest_Append=FALSE. Gated on any -Append*
# switch being bound so the legend only appears when at least one merge tally
# will actually be emitted.
if ($AppendFile -or $AppendUserInfo -or $AppendAgent365Info) {
	Write-LogHost "═══════════════════════════════════════════════════════" -ForegroundColor Cyan
	Write-LogHost "  APPEND/MERGE TALLY LEGEND" -ForegroundColor Cyan
	Write-LogHost "═══════════════════════════════════════════════════════" -ForegroundColor Cyan
	Write-LogHost "    Each '-Append*' run emits a merge tally with four counts:" -ForegroundColor White
	Write-LogHost "      Retained = rows present in BOTH the target file and this run's output (overlap)" -ForegroundColor White
	Write-LogHost "      New      = rows added by THIS run only (current-only; not in target before)" -ForegroundColor White
	Write-LogHost "      Departed = rows present in TARGET ONLY (not seen this run); KEPT in the union" -ForegroundColor White
	Write-LogHost "                 with In_Latest_Append=FALSE — NOT removed from the file" -ForegroundColor White
	Write-LogHost "      Union    = total rows in the merged output (= Retained + New + Departed)" -ForegroundColor White
	Write-LogHost "═══════════════════════════════════════════════════════" -ForegroundColor Cyan
	Write-LogHost ""
}

# Rollup post-processor banner. Emitted only when -Rollup or -RollupPlusRaw is in effect
# (either passed on the CLI or restored from checkpoint on resume). Sits immediately after
# the permissions banner so users see at a glance that an embedded Python post-processor
# will run at end-of-run, what mode, and what raw-CSV retention behavior to expect.
if ($Rollup -or $RollupPlusRaw) {
	$rollupSwitchBannerName = if ($Rollup) { '-Rollup' } else { '-RollupPlusRaw' }
	$rollupRetention = if ($Rollup) {
		switch ($script:RollupProcessorMode) {
			'CopilotInteraction' { 'Raw Purview CSV and Entra users CSV will be DELETED on processor success (only rolled-up output kept).' }
			'M365Bundle'         {
				if ($IncludeUserInfo) {
					'Raw Purview CSV will be DELETED on processor success; Entra users CSV will be KEPT (not consumed by this processor).'
				} else {
					'Raw Purview CSV will be DELETED on processor success (only rolled-up output kept).'
				}
			}
			default              { 'Raw CSV(s) will be DELETED on processor success (only rolled-up output kept).' }
		}
	}
	else {
		switch ($script:RollupProcessorMode) {
			'CopilotInteraction' { 'Raw Purview CSV and Entra users CSV will be KEPT alongside the rolled-up output.' }
			'M365Bundle'         {
				if ($IncludeUserInfo) {
					'Raw Purview CSV and Entra users CSV will be KEPT alongside the rolled-up output.'
				} else {
					'Raw Purview CSV will be KEPT alongside the rolled-up output.'
				}
			}
			default              { 'Raw CSV(s) will be KEPT alongside the rolled-up output.' }
		}
	}
	$processorLabel = switch ($script:RollupProcessorMode) {
		'CopilotInteraction' { "Purview_CopilotInteraction_Processor v$($Script:EMBEDDED_PROCESSOR_COPILOT_VERSION) (--profile $($script:RollupDashboardProfile); inputs: Purview CSV + Entra users CSV)" }
		'M365Bundle'         { "Purview_M365_Usage_Bundle_Explosion_Processor v$($Script:EMBEDDED_PROCESSOR_M365_VERSION) (input: Purview CSV)" }
		default              { 'unresolved' }
	}
	$rollupTargetDashboard = switch ($script:RollupProcessorMode) {
		'CopilotInteraction' {
			if ($script:RollupDashboard -eq 'AIBV') { 'AI Business Value (Analytics-Hub)' }
			else { 'AI-in-One (Analytics-Hub)' }
		}
		'M365Bundle'         { 'M365 Usage Analytics (Analytics-Hub)' }
		default              { 'unresolved' }
	}
	Write-LogHost "═══════════════════════════════════════════════════════" -ForegroundColor Cyan
	Write-LogHost "  ROLLUP POST-PROCESSOR ENABLED ($rollupSwitchBannerName)" -ForegroundColor Cyan
	Write-LogHost "═══════════════════════════════════════════════════════" -ForegroundColor Cyan
	Write-LogHost "    Purpose   : Produces input files for the Microsoft Copilot Growth ROI Advisory Team's" -ForegroundColor White
	Write-LogHost "                Power BI templates at https://github.com/microsoft/Analytics-Hub." -ForegroundColor White
	Write-LogHost "                Output is NOT intended for any other downstream use." -ForegroundColor White
	Write-LogHost "    Target    : $rollupTargetDashboard" -ForegroundColor White
	Write-LogHost "    Processor : $processorLabel" -ForegroundColor White
	Write-LogHost "    Retention : $rollupRetention" -ForegroundColor White
	if ($IncludeAgent365Info) {
		Write-LogHost "    Companion : Agent365_<ts>.csv (point-in-time snapshot; ALWAYS retained — consumed by the same Analytics-Hub dashboards alongside the rollup output)." -ForegroundColor White
	}
	Write-LogHost "    Runtime   : Python $($Script:ROLLUP_PYTHON_MIN_MAJOR).$($Script:ROLLUP_PYTHON_MIN_MINOR)+ required (auto-installed if missing); 'orjson' auto-installed for speed (optional)." -ForegroundColor Gray
	# Destination-aware Output line. The per-data-type destination banner above
	# already shows the resolved tier/path for every stream, so this line just
	# summarizes where the rollup output lands relative to the audit CSV.
	# In M365Bundle mode the processor emits four files (Rollup + UserStats +
	# SessionCohort + SessionStats sidecars) sharing a common stem, all written
	# to the same destination; CopilotInteraction emits a single Interactions Fact CSV.
	$rollupOutputLabel = switch ($script:RollupProcessorMode) {
		'CopilotInteraction' { 'Rollup Fact CSV' }
		'M365Bundle'         { 'Rollup CSV bundle (Rollup + UserStats + SessionCohort + SessionStats sidecars sharing the same stem)' }
		default              { 'Rollup CSV' }
	}
	$rollupOutputSummary =
		if ($AppendFile) {
			"$rollupOutputLabel destination follows the Append target shown in the Per-data-type destinations banner above."
		} elseif ($script:RemoteOutputMode -ne 'None') {
			"$rollupOutputLabel is uploaded to the $script:RemoteOutputMode destination resolved for the Purview audit stream (see banner above)."
		} else {
			"$rollupOutputLabel is written to the local Purview audit destination resolved above."
		}
	Write-LogHost ("    Output    : {0}" -f $rollupOutputSummary) -ForegroundColor Gray
	Write-LogHost "═══════════════════════════════════════════════════════" -ForegroundColor Cyan
	Write-LogHost ""
}

$startTimeStamp = try { $script:metrics.StartTime.ToUniversalTime().ToString('yyyy-MM-dd HH:mm:ss') } catch { (Get-Date).ToUniversalTime().ToString('yyyy-MM-dd HH:mm:ss') }
Write-LogHost ("Script execution started at $startTimeStamp UTC") -ForegroundColor White

# For OnlyUserInfo mode, show simplified header (no Mode/DateRange/Purview output info)
if (-not $OnlyUserInfo -and -not $OnlyAgent365Info) {
	Write-LogHost "Mode: $scriptMode" -ForegroundColor White
	${rangeText} = if ($RAWInputCSV) { if ([string]::IsNullOrWhiteSpace($StartDate) -and [string]::IsNullOrWhiteSpace($EndDate)) { 'Full CSV (no date filter)' } else { "$StartDate (inclusive) to $EndDate (exclusive) (filters)" } } else { "$StartDate (inclusive) to $EndDate (exclusive)" }
	Write-LogHost "Date Range: $rangeText" -ForegroundColor White
} elseif ($OnlyAgent365Info) {
	Write-LogHost "Mode: OnlyAgent365Info (Microsoft Agent 365 catalog export only - no audit logs)" -ForegroundColor Cyan
} else {
	Write-LogHost "Mode: OnlyUserInfo (Entra user and MAC licensing export only)" -ForegroundColor Cyan
}
} # end: if (-not $ResumeSpecified) — parse-time mode/permissions/rollup/start banner

# --- Early build of $finalActivityTypes for user warning checks (before auth) ---
# This preview build is used ONLY for multi-output warning and PAYG billing warning
# The full/authoritative build happens later in the pipeline after authentication
$finalActivityTypes = @()
if ($PSBoundParameters.ContainsKey('ActivityTypes') -and $ActivityTypes) {
	$finalActivityTypes += $ActivityTypes
}
if ($IncludeM365Usage) {
	$finalActivityTypes += $m365UsageActivityBundle
}
# Add CopilotInteraction as default if no custom types and not excluded
$userProvidedCustomTypes = $PSBoundParameters.ContainsKey('ActivityTypes')
if (-not $ExcludeCopilotInteraction -and -not $userProvidedCustomTypes) {
	if (-not ($finalActivityTypes -contains 'CopilotInteraction')) {
		$finalActivityTypes += 'CopilotInteraction'
	}
}
# Remove CopilotInteraction if explicitly excluded
if ($ExcludeCopilotInteraction) {
	$finalActivityTypes = $finalActivityTypes | Where-Object { $_ -ne 'CopilotInteraction' }
}
$finalActivityTypes = $finalActivityTypes | Select-Object -Unique

# --- Multi-Output Warning: Prompt when many files/tabs expected without -CombineOutput ---
$activityTypeCount = $finalActivityTypes.Count
$isMultiOutputScenario = ($activityTypeCount -gt 10) -and (-not $CombineOutput)
$outputType = if ($ExportWorkbook) { "tabs" } else { "CSV files" }

if ($isMultiOutputScenario -and -not $Force) {
	Write-LogHost ""
	Write-LogHost "============================================================================================================" -ForegroundColor Yellow
	Write-Host "WARNING: Multiple Output $outputType Detected" -ForegroundColor Yellow
	Write-LogHost "============================================================================================================" -ForegroundColor Yellow
	Write-LogHost ""
	Write-LogHost "You have $activityTypeCount activity types selected." -ForegroundColor Cyan
	Write-LogHost "Without -CombineOutput, this will create $activityTypeCount separate $outputType." -ForegroundColor Cyan
	Write-LogHost ""
	Write-LogHost "Recommendation:" -ForegroundColor Green
	Write-LogHost "  • Add -CombineOutput to merge all activity types into a single $(if ($ExportWorkbook) { 'tab' } else { 'CSV file' })" -ForegroundColor Green
	Write-LogHost ""
	Write-LogHost "Do you want to continue with $activityTypeCount separate $outputType?" -ForegroundColor White
	Write-LogHost ""
	Write-LogHost "  [Y] YES - Continue with separate $outputType (I understand there will be many $outputType)" -ForegroundColor Green
	Write-LogHost "  [C] COMBINE - Enable -CombineOutput and continue (single merged $(if ($ExportWorkbook) { 'tab' } else { 'CSV' }))" -ForegroundColor Cyan
	Write-LogHost "  [E] EXIT - Cancel script execution" -ForegroundColor Red
	Write-LogHost ""

	# Strict noninteractive guard: on a container/ACA Job/CI
	# runner there is nobody to choose Y/C/E. Default to [Y] CONTINUE so scheduled runs
	# do not hang on stdin. Operators who want the [C] COMBINE behavior should pass
	# -CombineOutput explicitly; the script's -Force path treats this prompt as Y anyway.
	if (script:Test-IsNonInteractive) {
		Write-LogHost "  Noninteractive host detected: auto-selecting [Y] - continuing with $activityTypeCount separate $outputType." -ForegroundColor DarkGray
		Write-LogHost "  Hint: pass -CombineOutput to merge into a single output, or -Force to suppress this banner." -ForegroundColor DarkGray
		$multiOutput_choice = 'Y'
	} else {
		Send-PromptNotification
		$multiOutput_choice = Read-Host "Enter your choice (Y/C/E)"
	}
	
	if ($multiOutput_choice -eq 'Y' -or $multiOutput_choice -eq 'y') {
		Write-LogHost ""
		Write-LogHost "Continuing with $activityTypeCount separate output files..." -ForegroundColor Green
		Write-LogHost ""
	}
	elseif ($multiOutput_choice -eq 'C' -or $multiOutput_choice -eq 'c') {
		Write-LogHost ""
		Write-LogHost "ENABLED: -CombineOutput mode" -ForegroundColor Green
		Write-LogHost "  All $activityTypeCount activity types will be merged into a single CSV file." -ForegroundColor Cyan
		Write-LogHost ""
		$CombineOutput = $true
	}
	else {
		Write-LogHost ""
		Write-LogHost "User choice: EXIT - Script execution cancelled" -ForegroundColor Red
		Write-LogHost ""
		exit 0
	}
}
elseif ($isMultiOutputScenario -and $Force) {
	Write-LogHost "Force mode: Skipping multi-output warning ($activityTypeCount activity types, separate $outputType)" -ForegroundColor DarkGray
	Write-LogHost "  → Continuing with separate $outputType (use -CombineOutput to merge if desired)" -ForegroundColor DarkGray
}
# --- End Multi-Output Warning ---

# --- DSPM for AI: Billing Information Warning ---
if (($finalActivityTypes -contains 'AIAppInteraction') -or ($finalActivityTypes -contains 'ConnectedAIAppInteraction') -or ($finalActivityTypes -contains 'AIInteraction')) {
	if ($IncludeM365Usage -and -not ($finalActivityTypes -contains 'AIAppInteraction')) {
		# Bundle-attributed DSPM signal: -IncludeM365Usage carries ConnectedAIAppInteraction
		# as part of the curated activity bundle. The DSPM informational prompt is redundant
		# because AIAppInteraction (the PAYG path) is not requested; silently bypass.
	}
	elseif (-not $Force) {
		Write-LogHost ""
		Write-LogHost "============================================================================================================" -ForegroundColor Yellow
		Write-Host "INFORMATION: DSPM for AI Audit Logging - Billing Details" -ForegroundColor Cyan
		Write-LogHost "============================================================================================================" -ForegroundColor Yellow
		Write-LogHost ""
		Write-LogHost "DSPM Activity Types:" -ForegroundColor Cyan
		Write-LogHost "  • AIInteraction - FREE (Microsoft platforms: Copilot Studio, Azure AI Studio)" -ForegroundColor Green
		Write-LogHost "  • ConnectedAIAppInteraction - MIXED (FREE for Microsoft apps, PAYG for third-party)" -ForegroundColor Yellow
		if ($finalActivityTypes -contains 'AIAppInteraction') {
			Write-LogHost "  • AIAppInteraction - PAYG BILLING REQUIRED (third-party AI like ChatGPT)" -ForegroundColor DarkYellow
		}
		Write-LogHost ""
		# Check if AIAppInteraction is included - offer options
		if ($finalActivityTypes -contains 'AIAppInteraction') {
			Write-LogHost "[!] IMPORTANT: AIAppInteraction REQUIRES Microsoft Purview PAYG billing" -ForegroundColor Yellow
			Write-LogHost ""
			Write-LogHost "PAYG Requirements:" -ForegroundColor Cyan
			Write-LogHost "  • Azure subscription linked to M365 tenant" -ForegroundColor Cyan
			Write-LogHost "  • Microsoft Purview PAYG billing enabled in Compliance portal" -ForegroundColor Cyan
			Write-LogHost ""
			Write-LogHost "Do you have PAYG billing configured in your tenant?" -ForegroundColor White
			Write-LogHost ""
			Write-LogHost "  [Y] YES - I have PAYG billing, continue with all DSPM types" -ForegroundColor Green
			Write-LogHost "  [N] NO - I don't have PAYG billing, remove AIAppInteraction and continue" -ForegroundColor Yellow
			Write-LogHost "      (Third-party AI records will NOT be included)" -ForegroundColor DarkGray
			Write-LogHost "  [E] EXIT - Cancel script execution" -ForegroundColor Red
			Write-LogHost ""

			# Strict noninteractive guard: cannot prompt for
			# PAYG confirmation on a container/CI runner. Fail-fast with explicit recovery
			# guidance rather than silently including or removing AIAppInteraction.
			if (script:Test-IsNonInteractive) {
				Write-LogHost "ERROR: Cannot prompt for PAYG billing confirmation on a noninteractive host." -ForegroundColor Red
				Write-LogHost "  Recovery: re-run WITHOUT -ActivityTypes AIAppInteraction if PAYG is not configured," -ForegroundColor Yellow
				Write-LogHost "  OR pass -Force to acknowledge PAYG is configured and continue with AIAppInteraction." -ForegroundColor Yellow
				exit 1
			}

			Send-PromptNotification
			$payg_choice = Read-Host "Enter your choice (Y/N/E)"
			
			if ($payg_choice -eq 'Y' -or $payg_choice -eq 'y') {
				Write-LogHost ""
				Write-LogHost "Continuing with all DSPM types (AIInteraction, ConnectedAIAppInteraction, AIAppInteraction)..." -ForegroundColor Green
				Write-LogHost ""
			}
			elseif ($payg_choice -eq 'N' -or $payg_choice -eq 'n') {
				Write-LogHost ""
				Write-LogHost "REMOVED: AIAppInteraction (third-party AI records will NOT be captured)" -ForegroundColor Yellow
				Write-LogHost "Continuing with: AIInteraction, ConnectedAIAppInteraction (Microsoft platforms only)" -ForegroundColor Green
				Write-LogHost ""
				Write-LogHost "Note: Without PAYG billing, only Microsoft-hosted AI activity will be captured." -ForegroundColor Yellow
				Write-LogHost "      Third-party AI apps (ChatGPT, etc.) require PAYG billing." -ForegroundColor Yellow
				Write-LogHost ""
				
				# Set flag to remove AIAppInteraction during later rebuild
				$script:RemoveAIAppInteraction = $true
				$finalActivityTypes = $finalActivityTypes | Where-Object { $_ -ne 'AIAppInteraction' }
			}
			else {
				Write-LogHost ""
				Write-LogHost "User choice: EXIT - Script execution cancelled" -ForegroundColor Red
				Write-LogHost ""
				exit 0
			}
		}
		else {
			# No AIAppInteraction - simple Y/N prompt
			Write-LogHost "Note: AIAppInteraction (PAYG-only third-party AI) is NOT included." -ForegroundColor DarkGray
			Write-LogHost "      Only Microsoft-hosted AI activity will be captured (AIInteraction, ConnectedAIAppInteraction)." -ForegroundColor DarkGray
			Write-LogHost ""

			# Strict noninteractive guard: default to [Y]
			# CONTINUE because the surrounding banner is informational-only (no PAYG
			# entitlements are required for the activity types that remain in scope).
			if (script:Test-IsNonInteractive) {
				Write-LogHost "  Noninteractive host detected: auto-selecting [Y] - continuing with DSPM for AI export." -ForegroundColor DarkGray
				Write-LogHost ""
				$payg_choice = 'Y'
			} else {
				Send-PromptNotification
				$payg_choice = Read-Host "Continue with DSPM for AI export? (Y/N)"
			}
			
			if ($payg_choice -eq 'Y' -or $payg_choice -eq 'y') {
				Write-LogHost ""
				Write-LogHost "Continuing with DSPM for AI export..." -ForegroundColor Green
				Write-LogHost ""
			}
			else {
				Write-LogHost ""
				Write-LogHost "User choice: ABORT - DSPM for AI export declined" -ForegroundColor Red
				Write-LogHost "Script execution cancelled by user." -ForegroundColor Yellow
				Write-LogHost ""
				exit 0
			}
		}
	}
	else {
		Write-LogHost "Force mode enabled: Skipping DSPM for AI billing information prompt" -ForegroundColor DarkGray
		Write-LogHost "User choice: CONTINUE (Force mode - automatic acceptance)" -ForegroundColor Gray
	}
}
# --- End PAYG Billing Warning ---

# Resume: suppress the parse-time Output Directory / Output Files / Log File /
# Authentication / Append/Destination banner. On -Resume the destination state
# ($OutputFile, $script:RemoteOutputMode, $displayLogFile, $Auth, $AppendFile…)
# is restored AFTER this point by Read-Checkpoint and re-resolved by the
# post-restore destination block. The post-restore Parameter Snapshot prints
# the authoritative values. Without this gate the early banner shows the
# bootstrap log path, a fresh non-restored timestamp in the Output Files line,
# and stale Auth=WebLogin on every resume run.
if (-not $ResumeSpecified) {
# Output file/directory display based on export mode
# Note: If activity type switches are used, detailed filenames will be shown after activity types are finalized
# For OnlyUserInfo / OnlyAgent365Info modes, show only the relevant standalone files
if ($OnlyUserInfo) {
	$outputDir = if ($OutputPath) { $OutputPath } else { "C:\Temp\" }
	if ($ExportWorkbook) {
		$entraOutputFile = Join-Path $outputDir "EntraUsers_MAClicensing_${global:ScriptRunTimestamp}.xlsx"
		Write-LogHost "Output File: $(Get-DisplayPath -LocalPath $entraOutputFile) (Entra users workbook)" -ForegroundColor White
	} else {
		# Honor -OutputPathUserInfo (or an Append-side promotion of DestRaw) when bound; otherwise inherit $outputDir.
		$_uiDt6 = script:Resolve-DataTypePaths -DataType 'UserInfo' -DefaultBasename (& $script:GetEffectiveEntraBasename)
		$entraOutputFile = if ($_uiDt6 -and $_uiDt6.IsBound -and $_uiDt6.Tier -eq 'Local') { Join-Path $_uiDt6.EffectiveDir $_uiDt6.Basename }
			elseif ($_uiDt6 -and $_uiDt6.IsBound) { $_uiDt6.EffectiveDir.TrimEnd('/') + '/' + $_uiDt6.Basename }
			else { Join-Path $outputDir (& $script:GetEffectiveEntraBasename) }
		if ($_uiDt6 -and $_uiDt6.IsBound -and $_uiDt6.Tier -ne 'Local') { Write-LogHost "Output File: $entraOutputFile" -ForegroundColor White }
		else { Write-LogHost "Output File: $(Get-DisplayPath -LocalPath $entraOutputFile)" -ForegroundColor White }
	}
	if ($IncludeAgent365Info) {
		# Honor -OutputPathAgent365Info (or an Append-side promotion of DestRaw) when bound; otherwise inherit $outputDir.
		$_aiDt6 = script:Resolve-DataTypePaths -DataType 'Agent365Info' -DefaultBasename (& $script:GetEffectiveAgent365Basename)
		$agent365PreviewFile = if ($_aiDt6 -and $_aiDt6.IsBound -and $_aiDt6.Tier -eq 'Local') { Join-Path $_aiDt6.EffectiveDir $_aiDt6.Basename }
			elseif ($_aiDt6 -and $_aiDt6.IsBound) { $_aiDt6.EffectiveDir.TrimEnd('/') + '/' + $_aiDt6.Basename }
			else { Join-Path $outputDir (& $script:GetEffectiveAgent365Basename) }
		if ($_aiDt6 -and $_aiDt6.IsBound -and $_aiDt6.Tier -ne 'Local') { Write-LogHost "  Agent 365 File: $agent365PreviewFile" -ForegroundColor Gray }
		else { Write-LogHost "  Agent 365 File: $(Get-DisplayPath -LocalPath $agent365PreviewFile)" -ForegroundColor Gray }
	}
} elseif ($OnlyAgent365Info) {
	# OnlyAgent365Info mode: only the Agents365 catalog CSV is produced
	$outputDir = if ($OutputPath) { $OutputPath } else { "C:\Temp\" }
	# Honor -OutputPathAgent365Info (or an Append-side promotion of DestRaw) when bound; otherwise inherit $outputDir.
	$_aiDt7 = script:Resolve-DataTypePaths -DataType 'Agent365Info' -DefaultBasename (& $script:GetEffectiveAgent365Basename)
	$agent365PreviewFile = if ($_aiDt7 -and $_aiDt7.IsBound -and $_aiDt7.Tier -eq 'Local') { Join-Path $_aiDt7.EffectiveDir $_aiDt7.Basename }
		elseif ($_aiDt7 -and $_aiDt7.IsBound) { $_aiDt7.EffectiveDir.TrimEnd('/') + '/' + $_aiDt7.Basename }
		else { Join-Path $outputDir (& $script:GetEffectiveAgent365Basename) }
	if ($_aiDt7 -and $_aiDt7.IsBound -and $_aiDt7.Tier -ne 'Local') { Write-LogHost "Output File: $agent365PreviewFile (Microsoft Agent 365 catalog)" -ForegroundColor White }
	else { Write-LogHost "Output File: $(Get-DisplayPath -LocalPath $agent365PreviewFile) (Microsoft Agent 365 catalog)" -ForegroundColor White }
} elseif ($AppendFile) {
	# AppendFile mode: the destination URL is already surfaced by the parameter
	# snapshot's AppendFile row. Re-emitting an 'Output File: ...' + 'Mode:
	# Appending to existing file' pair here duplicates that row (and in remote
	# tiers it also leaks the scratch-shadow URL via $displayOutputFile). Only
	# emit Agent 365 sibling info, which the snapshot does not cover.
	if ($IncludeAgent365Info) {
		# Agent 365 always writes a separate CSV alongside the appended file (or its own tab if Excel).
		# Honor -OutputPathAgent365Info (or an Append-side promotion of DestRaw) when bound; otherwise inherit the LOCAL OutputFile parent.
		$agent365TargetDir = Split-Path $OutputFile -Parent
		if ($ExportWorkbook) {
			Write-LogHost "  Agent 365 Tab: Agents365 (appended to workbook)" -ForegroundColor Gray
		} else {
			$_aiDt8 = script:Resolve-DataTypePaths -DataType 'Agent365Info' -DefaultBasename (& $script:GetEffectiveAgent365Basename)
			$agent365PreviewFile = if ($_aiDt8 -and $_aiDt8.IsBound -and $_aiDt8.Tier -eq 'Local') { Join-Path $_aiDt8.EffectiveDir $_aiDt8.Basename }
				elseif ($_aiDt8 -and $_aiDt8.IsBound) { $_aiDt8.EffectiveDir.TrimEnd('/') + '/' + $_aiDt8.Basename }
				else { Join-Path $agent365TargetDir (& $script:GetEffectiveAgent365Basename) }
			if ($_aiDt8 -and $_aiDt8.IsBound -and $_aiDt8.Tier -ne 'Local') { Write-LogHost "  Agent 365 File: $agent365PreviewFile" -ForegroundColor Gray }
			else { Write-LogHost "  Agent 365 File: $(Get-DisplayPath -LocalPath $agent365PreviewFile)" -ForegroundColor Gray }
		}
	}
} elseif ($ExcludeCopilotInteraction) {
	# Activity type switches present - defer detailed filename listing until after activity types are finalized
	$outputDir = if ($ExportWorkbook) {
		if ($OutputPath) { $OutputPath } else { "C:\Temp\" }
	} else {
		Split-Path $OutputFile -Parent
	}
	Write-LogHost "Output Directory: $(Get-DisplayPath -LocalPath $outputDir -Directory)\" -ForegroundColor White
	Write-LogHost "  (Detailed filenames will be shown after activity types are finalized)" -ForegroundColor Gray
} elseif ($ExportWorkbook) {
	# Excel mode: always one .xlsx file (combined tab or multiple tabs)
	$outputDir = if ($OutputPath) { $OutputPath } else { "C:\Temp\" }
	$displayDir = (Get-DisplayPath -LocalPath $outputDir -Directory).TrimEnd('/','\') + '/'
	if ($CombineOutput) {
		# New naming: Purview_Audit_CombinedUsageActivity[_EntraUsers]_timestamp.xlsx
		$baseName = "Purview_Audit_CombinedUsageActivity"
		if ($IncludeUserInfo -and -not $UseEOM) { $baseName += "_EntraUsers" }
		Write-LogHost "Output File: ${displayDir}${baseName}_<timestamp>.xlsx (single-tab workbook)" -ForegroundColor White
	} else {
		Write-LogHost "Output File: ${displayDir}Purview_Audit_MultiTab_<timestamp>.xlsx (multi-tab workbook)" -ForegroundColor White
	}
	if ($IncludeAgent365Info) { Write-LogHost "  Agent 365 Tab: Agents365 (appended to workbook after audit + EntraUsers)" -ForegroundColor Gray }
} else {
	# CSV mode: combined file or separate files per activity type
	if ($CombineOutput) {
		# Single combined CSV file. Suppress the "(combined - all activity types)"
		# qualifier when the run is gated to exactly one activity type — the file
		# name itself already carries the single activity-type name in that case.
		$_isSingleActivityRun = ($ActivityTypes -and @($ActivityTypes).Count -eq 1 -and -not $IncludeM365Usage)
		$_combinedQualifier = if ($_isSingleActivityRun) { '' } else { ' (combined - all activity types)' }
		Write-LogHost "Output File: ${displayOutputFile}${_combinedQualifier}" -ForegroundColor White
		if ($IncludeUserInfo -and -not $UseEOM) {
			# Honor -OutputPathUserInfo (or an Append-side promotion of DestRaw) when bound, so the
			# preview line matches the runtime writer's actual destination instead of unconditionally
			# joining the EntraUsers leaf onto $OutputFile's parent (the Purview -OutputPath dir).
			$_uiDt = script:Resolve-DataTypePaths -DataType 'UserInfo' -DefaultBasename (& $script:GetEffectiveEntraBasename)
			$entraFile = if ($_uiDt -and $_uiDt.IsBound -and $_uiDt.Tier -eq 'Local') {
				Join-Path $_uiDt.EffectiveDir $_uiDt.Basename
			} elseif ($_uiDt -and $_uiDt.IsBound) {
				$_uiDt.EffectiveDir.TrimEnd('/') + '/' + $_uiDt.Basename
			} else {
				Join-Path (Split-Path $OutputFile -Parent) (& $script:GetEffectiveEntraBasename)
			}
			if ($_uiDt -and $_uiDt.IsBound -and $_uiDt.Tier -ne 'Local') {
				Write-LogHost "  Entra Users File: $entraFile" -ForegroundColor Gray
			} else {
				Write-LogHost "  Entra Users File: $(Get-DisplayPath -LocalPath $entraFile)" -ForegroundColor Gray
			}
		}
		if ($IncludeAgent365Info) {
			# Honor -OutputPathAgent365Info (or an Append-side promotion of DestRaw) when bound; same
			# rationale as the EntraUsers branch above.
			$_aiDt = script:Resolve-DataTypePaths -DataType 'Agent365Info' -DefaultBasename (& $script:GetEffectiveAgent365Basename)
			$agent365PreviewFile = if ($_aiDt -and $_aiDt.IsBound -and $_aiDt.Tier -eq 'Local') {
				Join-Path $_aiDt.EffectiveDir $_aiDt.Basename
			} elseif ($_aiDt -and $_aiDt.IsBound) {
				$_aiDt.EffectiveDir.TrimEnd('/') + '/' + $_aiDt.Basename
			} else {
				Join-Path (Split-Path $OutputFile -Parent) (& $script:GetEffectiveAgent365Basename)
			}
			if ($_aiDt -and $_aiDt.IsBound -and $_aiDt.Tier -ne 'Local') {
				Write-LogHost "  Agent 365 File: $agent365PreviewFile" -ForegroundColor Gray
			} else {
				Write-LogHost "  Agent 365 File: $(Get-DisplayPath -LocalPath $agent365PreviewFile)" -ForegroundColor Gray
			}
		}
	} else {
		# Separate CSV files per activity type
		$outputDir  = Split-Path $OutputFile -Parent
		$displayDir = (Get-DisplayPath -LocalPath $outputDir -Directory).TrimEnd('/','\')
		$timestamp  = [System.IO.Path]::GetFileNameWithoutExtension($OutputFile) -replace '.*_(\d{8}_\d{6}).*', '$1'
		Write-LogHost "Output Directory: $displayDir\" -ForegroundColor White
		Write-LogHost "Output Files: ${displayDir}\Purview_Audit_UsageActivity_<ActivityType>_${timestamp}.csv" -ForegroundColor Gray
		if ($IncludeUserInfo -and -not $UseEOM) {
			# Honor -OutputPathUserInfo (or an Append-side promotion of DestRaw) when bound, so the
			# separate-files preview matches the runtime writer's actual destination instead of
			# unconditionally joining the EntraUsers leaf onto $OutputFile's parent.
			$_uiDt = script:Resolve-DataTypePaths -DataType 'UserInfo' -DefaultBasename (& $script:GetEffectiveEntraBasename)
			$entraFile = if ($_uiDt -and $_uiDt.IsBound -and $_uiDt.Tier -eq 'Local') {
				Join-Path $_uiDt.EffectiveDir $_uiDt.Basename
			} elseif ($_uiDt -and $_uiDt.IsBound) {
				$_uiDt.EffectiveDir.TrimEnd('/') + '/' + $_uiDt.Basename
			} else {
				Join-Path $outputDir (& $script:GetEffectiveEntraBasename)
			}
			if ($_uiDt -and $_uiDt.IsBound -and $_uiDt.Tier -ne 'Local') {
				Write-LogHost "  Entra Users: $entraFile" -ForegroundColor Gray
			} else {
				Write-LogHost "  Entra Users: $(Get-DisplayPath -LocalPath $entraFile)" -ForegroundColor Gray
			}
		}
		if ($IncludeAgent365Info) {
			# Honor -OutputPathAgent365Info (or an Append-side promotion of DestRaw) when bound; same
			# rationale as the EntraUsers branch above.
			$_aiDt = script:Resolve-DataTypePaths -DataType 'Agent365Info' -DefaultBasename (& $script:GetEffectiveAgent365Basename)
			$agent365PreviewFile = if ($_aiDt -and $_aiDt.IsBound -and $_aiDt.Tier -eq 'Local') {
				Join-Path $_aiDt.EffectiveDir $_aiDt.Basename
			} elseif ($_aiDt -and $_aiDt.IsBound) {
				$_aiDt.EffectiveDir.TrimEnd('/') + '/' + $_aiDt.Basename
			} else {
				Join-Path $outputDir (& $script:GetEffectiveAgent365Basename)
			}
			if ($_aiDt -and $_aiDt.IsBound -and $_aiDt.Tier -ne 'Local') {
				Write-LogHost "  Agent 365: $agent365PreviewFile" -ForegroundColor Gray
			} else {
				Write-LogHost "  Agent 365: $(Get-DisplayPath -LocalPath $agent365PreviewFile)" -ForegroundColor Gray
			}
		}
	}
}

Write-LogHost "Log File: $displayLogFile" -ForegroundColor White
if (-not $RAWInputCSV) {
	Write-LogHost "Authentication: $Auth" -ForegroundColor White
}

# Append-target / Fabric Delta destination summary. Only emitted when at least one
# is in effect, so non-append local runs see no extra banner noise.
if ($AppendFile -or $AppendUserInfo -or $AppendAgent365Info -or
    ($script:RemoteOutputMode -eq 'Fabric' -and $script:RemoteOutputUrl -match '/Tables/?$')) {
	Write-LogHost "Append / Destination:" -ForegroundColor Yellow
	if ($AppendFile)         { Write-LogHost ("  -AppendFile         : {0}" -f $AppendFile) -ForegroundColor Gray }
	if ($AppendUserInfo)     { Write-LogHost ("  -AppendUserInfo     : {0}" -f $AppendUserInfo) -ForegroundColor Gray }
	if ($AppendAgent365Info) { Write-LogHost ("  -AppendAgent365Info : {0}" -f $AppendAgent365Info) -ForegroundColor Gray }
	if ($script:RemoteOutputMode -eq 'Fabric' -and $script:RemoteOutputUrl -match '/Tables/?$') {
		Write-LogHost ("  Fabric destination  : {0}  (CSV outputs land as Delta tables)" -f $script:RemoteOutputUrl) -ForegroundColor Gray
	}
}
} # end: if (-not $ResumeSpecified) — parse-time output/log/auth/append banner

if ($AgentId -or $AgentsOnly -or $ExcludeAgents -or $PromptFilter -or $UserIds -or $GroupNames) {
	Write-LogHost "Filters:" -ForegroundColor Yellow
	if ($AgentsOnly) { Write-LogHost "  AgentsOnly: Only records with AgentId present" -ForegroundColor Gray }
	if ($AgentId) {
		$agentDisplay = if ($AgentId.Count -eq 1) {
			"Specific AgentId: $($AgentId[0])"
		}
		elseif ($AgentId.Count -le 3) {
			"Specific AgentIds ($($AgentId.Count)): " + ($AgentId -join '; ')
		}
		else {
			"Specific AgentIds ($($AgentId.Count) total):"
		}
		Write-LogHost "  $agentDisplay" -ForegroundColor Gray
		if ($AgentId.Count -gt 3) {
			for ($i = 0; $i -lt [Math]::Min(3, $AgentId.Count); $i++) {
				$displayId = if ($AgentId[$i].Length -gt 80) { $AgentId[$i].Substring(0, 77) + '...' } else { $AgentId[$i] }
				Write-LogHost "    [$($i+1)] $displayId" -ForegroundColor DarkGray
			}
			if ($AgentId.Count -gt 3) {
				Write-LogHost "    ... and $($AgentId.Count - 3) more" -ForegroundColor DarkGray
			}
		}
	}
	if ($ExcludeAgents) { Write-LogHost "  ExcludeAgents: Only records without AgentId" -ForegroundColor Gray }
	if ($PromptFilter) {
		$promptLabel = switch ($PromptFilter) {
			'Prompt'   { 'Only prompts (Message_isPrompt = True)' }
			'Response' { 'Only responses (Message_isPrompt = False)' }
			'Both'     { 'Both prompts and responses (Message_isPrompt = True or False)' }
			'Null'     { 'Only records with no Message_isPrompt values (Null/Empty)' }
		}
		Write-LogHost "  PromptFilter: $promptLabel" -ForegroundColor Gray
	}
	if ($UserIds -or $GroupNames) {
		if ($UserIds) {
			if ($UserIds.Count -eq 1) { Write-LogHost "  UserIds: 1 user" -ForegroundColor Gray } else { Write-LogHost "  UserIds: $($UserIds.Count) users" -ForegroundColor Gray }
		}
		if ($GroupNames) {
			if ($GroupNames.Count -eq 1) { Write-LogHost "  GroupNames: 1 group" -ForegroundColor Gray } else { Write-LogHost "  GroupNames: $($GroupNames.Count) groups" -ForegroundColor Gray }
		}
	}
}

Write-LogHost "=============================================" -ForegroundColor Cyan
Write-LogHost ""

# Now perform AppendFile validation if needed (after banner display).
#
# Test-AppendFileCompatibility's sole purpose is to detect a mismatch between
# the existing file's explosion schema (column shape produced by -ExplodeArrays
# or -ExplodeDeep) and the current run's explosion params. In a Standard →
# Standard append both modes are 'Standard (no explosion)' by construction
# and a mismatch is impossible — the only outcomes are 'compatible' (no-op)
# or a spurious failure when the existing-file probe (Get-Content -First 1)
# can't read the file (e.g. remote AppendFile URL not yet downloaded to
# scratch, file briefly locked by another process). Gate the validator on
# explosion actually being in play OR a replay (-RAWInputCSV) run so the
# only people who see this check are the ones it was designed for.
if ($AppendFile -and ($ExplodeArrays -or $ExplodeDeep -or $RAWInputCSV)) {
	
	$validation = Test-AppendFileCompatibility `
		-FilePath $OutputFile `
		-IsExcel $ExportWorkbook `
		-ExplodeArrays:$ExplodeArrays `
		-ExplodeDeep:$ExplodeDeep
	
	if (-not $validation.Compatible) {
		Write-Host ""
		Write-Host "════════════════════════════════════════════════════════════════════" -ForegroundColor Red
		Write-Host "  ERROR: Explosion Parameter Mismatch - Cannot Append" -ForegroundColor Red
		Write-Host "════════════════════════════════════════════════════════════════════" -ForegroundColor Red
		Write-Host ""
		Write-Host "The existing file was created with different explosion parameters than" -ForegroundColor Yellow
		Write-Host "the current command. Appending would create incompatible data structures." -ForegroundColor Yellow
		Write-Host ""
		Write-Host "Existing file: $OutputFile" -ForegroundColor White
		Write-Host "  Columns: $($validation.ExistingCount)" -ForegroundColor Gray
		Write-Host "  Mode: $($validation.ExistingMode.DisplayName)" -ForegroundColor Gray
		Write-Host ""
		Write-Host "Current command:" -ForegroundColor White
		Write-Host "  Mode: $($validation.CurrentMode.DisplayName)" -ForegroundColor Gray
		Write-Host ""
		Write-Host "Root Cause:" -ForegroundColor Cyan
		Write-Host "  Explosion parameters must match between original file and append operation." -ForegroundColor Yellow
		Write-Host ""
		Write-Host "Resolution Options:" -ForegroundColor Cyan
		Write-Host "  1. Match the original file's parameters:" -ForegroundColor White
		Write-Host "     Use: $($validation.ExistingMode.DisplayName)" -ForegroundColor Gray
		Write-Host "  2. Create new output file instead:" -ForegroundColor White
		Write-Host "     Remove -AppendFile parameter" -ForegroundColor Gray
		
		if ($ExportWorkbook) {
			Write-Host ""
			Write-Host "Note for Excel mode:" -ForegroundColor DarkGray
			Write-Host "  If parameters matched, mismatched columns would create timestamped" -ForegroundColor DarkGray
			Write-Host "  duplicate tabs instead of appending (no data loss)." -ForegroundColor DarkGray
		}
		else {
			Write-Host ""
			Write-Host "CRITICAL for CSV mode:" -ForegroundColor Yellow
			Write-Host "  CSV append with mismatched explosion parameters creates CORRUPTED files!" -ForegroundColor Yellow
			Write-Host "  This validation prevents data corruption by failing early." -ForegroundColor Yellow
		}
		
		Write-Host ""
		Write-Host "════════════════════════════════════════════════════════════════════" -ForegroundColor Red
		exit 1
	}
	
	Write-LogHost "  Explosion parameters compatible ($($validation.CurrentMode.DisplayName)) - safe to append" -ForegroundColor Green
}

if ($ExplodeDeep -and $ExplodeArrays) { Write-LogHost "Note: -ExplodeDeep takes precedence over -ExplodeArrays (arrays will still explode, plus deep flatten)." -ForegroundColor DarkYellow }
if ($ForcedRawInputCsvExplosion -and -not $ExplodeDeep -and -not $ExplodeArrays.IsPresent) { Write-LogHost "RAWInputCSV provided -> forcing Purview array explosion (non-exploded mode disabled)." -ForegroundColor Yellow }
if ($script:memoryFlushEnabled) { 
	$memSource = if ($MaxMemoryMB -eq -1) { "auto-detected" } else { "user-specified" }
	Write-LogHost "Memory management: $($script:ResolvedMaxMemoryMB)MB limit ($memSource) - will flush to disk when exceeded" -ForegroundColor Cyan 
} elseif ($script:ResolvedMaxMemoryMB -gt 0 -and ($ExplodeDeep -or $ExplodeArrays -or $ForcedRawInputCsvExplosion)) {
	Write-LogHost "Note: Memory limit ($($script:ResolvedMaxMemoryMB)MB) ignored because explosion mode is active" -ForegroundColor DarkYellow
}

if ($RAWInputCSV) {
	# Replay mode (offline): no live EOM/Graph query; show only relevant parameters.
	# The output-destinations cluster at the top mirrors the Graph-mode snapshot so
	# operators see all file paths in one block. Replay forbids remote destination
	# tiers in parameter validation, so the resolveAuxDisplayPath helper effectively
	# always falls through to local Get-DisplayPath here — but the structure is kept
	# identical for visual consistency between modes.
	$resolveAuxDisplayPath = {
		param([string]$DataTypeKey, [string]$FileName)
		if ($script:DestTier -and $script:DestTier.ContainsKey($DataTypeKey) -and $script:DestTier[$DataTypeKey] -and $script:DestTier[$DataTypeKey] -ne 'Local') {
			$folder = if ($script:DestParentUrl -and $script:DestParentUrl.ContainsKey($DataTypeKey) -and $script:DestParentUrl[$DataTypeKey]) { $script:DestParentUrl[$DataTypeKey] } else { $script:DestRaw[$DataTypeKey] }
			return ($folder.TrimEnd('/','\') + '/' + $FileName)
		}
		# Local tier: honor a per-stream -OutputPath<DataType> override (or an Append-side promotion of
		# DestRaw) so the snapshot reflects the actual on-disk destination, not the inherited -OutputPath
		# dir. Without this, EntraUsersOutput / Agents365Output displayed the -OutputPath parent even
		# when the runtime writer was routing the stream to its own -OutputPath<DataType> directory.
		$auxDt = script:Resolve-DataTypePaths -DataType $DataTypeKey -DefaultBasename $FileName
		if ($auxDt -and $auxDt.IsBound -and $auxDt.Tier -eq 'Local') {
			return (Get-DisplayPath -LocalPath (Join-Path $auxDt.EffectiveDir $FileName))
		}
		$localSibling = Join-Path (Split-Path $OutputFile -Parent) $FileName
		return (Get-DisplayPath -LocalPath $localSibling)
	}

	$paramSnapshot = [ordered]@{
		Mode                    = $scriptMode
		RAWInputCSV             = $RAWInputCSV
		'StartDate (inclusive)' = $StartDate
		'EndDate (exclusive)'   = $EndDate
	}

	# ── Output destinations cluster ──────────────────────────────────────
	# Append-vs-Output suppression: when an -Append* flag is bound the
	# resolved destination of that stream IS the Append target — emitting both
	# OutputFile/EntraUsersOutput/Agents365Output AND the matching Append* line
	# produces two identical URLs that read like a bug. Suppress the resolved-
	# destination line in append mode; the Append* line below is the single
	# source of truth for that stream.
	# Purview stream
	if ($PSBoundParameters.ContainsKey('AppendFile') -and $AppendFile) {
		$paramSnapshot['AppendFile'] = $AppendFile
	} else {
		$paramSnapshot['OutputFile'] = $displayOutputFile
	}

	# UserInfo stream (Entra users licensing export). Replay mode currently
	# does not regenerate EntraUsers, but if -IncludeUserInfo is in scope the
	# path is surfaced for parity with the standard snapshot.
	if ($PSBoundParameters.ContainsKey('AppendUserInfo') -and $AppendUserInfo) {
		$paramSnapshot['AppendUserInfo'] = $AppendUserInfo
	} elseif (($IncludeUserInfo -or $OnlyUserInfo) -and -not $UseEOM) {
		if ($ExportWorkbook) {
			$paramSnapshot['EntraUsersOutput'] = 'Workbook Tab: EntraUsers'
		} else {
			$paramSnapshot['EntraUsersOutput'] = & $resolveAuxDisplayPath 'UserInfo' (& $script:GetEffectiveEntraBasename)
		}
	}

	# Agent365Info stream
	if ($PSBoundParameters.ContainsKey('AppendAgent365Info') -and $AppendAgent365Info) {
		$paramSnapshot['AppendAgent365Info'] = $AppendAgent365Info
	} elseif ($IncludeAgent365Info -or $OnlyAgent365Info) {
		if ($ExportWorkbook) {
			$paramSnapshot['Agents365Output'] = 'Workbook Tab: Agents365'
		} else {
			$paramSnapshot['Agents365Output'] = & $resolveAuxDisplayPath 'Agent365Info' (& $script:GetEffectiveAgent365Basename)
		}
	}

	# Log stream
	$paramSnapshot['LogFile'] = $displayLogFile
	# ── End output destinations cluster ──────────────────────────────────

	$paramSnapshot['ActivityTypes']             = ($ActivityTypes -join ';')
	$paramSnapshot['ExcludeCopilotInteraction'] = $ExcludeCopilotInteraction.IsPresent
	$paramSnapshot['ExplodeArrays']             = $ForcedRawInputCsvExplosion
	$paramSnapshot['ExplodeDeep']               = $ExplodeDeep.IsPresent
	if ($ExplodeDeep -or $PSBoundParameters.ContainsKey('FlatDepth')) { $paramSnapshot['FlatDepth'] = $FlatDepth }
	$paramSnapshot['UseEOM']                    = $UseEOM.IsPresent
	$paramSnapshot['MaxMemoryMB']               = $(if ($script:ResolvedMaxMemoryMB -eq 0) { 'Off' } else { "$($script:ResolvedMaxMemoryMB)MB" + $(if ($MaxMemoryMB -eq -1) { ' (auto)' } else { '' }) })
	$paramSnapshot['StatusIntervalSeconds']     = $StatusIntervalSeconds
	$paramSnapshot['ExportWorkbook']            = $ExportWorkbook.IsPresent
	$paramSnapshot['CombineOutput']             = $CombineOutput.IsPresent
	$paramSnapshot['Deidentify']                = $Deidentify.IsPresent
	$paramSnapshot['FillerLabel']               = $script:HierarchyFillMode
	$paramSnapshot['FillerLabelText']           = $script:HierarchyFillLabel
	$paramSnapshot['Force']                     = $Force.IsPresent
	$paramSnapshot['SkipDiagnostics']           = $SkipDiagnostics.IsPresent
	$paramSnapshot['EmitMetricsJson']           = $EmitMetricsJson.IsPresent
	$paramSnapshot['MetricsPath']               = $(if ($MetricsPath) { $MetricsPath } else { '' })
	$paramSnapshot['StreamingSchemaSample']     = $StreamingSchemaSample
	$paramSnapshot['StreamingChunkSize']        = $StreamingChunkSize
	$paramSnapshot['PSVersion']                 = $PSVersionTable.PSVersion.ToString()
	$paramSnapshot['PSEdition']                 = $PSVersionTable.PSEdition
	$paramSnapshot['HostName']                  = $Host.Name
	$paramSnapshot['HostVersion']               = $(try { $Host.Version.ToString() } catch { '' })

	$copilotIncluded = $IncludeCopilotInteraction.IsPresent -or ($ActivityTypes -contains $copilotBaseActivityType)
	$paramSnapshot['IncludeCopilotInteraction'] = $copilotIncluded
}
else {
	# Smart parameter snapshot: Show only applicable parameters for the chosen query mode.
	#
	# Top of the snapshot is a single, contiguous "Output destinations" cluster so
	# operators can audit every file the run will produce at a glance. Each stream
	# (Purview / UserInfo / Agent365Info / Log) gets its lines kept together:
	#   1. The user-supplied -OutputPath* (if bound) — shown verbatim (DestRaw)
	#   2. The resolved artifact path — shown via Get-DisplayPath / DestParentUrl
	#      so SharePoint/Fabric tiers display as remote URLs, not local scratch
	#   3. The companion -Append* (if bound) — shown verbatim
	# Auxiliary helper resolves per-data-type display path for sibling artifacts
	# (EntraUsers, Agent365): if the data type's tier is non-Local, use that
	# tier's folder URL; otherwise fall through Get-DisplayPath (which maps onto
	# the Purview remote URL when the Purview output is remote, or returns the
	# local path verbatim when fully local).
	$resolveAuxDisplayPath = {
		param([string]$DataTypeKey, [string]$FileName)
		if ($script:DestTier -and $script:DestTier.ContainsKey($DataTypeKey) -and $script:DestTier[$DataTypeKey] -and $script:DestTier[$DataTypeKey] -ne 'Local') {
			$folder = if ($script:DestParentUrl -and $script:DestParentUrl.ContainsKey($DataTypeKey) -and $script:DestParentUrl[$DataTypeKey]) { $script:DestParentUrl[$DataTypeKey] } else { $script:DestRaw[$DataTypeKey] }
			return ($folder.TrimEnd('/','\') + '/' + $FileName)
		}
		# Local tier: honor a per-stream -OutputPath<DataType> override (or an Append-side promotion of
		# DestRaw) so the snapshot reflects the actual on-disk destination, not the inherited -OutputPath
		# dir. Without this, EntraUsersOutput / Agents365Output displayed the -OutputPath parent even
		# when the runtime writer was routing the stream to its own -OutputPath<DataType> directory.
		$auxDt = script:Resolve-DataTypePaths -DataType $DataTypeKey -DefaultBasename $FileName
		if ($auxDt -and $auxDt.IsBound -and $auxDt.Tier -eq 'Local') {
			return (Get-DisplayPath -LocalPath (Join-Path $auxDt.EffectiveDir $FileName))
		}
		$localSibling = Join-Path (Split-Path $OutputFile -Parent) $FileName
		return (Get-DisplayPath -LocalPath $localSibling)
	}

	$paramSnapshot = [ordered]@{
		'StartDate (inclusive)' = $StartDate
		'EndDate (exclusive)'   = $EndDate
	}

	# ── Output destinations cluster ──────────────────────────────────────
	# Append-vs-Output suppression: see RAWInputCSV branch for rationale.
	# Purview stream
	if ($PSBoundParameters.ContainsKey('AppendFile') -and $AppendFile) {
		$paramSnapshot['AppendFile'] = $AppendFile
	} else {
		$paramSnapshot['OutputFile'] = $displayOutputFile
	}

	# UserInfo stream (Entra users licensing export)
	if ($PSBoundParameters.ContainsKey('AppendUserInfo') -and $AppendUserInfo) {
		$paramSnapshot['AppendUserInfo'] = $AppendUserInfo
	} elseif (($IncludeUserInfo -or $OnlyUserInfo) -and -not $UseEOM) {
		if ($ExportWorkbook) {
			$paramSnapshot['EntraUsersOutput'] = 'Workbook Tab: EntraUsers'
		} else {
			$paramSnapshot['EntraUsersOutput'] = & $resolveAuxDisplayPath 'UserInfo' (& $script:GetEffectiveEntraBasename)
		}
	}

	# Agent365Info stream
	if ($PSBoundParameters.ContainsKey('AppendAgent365Info') -and $AppendAgent365Info) {
		$paramSnapshot['AppendAgent365Info'] = $AppendAgent365Info
	} elseif ($IncludeAgent365Info -or $OnlyAgent365Info) {
		if ($ExportWorkbook) {
			$paramSnapshot['Agents365Output'] = 'Workbook Tab: Agents365'
		} else {
			$paramSnapshot['Agents365Output'] = & $resolveAuxDisplayPath 'Agent365Info' (& $script:GetEffectiveAgent365Basename)
		}
	}

	# Log stream
	$paramSnapshot['LogFile'] = $displayLogFile
	# ── End output destinations cluster ──────────────────────────────────
	
	# Authentication (both modes, but different usage)
	if ($UseEOM) {
		# EOM mode: Auth parameter controls connection
		$paramSnapshot['Auth'] = $Auth
	} else {
		# Graph API mode: Auth parameter controls connection
		$paramSnapshot['Auth'] = $Auth
		# Capture AppRegistration context (without exposing secrets)
		$paramSnapshot['TenantId'] = $(if ($TenantId) { $TenantId } elseif ($env:GRAPH_TENANT_ID) { '[GRAPH_TENANT_ID]' } else { '' })
		$paramSnapshot['ClientId'] = $(if ($ClientId) { $ClientId } elseif ($env:GRAPH_CLIENT_ID) { '[GRAPH_CLIENT_ID]' } else { '' })
		if ($PSBoundParameters.ContainsKey('ClientSecret') -or $env:GRAPH_CLIENT_SECRET) {
			$paramSnapshot['ClientSecret'] = '[securestring provided]'
		}
		if ($PSBoundParameters.ContainsKey('ClientCertificateThumbprint')) {
			$paramSnapshot['ClientCertificateThumbprint'] = $ClientCertificateThumbprint
		}
		if ($PSBoundParameters.ContainsKey('ClientCertificateStoreLocation')) {
			$paramSnapshot['ClientCertificateStoreLocation'] = $ClientCertificateStoreLocation
		}
		if ($PSBoundParameters.ContainsKey('ClientCertificatePath')) {
			$paramSnapshot['ClientCertificatePath'] = $ClientCertificatePath
		}
		if ($PSBoundParameters.ContainsKey('ClientCertificatePassword')) {
			$paramSnapshot['ClientCertificatePassword'] = '[securestring provided]'
		}
	}
	
	# Query parameters specific to each mode
	if ($UseEOM) {
		# EOM-only: Search-UnifiedAuditLog parameters
		$paramSnapshot['BlockHours'] = $BlockHours
		$paramSnapshot['ResultSize'] = $ResultSize
		$paramSnapshot['PacingMs'] = $PacingMs
		$paramSnapshot['DisableAdaptive'] = $DisableAdaptive.IsPresent
		$paramSnapshot['MemoryPressureMB'] = $MemoryPressureMB
		$paramSnapshot['BackoffBaseSeconds'] = $BackoffBaseSeconds
		$paramSnapshot['BackoffMaxSeconds'] = $BackoffMaxSeconds
		$paramSnapshot['CircuitBreakerThreshold'] = $CircuitBreakerThreshold
		$paramSnapshot['CircuitBreakerCooldownSeconds'] = $CircuitBreakerCooldownSeconds
		$paramSnapshot['ProgressSmoothingAlpha'] = $ProgressSmoothingAlpha
		# Adaptive-pacing controls — surfaced whenever -UseEOM is in play so the
		# effective tuning that drove the run is auditable. These do nothing under
		# -DisableAdaptive but are still informative for post-run analysis.
		$paramSnapshot['HighLatencyMs'] = $HighLatencyMs
		$paramSnapshot['LowLatencyMs'] = $LowLatencyMs
		$paramSnapshot['LowLatencyConsecutive'] = $LowLatencyConsecutive
		$paramSnapshot['ThroughputDropPct'] = $ThroughputDropPct
		$paramSnapshot['ThroughputSmoothingAlpha'] = $ThroughputSmoothingAlpha
		$paramSnapshot['AdaptiveConcurrencyCeiling'] = $AdaptiveConcurrencyCeiling
		$paramSnapshot['AutoCompleteness'] = $AutoCompleteness.IsPresent
	} else {
		# Graph-only: parallel/partition orchestration
		$paramSnapshot['ParallelMode'] = $ParallelMode
		$paramSnapshot['MaxParallelGroups'] = $MaxParallelGroups
		$paramSnapshot['EnableParallel'] = $EnableParallel.IsPresent
		$paramSnapshot['PartitionHours'] = if ($PartitionHours -gt 0) { $PartitionHours } else { 'auto' }
		$paramSnapshot['MaxPartitions'] = $MaxPartitions
		$paramSnapshot['MaxNetworkOutageMinutes'] = $MaxNetworkOutageMinutes
		$paramSnapshot['IncludeUserInfo'] = $IncludeUserInfo.IsPresent
		$paramSnapshot['OnlyUserInfo'] = $OnlyUserInfo.IsPresent
		$paramSnapshot['IncludeTelemetry'] = $IncludeTelemetry.IsPresent
	}

	# Crossover (both modes)
	$paramSnapshot['MaxConcurrency'] = $MaxConcurrency
	$paramSnapshot['MaxMemoryMB'] = $(if ($script:ResolvedMaxMemoryMB -eq 0) { 'Off' } else { "$($script:ResolvedMaxMemoryMB)MB" + $(if ($MaxMemoryMB -eq -1) { ' (auto)' } else { '' }) })
	$paramSnapshot['StatusIntervalSeconds'] = $StatusIntervalSeconds

	# Common toggles and output options
	$paramSnapshot['UseEOM'] = $UseEOM.IsPresent
	$paramSnapshot['ExportWorkbook'] = $ExportWorkbook.IsPresent
	$paramSnapshot['CombineOutput'] = $CombineOutput.IsPresent
	$paramSnapshot['Deidentify'] = $Deidentify.IsPresent
	$paramSnapshot['FillerLabel'] = $script:HierarchyFillMode
	$paramSnapshot['FillerLabelText'] = $script:HierarchyFillLabel
	# AppendFile / AppendUserInfo / AppendAgent365Info live in the output-destinations
	# cluster at the top of the snapshot, kept next to their corresponding -OutputPath*
	# and resolved artifact paths so operators see the full file-routing picture in one
	# block. They are intentionally not repeated here.
	$paramSnapshot['Force'] = $Force.IsPresent
	$paramSnapshot['SkipDiagnostics'] = $SkipDiagnostics.IsPresent
	$paramSnapshot['Rollup'] = $Rollup.IsPresent
	$paramSnapshot['RollupPlusRaw'] = $RollupPlusRaw.IsPresent
	$paramSnapshot['Dashboard'] = $Dashboard
	$paramSnapshot['EmitMetricsJson'] = $EmitMetricsJson.IsPresent
	$paramSnapshot['MetricsPath'] = $(if ($MetricsPath) { $MetricsPath } else { '' })
	$paramSnapshot['StreamingSchemaSample'] = $StreamingSchemaSample
	$paramSnapshot['StreamingChunkSize'] = $StreamingChunkSize
	
	# Common parameters (work in both modes)
	$paramSnapshot['ActivityTypes'] = ($ActivityTypes -join ';')
	$paramSnapshot['RecordTypes'] = $(if ($RecordTypes) { ($RecordTypes -join ';') } else { '' })
	$paramSnapshot['ServiceTypes'] = $(if ($ServiceTypes) { ($ServiceTypes -join ';') } else { '' })
	$copilotIncluded = $IncludeCopilotInteraction.IsPresent -or ($ActivityTypes -contains $copilotBaseActivityType)
	$paramSnapshot['IncludeCopilotInteraction'] = $copilotIncluded
	$paramSnapshot['IncludeM365Usage'] = $IncludeM365Usage.IsPresent
	$paramSnapshot['IncludeAgent365Info'] = $IncludeAgent365Info.IsPresent
	$paramSnapshot['OnlyAgent365Info'] = $OnlyAgent365Info.IsPresent
	$paramSnapshot['ExcludeCopilotInteraction'] = $ExcludeCopilotInteraction.IsPresent
	
	# Post-processing filters (work in both modes - applied during/after explosion)
	$paramSnapshot['AgentsOnly'] = $AgentsOnly.IsPresent
	$paramSnapshot['AgentId'] = $(if ($AgentId) { ($AgentId -join ';') } else { '' })
	$paramSnapshot['ExcludeAgents'] = $ExcludeAgents.IsPresent
	$paramSnapshot['UserId'] = $(if ($UserIds) { ($UserIds -join ';') } else { '' })
	
	# GroupNames only works in live mode (requires auth for expansion)
	if (-not $UseEOM -and $GroupNames) {
		$paramSnapshot['GroupName'] = ($GroupNames -join ';')
	}
	
	$paramSnapshot['PromptFilter'] = $(if ($PromptFilter) { $PromptFilter } else { '' })
	
	# Output format parameters (work in both modes)
	$paramSnapshot['ExplodeArrays'] = ($ExplodeArrays.IsPresent -or $ForcedRawInputCsvExplosion -or $ExplodeDeep.IsPresent)
	$paramSnapshot['ExplodeDeep'] = $ExplodeDeep.IsPresent
	# FlatDepth governs how many nested levels -ExplodeDeep walks. Surface it whenever
	# ExplodeDeep is in play, OR whenever the user explicitly set it on the CLI, so
	# operators can verify depth was honored.
	if ($ExplodeDeep -or $PSBoundParameters.ContainsKey('FlatDepth')) { $paramSnapshot['FlatDepth'] = $FlatDepth }
	$paramSnapshot['ExplosionThreads'] = $(if ($ExplosionThreads -eq 0) { 'auto' } else { $ExplosionThreads })
	
	# Environment info
	$paramSnapshot['PSVersion'] = $PSVersionTable.PSVersion.ToString()
	$paramSnapshot['PSEdition'] = $PSVersionTable.PSEdition
	$paramSnapshot['HostName'] = $Host.Name
	$paramSnapshot['HostVersion'] = $(try { $Host.Version.ToString() } catch { '' })

	# EntraUsersOutput / Agents365Output are emitted up in the output-destinations
	# cluster at the top of the snapshot so all per-stream file paths stay together.
	# The earlier injection-via-rebuild logic was removed when that cluster was added.
}
